/**
 * 组件测试模板
 * 用于快速创建新的组件测试
 */

import React from 'react'
import { render, screen, fireEvent, waitFor } from '@testing-library/react'
import { QueryClient, QueryClientProvider } from '@tanstack/react-query'
import { BrowserRouter } from 'react-router-dom'

// 导入Mock配置
import {
  setupDefaultMocks,
  clearAllMocks,
  mockHasPermission
} from './mocks'

// 测试工具函数
const createTestQueryClient = () => new QueryClient({
  defaultOptions: {
    queries: { retry: false },
    mutations: { retry: false },
  },
})

// 测试包装器组件
const TestWrapper = ({ children }: {
  children: React.ReactNode
}) => {
  const queryClient = createTestQueryClient()

  return (
    <QueryClientProvider client={queryClient}>
      <BrowserRouter>
        {children}
      </BrowserRouter>
    </QueryClientProvider>
  )
}

// 通用测试辅助函数
export const renderWithProviders = (
  ui: React.ReactElement,
  _options: { initialEntries?: string[] } = {}
) => {
  return render(ui, { wrapper: ({ children }) =>
    <TestWrapper>{children}</TestWrapper>
  })
}

// 模拟用户权限
// const mockUserPermissions = ['asset.read', 'asset.create', 'asset.update', 'asset.delete']

// 测试套件模板
export const createComponentTestSuite = (
  componentName: string,
  componentPath: string,
  requiredProps: Record<string, unknown> = {},
  _mockServices: Record<string, unknown> = {}
) => {
  // 动态导入组件
  let Component: React.ComponentType<any>
  try {
    // eslint-disable-next-line @typescript-eslint/no-require-imports
    Component = require(componentPath).default
  } catch {
    throw new Error(`无法加载组件: ${componentPath}`)
  }

  describe(`${componentName} 组件测试`, () => {
    beforeEach(() => {
      clearAllMocks()
      setupDefaultMocks()
    })

    test('应该正确渲染组件', () => {
      renderWithProviders(<Component {...requiredProps} />)

      // 验证组件是否渲染
      expect(screen.getByTestId(componentName.toLowerCase())).toBeInTheDocument()
    })

    test('应该显示必需的props', () => {
      renderWithProviders(<Component {...requiredProps} />)

      // 验证必需的props是否正确显示
      Object.entries(requiredProps).forEach(([_key, value]) => {
        if (typeof value === 'string') {
          expect(screen.getByText(value)).toBeInTheDocument()
        }
      })
    })

    test('应该处理用户交互', async () => {
      const mockOnClick = jest.fn()
      const propsWithClick = { ...requiredProps, onClick: mockOnClick }

      renderWithProviders(<Component {...propsWithClick} />)

      // 查找可点击的元素
      const clickableElement = screen.getByRole('button') || screen.getByTestId('button')

      // 模拟点击
      fireEvent.click(clickableElement)

      // 验证回调被调用
      expect(mockOnClick).toHaveBeenCalledTimes(1)
    })

    test('应该处理加载状态', () => {
      renderWithProviders(<Component {...requiredProps} />)

      // 验证加载状态
      expect(screen.getByTestId('loading') || screen.getByText('加载中...')).toBeInTheDocument()
    })

    test('应该处理错误状态', async () => {
      renderWithProviders(<Component {...requiredProps} />)

      // 等待错误显示
      await waitFor(() => {
        expect(screen.getByText('网络错误') || screen.getByTestId('error')).toBeInTheDocument()
      })
    })

    test('应该正确处理权限控制', () => {
      mockHasPermission.mockReturnValue(false)

      renderWithProviders(<Component {...requiredProps} requiredPermission="asset.create" />)

      // 验证无权限时的显示
      expect(screen.getByText('无权限访问') || screen.getByTestId('no-permission')).toBeInTheDocument()
    })

    test('应该响应式适配', () => {
      // Mock不同屏幕尺寸
      Object.defineProperty(window, 'innerWidth', {
        writable: true,
        configurable: true,
        value: 768,
      })

      renderWithProviders(<Component {...requiredProps} />)

      // 验证响应式行为
      expect(screen.getByTestId('responsive-layout')).toBeInTheDocument()
    })

    test('应该正确处理表单提交', async () => {
      const mockOnSubmit = jest.fn()
      const formProps = { ...requiredProps, onSubmit: mockOnSubmit }

      renderWithProviders(<Component {...formProps} />)

      // 填写表单
      const input = screen.getByLabelText(/名称/i) || screen.getByPlaceholderText(/输入/i)
      fireEvent.change(input, { target: { value: '测试值' } })

      // 提交表单
      const submitButton = screen.getByRole('button', { name: /提交|保存/i })
      fireEvent.click(submitButton)

      // 验证提交
      await waitFor(() => {
        expect(mockOnSubmit).toHaveBeenCalledWith(expect.objectContaining({
          name: '测试值'
        }))
      })
    })

    test('应该正确处理数据更新', async () => {
      const initialData = { id: '1', name: '初始名称' }
      const updatedData = { id: '1', name: '更新名称' }

      const { rerender } = renderWithProviders(
        <Component {...requiredProps} data={initialData} />
      )

      expect(screen.getByText('初始名称')).toBeInTheDocument()

      rerender(
        <TestWrapper>
          <Component {...requiredProps} data={updatedData} />
        </TestWrapper>
      )

      expect(screen.getByText('更新名称')).toBeInTheDocument()
    })

    test('应该正确处理键盘事件', () => {
      renderWithProviders(<Component {...requiredProps} />)

      const input = screen.getByRole('textbox') || screen.getByRole('combobox')

      // 测试Enter键
      fireEvent.keyDown(input, { key: 'Enter' })

      // 测试Escape键
      fireEvent.keyDown(input, { key: 'Escape' })

      // 验证键盘事件处理
      expect(screen.getByDisplayValue('')).toBeInTheDocument()
    })
  })
}

// 组件集成测试模板
export const createIntegrationTestSuite = (
  componentName: string,
  componentPath: string,
  requiredProps: Record<string, unknown> = {}
) => {
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  const Component = require(componentPath).default

  describe(`${componentName} 集成测试`, () => {
    beforeEach(() => {
      clearAllMocks()
      setupDefaultMocks()
    })

    test('应该与路由系统集成', async () => {
      renderWithProviders(<Component {...requiredProps} />, {
        initialEntries: ['/test-route']
      })

      await waitFor(() => {
        expect(screen.getByTestId(componentName.toLowerCase())).toBeInTheDocument()
      })
    })

    test('应该与状态管理集成', async () => {
      // Mock状态管理
      const mockState = { data: 'test-data' }

      renderWithProviders(<Component {...requiredProps} state={mockState} />)

      await waitFor(() => {
        expect(screen.getByText('test-data')).toBeInTheDocument()
      })
    })

    test('应该与API服务集成', async () => {
      renderWithProviders(<Component {...requiredProps} />)

      await waitFor(() => {
        expect(screen.getByTestId(componentName.toLowerCase())).toBeInTheDocument()
      })
    })
  })
}

// 导出模板和工具函数
export {
  TestWrapper,
  createTestQueryClient,
}

export default {
  createComponentTestSuite,
  createIntegrationTestSuite,
  TestWrapper,
  renderWithProviders,
  createTestQueryClient,
}

/**
 * 简单的Jest测试
 * 专注于基本的React和Jest功能
 */

// React导入
import * as React from 'react';

// 简单的测试
describe('基础测试', () => {
  test('数学运算', () => {
    expect(2 + 2).toBe(4);
    expect(5 * 5).toBe(25);
  });

  test('字符串操作', () => {
    const str = 'Hello World';
    expect(str).toContain('Hello');
    expect(str.toUpperCase()).toBe('HELLO WORLD');
  });

  test('数组操作', () => {
    const arr = [1, 2, 3, 4, 5];
    expect(arr).toHaveLength(5);
    expect(arr.includes(3)).toBe(true);
  });

  test('对象操作', () => {
    const obj = { name: 'test', value: 123 };
    expect(obj.name).toBe('test');
    expect(obj.value).toBe(123);
    expect(obj).toHaveProperty('name');
  });

  test('布尔逻辑', () => {
    expect(true).toBe(true);
    expect(false).toBe(false);
    expect(1 > 0).toBe(true);
    expect(null).toBeNull();
    expect(undefined).toBeUndefined();
  });
});

// Mock测试
describe('Mock测试', () => {
  test('函数mock', () => {
    const mockFn = jest.fn();
    mockFn('arg1', 'arg2');

    expect(mockFn).toHaveBeenCalledWith('arg1', 'arg2');
    expect(mockFn).toHaveBeenCalledTimes(1);
  });

  test('返回值mock', () => {
    const mockFn = jest.fn().mockReturnValue('mocked result');
    const result = mockFn();

    expect(result).toBe('mocked result');
    expect(mockFn).toHaveBeenCalled();
  });

  test('异步函数mock', async () => {
    const mockAsyncFn = jest.fn().mockResolvedValue('async result');
    const result = await mockAsyncFn();

    expect(result).toBe('async result');
    expect(mockAsyncFn).toHaveBeenCalled();
  });

  test('错误mock', () => {
    const mockFn = jest.fn().mockImplementation(() => {
      throw new Error('Mock error');
    });

    expect(() => mockFn()).toThrow('Mock error');
  });
});

// React组件测试（简化版）
describe('React基础测试', () => {
  test('React引用', () => {
    expect(React).toBeDefined();
    expect(React.createElement).toBeDefined();
    expect(React.Component).toBeDefined();
  });

  test('JSX解析', () => {
    // 这应该不会抛出错误，说明JSX解析正常
    const element = React.createElement('div', { className: 'test' }, 'Hello');
    expect(element.type).toBe('div');
    expect(element.props.className).toBe('test');
    expect((element.props as any).children).toBe('Hello');
  });
});

// 异步测试
describe('异步测试', () => {
  test('Promise解析', async () => {
    const promise = Promise.resolve('success');
    const result = await promise;
    expect(result).toBe('success');
  });

  test('Promise拒绝', async () => {
    const promise = Promise.reject(new Error('failure'));
    await expect(promise).rejects.toThrow('failure');
  });

  test('async/await', async () => {
    const asyncFunction = async () => {
      return await Promise.resolve('async result');
    };

    const result = await asyncFunction();
    expect(result).toBe('async result');
  });
});

// 工具函数测试
describe('工具函数测试', () => {
  test('日期处理', () => {
    const date = new Date('2023-01-01');
    expect(date.getFullYear()).toBe(2023);
    expect(date.getMonth()).toBe(0); // 月份是0-indexed
    expect(date.getDate()).toBe(1);
  });

  test('数学函数', () => {
    expect(Math.round(3.7)).toBe(4);
    expect(Math.floor(3.9)).toBe(3);
    expect(Math.ceil(3.1)).toBe(4);
    expect(Math.max(1, 5, 3)).toBe(5);
    expect(Math.min(1, 5, 3)).toBe(1);
  });

  test('字符串函数', () => {
    const str = 'Hello World';
    expect(str.split(' ')).toEqual(['Hello', 'World']);
    expect(str.replace('World', 'Universe')).toBe('Hello Universe');
    expect(str.slice(0, 5)).toBe('Hello');
    expect(str.substring(6)).toBe('World');
  });
});

// 错误处理测试
describe('错误处理测试', () => {
  test('try-catch', () => {
    try {
      throw new Error('Test error');
    } catch (error) {
      expect(error).toBeInstanceOf(Error);
      expect((error as Error).message).toBe('Test error');
    }
  });

  test('错误类型检查', () => {
    const typeError = new TypeError('Type error');
    const referenceError = new ReferenceError('Reference error');

    expect(typeError).toBeInstanceOf(TypeError);
    expect(referenceError).toBeInstanceOf(ReferenceError);
  });
});

// 性能相关测试
describe('性能测试', () => {
  test('执行时间', () => {
    const start = performance.now();

    // 执行一些操作
    let sum = 0;
    for (let i = 0; i < 1000; i++) {
      sum += i;
    }

    const end = performance.now();
    const duration = end - start;

    expect(sum).toBe(499500); // 0 + 1 + ... + 999
    expect(duration).toBeLessThan(100); // 应该在100ms内完成
  });

  test('内存使用', () => {
    // 创建大量对象测试内存分配
    const objects = Array.from({ length: 1000 }, (_, i) => ({
      id: i,
      name: `Object ${i}`,
      data: Array.from({ length: 100 }, (_, j) => j)
    }));

    expect(objects).toHaveLength(1000);
    expect(objects[0].name).toBe('Object 0');
    expect(objects[999].name).toBe('Object 999');
    expect(objects[0].data).toHaveLength(100);
  });
});

// 类型检查测试
describe('类型检查测试', () => {
  test('基本类型', () => {
    const str: string = 'test';
    const num: number = 123;
    const bool: boolean = true;
    const arr: number[] = [1, 2, 3];
    const obj: { key: string } = { key: 'value' };

    expect(typeof str).toBe('string');
    expect(typeof num).toBe('number');
    expect(typeof bool).toBe('boolean');
    expect(Array.isArray(arr)).toBe(true);
    expect(typeof obj).toBe('object');
  });

  test('类型转换', () => {
    const strNum = '123';
    const numStr = '456';

    expect(Number(strNum)).toBe(123);
    expect(String(numStr)).toBe('456');
    expect(Boolean('true')).toBe(true);
    expect(Boolean('')).toBe(false);
  });
});

// 清理测试
afterEach(() => {
  jest.clearAllMocks();
});

import React from 'react'
import { render, RenderOptions } from '@testing-library/react'
import { QueryClient, QueryClientProvider } from '@tanstack/react-query'
import { BrowserRouter } from 'react-router-dom'
import { ConfigProvider } from 'antd'
import zhCN from 'antd/locale/zh_CN'

// 创建测试用的QueryClient
const createTestQueryClient = () => new QueryClient({
  defaultOptions: {
    queries: { retry: false },
    mutations: { retry: false },
  },
})

// 测试渲染函数
const AllTheProviders = ({ children }: { children: React.ReactNode }) => {
  const queryClient = createTestQueryClient()

  return (
    <QueryClientProvider client={queryClient}>
      <BrowserRouter>
        <ConfigProvider locale={zhCN}>
          {children}
        </ConfigProvider>
      </BrowserRouter>
    </QueryClientProvider>
  )
}

// 自定义渲染函数
const customRender = (ui: React.ReactElement, options?: RenderOptions) =>
  render(ui, { wrapper: AllTheProviders, ...options })

// 重新导出所有测试工具
export * from '@testing-library/react'
export { customRender as render }
export { screen, fireEvent, waitFor } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
export { userEvent }
export { QueryClient } from '@tanstack/react-query'

import React from 'react'
import {
  PieChart,
  Pie,
  Cell,
  BarChart,
  Bar,
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer
} from 'recharts'
import { Card, Empty, Spin } from 'antd'

// 图表颜色主题
const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8', '#82ca9d', '#ffc658', '#ff7300']

// 基础图表组件属性
interface BaseChartProps {
  title: string
  loading?: boolean
  height?: number
  className?: string
}

// 饼图数据接口
interface PieData {
  name: string
  value: number
  count?: number
  percentage?: number
}

// 柱状图数据接口
interface BarData {
  name: string
  value: number
  [key: string]: unknown
}

// 折线图数据接口
interface LineData {
  date: string
  [key: string]: unknown
}

// 饼图组件
interface PieChartProps extends BaseChartProps {
  data: PieData[]
  showLegend?: boolean
  showTooltip?: boolean
  innerRadius?: number
  outerRadius?: number
}

export const AnalyticsPieChart: React.FC<PieChartProps> = ({
  title,
  data,
  loading = false,
  height = 300,
  showLegend = true,
  showTooltip = true,
  innerRadius = 0,
  outerRadius = 80,
  className
}) => {
  const renderCustomizedLabel = ({
    cx,
    cy,
    midAngle,
    innerRadius,
    outerRadius,
    percent
  }: {
    cx: number
    cy: number
    midAngle: number
    innerRadius: number
    outerRadius: number
    percent: number
  }) => {
    if (percent < 0.05) return null // 小于5%不显示标签

    const RADIAN = Math.PI / 180
    const radius = innerRadius + (outerRadius - innerRadius) * 0.5
    const x = cx + radius * Math.cos(-midAngle * RADIAN)
    const y = cy + radius * Math.sin(-midAngle * RADIAN)

    return (
      <text
        x={x}
        y={y}
        fill="white"
        textAnchor={x > cx ? 'start' : 'end'}
        dominantBaseline="central"
        fontSize={12}
        fontWeight="bold"
      >
        {`${(percent * 100).toFixed(0)}%`}
      </text>
    )
  }

  if (loading) {
    return (
      <Card title={title} className={className}>
        <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Spin size="large" />
        </div>
      </Card>
    )
  }

  if (!data || data.length === 0) {
    return (
      <Card title={title} className={className}>
        <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Empty description="暂无数据" />
        </div>
      </Card>
    )
  }

  return (
    <Card title={title} className={className}>
      <ResponsiveContainer width="100%" height={height}>
        <PieChart>
          <Pie
            data={data}
            cx="50%"
            cy="50%"
            innerRadius={innerRadius}
            outerRadius={outerRadius}
            paddingAngle={2}
            dataKey="value"
            label={renderCustomizedLabel}
            labelLine={false}
          >
            {data.map((_, index) => (
              <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
            ))}
          </Pie>
          {showTooltip && <Tooltip formatter={(value: number, name: string) => [formatAreaValue(value), name]} />}
          {showLegend && <Legend />}
        </PieChart>
      </ResponsiveContainer>
    </Card>
  )
}

// 柱状图组件
interface BarChartProps extends BaseChartProps {
  data: BarData[]
  xAxisKey: string
  barKey: string
  barSize?: number
  showLegend?: boolean
  showTooltip?: boolean
  showGrid?: boolean
  color?: string
}

export const AnalyticsBarChart: React.FC<BarChartProps> = ({
  title,
  data,
  xAxisKey,
  barKey,
  loading = false,
  height = 300,
  barSize = 30,
  showLegend = false,
  showTooltip = true,
  showGrid = true,
  color = '#0088FE',
  className
}) => {
  // 添加调试信息
  // Debug information for chart rendering

  if (loading) {
    return (
      <Card title={title} className={className}>
        <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Spin size="large" />
        </div>
      </Card>
    )
  }

  if (!data || data.length === 0) {
    return (
      <Card title={title} className={className}>
        <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Empty description="暂无数据" />
        </div>
      </Card>
    )
  }

  return (
    <Card title={title} className={className}>
      <ResponsiveContainer width="100%" height={height}>
        <BarChart data={data} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
          {showGrid && <CartesianGrid strokeDasharray="3 3" />}
          <XAxis
            dataKey={xAxisKey}
            tick={{ fontSize: 12 }}
            interval={0}
            angle={-45}
            textAnchor="end"
            height={60}
          />
          <YAxis
            tick={{ fontSize: 12 }}
            tickFormatter={(value: number) => {
              // Y轴数值格式化 - 使用激进的格式化逻辑但不显示单位
              return formatAggressive(value);
            }}
          />
          {showTooltip && <Tooltip formatter={(value: number, name: string) => [formatAreaValue(value), name]} />}
          {showLegend && <Legend />}
          <Bar
            dataKey={barKey}
            fill={color}
            radius={[4, 4, 0, 0]}
            barSize={barSize}
            label={{
              position: 'top',
              formatter: (value: number) => {
                // 格式化数据标签显示 - 使用激进的格式化去除尾随零
                return formatAggressive(value);
              },
              fontSize: 12,
              fill: '#666'
            }}
          />
        </BarChart>
      </ResponsiveContainer>
    </Card>
  )
}

// 折线图组件
interface LineChartProps extends BaseChartProps {
  data: LineData[]
  lines: Array<{
    key: string
    name: string
    color: string
    strokeWidth?: number
  }>
  xAxisKey: string
  showGrid?: boolean
  showLegend?: boolean
  showTooltip?: boolean
  showDots?: boolean
}

export const AnalyticsLineChart: React.FC<LineChartProps> = ({
  title,
  data,
  lines,
  xAxisKey,
  loading = false,
  height = 300,
  showGrid = true,
  showLegend = true,
  showTooltip = true,
  showDots = true,
  className
}) => {
  if (loading) {
    return (
      <Card title={title} className={className}>
        <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Spin size="large" />
        </div>
      </Card>
    )
  }

  if (!data || data.length === 0) {
    return (
      <Card title={title} className={className}>
        <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Empty description="暂无数据" />
        </div>
      </Card>
    )
  }

  return (
    <Card title={title} className={className}>
      <ResponsiveContainer width="100%" height={height}>
        <LineChart data={data} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
          {showGrid && <CartesianGrid strokeDasharray="3 3" />}
          <XAxis
            dataKey={xAxisKey}
            tick={{ fontSize: 12 }}
          />
          <YAxis tick={{ fontSize: 12 }} />
          {showTooltip && <Tooltip />}
          {showLegend && <Legend />}
          {lines.map((line) => (
            <Line
              key={line.key}
              type="monotone"
              dataKey={line.key}
              name={line.name}
              stroke={line.color}
              strokeWidth={line.strokeWidth || 2}
              dot={showDots}
              activeDot={{ r: 6 }}
            />
          ))}
        </LineChart>
      </ResponsiveContainer>
    </Card>
  )
}

// 统一的数值格式化函数
const formatAreaValue = (value: number): string => {
  const num = Number(value);
  if (isNaN(num)) return '0㎡';

  if (num >= 10000) {
    return `${(num / 10000).toFixed(2)}万㎡`;
  } else if (num >= 1000) {
    return `${(num / 1000).toFixed(1)}千㎡`;
  } else {
    // 对于小于1000的数值，移除不必要的.00
    const formatted = num.toFixed(2);
    return formatted.endsWith('.00') ? `${Math.round(num)}㎡` : `${formatted}㎡`;
  }
};

// 更激进的数值格式化函数，用于去除所有可能的尾随零
const formatAggressive = (value: number): string => {
  const num = Number(value);
  if (isNaN(num)) return '0';

  if (num >= 10000) {
    const result = (num / 10000).toFixed(2);
    return result.endsWith('.00') ? `${(num / 10000).toFixed(0)}万` : result + '万';
  } else if (num >= 1000) {
    const result = (num / 1000).toFixed(1);
    return result.endsWith('.0') ? `${(num / 1000).toFixed(0)}千` : result + '千';
  } else {
    return num.toFixed(0);
  }
};

// 数据转换工具函数
export const chartDataUtils = {
  // 转换饼图数据
  toPieData: (data: Array<{ name: string; count: number; percentage?: number }>): PieData[] => {
    return data.map(item => ({
      name: item.name,
      value: item.count,
      count: item.count,
      percentage: item.percentage
    }))
  },

  // 转换业态类别数据
  toBusinessCategoryData: (data: Array<{ category: string; count: number; occupancy_rate?: number }>): BarData[] => {
    return data.map(item => ({
      name: item.category,
      value: item.count,
      count: item.count,
      occupancy_rate: item.occupancy_rate || 0
    }))
  },

  // 转换出租率分布数据
  toOccupancyData: (data: Array<{ range: string; count: number; percentage?: number }>): BarData[] => {
    return data.map(item => ({
      name: item.range,
      value: item.count,
      count: item.count,
      percentage: item.percentage
    }))
  },

  // 转换趋势数据
  toTrendData: (data: Array<{ date: string; occupancy_rate: number; total_rented_area?: number; total_rentable_area?: number }>): LineData[] => {
    return data.map(item => ({
      date: item.date,
      occupancy_rate: item.occupancy_rate,
      total_rented_area: item.total_rented_area || 0,
      total_rentable_area: item.total_rentable_area || 0
    }))
  },

  // 转换面积维度数据
  toAreaData: (data: Array<{ name: string; total_area: number; area_percentage: number; average_area?: number }>): PieData[] => {
    return data.map(item => ({
      name: item.name,
      value: Math.round(item.total_area * 100) / 100, // 使用round方法避免浮点精度问题
      total_area: Math.round(item.total_area * 100) / 100,
      percentage: item.area_percentage,
      average_area: item.average_area || 0
    }))
  },

  // 转换面积维度柱状图数据
  toAreaBarData: (data: Array<{ name: string; total_area: number; count?: number; average_area?: number }>): BarData[] => {
    return data.map(item => ({
      name: item.name,
      value: Math.round(item.total_area * 100) / 100, // 使用round方法避免浮点精度问题
      total_area: Math.round(item.total_area * 100) / 100,
      count: item.count || 0,
      average_area: item.average_area || 0
    }))
  },

  // 转换业态类别面积数据
  toBusinessCategoryAreaData: (data: Array<{ category: string; total_area: number; area_percentage: number; occupancy_rate?: number }>): BarData[] => {
    return data.map(item => ({
      name: item.category,
      value: Math.round(item.total_area * 100) / 100, // 使用round方法避免浮点精度问题
      total_area: Math.round(item.total_area * 100) / 100,
      area_percentage: item.area_percentage,
      occupancy_rate: item.occupancy_rate || 0
    }))
  }
}

import React, { useState, useMemo } from 'react'
import { Row, Col, Card, Typography, Button, Space, Dropdown, Menu } from 'antd'
import {
  ReloadOutlined,
  DownloadOutlined,
  SettingOutlined,
  FullscreenOutlined,
  FullscreenExitOutlined
} from '@ant-design/icons'
import { useAnalytics } from '../../hooks/useAnalytics'
import type { AssetSearchParams } from '../../types/asset'

import { AnalyticsFilters } from './AnalyticsFilters'
import { StatisticCard, FinancialStatisticCard } from './StatisticCard'
import { ChartCard } from './AnalyticsCard'
import {
