                  dataKey="value"
                  labelKey="name"
                />
              </ChartCard>
            </Col>

            {/* 确权状态分布 */}
            <Col xs={24} lg={12}>
              <ChartCard
                title="确权状态分布"
                hasData={analytics?.ownership_status_distribution?.length > 0}
