                    percentage: item.percentage
                  }))}
                  xDataKey="status"
                  yDataKey="count"
                  barName="资产数量"
                />
              </ChartCard>
            </Col>

            {/* 使用状态分布 */}
            <Col xs={24} lg={12}>
              <ChartCard
                title="使用状态分布"
                hasData={analytics?.usage_status_distribution?.length > 0}
                loading={isLoading}
              >
                <AnalyticsPieChart
                  data={analytics?.usage_status_distribution?.map(item => ({
                    name: item.status,
                    value: item.count,
                    percentage: item.percentage
                  })) || []}
                  dataKey="value"
                  labelKey="name"
                />
              </ChartCard>
            </Col>

            {/* 出租率分布 */}
            <Col xs={24} lg={12}>
              <ChartCard
                title="出租率区间分布"
                hasData={analytics?.occupancy_distribution?.length > 0}
                loading={isLoading}
              >
                <AnalyticsBarChart
                  data={(analytics?.occupancy_distribution || []).map(item => ({
                    range: item.range,
                    count: item.count,
                    percentage: item.percentage
