import React, { useState } from 'react'
import {
  Card,
  Timeline,
  Tag,
  Button,
  Space,
  Spin,
  Alert,
  Modal,
  Descriptions,
  Empty,
  Select,
  DatePicker,
  Row,
  Col,
  Pagination,
} from 'antd'
import {
  HistoryOutlined,
  EyeOutlined,
  FilterOutlined,
  ReloadOutlined,
  UserOutlined,
  CalendarOutlined,
  EditOutlined,
  PlusOutlined,
  DeleteOutlined,
} from '@ant-design/icons'
import { useQuery } from '@tanstack/react-query'
import dayjs from 'dayjs'

import { assetService } from '@/services/assetService'
import type { AssetHistory } from '@/types/asset'
import { formatDate } from '@/utils/format'

const { Option } = Select
const { RangePicker } = DatePicker

interface AssetHistoryProps {
  assetId: string
}

const AssetHistory: React.FC<AssetHistoryProps> = ({ assetId }) => {
  const [page, setPage] = useState(1)
  const [limit, setLimit] = useState(20)
  const [changeType, setChangeType] = useState<string | undefined>(undefined)
  const [dateRange, setDateRange] = useState<[dayjs.Dayjs, dayjs.Dayjs] | null>(null)
  const [selectedHistory, setSelectedHistory] = useState<AssetHistory | null>(null)
  const [detailVisible, setDetailVisible] = useState(false)

  // 获取变更历史
  const {
    data: historyData,
    isLoading,
    error,
    refetch,
  } = useQuery({
    queryKey: ['asset-history', assetId, page, limit, changeType, dateRange],
    queryFn: () => assetService.getAssetHistory(assetId, page, limit, changeType),
    enabled: !!assetId,
  })

  // 获取历史详情
  const {
    data: historyDetail,
    isLoading: detailLoading,
  } = useQuery({
    queryKey: ['history-detail', selectedHistory?.id],
    queryFn: () => assetService.getHistoryDetail(selectedHistory!.id),
    enabled: !!selectedHistory,
  })

  // 处理查看详情
  const handleViewDetail = (history: AssetHistory) => {
    setSelectedHistory(history)
    setDetailVisible(true)
  }

  // 处理筛选重置
  const handleResetFilter = () => {
    setChangeType(undefined)
    setDateRange(null)
    setPage(1)
  }

  // 获取变更类型图标和颜色
  const getChangeTypeConfig = (type: string) => {
    switch (type) {
      case 'create':
        return {
          icon: <PlusOutlined />,
          color: 'green',
          text: '创建',
        }
      case 'update':
        return {
          icon: <EditOutlined />,
          color: 'blue',
          text: '更新',
        }
      case 'delete':
        return {
          icon: <DeleteOutlined />,
          color: 'red',
          text: '删除',
        }
      default:
        return {
          icon: <EditOutlined />,
          color: 'default',
          text: type,
        }
    }
  }

  // 渲染字段变更详情
  const renderFieldChanges = (oldValues: Record<string, unknown>, newValues: Record<string, unknown>) => {
    const changes = []
    
    // 合并所有变更的字段
    const allFields = new Set([...Object.keys(oldValues || {}), ...Object.keys(newValues || {})])
    
    for (const field of allFields) {
      const oldValue = oldValues?.[field]
      const newValue = newValues?.[field]
      
      if (oldValue !== newValue) {
        changes.push({
          field,
          oldValue: oldValue || '-',
          newValue: newValue || '-',
        })
      }
    }

    return changes.map((change, index) => (
      <Descriptions.Item key={index} label={change.field} span={3}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span style={{ color: '#ff4d4f', textDecoration: 'line-through' }}>
            {String(change.oldValue)}
          </span>
          <span>→</span>
          <span style={{ color: '#52c41a', fontWeight: 'bold' }}>
            {String(change.newValue)}
          </span>
        </div>
      </Descriptions.Item>
    ))
  }

  if (error) {
    return (
      <Alert
        message="加载失败"
        description="无法加载变更历史，请稍后重试"
        type="error"
        showIcon
        action={
          <Button onClick={() => refetch()}>
            重新加载
          </Button>
        }
      />
    )
  }

  return (
    <div>
      {/* 筛选器 */}
      <Card size="small" style={{ marginBottom: 16 }}>
        <Row gutter={16} align="middle">
          <Col xs={24} sm={8} md={6}>
            <Select
              placeholder="变更类型"
              value={changeType}
              onChange={setChangeType}
              allowClear
              style={{ width: '100%' }}
            >
              <Option value="create">创建</Option>
              <Option value="update">更新</Option>
              <Option value="delete">删除</Option>
            </Select>
          </Col>
          
          <Col xs={24} sm={10} md={8}>
            <RangePicker
              value={dateRange}
              onChange={setDateRange}
              placeholder={['开始日期', '结束日期']}
              style={{ width: '100%' }}
            />
          </Col>
          
          <Col xs={24} sm={6} md={4}>
            <Space>
              <Button
                icon={<FilterOutlined />}
                onClick={handleResetFilter}
              >
                重置
              </Button>
              <Button
                icon={<ReloadOutlined />}
                onClick={() => refetch()}
                loading={isLoading}
              >
                刷新
              </Button>
            </Space>
          </Col>
          
          <Col xs={24} sm={24} md={6} style={{ textAlign: 'right' }}>
            <span style={{ color: '#8c8c8c', fontSize: '14px' }}>
              共 {historyData?.total || 0} 条记录
            </span>
          </Col>
        </Row>
      </Card>

      {/* 历史记录时间线 */}
      <Card
        title={
          <span>
            <HistoryOutlined style={{ marginRight: 8 }} />
            变更历史
          </span>
        }
      >
        <Spin spinning={isLoading}>
          {historyData?.data && historyData.data.length > 0 ? (
            <>
              <Timeline>
                {historyData.data.map((history) => {
                  const config = getChangeTypeConfig(history.change_type)
                  
                  return (
                    <Timeline.Item
                      key={history.id}
                      dot={config.icon}
                      color={config.color}
                    >
                      <div style={{ paddingBottom: 16 }}>
                        {/* 变更标题 */}
                        <div style={{ marginBottom: 8 }}>
                          <Space>
                            <Tag color={config.color}>{config.text}</Tag>
                            <span style={{ fontWeight: 'bold' }}>
                              {history.changed_fields.join(', ')}
                            </span>
                          </Space>
                        </div>

                        {/* 变更信息 */}
                        <div style={{ marginBottom: 8, color: '#8c8c8c', fontSize: '14px' }}>
                          <Space split={<span>•</span>}>
                            <span>
                              <UserOutlined style={{ marginRight: 4 }} />
                              {history.changed_by}
                            </span>
                            <span>
                              <CalendarOutlined style={{ marginRight: 4 }} />
                              {formatDate(history.changed_at, 'datetime')}
                            </span>
                          </Space>
                        </div>

                        {/* 变更原因 */}
                        {history.reason && (
                          <div style={{ marginBottom: 8, color: '#595959' }}>
                            原因：{history.reason}
                          </div>
                        )}

                        {/* 操作按钮 */}
                        <div>
                          <Button
                            type="link"
                            size="small"
                            icon={<EyeOutlined />}
                            onClick={() => handleViewDetail(history)}
                            style={{ padding: 0 }}
                          >
                            查看详情
                          </Button>
                        </div>
                      </div>
                    </Timeline.Item>
                  )
                })}
              </Timeline>

              {/* 分页 */}
              {historyData.total > limit && (
                <div style={{ textAlign: 'center', marginTop: 24 }}>
                  <Pagination
                    current={page}
                    pageSize={limit}
                    total={historyData.total}
                    showSizeChanger
                    showQuickJumper
                    showTotal={(total, range) =>
                      `第 ${range[0]}-${range[1]} 条，共 ${total} 条`
                    }
                    onChange={(newPage, newPageSize) => {
                      setPage(newPage)
                      setLimit(newPageSize || limit)
                    }}
                  />
                </div>
              )}
            </>
          ) : (
            <Empty
              description="暂无变更历史"
              image={Empty.PRESENTED_IMAGE_SIMPLE}
            />
          )}
        </Spin>
      </Card>

      {/* 详情对话框 */}
      <Modal
        title={
          selectedHistory && (
            <span>
              变更详情 - {getChangeTypeConfig(selectedHistory.change_type).text}
            </span>
          )
        }
        open={detailVisible}
        onCancel={() => {
          setDetailVisible(false)
          setSelectedHistory(null)
        }}
        footer={[
          <Button key="close" onClick={() => setDetailVisible(false)}>
            关闭
          </Button>,
        ]}
        width={800}
      >
        {selectedHistory && (
          <Spin spinning={detailLoading}>
            <Descriptions
              bordered
              column={1}
              labelStyle={{ width: '120px' }}
            >
              <Descriptions.Item label="变更类型">
                <Tag color={getChangeTypeConfig(selectedHistory.change_type).color}>
                  {getChangeTypeConfig(selectedHistory.change_type).text}
                </Tag>
              </Descriptions.Item>
              
              <Descriptions.Item label="变更字段">
                {selectedHistory.changed_fields.join(', ')}
              </Descriptions.Item>
              
              <Descriptions.Item label="操作人">
                {selectedHistory.changed_by}
              </Descriptions.Item>
              
              <Descriptions.Item label="变更时间">
                {formatDate(selectedHistory.changed_at, 'datetime')}
              </Descriptions.Item>
              
              {selectedHistory.reason && (
                <Descriptions.Item label="变更原因">
                  {selectedHistory.reason}
                </Descriptions.Item>
              )}
            </Descriptions>

            {/* 字段变更详情 */}
            {selectedHistory.change_type === 'update' && 
             selectedHistory.old_values && 
             selectedHistory.new_values && (
              <div style={{ marginTop: 24 }}>
                <h4>字段变更详情</h4>
                <Descriptions
                  bordered
                  column={1}
                  labelStyle={{ width: '120px' }}
                >
                  {renderFieldChanges(selectedHistory.old_values, selectedHistory.new_values)}
                </Descriptions>
              </div>
            )}

            {/* 创建时的数据 */}
            {selectedHistory.change_type === 'create' && selectedHistory.new_values && (
              <div style={{ marginTop: 24 }}>
                <h4>创建时的数据</h4>
                <Descriptions
                  bordered
                  column={2}
                  labelStyle={{ width: '120px' }}
                >
                  {Object.entries(selectedHistory.new_values).map(([key, value]) => (
                    <Descriptions.Item key={key} label={key}>
                      {String(value)}
                    </Descriptions.Item>
                  ))}
                </Descriptions>
              </div>
            )}
          </Spin>
        )}
      </Modal>
    </div>
  )
}

export default AssetHistory

import React, { useState } from 'react'
import {
  Card,
  Typography,
  Upload,
  Button,
  Progress,
  Space,
  Alert,
  Steps,
  Table,
  Tag,
  message,
  Row,
  Col,
  Statistic,
  Divider,
  Switch,
  Form,
  InputNumber,
  Select
} from 'antd'
import {
  UploadOutlined,
  DownloadOutlined,
  FileExcelOutlined,
  CheckCircleOutlined,
  ExclamationCircleOutlined,
  SettingOutlined,
  ThunderboltOutlined,
  ClockCircleOutlined
} from '@ant-design/icons'
import type { UploadProps, UploadFile } from 'antd'
import { api } from '../../services/api'
import { STANDARD_SHEET_NAME, IMPORT_INSTRUCTIONS } from '../../config/excelConfig'

const { Title, Text } = Typography
const { Step } = Steps
const { Option } = Select

interface ImportResult {
  success: number
  failed: number
  total: number
  errors: string[]
  message: string
  processing_time?: number
  filename?: string
  performance_metrics?: {
    records_per_second: number
    estimated_time_for_1000: number
  }
}

interface ImportConfig {
  useOptimized: boolean
  batchSize: number
  skipErrors: boolean
  timeout: number
}

const OptimizedAssetImport: React.FC = () => {
  const [currentStep, setCurrentStep] = useState(0)
  const [fileList, setFileList] = useState<UploadFile[]>([])
  const [uploading, setUploading] = useState(false)
  const [importResult, setImportResult] = useState<ImportResult | null>(null)
  const [progress, setProgress] = useState(0)
  const [showConfig, setShowConfig] = useState(false)
  const [config, setConfig] = useState<ImportConfig>({
    useOptimized: true,
    batchSize: 100,
    skipErrors: true,
    timeout: 600 // 10分钟
  })

  // 下载模板
  const handleDownloadTemplate = async () => {
    try {
      const response = await api.get('/excel/template', {
        responseType: 'blob'
      })

      const blob = new Blob([response.data])
      const url = window.URL.createObjectURL(blob)
      const link = document.createElement('a')
      link.href = url
      link.download = 'land_property_asset_template.xlsx'
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      window.URL.revokeObjectURL(url)

      message.success('模板下载成功')
    } catch (error) {
      message.error('模板下载失败')
    }
  }

  // 文件上传配置
  const uploadProps: UploadProps = {
    fileList,
    beforeUpload: (file) => {
      const isExcel = file.type === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' ||
                     file.type === 'application/vnd.ms-excel'

      if (!isExcel) {
        message.error('只能上传Excel文件(.xlsx, .xls)')
        return false
      }

      const isLt50M = file.size / 1024 / 1024 < 50
      if (!isLt50M) {
        message.error('文件大小不能超过50MB')
        return false
      }

      setFileList([file])
      setCurrentStep(1)
      return false
    },
    onRemove: () => {
      setFileList([])
      setCurrentStep(0)
      setImportResult(null)
    },
    maxCount: 1,
  }

  // 模拟进度条
  const simulateProgress = () => {
    setProgress(0)
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 95) {
          clearInterval(interval)
          return 95
        }
        return prev + Math.random() * 10
      })
    }, 500)
    return interval
  }

  // 执行导入
  const handleImport = async () => {
    if (fileList.length === 0) {
      message.error('请先选择要导入的文件')
      return
    }

    setUploading(true)
    const progressInterval = simulateProgress()

    try {
      const formData = new FormData()
      formData.append('file', fileList[0] as File)

      // Start enhanced import process
      setImporting(true)

      const endpoint = config.useOptimized ? '/excel/import/optimized' : '/excel/import'

      const response = await api.post(endpoint, formData, {
        params: {
          sheet_name: STANDARD_SHEET_NAME,
          skip_errors: config.skipErrors
        },
        timeout: config.timeout * 1000
      })

      clearInterval(progressInterval)
      setProgress(100)

      const result = response.data
      // Import completed successfully
      // console.log('=== 导入结果 ===')
      // console.log('响应数据:', result)

      setImportResult(result)
      setCurrentStep(2)

      // 显示性能信息
      if (result.processing_time) {
        message.success(`🎉 导入完成！用时 ${result.processing_time} 秒`)
      } else {
        message.success(`🎉 导入完成！成功导入 ${result.success} 条记录`)
      }

    } catch (error: unknown) {
      clearInterval(progressInterval)
      console.error('导入错误:', error)
      console.error('错误响应:', error.response?.data)

      const errorResult = error.response?.data || {
        success: 0,
        failed: 0,
        total: 0,
        errors: [error.message || '网络错误'],
        processing_time: 0,
        filename: fileList[0]?.name
      }

      setImportResult(errorResult)
      setCurrentStep(2)
      message.error(`❌ 导入失败: ${errorResult.errors?.[0] || '未知错误'}`)
    } finally {
      setUploading(false)
    }
  }

  // 重新开始
  const handleReset = () => {
    setCurrentStep(0)
    setFileList([])
    setImportResult(null)
    setProgress(0)
  }

  // 错误信息表格列
  const errorColumns = [
    {
      title: '序号',
      dataIndex: 'index',
      key: 'index',
      width: 80,
      render: (_: unknown, __: unknown, index: number) => index + 1,
    },
    {
      title: '错误信息',
      dataIndex: 'error',
      key: 'error',
      ellipsis: true,
    },
  ]

  const errorData = importResult?.errors?.map((error, index) => ({
    key: index,
    error,
  })) || []

  return (
    <div style={{ padding: '24px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
        <Title level={2}>
          <FileExcelOutlined />
          {' '}
          数据导入
        </Title>
        <Button
          type="dashed"
          icon={<SettingOutlined />}
          onClick={() => setShowConfig(!showConfig)}
        >
          {showConfig ? '隐藏配置' : '显示配置'}
        </Button>
      </div>

      {/* 配置面板 */}
      {showConfig && (
        <Card title="导入配置" size="small" style={{ marginBottom: '24px' }}>
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={12} md={6}>
              <Form.Item label="使用优化导入">
                <Switch
                  checked={config.useOptimized}
                  onChange={(checked) => setConfig(prev => ({ ...prev, useOptimized: checked }))}
                />
              </Form.Item>
            </Col>
            <Col xs={24} sm={12} md={6}>
              <Form.Item label="超时时间(秒)">
                <InputNumber
                  min={60}
                  max={1800}
                  value={config.timeout}
                  onChange={(value) => setConfig(prev => ({ ...prev, timeout: value || 600 }))}
                />
              </Form.Item>
            </Col>
            <Col xs={24} sm={12} md={6}>
              <Form.Item label="跳过错误">
                <Switch
                  checked={config.skipErrors}
                  onChange={(checked) => setConfig(prev => ({ ...prev, skipErrors: checked }))}
                />
              </Form.Item>
            </Col>
            <Col xs={24} sm={12} md={6}>
              <Form.Item label="批量大小">
                <Select
                  value={config.batchSize}
                  onChange={(value) => setConfig(prev => ({ ...prev, batchSize: value || 100 }))}
                >
                  <Option value={50}>50</Option>
                  <Option value={100}>100</Option>
                  <Option value={200}>200</Option>
                  <Option value={500}>500</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
        </Card>
      )}

      <Card>
        <Steps current={currentStep} style={{ marginBottom: '32px' }}>
          <Step title="选择文件" description="上传Excel文件" />
          <Step title="执行导入" description="处理数据" />
          <Step title="查看结果" description="导入完成" />
        </Steps>

        {/* 步骤0: 选择文件 */}
        {currentStep === 0 && (
          <div>
            <Alert
              message="导入说明"
              description={
                <div>
                  <p>• 支持Excel文件批量导入资产数据</p>
                  <p>• 智能数据验证和错误处理</p>
                  <p>• 实时导入进度反馈</p>
                  <p>• 支持大文件导入 (最大50MB)</p>
                  {IMPORT_INSTRUCTIONS.map((instruction, index) => (
                    <p key={index}>{index + 1}. {instruction}</p>
                  ))}
                </div>
              }
              type="info"
              showIcon
              style={{ marginBottom: '24px' }}
            />

            <Row gutter={[16, 16]}>
              <Col xs={24} sm={12}>
                <Card size="small" title="第一步：下载模板">
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Text>下载标准的Excel导入模板</Text>
                    <Button
                      type="primary"
                      icon={<DownloadOutlined />}
                      onClick={handleDownloadTemplate}
                      block
                    >
                      下载Excel模板
                    </Button>
                  </Space>
                </Card>
              </Col>

              <Col xs={24} sm={12}>
                <Card size="small" title="第二步：上传文件">
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Text>选择填写好的Excel文件</Text>
                    <Upload.Dragger {...uploadProps}>
                      <p className="ant-upload-drag-icon">
                        <FileExcelOutlined style={{ fontSize: '48px', color: '#1890ff' }} />
                      </p>
                      <p className="ant-upload-text">点击或拖拽文件到此区域上传</p>
                      <p className="ant-upload-hint">
                        支持单个文件上传，仅支持.xlsx和.xls格式，最大50MB
                      </p>
                    </Upload.Dragger>
                  </Space>
                </Card>
              </Col>
            </Row>
          </div>
        )}

        {/* 步骤1: 执行导入 */}
        {currentStep === 1 && (
          <div style={{ textAlign: 'center' }}>
            <FileExcelOutlined style={{ fontSize: '64px', color: '#52c41a', marginBottom: '16px' }} />
            <Title level={4}>文件已选择</Title>
            <Text>文件名：{fileList[0]?.name}</Text>
            <br />
            <Text type="secondary">
              文件大小：{((fileList[0]?.size || 0) / 1024 / 1024).toFixed(2)} MB
            </Text>

            {uploading && (
              <div style={{ marginTop: '24px' }}>
                <Progress percent={Math.round(progress)} status="active" />
                <Text type="secondary">
                  导入中...
                </Text>
              </div>
            )}

            <Divider />

            <Space size="large">
              <Button onClick={() => setCurrentStep(0)}>
                重新选择
              </Button>
              <Button
                type="primary"
                icon={<UploadOutlined />}
                onClick={handleImport}
                loading={uploading}
                size="large"
              >
                {uploading ? '导入中...' : '开始导入'}
              </Button>
            </Space>
          </div>
        )}

        {/* 步骤2: 查看结果 */}
        {currentStep === 2 && importResult && (
          <div>
            {/* 导入状态概览 */}
            <Card
              size="small"
              style={{
                marginBottom: '24px',
                backgroundColor: importResult.success > 0 ? '#f6ffed' :
                               importResult.failed > 0 ? '#fff2f0' : '#f0f2f5',
                border: importResult.success > 0 ? '1px solid #b7eb8f' :
                         importResult.failed > 0 ? '1px solid #ffccc7' : '1px solid #d9d9d9'
              }}
            >
              <div style={{ textAlign: 'center', padding: '16px' }}>
                {importResult.success > 0 && importResult.failed === 0 ? (
                  <CheckCircleOutlined style={{ fontSize: '64px', color: '#52c41a' }}
                ) : importResult.success > 0 && importResult.failed > 0 ? (
                  <ExclamationCircleOutlined style={{ fontSize: '64px', color: '#faad14' }}
                ) : (
                  <ExclamationCircleOutlined style={{ fontSize: '64px', color: '#ff4d4f' }}
                )}

                <Title level={3} style={{ marginTop: '8px' }}>
                  {importResult.success > 0 && importResult.failed === 0 ? '🎉 导入成功！' :
                   importResult.success > 0 && importResult.failed > 0 ? '⚠️ 部分成功' :
                   importResult.failed > 0 ? '❌ 导入失败' : '📄 导入完成'}
                </Title>

                <Text type="secondary" style={{ fontSize: '16px' }}>
                  {importResult.processing_time && (
                    <span>处理时间: {importResult.processing_time}秒 | </span>
                  )}
                  {importResult.success > 0 && importResult.failed === 0 ? (
                    `成功导入 ${importResult.success} 条资产记录`
                  ) : importResult.success > 0 && importResult.failed > 0 ? (
                    `成功 ${importResult.success} 条，失败 ${importResult.failed} 条，总计 ${importResult.total} 条`
                  ) : importResult.failed > 0 ? (
                    `${importResult.failed} 条记录导入失败`
                  ) : (
                    '没有数据被导入，请检查文件格式和内容'
                  )}
                </Text>

                {/* 性能指标 */}
                {importResult.performance_metrics && (
                  <div style={{ marginTop: '16px' }}>
                    <Text type="secondary">
                      性能指标: {importResult.performance_metrics.records_per_second} 记录/秒
                      {importResult.performance_metrics.estimated_time_for_1000 > 0 && (
                        <span> | 预估1000条记录需 {importResult.performance_metrics.estimated_time_for_1000} 秒</span>
                      )}
                    </Text>
                  </div>
                )}
              </div>
            </Card>

            {/* 详细统计 */}
            <Row gutter={[16, 16]} style={{ marginBottom: '24px' }}>
              <Col xs={24} sm={8}>
                <Card size="small" bordered={false}>
                  <Statistic
                    title="成功记录"
                    value={importResult.success}
                    valueStyle={{ color: '#3f8600' }}
                  />
                </Card>
              </Col>
              <Col xs={24} sm={8}>
                <Card size="small" bordered={false}>
                  <Statistic
                    title="失败记录"
                    value={importResult.failed}
                    valueStyle={{ color: importResult.failed > 0 ? '#cf1322' : '#d9d9d9' }}
                  />
                </Card>
              </Col>
              <Col xs={24} sm={8}>
                <Card size="small" bordered={false}>
                  <Statistic
                    title="总计"
                    value={importResult.total}
                    valueStyle={{ color: '#1890ff' }}
                  />
                </Card>
              </Col>
            </Row>

            {/* 错误详情 */}
            {importResult.failed > 0 && importResult.errors.length > 0 && (
              <Card
                title={`错误详情 (${importResult.errors.length} 条)`}
                size="small"
                style={{ marginBottom: '16px' }}
                extra={
                  <Button type="link" onClick={() => {
                    const errorText = importResult.errors.join('\\n')
                    navigator.clipboard.writeText(errorText)
                    message.success('错误信息已复制到剪贴板')
                  }}>
                    复制错误信息
                  </Button>
                }
              >
                <Table
                  columns={errorColumns}
                  dataSource={errorData}
                  pagination={{ pageSize: 10 }}
                  size="small"
                  scroll={{ y: 300 }}
                />
              </Card>
            )}

            <div style={{ textAlign: 'center', marginTop: '24px' }}>
              <Space size="large">
                <Button onClick={handleReset}>
                  重新导入
                </Button>
                <Button type="primary" onClick={() => window.location.href = '/assets'}>
                  查看资产列表
                </Button>
              </Space>
            </div>
          </div>
        )}
      </Card>
    </div>
  )
}

export default OptimizedAssetImport

import React from 'react'
import { Table, Tag, Button, Space, Popconfirm, Tooltip } from 'antd'
import {
  EditOutlined,
  DeleteOutlined,
  EyeOutlined,
  HistoryOutlined,
} from '@ant-design/icons'
import type { ColumnsType } from 'antd/es/table'

import type { Asset, AssetListResponse } from '@/types/asset'
import { formatArea, formatPercentage, formatDate, getStatusColor } from '@/utils/format'

interface AssetListProps {
  data?: AssetListResponse
  loading?: boolean
  onEdit: (asset: Asset) => void
  onDelete: (id: string) => void
  onView: (asset: Asset) => void
  onViewHistory: (asset: Asset) => void
  onTableChange: (pagination: { current: number; pageSize: number; total: number }, filters: Record<string, unknown>, sorter: { field: string; order: string }) => void
  selectedRowKeys?: string[]
  onSelectChange?: (selectedRowKeys: string[]) => void
}

const AssetList: React.FC<AssetListProps> = ({
  data,
  loading = false,
  onEdit,
  onDelete,
  onView,
  onViewHistory,
  onTableChange,
  selectedRowKeys = [],
  onSelectChange,
}) => {

  // 表格列定义
  const columns: ColumnsType<Asset> = [
    {
      title: '所属项目',
      dataIndex: 'project_name',
      key: 'project_name',
      width: 150,
      fixed: 'left',
      sorter: true,
      ellipsis: {
        showTitle: false,
      },
      render: (text, record) => {
        // 如果是项目ID格式，尝试显示关联的项目名称
        const projectName = record.project_name || text
        const isId = typeof projectName === 'string' && projectName.length === 36 // UUID格式

        let displayText = projectName
        if (isId) {
          // 如果是ID格式，显示"未配置项目"
          displayText = '未配置项目'
        }

        return (
          <Tooltip title={displayText || '未设置'}>
            {displayText || '-'}
          </Tooltip>
        )
      },
    },
    {
      title: '物业名称',
      dataIndex: 'property_name',
      key: 'property_name',
      width: 200,
      fixed: 'left',
      sorter: true,
      render: (text, record) => (
        <Button
          type="link"
          onClick={() => onView(record)}
          style={{ padding: 0, height: 'auto', textAlign: 'left' }}
        >
          <Tooltip title="点击查看详情">
            {text}
          </Tooltip>
        </Button>
      ),
    },
    {
      title: '权属方',
      dataIndex: 'ownership_entity',
      key: 'ownership_entity',
      width: 150,
      sorter: true,
      ellipsis: {
        showTitle: false,
      },
      render: (text) => (
        <Tooltip title={text}>
          {text}
        </Tooltip>
      ),
    },
    {
      title: '权属类别',
      dataIndex: 'ownership_category',
      key: 'ownership_category',
      width: 150,
      sorter: true,
      ellipsis: {
        showTitle: false,
      },
      filters: [
        { text: '国资管理集团合并口径', value: '1' },
        { text: '民政托管企业', value: '2' },
        { text: '其他', value: '3' },
      ],
      render: (text, record) => {
        // 权属类别映射
        let displayText = text
        if (typeof text === 'string') {
          // 权属类别字典映射
          const categoryMap: Record<string, string> = {
            '1': '国资管理集团合并口径',
            '2': '民政托管企业',
            '3': '其他'
          }
          // 如果是数字ID，转换为对应文字
          if (/^\d+$/.test(text) && categoryMap[text]) {
            displayText = categoryMap[text]
          }
        }

        return (
          <Tooltip title={displayText || '未设置'}>
            {displayText || '-'}
          </Tooltip>
        )
      },
    },
    {
      title: '所在地址',
      dataIndex: 'address',
      key: 'address',
      width: 200,
      ellipsis: {
        showTitle: false,
      },
      render: (text) => (
        <Tooltip title={text}>
          {text}
        </Tooltip>
      ),
    },
    {
      title: '土地面积',
      dataIndex: 'land_area',
      key: 'land_area',
      width: 120,
      align: 'right',
      sorter: true,
      render: (value) => formatArea(value),
    },
    {
      title: '实际面积',
      dataIndex: 'actual_property_area',
      key: 'actual_property_area',
      width: 120,
      align: 'right',
      sorter: true,
      render: (value) => formatArea(value),
    },
    {
      title: '可出租面积',
      dataIndex: 'rentable_area',
      key: 'rentable_area',
      width: 130,
      align: 'right',
      sorter: true,
      render: (value) => formatArea(value),
    },
    {
      title: '已出租面积',
      dataIndex: 'rented_area',
      key: 'rented_area',
      width: 130,
      align: 'right',
      sorter: true,
      render: (value) => formatArea(value),
    },
    {
      title: '确权状态',
      dataIndex: 'ownership_status',
      key: 'ownership_status',
      width: 100,
      filters: [
        { text: '已确权', value: '已确权' },
        { text: '未确权', value: '未确权' },
        { text: '部分确权', value: '部分确权' },
      ],
      render: (status) => (
        <Tag color={getStatusColor(status, 'ownership')}>
          {status}
        </Tag>
      ),
    },
    {
      title: '物业性质',
      dataIndex: 'property_nature',
      key: 'property_nature',
      width: 100,
      filters: [
        { text: '经营性', value: '经营性' },
        { text: '非经营性', value: '非经营性' },
      ],
      render: (nature) => (
        <Tag color={getStatusColor(nature, 'property')}>
          {nature}
        </Tag>
      ),
    },
    {
      title: '使用状态',
      dataIndex: 'usage_status',
      key: 'usage_status',
      width: 100,
      filters: [
        { text: '出租', value: '出租' },
        { text: '空置', value: '空置' },
        { text: '自用', value: '自用' },
        { text: '公房', value: '公房' },
        { text: '待移交', value: '待移交' },
        { text: '待处置', value: '待处置' },
        { text: '其他', value: '其他' },
      ],
      render: (status) => (
        <Tag color={getStatusColor(status, 'usage')}>
          {status}
        </Tag>
      ),
    },
    {
      title: '出租率',
      dataIndex: 'occupancy_rate',
      key: 'occupancy_rate',
      width: 100,
      align: 'right',
      sorter: true,
      render: (rate, record) => {
        // 如果有出租率字段直接显示，否则计算
        if (rate) {
          return formatPercentage(rate)
        }
        
        // 计算出租率
        if (record.rentable_area && record.rented_area) {
          const calculatedRate = (record.rented_area / record.rentable_area) * 100
          return (
            <span style={{ 
              color: calculatedRate >= 80 ? '#52c41a' : 
                     calculatedRate >= 60 ? '#faad14' : '#ff4d4f'
            }}>
              {formatPercentage(calculatedRate)}
            </span>
          )
        }
        
        return '-'
      },
    },
    {
      title: '是否涉诉',
      dataIndex: 'is_litigated',
      key: 'is_litigated',
      width: 100,
      filters: [
        { text: '是', value: true },
        { text: '否', value: false },
      ],
      render: (isLitigated) => (
        <Tag color={isLitigated ? 'red' : 'green'}>
          {isLitigated ? '是' : '否'}
        </Tag>
      ),
    },
    {
      title: '创建时间',
      dataIndex: 'created_at',
      key: 'created_at',
      width: 120,
      sorter: true,
      render: (date) => formatDate(date),
    },
    {
      title: '更新时间',
      dataIndex: 'updated_at',
      key: 'updated_at',
      width: 120,
      sorter: true,
      render: (date) => formatDate(date),
    },
    {
      title: '操作',
      key: 'actions',
      width: 150,
      fixed: 'right',
      render: (_, record) => (
        <Space size="small">
          <Tooltip title="查看详情">
            <Button
              type="text"
              icon={<EyeOutlined />}
              onClick={() => onView(record)}
              size="small"
            />
          </Tooltip>
          
          <Tooltip title="编辑">
            <Button
              type="text"
              icon={<EditOutlined />}
              onClick={() => onEdit(record)}
              size="small"
            />
          </Tooltip>
          
          <Tooltip title="查看历史">
            <Button
              type="text"
              icon={<HistoryOutlined />}
              onClick={() => onViewHistory(record)}
              size="small"
            />
          </Tooltip>
          
          <Popconfirm
            title="确定要删除这个资产吗？"
            description="删除后无法恢复，请谨慎操作"
            onConfirm={() => onDelete(record.id)}
            okText="确定"
            cancelText="取消"
            okType="danger"
          >
            <Tooltip title="删除">
              <Button
                type="text"
                danger
                icon={<DeleteOutlined />}
                size="small"
              />
            </Tooltip>
          </Popconfirm>
        </Space>
      ),
    },
  ]

  // 计算当前页汇总数据
  const calculateSummary = () => {
    const items = data?.items || []
    if (items.length === 0) return null

    const summary = items.reduce((acc, item) => {
      return {
        landArea: acc.landArea + (Number(item.land_area) || 0),
        actualArea: acc.actualArea + (Number(item.actual_property_area) || 0),
        rentableArea: acc.rentableArea + (Number(item.rentable_area) || 0),
        rentedArea: acc.rentedArea + (Number(item.rented_area) || 0),
      }
    }, {
      landArea: 0,
      actualArea: 0,
      rentableArea: 0,
      rentedArea: 0,
    })

    // 正确计算未出租面积和出租率
    const unrentedArea = summary.rentableArea - summary.rentedArea
    const occupancyRate = summary.rentableArea > 0 ? (summary.rentedArea / summary.rentableArea) * 100 : 0

    return {
      ...summary,
      unrentedArea,
      occupancyRate,
    }
  }

  const summary = calculateSummary()

  // 汇总行渲染函数
  const renderSummary = (pageData: unknown[]) => {
    if (!summary) return null

    return (
      <Table.Summary fixed>
        <Table.Summary.Row>
          <Table.Summary.Cell index={0} colSpan={6} align="right">
            <strong>当前页合计：</strong>
          </Table.Summary.Cell>
          <Table.Summary.Cell index={6} align="right">
            <strong>{formatArea(summary.landArea)}</strong>
          </Table.Summary.Cell>
          <Table.Summary.Cell index={7} align="right">
            <strong>{formatArea(summary.actualArea)}</strong>
          </Table.Summary.Cell>
          <Table.Summary.Cell index={8} align="right">
            <strong>{formatArea(summary.rentableArea)}</strong>
          </Table.Summary.Cell>
          <Table.Summary.Cell index={9} align="right">
            <strong>{formatArea(summary.rentedArea)}</strong>
          </Table.Summary.Cell>
          <Table.Summary.Cell index={10} colSpan={5} />
          <Table.Summary.Cell index={15} align="right">
            <strong style={{
              color: summary.occupancyRate >= 80 ? '#52c41a' :
                     summary.occupancyRate >= 60 ? '#faad14' : '#ff4d4f'
            }}>
              {formatPercentage(summary.occupancyRate)}
            </strong>
          </Table.Summary.Cell>
          <Table.Summary.Cell index={16} colSpan={3} />
        </Table.Summary.Row>
      </Table.Summary>
    )
  }

  // 行选择配置
  const rowSelection = onSelectChange ? {
    selectedRowKeys,
    onChange: onSelectChange,
    getCheckboxProps: (record: Asset) => ({
      name: record.property_name,
    }),
  } : undefined

  return (
    <Table
      columns={columns}
      dataSource={data?.items || []}
      rowKey="id"
      loading={loading}
      scroll={{ x: 1800, y: 600 }}
      rowSelection={rowSelection}
      summary={renderSummary}
      pagination={{
        current: data?.page || 1,
        pageSize: data?.limit || 20,
        total: data?.total || 0,
        showSizeChanger: true,
        showQuickJumper: true,
        showTotal: (total, range) =>
          `第 ${range[0]}-${range[1]} 条，共 ${total} 条记录`,
        pageSizeOptions: ['10', '20', '50', '100'],
        size: 'default',
      }}
      onChange={onTableChange}
      size="middle"
      bordered
      sticky={{ offsetHeader: 64 }}
    />
  )
}

export default AssetList

import React, { useState, useEffect } from 'react'
import {
  Card,
  Form,
  Input,
  Select,
  DatePicker,
  InputNumber,
  Button,
  Space,
  Row,
  Col,
  Collapse,
  Switch,
  Slider,
  Dropdown,
  Modal,
  List,
  Typography,
  Popconfirm,
  message,
  Tooltip,
  Tag,
} from 'antd'
import {
  SearchOutlined,
  ReloadOutlined,
  DownOutlined,
  UpOutlined,
  FilterOutlined,
  SaveOutlined,
  HistoryOutlined,
  DeleteOutlined,
  EditOutlined,
  StarOutlined,
  StarFilled,
} from '@ant-design/icons'
import { useQueries } from '@tanstack/react-query'
import dayjs from 'dayjs'

import type { AssetSearchParams, OwnershipStatus, PropertyNature, UsageStatus } from '@/types/asset'
import { assetService } from '@/services/assetService'
import { useSearchHistory } from '@/hooks/useSearchHistory'
import styles from './AssetSearch.module.css'

const { Option } = Select
const { RangePicker } = DatePicker
const { Panel } = Collapse
const { Text } = Typography

interface AssetSearchProps {
  onSearch: (params: AssetSearchParams) => void
  onReset: () => void
  initialValues?: Partial<AssetSearchParams>
  loading?: boolean
  showSaveButton?: boolean
  showHistoryButton?: boolean
}

const AssetSearch: React.FC<AssetSearchProps> = ({
  onSearch,
  onReset,
  initialValues = {},
  loading = false,
  showSaveButton = true,
  showHistoryButton = true,
}) => {
  const [form] = Form.useForm()
  const [expanded, setExpanded] = useState(false)
  const [areaRange, setAreaRange] = useState<[number, number]>([0, 100000])
  const [saveModalVisible, setSaveModalVisible] = useState(false)
  const [historyModalVisible, setHistoryModalVisible] = useState(false)
  const [saveName, setSaveName] = useState('')
  const [editingHistoryId, setEditingHistoryId] = useState<string | null>(null)
  const [editingName, setEditingName] = useState('')

  // 搜索历史Hook
  const {
    searchHistory,
    addSearchHistory,
    removeSearchHistory,
    clearSearchHistory,
    updateSearchHistoryName,
  } = useSearchHistory()

  // 使用并行查询获取所有下拉框数据，简化逻辑避免错误
  const searchQueries = useQueries({
    queries: [
      {
        queryKey: ['ownership-entities'],
        queryFn: async () => {
          try {
            // 直接从专门的API获取
            return await assetService.getOwnershipEntities()
          } catch (error) {
            console.warn('获取权属方失败，使用默认选项:', error)
            return ['政府', '企业', '事业单位', '社会团体', '其他']
          }
        },
        staleTime: 30 * 60 * 1000,
        retry: 0, // 不重试，立即使用默认值
      },
      {
        queryKey: ['business-categories'],
        queryFn: async () => {
          try {
            // 直接从专门的API获取
            return await assetService.getBusinessCategories()
          } catch (error) {
            console.warn('获取业态类别失败，使用默认选项:', error)
            return ['办公', '商业', '工业', '仓储', '住宅', '酒店', '餐饮', '其他']
          }
        },
        staleTime: 30 * 60 * 1000,
        retry: 0,
      },
    ],
  })

  // 提取查询结果
  const ownershipEntities = searchQueries[0].data || []
  const businessCategories = searchQueries[1].data || []

  // 检查是否所有查询都已加载完成
  const isLoadingQueries = searchQueries.some(query => query.isLoading)

  // 合并外部loading和内部查询loading
  const isComponentLoading = loading || isLoadingQueries

  // 设置初始值
  useEffect(() => {
    if (initialValues) {
      form.setFieldsValue(initialValues)
    }
  }, [initialValues, form])

  // 处理搜索
  const handleSearch = () => {
    const values = form.getFieldsValue()

    // 处理日期范围
    if (values.dateRange) {
      values.created_start = values.dateRange[0]?.format('YYYY-MM-DD')
      values.created_end = values.dateRange[1]?.format('YYYY-MM-DD')
      delete values.dateRange
    }

    // 处理面积范围
    if (values.areaRange) {
      values.area_min = values.areaRange[0]
      values.area_max = values.areaRange[1]
      delete values.areaRange
    }

    // 过滤空值
    const searchParams = Object.entries(values).reduce((acc, [key, value]) => {
      if (value !== undefined && value !== null && value !== '') {
        acc[key] = value
      }
      return acc
    }, {} as any)

    onSearch(searchParams)
  }

  // 处理重置
  const handleReset = () => {
    form.resetFields()
    setAreaRange([0, 100000])
    onReset()
  }

  // 处理保存搜索条件
  const handleSaveSearch = () => {
    const values = form.getFieldsValue()

    // 检查是否有搜索条件
    const hasConditions = Object.values(values).some(value =>
      value !== undefined && value !== null && value !== ''
    )

    if (!hasConditions) {
      message.warning('请先设置搜索条件')
      return
    }

    if (!saveName.trim()) {
      message.warning('请输入保存名称')
      return
    }

    addSearchHistory({
      id: Date.now().toString(),
      name: saveName,
      conditions: values,
      createdAt: new Date().toISOString(),
    })

    setSaveName('')
    setSaveModalVisible(false)
    message.success('搜索条件已保存')
  }

  // 处理应用历史搜索条件
  const handleApplyHistory = (historyId: string) => {
    const history = searchHistory.find(h => h.id === historyId)
    if (history) {
      form.setFieldsValue(history.conditions)
      handleSearch()
      setHistoryModalVisible(false)
    }
  }

  // 处理删除历史记录
  const handleDeleteHistory = (historyId: string) => {
    removeSearchHistory(historyId)
    message.success('历史记录已删除')
  }

  // 处理编辑历史记录名称
  const handleEditHistory = (historyId: string, currentName: string) => {
    setEditingHistoryId(historyId)
    setEditingName(currentName)
  }

  // 保存编辑的名称
  const handleSaveEdit = () => {
    if (editingHistoryId && editingName.trim()) {
      updateSearchHistoryName(editingHistoryId, editingName.trim())
      setEditingHistoryId(null)
      setEditingName('')
      message.success('名称已更新')
    }
  }

  return (
    <Card
      title={
        <Space>
          <SearchOutlined />
          <span>资产搜索</span>
          {isComponentLoading && (
            <Tag color="processing">加载中...</Tag>
          )}
        </Space>
      }
      extra={
        <Space>
          {showSaveButton && (
            <Button
              type="default"
              icon={<SaveOutlined />}
              onClick={() => setSaveModalVisible(true)}
              disabled={isComponentLoading}
            >
              保存条件
            </Button>
          )}
          {showHistoryButton && (
            <Button
              type="default"
              icon={<HistoryOutlined />}
              onClick={() => setHistoryModalVisible(true)}
            >
              搜索历史
            </Button>
          )}
          <Button
            type="primary"
            icon={<SearchOutlined />}
            onClick={handleSearch}
            loading={isComponentLoading}
          >
            搜索
          </Button>
          <Button
            icon={<ReloadOutlined />}
            onClick={handleReset}
            disabled={isComponentLoading}
          >
            重置
          </Button>
          <Button
            type="text"
            icon={expanded ? <UpOutlined /> : <DownOutlined />}
            onClick={() => setExpanded(!expanded)}
          >
            {expanded ? '收起' : '展开'}
          </Button>
        </Space>
      }
    >
      <Form
        form={form}
        layout="vertical"
        disabled={isComponentLoading}
      >
        <Row gutter={16}>
          {/* 基础搜索字段 */}
          <Col xs={24} sm={12} md={8} lg={6}>
            <Form.Item name="search" label="关键词搜索">
              <Input
                placeholder="输入物业名称、地址等关键词"
                prefix={<SearchOutlined />}
                allowClear
              />
            </Form.Item>
          </Col>

          <Col xs={24} sm={12} md={8} lg={6}>
            <Form.Item name="ownership_status" label="确权状态">
              <Select
                placeholder="选择确权状态"
                allowClear
                showSearch
                optionFilterProp="children"
              >
                <Option value="已确权">已确权</Option>
                <Option value="未确权">未确权</Option>
                <Option value="部分确权">部分确权</Option>
                <Option value="无法确认业权">无法确认业权</Option>
              </Select>
            </Form.Item>
          </Col>

          <Col xs={24} sm={12} md={8} lg={6}>
            <Form.Item name="property_nature" label="物业性质">
              <Select
                placeholder="选择物业性质"
                allowClear
                showSearch
                optionFilterProp="children"
              >
                <Option value="经营性">经营性</Option>
                <Option value="非经营性">非经营性</Option>
                <Option value="经营-外部">经营-外部</Option>
                <Option value="经营-内部">经营-内部</Option>
                <Option value="经营-租赁">经营-租赁</Option>
                <Option value="非经营类-公配">非经营类-公配</Option>
                <Option value="非经营类-其他">非经营类-其他</Option>
                <Option value="经营类">经营类</Option>
                <Option value="非经营类">非经营类</Option>
                <Option value="经营-配套">经营-配套</Option>
                <Option value="非经营-配套">非经营-配套</Option>
                <Option value="经营-配套镇">经营-配套镇</Option>
                <Option value="非经营-配套镇">非经营-配套镇</Option>
                <Option value="经营-处置类">经营-处置类</Option>
                <Option value="非经营-处置类">非经营-处置类</Option>
                <Option value="非经营-公配房">非经营-公配房</Option>
                <Option value="非经营类-配套">非经营类-配套</Option>
              </Select>
            </Form.Item>
          </Col>

          <Col xs={24} sm={12} md={8} lg={6}>
            <Form.Item name="usage_status" label="使用状态">
              <Select
                placeholder="选择使用状态"
                allowClear
                showSearch
                optionFilterProp="children"
              >
                <Option value="出租">出租</Option>
                <Option value="空置">空置</Option>
                <Option value="自用">自用</Option>
                <Option value="公房">公房</Option>
                <Option value="其他">其他</Option>
                <Option value="转租">转租</Option>
                <Option value="公配">公配</Option>
                <Option value="空置规划">空置规划</Option>
                <Option value="空置预留">空置预留</Option>
                <Option value="配套">配套</Option>
                <Option value="空置配套">空置配套</Option>
                <Option value="空置配">空置配</Option>
                <Option value="待处置">待处置</Option>
                <Option value="待移交">待移交</Option>
                <Option value="闲置">闲置</Option>
              </Select>
            </Form.Item>
          </Col>
        </Row>

        {/* 高级搜索条件 */}
        {expanded && (
          <>
            <Row gutter={16}>
              <Col xs={24} sm={12} md={8} lg={6}>
                <Form.Item name="ownership_entity" label="权属方">
                  <Select
                    placeholder="选择权属方"
                    allowClear
                    showSearch
                    optionFilterProp="children"
                    loading={searchQueries[0].isLoading}
                  >
                    {ownershipEntities.map(entity => (
                      <Option key={entity} value={entity}>
                        {entity}
                      </Option>
                    ))}
                  </Select>
                </Form.Item>
              </Col>

              <Col xs={24} sm={12} md={8} lg={6}>
                <Form.Item name="business_category" label="业态类别">
                  <Select
                    placeholder="选择业态类别"
                    allowClear
                    showSearch
                    optionFilterProp="children"
                    loading={searchQueries[1].isLoading}
                  >
                    {businessCategories.map(category => (
                      <Option key={category} value={category}>
                        {category}
                      </Option>
                    ))}
                  </Select>
                </Form.Item>
              </Col>

              <Col xs={24} sm={12} md={8} lg={6}>
                <Form.Item name="is_litigated" label="是否涉诉">
                  <Select placeholder="选择是否涉诉" allowClear>
                    <Option value="是">是</Option>
                    <Option value="否">否</Option>
                  </Select>
                </Form.Item>
              </Col>
            </Row>

            <Row gutter={16}>
              <Col xs={24} sm={12} md={8}>
                <Form.Item label="面积范围">
                  <Space.Compact>
                    <InputNumber
                      style={{ width: '45%' }}
                      placeholder="最小面积"
                      value={areaRange[0]}
                      onChange={(value) =>
                        setAreaRange([value || 0, areaRange[1]])
                      }
                    />
                    <Input
                      style={{ width: '10%', borderLeft: 0, borderRight: 0, pointerEvents: 'none' }}
                      placeholder="~"
                      disabled
                    />
                    <InputNumber
                      style={{ width: '45%' }}
                      placeholder="最大面积"
                      value={areaRange[1]}
                      onChange={(value) =>
                        setAreaRange([areaRange[0], value || 100000])
                      }
                    />
                  </Space.Compact>
                </Form.Item>
              </Col>

              <Col xs={24} sm={12} md={8}>
                <Form.Item name="dateRange" label="创建日期">
                  <RangePicker
                    style={{ width: '100%' }}
                    format="YYYY-MM-DD"
                  />
                </Form.Item>
              </Col>

              <Col xs={24} sm={12} md={8}>
                <Form.Item label="排序方式">
                  <Space.Compact>
                    <Form.Item name="sort_field" noStyle>
                      <Select style={{ width: '60%' }} defaultValue="created_at">
                        <Option value="created_at">创建时间</Option>
                        <Option value="property_name">物业名称</Option>
                        <Option value="total_area">建筑面积</Option>
                        <Option value="rentable_area">可租面积</Option>
                      </Select>
                    </Form.Item>
                    <Form.Item name="sort_order" noStyle>
                      <Select style={{ width: '40%' }} defaultValue="desc">
                        <Option value="asc">升序</Option>
                        <Option value="desc">降序</Option>
                      </Select>
                    </Form.Item>
                  </Space.Compact>
                </Form.Item>
              </Col>
            </Row>
          </>
        )}
      </Form>

      {/* 保存搜索条件弹窗 */}
      <Modal
        title="保存搜索条件"
        open={saveModalVisible}
        onOk={handleSaveSearch}
        onCancel={() => setSaveModalVisible(false)}
        destroyOnHidden
      >
        <Input
          placeholder="输入保存名称"
          value={saveName}
          onChange={(e) => setSaveName(e.target.value)}
          onPressEnter={handleSaveSearch}
        />
      </Modal>

      {/* 搜索历史弹窗 */}
      <Modal
        title="搜索历史"
        open={historyModalVisible}
        onCancel={() => {
          setHistoryModalVisible(false)
          setEditingHistoryId(null)
          setEditingName('')
        }}
        footer={null}
        width={600}
        destroyOnHidden
      >
        <List
          dataSource={searchHistory}
          locale={{
            emptyText: '暂无搜索历史'
          }}
          renderItem={item => (
            <List.Item
              key={item.id}
              actions={[
                <Button
                  key="apply"
                  type="link"
                  size="small"
                  onClick={() => handleApplyHistory(item.id)}
                >
                  应用
                </Button>,
                <Button
                  key="edit"
                  type="link"
                  size="small"
                  onClick={() => handleEditHistory(item.id, item.name)}
                >
                  编辑
                </Button>,
                <Popconfirm
                  key="delete"
                  title="确定要删除这条历史记录吗？"
                  onConfirm={() => handleDeleteHistory(item.id)}
                  okText="确定"
                  cancelText="取消"
                >
                  <Button
                    type="link"
                    size="small"
                    danger
                  >
                    删除
                  </Button>
                </Popconfirm>
              ]}
            >
              <List.Item.Meta
                title={
                  editingHistoryId === item.id ? (
                    <Input
                      size="small"
                      value={editingName}
                      onChange={(e) => setEditingName(e.target.value)}
                      onBlur={handleSaveEdit}
                      onPressEnter={handleSaveEdit}
                      style={{ width: 200 }}
                    />
                  ) : (
                    <Text>{item.name}</Text>
                  )
                }
                description={
                  <Space direction="vertical" size="small">
                    <Text type="secondary">
                      保存时间: {dayjs(item.createdAt).format('YYYY-MM-DD HH:mm:ss')}
                    </Text>
                    <Text type="secondary">
                      条件数: {Object.keys(item.conditions).length}
                    </Text>
                  </Space>
                }
              />
            </List.Item>
          )}
        />

        {searchHistory.length > 0 && (
          <div style={{ textAlign: 'center', marginTop: 16 }}>
            <Popconfirm
              title="确定要清空所有搜索历史吗？"
              onConfirm={clearSearchHistory}
              okText="确定"
              cancelText="取消"
            >
              <Button danger size="small">
                清空历史
              </Button>
            </Popconfirm>
          </div>
        )}
      </Modal>
    </Card>
  )
}

export default AssetSearch

import React from 'react'
import { Card, List, Typography, Tag, Space, Button, Tooltip } from 'antd'
import {
  EyeOutlined,
  EditOutlined,
  EnvironmentOutlined,
  UserOutlined,
  HomeOutlined,
} from '@ant-design/icons'

import type { Asset, AssetSearchParams } from '@/types/asset'
import { highlightText, extractSearchTerms } from '@/utils/highlight'
import { formatArea, getStatusColor } from '@/utils/format'

const { Text, Paragraph } = Typography

interface AssetSearchResultProps {
  assets: Asset[]
  searchParams: AssetSearchParams
  loading?: boolean
  onViewDetail: (asset: Asset) => void
  onEdit: (asset: Asset) => void
}

const AssetSearchResult: React.FC<AssetSearchResultProps> = ({
  assets,
  searchParams,
  loading = false,
  onViewDetail,
  onEdit,
}) => {
  // 提取搜索关键词
  const searchTerms = extractSearchTerms(searchParams.search || '')

  // 高亮文本的辅助函数
  const highlightSearchText = (text: string) => {
    if (!searchTerms.length) return text
    return highlightText(text, searchParams.search || '')
  }

  return (
    <List
      loading={loading}
      dataSource={assets}
      renderItem={(asset) => (
        <List.Item
          key={asset.id}
          actions={[
            <Tooltip title="查看详情">
              <Button
                type="text"
                icon={<EyeOutlined />}
                onClick={() => onViewDetail(asset)}
              />
            </Tooltip>,
            <Tooltip title="编辑">
              <Button
                type="text"
                icon={<EditOutlined />}
                onClick={() => onEdit(asset)}
              />
            </Tooltip>,
          ]}
        >
          <List.Item.Meta
            title={
              <Space>
                <HomeOutlined style={{ color: '#1890ff' }} />
                <Text strong style={{ fontSize: '16px' }}>
                  {highlightSearchText(asset.property_name)}
                </Text>
                <Tag color={getStatusColor(asset.ownership_status, 'ownership')}>
                  {asset.ownership_status}
                </Tag>
                <Tag color={getStatusColor(asset.property_nature, 'property')}>
                  {asset.property_nature}
                </Tag>
                <Tag color={getStatusColor(asset.usage_status, 'usage')}>
                  {asset.usage_status}
                </Tag>
              </Space>
            }
            description={
              <div>
                {/* 地址信息 */}
                <div style={{ marginBottom: 8 }}>
                  <Space>
                    <EnvironmentOutlined style={{ color: '#8c8c8c' }} />
                    <Text type="secondary">
                      {highlightSearchText(asset.address)}
                    </Text>
                  </Space>
                </div>

                {/* 权属信息 */}
                <div style={{ marginBottom: 8 }}>
                  <Space>
                    <UserOutlined style={{ color: '#8c8c8c' }} />
                    <Text type="secondary">
                      权属方: {highlightSearchText(asset.ownership_entity)}
                    </Text>
                    {asset.management_entity && (
                      <>
                        <Text type="secondary">|</Text>
                        <Text type="secondary">
                          管理方: {highlightSearchText(asset.management_entity)}
                        </Text>
                      </>
                    )}
                  </Space>
                </div>

                {/* 面积信息 */}
                <div style={{ marginBottom: 8 }}>
                  <Space wrap>
                    {asset.actual_property_area && (
                      <Text type="secondary">
                        实际面积: {formatArea(asset.actual_property_area)}
                      </Text>
                    )}
                    {asset.rentable_area && (
                      <Text type="secondary">
                        可租面积: {formatArea(asset.rentable_area)}
                      </Text>
                    )}
                    {asset.rented_area && (
                      <Text type="secondary">
                        已租面积: {formatArea(asset.rented_area)}
                      </Text>
                    )}
                    {asset.occupancy_rate && (
                      <Text type="secondary">
                        出租率: {asset.occupancy_rate}
                      </Text>
                    )}
                  </Space>
                </div>

                {/* 用途信息 */}
                {(asset.certificated_usage || asset.actual_usage || asset.business_category) && (
                  <div style={{ marginBottom: 8 }}>
                    <Space wrap>
                      {asset.certificated_usage && (
                        <Text type="secondary">
                          证载用途: {highlightSearchText(asset.certificated_usage)}
                        </Text>
                      )}
                      {asset.actual_usage && (
                        <Text type="secondary">
                          实际用途: {highlightSearchText(asset.actual_usage)}
                        </Text>
                      )}
                      {asset.business_category && (
                        <Text type="secondary">
                          业态: {highlightSearchText(asset.business_category)}
                        </Text>
                      )}
                    </Space>
                  </div>
                )}

                {/* 租户信息 */}
                {asset.tenant_name && (
                  <div style={{ marginBottom: 8 }}>
                    <Text type="secondary">
                      租户: {highlightSearchText(asset.tenant_name)}
                    </Text>
                  </div>
                )}

                {/* 特殊标记 */}
                <div>
                  <Space>
                    {asset.is_litigated && (
                      <Tag color="red">涉诉</Tag>
                    )}
                    {asset.include_in_occupancy_rate && (
                      <Tag color="green">计入出租率</Tag>
                    )}
                    {asset.wuyang_project_name && (
                      <Tag color="blue">五羊项目</Tag>
                    )}
                  </Space>
                </div>

                {/* 描述信息 */}
                {asset.description && (
                  <div style={{ marginTop: 8 }}>
                    <Paragraph
                      ellipsis={{ rows: 2, expandable: true, symbol: '展开' }}
                      style={{ margin: 0, fontSize: '12px', color: '#8c8c8c' }}
                    >
                      {highlightSearchText(asset.description)}
                    </Paragraph>
                  </div>
                )}
              </div>
            }
          />
        </List.Item>
      )}
    />
  )
}

