                  </div>
                  <div style={{ textAlign: 'right' }}>
                    <Text style={{ color: '#ff4d4f', fontWeight: 'bold' }}>
                      {asset.rate.toFixed(2)}%
                    </Text>
                  </div>
                </div>
              ))}
            </div>
          </Card>
        </Col>
      </Row>
    </div>
  )
