import type { UploadFile, UploadProps } from 'antd';

import { pdfImportService } from '../../services/pdfImportService';
import type {
  FileUploadResponse,
  SessionProgress,
  EnhancedFileUploadResponse,
  EnhancedSystemInfoResponse
} from '../../services/pdfImportService';

const { Dragger } = Upload;
const { Step } = Steps;
const { Title, Text, Paragraph } = Typography;

interface EnhancedPDFImportUploaderProps {
  onUploadSuccess: (sessionId: string, fileInfo: UploadFile) => void;
  onUploadError: (error: string) => void;
  maxSize?: number; // MB
  className?: string;
}

interface ProcessingStep {
  title: string;
  description: string;
  status: 'wait' | 'process' | 'finish' | 'error';
  progress?: number;
  duration?: number;
}

interface UploadStats {
  uploadSpeed: number; // KB/s
  estimatedTime: number; // seconds
  fileAnalysis: {
    type: 'scanned' | 'digital' | 'mixed' | 'unknown';
    quality: 'excellent' | 'good' | 'fair' | 'poor';
    recommendedMethod: string;
  };
}

const EnhancedPDFImportUploader: React.FC<EnhancedPDFImportUploaderProps> = ({
  onUploadSuccess,
  onUploadError,
  maxSize = 50,
  className
}) => {
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [currentSession, setCurrentSession] = useState<string | null>(null);
  const [processingProgress, setProcessingProgress] = useState<SessionProgress | null>(null);
  const [showAdvancedOptions, setShowAdvancedOptions] = useState(false);
  const [systemInfo, setSystemInfo] = useState<EnhancedSystemInfoResponse | null>(null);
  const [uploadStats, setUploadStats] = useState<UploadStats | null>(null);
  const [processingSteps, setProcessingSteps] = useState<ProcessingStep[]>([]);
  const [showPreviewModal, setShowPreviewModal] = useState(false);

  const abortControllerRef = useRef<AbortController | null>(null);
  const progressTimerRef = useRef<NodeJS.Timeout | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // 默认处理选项
  const [processingOptions, setProcessingOptions] = useState({
    prefer_ocr: true,
    enable_chinese_optimization: true,
    enable_table_detection: true,
    enable_seal_detection: true,
    confidence_threshold: 0.7,
    use_template_learning: true,
    enable_multi_engine_fusion: true,
    enable_semantic_validation: true
  });

  // 加载系统信息
  useEffect(() => {
    loadSystemInfo();
    return () => {
      if (progressTimerRef.current) {
        clearInterval(progressTimerRef.current);
      }
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, []);

  const loadSystemInfo = async () => {
    try {
      const info = await pdfImportService.getEnhancedSystemInfo();
      setSystemInfo(info);
    } catch (error) {
      // Failed to get system info
    }
  };

  // 初始化处理步骤
  const initializeProcessingSteps = (): ProcessingStep[] => [
    {
      title: '文件上传',
      description: '上传PDF文件到服务器',
      status: 'wait'
    },
    {
      title: '文档分析',
      description: '分析文档类型和质量',
      status: 'wait'
    },
    {
      title: '文本提取',
      description: '提取PDF文本内容',
      status: 'wait'
    },
    {
      title: '信息识别',
      description: '智能识别合同信息',
      status: 'wait'
    },
    {
      title: '数据验证',
      description: '验证和映射数据',
      status: 'wait'
    },
    {
      title: '处理完成',
      description: '准备人工确认',
      status: 'wait'
    }
  ];

  // 更新处理步骤状态
  const updateProcessingSteps = (progress: SessionProgress) => {
    const steps = initializeProcessingSteps();

    // 根据进度映射到步骤
    const stepMapping: Record<string, number> = {
      'uploading': 0,
      'analyzing': 1,
      'text_extraction': 2,
      'info_extraction': 3,
      'validation': 4,
      'matching': 4,
      'ready_for_review': 5,
      'completed': 5,
      'failed': -1
    };

    const currentStepIndex = stepMapping[progress.status] || 0;

    // 更新步骤状态
    steps.forEach((step, index) => {
      if (index < currentStepIndex) {
        step.status = 'finish';
        step.progress = 100;
      } else if (index === currentStepIndex) {
        step.status = progress.status === 'failed' ? 'error' : 'process';
        step.progress = progress.progress;
      } else {
        step.status = 'wait';
        step.progress = 0;
      }
    });

    setProcessingSteps(steps);
  };

  // 文件上传前验证
  const beforeUpload = useCallback((file: File) => {
    const isPDF = file.type === 'application/pdf' || file.name.toLowerCase().endsWith('.pdf');
    if (!isPDF) {
      message.error('只能上传PDF文件！');
      return false;
    }

    const isLtMaxSize = file.size / 1024 / 1024 < maxSize;
    if (!isLtMaxSize) {
      message.error(`文件大小不能超过 ${maxSize}MB！`);
      return false;
    }

    return true;
  }, [maxSize]);

  // 上传配置
  const uploadProps: UploadProps = {
    name: 'file',
    multiple: false,
    accept: '.pdf,application/pdf',
    beforeUpload,
    showUploadList: false,
    customRequest: async ({ file, onSuccess, onError, onProgress }) => {
      try {
        setUploading(true);
        setUploadProgress(0);

        // 创建AbortController
        abortControllerRef.current = new AbortController();

        // 模拟上传进度
        const progressInterval = setInterval(() => {
          setUploadProgress(prev => {
            const newProgress = prev + Math.random() * 10;
            return Math.min(newProgress, 90);
          });
        }, 200);

        // 使用增强上传
        const response = await pdfImportService.uploadPDFFileEnhanced(
          file,
          processingOptions,
          abortControllerRef.current.signal
        );

        clearInterval(progressInterval);
        setUploadProgress(100);

        if (response.success) {
          setCurrentSession(response.session_id!);

          // 开始轮询处理进度
          startProgressPolling(response.session_id!);

          // 获取文件分析信息
          if (response.enhanced_status) {
            setUploadStats({
              uploadSpeed: file.size / 1024 / (Date.now() / 1000),
              estimatedTime: 30,
              fileAnalysis: {
                type: 'mixed',
                quality: 'good',
                recommendedMethod: response.enhanced_status.final_results?.extraction_quality?.processing_methods?.[0] || 'hybrid'
              }
            });
          }

          onSuccess?.(response);
          onUploadSuccess(response.session_id!, {
            uid: file.uid,
            name: file.name,
            status: 'done',
            size: file.size,
            type: file.type
          });

          message.success('文件上传成功，开始智能处理...');
        } else {
          throw new Error(response.error || '上传失败');
        }

      } catch (error: unknown) {
        clearInterval(progressInterval);
        setUploading(false);
        setUploadProgress(0);

        const errorMessage = error.message || '上传失败';
        onError?.(new Error(errorMessage));
        onUploadError(errorMessage);
        message.error(errorMessage);
      } finally {
        setTimeout(() => {
          setUploading(false);
          setUploadProgress(0);
        }, 1000);
      }
    }
  };

  // 开始进度轮询
  const startProgressPolling = (sessionId: string) => {
    if (progressTimerRef.current) {
      clearInterval(progressTimerRef.current);
    }

    progressTimerRef.current = setInterval(async () => {
      try {
        const result = await pdfImportService.getEnhancedProgress(sessionId);

        if (result.success && result.session_status) {
          setProcessingProgress(result.session_status);
          updateProcessingSteps(result.session_status);

          // 如果处理完成或失败，停止轮询
          if (['ready_for_review', 'completed', 'failed', 'cancelled'].includes(result.session_status.status)) {
            if (progressTimerRef.current) {
              clearInterval(progressTimerRef.current);
              progressTimerRef.current = null;
            }

            if (result.session_status.status === 'ready_for_review' || result.session_status.status === 'completed') {
              message.success('文件处理完成！');
            } else if (result.session_status.status === 'failed') {
              message.error(`处理失败: ${result.session_status.error_message || '未知错误'}`);
            }
          }
        }
      } catch (error) {
        console.error('获取进度失败:', error);
      }
    }, 2000);
  };

  // 取消上传
  const handleCancel = useCallback(() => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    if (currentSession) {
      pdfImportService.cancelEnhancedSession(currentSession, '用户取消');
    }

    if (progressTimerRef.current) {
      clearInterval(progressTimerRef.current);
      progressTimerRef.current = null;
    }

    setUploading(false);
    setUploadProgress(0);
    setProcessingProgress(null);
    setCurrentSession(null);
    setProcessingSteps(initializeProcessingSteps());

    message.info('已取消上传');
  }, [currentSession]);

  // 重置状态
  const handleReset = useCallback(() => {
    setUploading(false);
    setUploadProgress(0);
    setProcessingProgress(null);
    setCurrentSession(null);
    setProcessingSteps(initializeProcessingSteps());
    setUploadStats(null);

    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  }, []);

  // 获取步骤图标
  const getStepIcon = (step: ProcessingStep) => {
    switch (step.status) {
      case 'finish':
        return <CheckCircleOutlined style={{ color: '#52c41a' }} />;
      case 'process':
        return <LoadingOutlined style={{ color: '#1890ff' }} />;
      case 'error':
        return <ExclamationCircleOutlined style={{ color: '#ff4d4f' }} />;
      default:
        return <FileTextOutlined />;
    }
  };

  // 获取处理方法标签颜色
  const getMethodTagColor = (method: string) => {
    const colorMap: Record<string, string> = {
      'enhanced': 'blue',
      'multi_engine': 'green',
      'ocr': 'orange',
      'hybrid': 'purple'
    };
    return colorMap[method] || 'default';
  };

  return (
    <div className={className}>
      <Card
        title={
          <Space>
            <CloudUploadOutlined />
            <span>智能PDF导入</span>
            {systemInfo && (
              <Badge
                count="AI增强"
                style={{ backgroundColor: '#52c41a' }}
              />
            )}
          </Space>
        }
        extra={
          <Space>
            <Tooltip title="高级选项">
              <Button
                type="text"
                icon={<SettingOutlined />}
                onClick={() => setShowAdvancedOptions(!showAdvancedOptions)}
              />
            </Tooltip>
            {currentSession && (
              <Tooltip title="预览处理结果">
                <Button
                  type="text"
                  icon={<EyeOutlined />}
                  onClick={() => setShowPreviewModal(true)}
                />
              </Tooltip>
            )}
          </Space>
        }
      >
        {/* 处理步骤显示 */}
        {processingSteps.length > 0 && (uploading || processingProgress) && (
          <div style={{ marginBottom: 24 }}>
            <Steps
              size="small"
              current={processingSteps.findIndex(s => s.status === 'process')}
              items={processingSteps.map(step => ({
                title: step.title,
                description: step.description,
                status: step.status as any,
                icon: getStepIcon(step)
              }))}
            />

            {(uploading || processingProgress) && (
              <div style={{ marginTop: 16 }}>
                <Progress
                  percent={uploading ? uploadProgress : (processingProgress?.progress || 0)}
                  status={processingProgress?.status === 'failed' ? 'exception' : undefined}
                  strokeColor={{
                    '0%': '#108ee9',
                    '100%': '#87d068',
                  }}
                />

                {processingProgress && (
                  <div style={{ marginTop: 8, display: 'flex', justifyContent: 'space-between' }}>
                    <Text type="secondary">
                      {processingProgress.current_step || '准备中...'}
                    </Text>
                    <Text type="secondary">
                      {processingProgress.progress || 0}%
                    </Text>
                  </div>
                )}
              </div>
            )}
          </div>
        )}

        {/* 上传区域 */}
        {!currentSession && (
          <Dragger {...uploadProps} disabled={uploading}>
            <p className="ant-upload-drag-icon">
              <CloudUploadOutlined style={{ fontSize: 48, color: '#1890ff' }} />
            </p>
            <p className="ant-upload-text">
              点击或拖拽文件到此区域上传
            </p>
            <p className="ant-upload-hint">
              支持PDF文件，最大{maxSize}MB
            </p>
          </Dragger>
        )}

        {/* 高级选项 */}
        {showAdvancedOptions && (
          <Card
            size="small"
            title="处理选项"
            style={{ marginTop: 16 }}
            extra={
              <Space>
                <Switch
                  checked={processingOptions.prefer_ocr}
                  onChange={(checked) => setProcessingOptions(prev => ({ ...prev, prefer_ocr: checked }))}
                  checkedChildren="OCR"
                  unCheckedChildren="文本"
                />
                <Switch
                  checked={processingOptions.enable_chinese_optimization}
                  onChange={(checked) => setProcessingOptions(prev => ({ ...prev, enable_chinese_optimization: checked }))}
                  checkedChildren="中文优化"
                />
              </Space>
            }
          >
            <Row gutter={16}>
              <Col span={12}>
                <Space direction="vertical" style={{ width: '100%' }}>
                  <div>
                    <Text strong>置信度阈值</Text>
                    <input
                      type="range"
                      min="0.1"
                      max="1.0"
                      step="0.1"
                      value={processingOptions.confidence_threshold}
                      onChange={(e) => setProcessingOptions(prev => ({ ...prev, confidence_threshold: parseFloat(e.target.value) }))}
                      style={{ width: '100%' }}
                    />
                    <Text type="secondary">{processingOptions.confidence_threshold}</Text>
                  </div>
                </Space>
              </Col>
              <Col span={12}>
                <Space direction="vertical" style={{ width: '100%' }}>
                  <Switch
                    checked={processingOptions.enable_multi_engine_fusion}
                    onChange={(checked) => setProcessingOptions(prev => ({ ...prev, enable_multi_engine_fusion: checked }))}
                    checkedChildren="多引擎融合"
                  />
                  <Switch
                    checked={processingOptions.enable_semantic_validation}
                    onChange={(checked) => setProcessingOptions(prev => ({ ...prev, enable_semantic_validation: checked }))}
                    checkedChildren="语义验证"
                  />
                </Space>
              </Col>
            </Row>
          </Card>
        )}

        {/* 系统信息显示 */}
        {systemInfo && (
          <Alert
            message={
              <Space>
                <RocketOutlined />
                <span>AI增强PDF处理系统已就绪</span>
              </Space>
            }
            description={
              <Space wrap>
                <Tag color="blue">多引擎处理</Tag>
                <Tag color="green">中文优化</Tag>
                <Tag color="purple">智能验证</Tag>
                <Tag color="orange">语义分析</Tag>
              </Space>
            }
            type="success"
            showIcon
            style={{ marginTop: 16 }}
          />
        )}

        {/* 处理统计 */}
        {uploadStats && (
          <Row gutter={16} style={{ marginTop: 16 }}>
            <Col span={8}>
              <Statistic
                title="上传速度"
                value={uploadStats.uploadSpeed}
                suffix="KB/s"
                precision={1}
              />
            </Col>
            <Col span={8}>
              <Statistic
                title="预估时间"
                value={uploadStats.estimatedTime}
                suffix="秒"
              />
            </Col>
            <Col span={8}>
              <Statistic
                title="推荐方法"
                value={uploadStats.fileAnalysis.recommendedMethod}
                valueStyle={{ fontSize: 14 }}
              />
            </Col>
          </Row>
        )}

        {/* 操作按钮 */}
        {(uploading || currentSession) && (
          <div style={{ marginTop: 16, textAlign: 'center' }}>
            <Space>
              <Button onClick={handleCancel} danger>
                取消处理
              </Button>
              <Button onClick={handleReset}>
                重新开始
              </Button>
            </Space>
          </div>
        )}

        {/* 预览模态框 */}
        <Modal
          title="处理结果预览"
          open={showPreviewModal}
          onCancel={() => setShowPreviewModal(false)}
          footer={[
            <Button key="close" onClick={() => setShowPreviewModal(false)}>
              关闭
            </Button>
          ]}
          width={800}
        >
          {processingProgress && (
            <div>
              <Paragraph>
                <Text strong>处理状态：</Text>
                <Tag color={processingProgress.status === 'ready_for_review' ? 'green' : 'blue'}>
                  {processingProgress.status}
                </Tag>
              </Paragraph>

              {processingProgress.enhanced_status && (
                <div>
                  <Divider />
                  <Paragraph>
                    <Text strong>文档分析结果：</Text>
                  </Paragraph>
                  <ul>
                    <li>文档类型：{processingProgress.enhanced_status.document_analysis?.document_type || '未知'}</li>
                    <li>质量评分：{processingProgress.enhanced_status.document_analysis?.quality_score || 0}/10</li>
                    <li>建议：{processingProgress.enhanced_status.document_analysis?.recommendations?.join('；') || '无'}</li>
                  </ul>

                  <Paragraph>
                    <Text strong>提取质量：</Text>
                  </Paragraph>
                  <ul>
                    <li>总体质量：{processingProgress.enhanced_status.final_results?.extraction_quality?.overall_quality || 0}/10</li>
                    <li>验证分数：{processingProgress.enhanced_status.final_results?.validation_score || 0}/10</li>
                    <li>处理方法：{processingProgress.enhanced_status.final_results?.extraction_quality?.processing_methods?.join('、') || '未知'}</li>
                  </ul>
                </div>
              )}
            </div>
          )}
        </Modal>
      </Card>
    </div>
  );
};

export default EnhancedPDFImportUploader;

/**
 * 增强版PDF处理状态组件
 * 支持中文合同识别的详细处理进度和状态显示
 */

import React, { useState, useEffect, useMemo } from 'react';
import {
  Card,
  Steps,
  Progress,
  Tag,
  Row,
  Col,
  Statistic,
  Alert,
  Tooltip,
  Space,
  Divider,
  Button,
  Timeline,
  Badge,
  Typography,
  Spin,
  Descriptions,
  List
} from 'antd';
import {
  CheckCircleOutlined,
  CloseCircleOutlined,
  ClockCircleOutlined,
  InfoCircleOutlined,
  WarningOutlined,
  LoadingOutlined,
  RocketOutlined,
  ExperimentOutlined,
  EyeOutlined,
  SyncOutlined,
  FireOutlined,
  ThunderboltOutlined,
  RobotOutlined,
  SafetyCertificateOutlined,
  FileTextOutlined,
  TableOutlined,
  ScanOutlined,
  EditOutlined
} from '@ant-design/icons';
import type {
  EnhancedSessionProgress,
  ValidationLevel,
  EngineType,
  ProcessingOptions,
  QualityMetrics
} from '../../types/enhancedPdfImport';

const { Title, Text, Paragraph } = Typography;

interface ProcessingStep {
  step: string;
  status: 'waiting' | 'processing' | 'completed' | 'error';
  title: string;
  description?: string;
  progress?: number;
  duration?: number;
  error?: string;
  details?: Record<string, unknown>;
}

interface EnhancedProcessingStatusProps {
  sessionId: string;
  currentStatus?: EnhancedSessionProgress;
  processingOptions?: ProcessingOptions;
  onRefresh?: () => void;
  onCancel?: () => void;
  showDetails?: boolean;
  compact?: boolean;
  onError?: (error: string) => void;
}

const EnhancedProcessingStatus: React.FC<EnhancedProcessingStatusProps> = ({
  sessionId,
  currentStatus,
  processingOptions,
  onRefresh,
  onCancel,
  showDetails = true,
  compact = false,
  onError
}) => {
  const [expanded, setExpanded] = useState<string | null>(null);
  const [autoRefresh, setAutoRefresh] = useState(true);

  // 增强版处理步骤映射
  const enhancedStepMap: Record<string, string> = {
    'pdf_conversion': 'PDF转换',
    'enhanced_text_extraction': '增强版文本提取',
    'table_analysis': '表格分析',
    'enhanced_info_extraction': '增强版信息提取',
    'multi_engine_fusion': '多引擎融合',
    'semantic_validation': '语义验证',
    'final_validation': '最终验证',
    'ready_for_review': '等待审核'
  };

  // 兼容旧版步骤映射
  const stepMap: Record<string, string> = {
    'file_upload': '文件上传',
    'pdf_conversion': 'PDF转换',
    'text_extraction': '文本提取',
    'info_extraction': '信息提取',
    'data_validation': '数据验证',
    'asset_matching': '资产匹配',
    'ownership_matching': '权属方匹配',
    'duplicate_check': '重复检查',
    'final_review': '最终审核'
  };

  // 状态颜色映射
  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return 'success';
      case 'processing': return 'processing';
      case 'error': return 'error';
      case 'uploading': return 'warning';
      default: return 'default';
    }
  };

  // 获取状态图标
  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'completed': return <CheckCircleOutlined />;
      case 'processing': return <LoadingOutlined spin />;
      case 'error': return <CloseCircleOutlined />;
      default: return <ClockCircleOutlined />;
    }
  };

  // 处理步骤数据
  const processingSteps = useMemo((): ProcessingStep[] => {
    if (!currentStatus) return [];

    const steps: ProcessingStep[] = [
      {
        step: 'file_upload',
        status: 'completed',
        title: '文件上传',
        description: 'PDF文件已成功上传并保存',
        progress: 100
      },
      {
        step: 'pdf_conversion',
        status: currentStatus.processing_method === 'ocr' ? 'processing' : 'completed',
        title: 'PDF处理',
        description: currentStatus.processing_method === 'ocr'
          ? '正在使用OCR技术处理PDF文档'
          : 'PDF文档处理完成',
        progress: currentStatus.processing_method === 'ocr' ? 80 : 100
      },
      {
        step: 'text_extraction',
        status: 'completed',
        title: '文本提取',
        description: `成功提取${currentStatus.chinese_char_count || 0}个中文字符`,
        progress: 100
      },
      {
        step: 'info_extraction',
        status: 'completed',
        title: '信息提取',
        description: `提取了${Object.keys(currentStatus.extracted_data || {}).length}个字段`,
        progress: 100
      },
      {
        step: 'data_validation',
        status: currentStatus.validation_results ? 'completed' : 'processing',
        title: '数据验证',
        description: currentStatus.validation_results
          ? '数据验证完成，置信度优秀'
          : '正在进行智能数据验证',
        progress: currentStatus.validation_results ? 100 : 70
      },
      {
        step: 'matching',
        status: 'processing',
        title: '智能匹配',
        description: '正在进行资产和权属方智能匹配',
        progress: 60
      },
      {
        step: 'final_review',
        status: 'waiting',
        title: '最终审核',
        description: '等待用户审核和确认',
        progress: 0
      }
    ];

    // 根据实际状态更新步骤
    const currentStep = currentStatus.current_step;
    if (currentStep) {
      const stepIndex = steps.findIndex(s => s.step === currentStep);
      if (stepIndex !== -1) {
        // 更新当前步骤及之前步骤的状态
        steps.forEach((step, index) => {
          if (index < stepIndex) {
            step.status = 'completed';
            step.progress = 100;
          } else if (index === stepIndex) {
            step.status = 'processing';
            step.progress = currentStatus.progress_percentage || 0;
          } else {
            step.status = 'waiting';
            step.progress = 0;
          }
        });
      }
    }

    return steps;
  }, [currentStatus]);

  // 性能指标
  const performanceMetrics = useMemo(() => {
    if (!currentStatus) return null;

    return {
      processingMethod: currentStatus.processing_method,
      textQuality: currentStatus.chinese_char_count ? '优秀' : '良好',
      extractionConfidence: currentStatus.confidence_score
        ? `${(currentStatus.confidence_score * 100).toFixed(1)}%`
        : '计算中',
      ocrUsed: currentStatus.ocr_used,
      estimatedTime: currentStatus.processing_method === 'ocr' ? '45-60秒' : '30-45秒'
    };
  }, [currentStatus]);

  // 错误处理和重试逻辑
  const handleRetry = async () => {
    if (onRefresh) {
      onRefresh();
    }
  };

  const handleStepDetail = (step: string) => {
    setExpanded(expanded === step ? null : step);
  };

  if (!currentStatus) {
    return (
      <Card>
        <Spin size="large" tip="加载处理状态中...">
          <div style={{ height: 200 }} />
        </Spin>
      </Card>
    );
  }

  return (
    <div className="enhanced-processing-status">
      {/* 整体进度 */}
      <Card
        title={
          <Space>
            <RocketOutlined />
            <span>PDF智能处理进度</span>
            <Button
              type="text"
              size="small"
              icon={<SyncOutlined />}
              onClick={handleRetry}
            >
              刷新
            </Button>
          </Space>
        }
        >
          <Row gutter={16}>
            <Col span={16}>
              <Progress
                percent={currentStatus.progress_percentage || 0}
                status={currentStatus.progress_percentage === 100 ? 'success' : 'active'}
                strokeColor={{
                  '0%': '#108ee9',
                  '100%': '#87d068',
                }}
                strokeWidth={8}
                format={(percent) => `${percent}%`}
              />
              <div style={{ marginTop: 16 }}>
                <Text type="secondary">
                  当前状态：{stepMap[currentStatus.current_step] || '准备中'}
                </Text>
              </div>
            </Col>
            <Col span={8}>
              <Space direction="vertical" style={{ width: '100%' }}>
                <Statistic
                  title="处理方法"
                  value={performanceMetrics?.processingMethod === 'ocr' ? 'OCR识别' : '文本提取'}
                  prefix={<ExperimentOutlined />}
                />
                <Statistic
                  title="置信度"
                  value={performanceMetrics?.extractionConfidence || '计算中'}
                  suffix="%"
                  valueStyle={{
                    color: parseFloat(performanceMetrics?.extractionConfidence || '0') > 80 ? '#3f8600' : '#cf1322'
                  }}
                />
              </Space>
            </Col>
          </Row>
        </Card>

      {/* 详细步骤 */}
      {showDetails && (
        <Card title="处理详情" style={{ marginTop: 16 }}>
          <Timeline>
            {processingSteps.map((step, index) => (
              <Timeline.Item
                key={step.step}
                dot={getStatusIcon(step.status)}
                color={getStatusColor(step.status)}
              >
                <div
                  style={{
                    cursor: step.details ? 'pointer' : 'default',
                    padding: '8px 12px',
                    borderRadius: '6px',
                    backgroundColor: step.status === 'processing' ? '#f6ffed' : 'transparent'
                  }}
                  onClick={() => step.details && handleStepDetail(step.step)}
                >
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Space>
                      <Text strong>{step.title}</Text>
                      <Badge
                        status={step.status === 'completed' ? 'success' :
                               step.status === 'processing' ? 'processing' :
                               step.status === 'error' ? 'error' : 'default'}
                        text={
                          step.status === 'completed' ? '已完成' :
                          step.status === 'processing' ? '处理中' :
                          step.status === 'error' ? '失败' : '等待中'
                        }
                      />
                    </Space>

                    {step.description && (
                      <Text type="secondary" style={{ fontSize: '12px' }}>
                        {step.description}
                      </Text>
                    )}

                    {step.progress !== undefined && (
                      <Progress
                        percent={step.progress}
                        size="small"
                        showInfo={false}
                        strokeColor={step.status === 'completed' ? '#52c41a' : '#1890ff'}
                      />
                    )}

                    {step.error && (
                      <Alert
                        message={step.error}
                        type="error"
                        size="small"
                        style={{ marginTop: 8 }}
                      />
                    )}
                  </Space>

                  {/* 展开的详细信息 */}
                  {expanded === step.step && step.details && (
                    <div style={{
                      marginTop: 12,
                      padding: 12,
                      backgroundColor: '#fafafa',
                      borderRadius: 4,
                      border: '1px solid #d9d9d9'
                    }}>
                      <Text code>
                        {JSON.stringify(step.details, null, 2)}
                      </Text>
                    </div>
                  )}
                </div>
              </Timeline.Item>
            ))}
          </Timeline>
        </Card>
      )}

      {/* 警告和建议 */}
      {currentStatus.warnings && currentStatus.warnings.length > 0 && (
        <Alert
          message="处理提示"
          description={
            <ul>
              {currentStatus.warnings.map((warning: string, index: number) => (
                <li key={index}>{warning}</li>
              ))}
            </ul>
          }
          type="warning"
          showIcon
          style={{ marginTop: 16 }}
        />
      )}

      {/* 增强功能标识 */}
      <Card size="small" style={{ marginTop: 16 }}>
        <Space wrap>
          <Tag icon={<ExperimentOutlined />} color="blue">
            增强版提取器
          </Tag>
          <Tag icon={<EyeOutlined />} color="green">
            智能质量评估
          </Tag>
          <Tag color="purple">
            多引擎支持
          </Tag>
          {performanceMetrics?.ocrUsed && (
            <Tag color="orange">
              OCR增强
            </Tag>
          )}
        </Space>
      </Card>
    </div>
  );
};

export default EnhancedProcessingStatus;

import React, { useState, useEffect } from 'react';
import {
  Modal,
  Button,
  Space,
  Typography,
  Alert,
  Steps,
  Card,
  Row,
  Col,
  Table,
  Tag,
  Tooltip,
  message,
  Spin,
  Divider
} from 'antd';
import {
  CheckCircleOutlined,
  ExclamationCircleOutlined,
  InfoCircleOutlined,
  ReloadOutlined,
  CopyOutlined,
  EditOutlined
} from '@ant-design/icons';
import { validateFilenameAPI } from '../../services/pdfImportService';

const { Title, Text, Paragraph } = Typography;

interface FilenameFixDialogProps {
  visible: boolean;
  onCancel: () => void;
  originalFilename: string;
  onFilenameFixed: (fixedFilename: string) => void;
}

interface ValidationResult {
  valid: boolean;
  issues: string[];
  suggestions: string[];
  severity: 'low' | 'medium' | 'high';
}

interface FixStep {
  title: string;
  description: string;
  status: 'wait' | 'process' | 'finish' | 'error';
  content?: React.ReactNode;
}

interface FilenameChange {
  original: string;
  fixed: string;
  reason: string;
  type: 'replacement' | 'removal' | 'truncation' | 'addition';
}

export const FilenameFixDialog: React.FC<FilenameFixDialogProps> = ({
  visible,
  onCancel,
  originalFilename,
  onFilenameFixed
}) => {
  const [loading, setLoading] = useState(false);
  const [validationResult, setValidationResult] = useState<ValidationResult | null>(null);
  const [suggestedFilename, setSuggestedFilename] = useState<string>('');
  const [currentStep, setCurrentStep] = useState<number>(0);
  const [filenameChanges, setFilenameChanges] = useState<FilenameChange[]>([]);
  const [customFilename, setCustomFilename] = useState<string>('');
  const [copySuccess, setCopySuccess] = useState<boolean>(false);

  // 步骤定义
  const [steps, setSteps] = useState<FixStep[]>([]);

  // 中文特殊字符映射
  const charMappings: { [key: string]: string } = {
    '【': '[',
    '】': ']',
    '（': '(',
    '）': ')',
    '《': '<',
    '》': '>',
    '"': '"',
    '"': '"',
    "'": "'",
    "'": "'",
    '：': ':',
    '，': ',',
    '。': '.',
    '；': ';',
    '！': '!',
    '？': '?',
    '…': '...',
    '—': '-',
    '–': '-'
  };

  const analyzeAndFixFilename = (filename: string): { fixed: string; changes: FilenameChange[] } => {
    const changes: FilenameChange[] = [];
    let fixed = filename;

    // 步骤1: 分离文件名和扩展名
    const nameWithoutExt = fixed.replace(/\.pdf$/i, '');
    const ext = fixed.endsWith('.pdf') ? '.pdf' : '';

    // 步骤2: 替换中文特殊字符
    let tempFixed = nameWithoutExt;
    Object.entries(charMappings).forEach(([chinese, standard]) => {
      if (tempFixed.includes(chinese)) {
        const before = tempFixed;
        tempFixed = tempFixed.replace(new RegExp(chinese, 'g'), standard);
        if (before !== tempFixed) {
          changes.push({
            original: chinese,
            fixed: standard,
            reason: '中文特殊字符替换为标准字符',
            type: 'replacement'
          });
        }
      }
    });

    // 步骤3: 移除危险字符
    const dangerousChars = /[<>:"/\\|?*]/g;
    const beforeDangerous = tempFixed;
    tempFixed = tempFixed.replace(dangerousChars, '_');
    if (beforeDangerous !== tempFixed) {
      const dangerousMatches = beforeDangerous.match(/[<>:"/\\|?*]/g) || [];
      dangerousMatches.forEach(char => {
        changes.push({
          original: char,
          fixed: '_',
          reason: '移除系统不兼容字符',
          type: 'removal'
        });
      });
    }

    // 步骤4: 合并连续的特殊字符
    const beforeConsecutive = tempFixed;
    tempFixed = tempFixed.replace(/_{2,}/g, '_');
    if (beforeConsecutive !== tempFixed) {
      changes.push({
        original: '__',
        fixed: '_',
        reason: '合并连续的特殊字符',
        type: 'removal'
      });
    }

    // 步骤5: 移除开头和结尾的特殊字符
    const beforeTrim = tempFixed;
    tempFixed = tempFixed.trim('._-');
    if (beforeTrim !== tempFixed) {
      changes.push({
        original: beforeTrim + (beforeTrim !== tempFixed ? '...' : ''),
        fixed: tempFixed,
        reason: '移除开头/结尾的特殊字符',
        type: 'removal'
      });
    }

    // 步骤6: 长度检查和截断
    const maxLength = 200;
    if (tempFixed.length > maxLength - ext.length) {
      const originalLength = tempFixed.length;
      const keepLength = maxLength - ext.length - 15;
      const tempFixed2 = tempFixed.substring(0, keepLength) + '...' + tempFixed.substring(-12);
      changes.push({
        original: tempFixed,
        fixed: tempFixed2,
        reason: `文件名截断 (${originalLength} → ${tempFixed2.length})`,
        type: 'truncation'
      });
      tempFixed = tempFixed2;
    }

    // 步骤7: 确保有PDF扩展名
    if (!ext || !ext.toLowerCase().includes('.pdf')) {
      const beforeExt = tempFixed;
      tempFixed += '.pdf';
      if (beforeExt !== tempFixed) {
        changes.push({
          original: beforeExt,
          fixed: tempFixed,
          reason: '添加PDF扩展名',
          type: 'addition'
        });
      }
    }

    fixed = tempFixed;
    return { fixed, changes };
  };

  useEffect(() => {
    if (visible && originalFilename) {
      validateAndSuggest();
    }
  }, [visible, originalFilename]);

  const validateAndSuggest = async () => {
    setLoading(true);
    setCurrentStep(0);

    try {
      // 本地分析和修复
      const { fixed, changes } = analyzeAndFixFilename(originalFilename);
      setSuggestedFilename(fixed);
      setFilenameChanges(changes);
      setCustomFilename(fixed);

      // 构建步骤信息
      const newSteps: FixStep[] = [
        {
          title: '文件名分析',
          description: '分析原始文件名中的问题',
          status: 'finish',
          content: (
            <div>
              <Text strong>原始文件名:</Text>
              <div style={{
                padding: '8px 12px',
                backgroundColor: '#fff1f0',
                borderRadius: '6px',
                marginTop: '8px',
                wordBreak: 'break-all'
              }}>
                <Text code>{originalFilename}</Text>
              </div>
            </div>
          )
        }
      ];

      if (changes.length > 0) {
        newSteps.push({
          title: '自动修复',
          description: `执行 ${changes.length} 项修复操作`,
          status: 'finish',
          content: (
            <Table
              size="small"
              dataSource={changes}
              pagination={false}
              columns={[
                {
                  title: '原字符',
                  dataIndex: 'original',
                  key: 'original',
                  render: (text: string) => (
                    <Tag color="red">{text}</Tag>
                  )
                },
                {
                  title: '修复为',
                  dataIndex: 'fixed',
                  key: 'fixed',
                  render: (text: string) => (
                    <Tag color="green">{text}</Tag>
                  )
                },
                {
                  title: '原因',
                  dataIndex: 'reason',
                  key: 'reason',
                  ellipsis: true
                }
              ]}
            />
          )
        });
      }

      newSteps.push({
        title: '完成检查',
        description: '验证修复结果',
        status: 'finish',
        content: (
          <div>
            <Space direction="vertical">
              <div>
                <Text strong>建议文件名:</Text>
                <div style={{
                  padding: '8px 12px',
                  backgroundColor: '#f6ffed',
                  borderRadius: '6px',
                  marginTop: '8px',
                  wordBreak: 'break-all'
                }}>
                  <Text code style={{ color: '#389e0d' }}>{fixed}</Text>
                </div>
              </div>
              <Button
                size="small"
                icon={<CopyOutlined />}
                onClick={() => {
                  navigator.clipboard.writeText(fixed);
                  setCopySuccess(true);
                  setTimeout(() => setCopySuccess(false), 2000);
                  message.success('文件名已复制到剪贴板');
                }}
              >
                {copySuccess ? '已复制' : '复制文件名'}
              </Button>
            </Space>
          </div>
        )
      });

      setSteps(newSteps);
      setCurrentStep(newSteps.length - 1);

    } catch (error) {
      console.error('文件名修复失败:', error);
      setSteps([
        {
          title: '修复失败',
          description: '文件名修复过程中发生错误',
          status: 'error',
          content: (
            <Alert
              type="error"
              message="文件名修复失败"
              description="请检查文件名格式或手动重命名"
            />
          )
        }
      ]);
    } finally {
      setLoading(false);
    }
  };

  const handleCustomFilenameChange = (value: string) => {
    setCustomFilename(value);
    const { fixed, changes } = analyzeAndFixFilename(value);
    setSuggestedFilename(fixed);
    setFilenameChanges(changes);
  };

  const handleConfirm = () => {
    onFilenameFixed(suggestedFilename);
    onCancel();
    message.success('文件名已更新');
  };

  const renderStepContent = () => {
    const currentStepData = steps[currentStep];
    if (!currentStepData) return null;

    return (
      <div style={{ padding: '20px 0' }}>
        {currentStepData.content}
      </div>
    );
  };

  return (
    <Modal
      title={
        <Space>
          <InfoCircleOutlined />
          <span>文件名优化助手</span>
        </Space>
      }
      open={visible}
      onCancel={onCancel}
      width={800}
      footer={[
        <Button key="cancel" onClick={onCancel}>
          取消
        </Button>,
        <Button
          key="retry"
          icon={<ReloadOutlined />}
          onClick={validateAndSuggest}
          loading={loading}
        >
          重新分析
        </Button>,
        <Button
          key="confirm"
          type="primary"
          onClick={handleConfirm}
          disabled={!suggestedFilename}
        >
          确认使用
        </Button>
      ]}
      destroyOnHidden
    >
      <Spin spinning={loading}>
        <Space direction="vertical" size="large" style={{ width: '100%' }}>
          <div>
            <Title level={4}>文件名智能修复</Title>
            <Paragraph type="secondary">
              系统将自动检测并修复文件名中的问题，确保文件名在所有操作系统上都能正常工作。
            </Paragraph>
          </div>

          <Card>
            <Steps current={currentStep} items={steps} />
            {renderStepContent()}
          </Card>

          {/* 手动编辑选项 */}
          <Card title="手动调整（可选）" size="small">
            <Space direction="vertical" style={{ width: '100%' }}>
              <div>
                <Text strong>自定义文件名:</Text>
                <div style={{ marginTop: 8 }}>
                  <input
                    type="text"
                    value={customFilename}
                    onChange={(e) => handleCustomFilenameChange(e.target.value)}
                    placeholder="输入自定义文件名"
                    style={{
                      width: '100%',
                      padding: '8px 12px',
                      border: '1px solid #d9d9d9',
                      borderRadius: '6px'
                    }}
                  />
                </div>
              </div>
              <Alert
                message="提示"
                description="您可以直接编辑文件名，系统会实时验证并提供修复建议。"
                type="info"
                showIcon
                style={{ fontSize: '12px' }}
              />
            </Space>
          </Card>

          {/* 预览结果 */}
          {suggestedFilename && (
            <Card title="修复结果预览" size="small">
              <Space direction="vertical" style={{ width: '100%' }}>
                <Row gutter={16}>
                  <Col span={4}>
                    <Text strong>修复前:</Text>
                  </Col>
                  <Col span={20}>
                    <Text code style={{ wordBreak: 'break-all', fontSize: '12px' }}>
                      {originalFilename}
                    </Text>
                  </Col>
                </Row>
                <Row gutter={16}>
                  <Col span={4}>
                    <Text strong>修复后:</Text>
                  </Col>
                  <Col span={20}>
                    <Text code style={{ wordBreak: 'break-all', fontSize: '12px', color: '#389e0d' }}>
                      {suggestedFilename}
                    </Text>
                  </Col>
                </Row>
              </Space>
            </Card>
          )}

          {/* 修复说明 */}
          <Alert
            message="关于文件名修复"
            description={
              <div style={{ fontSize: '12px' }}>
                <p>• <strong>中文特殊字符</strong>：【】（）等会被替换为标准字符 []()</p>
                <p>• <strong>危险字符</strong>：&lt;&gt;:"/\\|?* 等会被移除或替换</p>
                <p>• <strong>长度限制</strong>：超过200字符的文件名会被智能截断</p>
                <p>• <strong>扩展名</strong>：确保文件以.pdf结尾</p>
              </div>
            }
            type="info"
            showIcon
          />
        </Space>
      </Spin>
    </Modal>
  );
};

export default FilenameFixDialog;

import React, { useState, useEffect } from 'react';
import { Form, Input, Alert, Typography, Space, Button, Tooltip, Tag, Divider } from 'antd';
import { InfoCircleOutlined, CheckCircleOutlined, ExclamationCircleOutlined, EditOutlined } from '@ant-design/icons';
import { validateFilenameAPI } from '../../services/pdfImportService';

const { Text, Title } = Typography;

interface FilenameValidationResult {
  valid: boolean;
  issues: string[];
  suggestions: string[];
  severity: 'low' | 'medium' | 'high';
}

interface FilenameValidatorProps {
  filename: string;
  onValidationChange?: (isValid: boolean, sanitizedFilename?: string) => void;
  onFilenameChange?: (newFilename: string) => void;
  showSuggestions?: boolean;
  className?: string;
}

export const FilenameValidator: React.FC<FilenameValidatorProps> = ({
  filename,
  onValidationChange,
  onFilenameChange,
  showSuggestions = true,
  className = ''
}) => {
  const [validationResult, setValidationResult] = useState<FilenameValidationResult | null>(null);
  const [suggestedFilename, setSuggestedFilename] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);
  const [editing, setEditing] = useState<boolean>(false);
  const [customFilename, setCustomFilename] = useState<string>(filename);

  // 中文特殊字符映射
  const chineseSpecialCharsMap: { [key: string]: string } = {
    '【': '[',
    '】': ']',
    '（': '(',
    '）': ')',
    '《': '<',
    '》': '>',
    '"': '"',
    '"': '"',
    "'": "'",
    "'": "'",
    '：': ':',
    '，': ',',
    '。': '.',
    '；': ';',
    '！': '!',
    '？': '?',
    '…': '...'
  };

  // 本地文件名验证
  const validateLocalFilename = (fname: string): FilenameValidationResult => {
    const issues: string[] = [];
    const suggestions: string[] = [];
    let severity: 'low' | 'medium' | 'high' = 'low';

    // 长度检查
    if (fname.length > 200) {
      issues.push(`文件名过长 (${fname.length} > 200)`);
      suggestions.push('建议缩短文件名');
      severity = 'high';
    } else if (fname.length > 150) {
      issues.push(`文件名较长 (${fname.length} > 150)`);
      suggestions.push('考虑缩短文件名以提高兼容性');
      severity = 'medium';
    }

    // 中文特殊字符检查
    const hasChineseSpecial = Object.keys(chineseSpecialCharsMap).some(char => fname.includes(char));
    if (hasChineseSpecial) {
      issues.push('包含中文特殊字符');
      suggestions.push('建议将中文特殊字符替换为标准字符');
      if (severity === 'low') severity = 'medium';
    }

    // Unicode字符检查
    const hasUnicode = [...fname].some(char => char.charCodeAt(0) > 127);
    if (hasUnicode) {
      issues.push('包含Unicode字符');
      suggestions.push('确保系统支持Unicode字符');
    }

    // 扩展名检查
    if (!fname.toLowerCase().endsWith('.pdf')) {
      issues.push('缺少PDF扩展名');
      suggestions.push('确保文件扩展名为.pdf');
      severity = 'medium';
    }

    // 危险字符检查
    const dangerousChars = /[<>:"/\\|?*]/;
    if (dangerousChars.test(fname)) {
      issues.push('包含系统不兼容字符');
      suggestions.push('移除或替换特殊字符');
      severity = 'high';
    }

    return {
      valid: issues.length === 0,
      issues,
      suggestions,
      severity
    };
  };

  // 生成本地建议文件名
  const generateLocalSuggestedFilename = (fname: string): string => {
    let suggested = fname;

    // 替换中文特殊字符
    Object.entries(chineseSpecialCharsMap).forEach(([chinese, standard]) => {
      suggested = suggested.replace(new RegExp(chinese, 'g'), standard);
    });

    // 移除危险字符
    suggested = suggested.replace(/[<>:"/\\|?*]/g, '_');

    // 合并连续的下划线
    suggested = suggested.replace(/_{2,}/g, '_');

    // 移除开头和结尾的特殊字符
    suggested = suggested.trim('._-');

    // 确保有PDF扩展名
    if (!suggested.toLowerCase().endsWith('.pdf')) {
      suggested += '.pdf';
    }

    return suggested;
  };

  const validateFilename = async (fname: string) => {
    if (!fname) {
      setValidationResult(null);
      setSuggestedFilename('');
      return;
    }

    setLoading(true);

    try {
      // 首先进行本地验证（快速响应）
      const localResult = validateLocalFilename(fname);
      setValidationResult(localResult);

      // 生成本地建议文件名
      const localSuggested = generateLocalSuggestedFilename(fname);
      setSuggestedFilename(localSuggested);

      // 如果需要服务器验证（可选）
      if (showSuggestions && localResult.issues.length > 0) {
        try {
          // const response = await validateFilenameAPI(fname);
          // setSuggestedFilename(response.suggested_filename || localSuggested);
        } catch (error) {
          console.warn('服务器验证失败，使用本地验证结果:', error);
        }
      }

    } catch (error) {
      console.error('文件名验证失败:', error);
      setValidationResult({
        valid: false,
        issues: ['验证过程中发生错误'],
        suggestions: ['请稍后重试'],
        severity: 'high'
      });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    validateFilename(filename);
    setCustomFilename(filename);
  }, [filename]);

  useEffect(() => {
    if (validationResult && onValidationChange) {
      onValidationChange(
        validationResult.valid,
        validationResult.valid ? undefined : suggestedFilename
      );
    }
  }, [validationResult, suggestedFilename, onValidationChange]);

  const handleCustomFilenameChange = (value: string) => {
    setCustomFilename(value);
    validateFilename(value);
    if (onFilenameChange) {
      onFilenameChange(value);
    }
  };

  const acceptSuggestion = () => {
    setCustomFilename(suggestedFilename);
    if (onFilenameChange) {
      onFilenameChange(suggestedFilename);
    }
  };

  const getStatusIcon = () => {
    if (!validationResult) return <InfoCircleOutlined style={{ color: '#1890ff' }} />;
    if (validationResult.valid) return <CheckCircleOutlined style={{ color: '#52c41a' }} />;
    if (validationResult.severity === 'high') return <ExclamationCircleOutlined style={{ color: '#ff4d4f' }} />;
    return <ExclamationCircleOutlined style={{ color: '#faad14' }} />;
  };

  const getStatusColor = () => {
    if (!validationResult) return '#1890ff';
    if (validationResult.valid) return '#52c41a';
    if (validationResult.severity === 'high') return '#ff4d4f';
    return '#faad14';
  };

  const getStatusText = () => {
    if (!validationResult) return '正在验证...';
    if (validationResult.valid) return '文件名符合要求';
    if (validationResult.severity === 'high') return '文件名存在问题，建议修改';
    return '文件名可以优化';
  };

  return (
    <div className={`filename-validator ${className}`}>
      <Space direction="vertical" size="small" style={{ width: '100%' }}>
        {/* 状态显示 */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          {getStatusIcon()}
          <Text strong style={{ color: getStatusColor() }}>
            {getStatusText()}
          </Text>
          {validationResult && (
            <Tag color={validationResult.valid ? 'success' : validationResult.severity === 'high' ? 'error' : 'warning'}>
              {validationResult.severity === 'high' ? '严重' : validationResult.severity === 'medium' ? '警告' : '轻微'}
            </Tag>
          )}
        </div>

        {/* 文件名输入 */}
        <div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
            <Text strong>文件名:</Text>
            {!editing && (
              <Button
                type="text"
                size="small"
                icon={<EditOutlined />}
                onClick={() => setEditing(true)}
              >
                编辑
              </Button>
            )}
          </div>
          {editing ? (
            <Input
              value={customFilename}
              onChange={(e) => handleCustomFilenameChange(e.target.value)}
              onBlur={() => setEditing(false)}
              placeholder="输入文件名"
              status={validationResult && !validationResult.valid ? 'error' : undefined}
            />
          ) : (
            <div style={{
              padding: '8px 12px',
              backgroundColor: '#f5f5f5',
              borderRadius: '6px',
              border: `1px solid ${validationResult && !validationResult.valid ? '#ff4d4f' : '#d9d9d9'}`
            }}>
              <Text code style={{ wordBreak: 'break-all' }}>{customFilename}</Text>
            </div>
          )}
        </div>

        {/* 验证结果详情 */}
        {validationResult && (
          <>
            {validationResult.issues.length > 0 && (
              <Alert
                type={validationResult.severity === 'high' ? 'error' : 'warning'}
                showIcon
                message="发现以下问题:"
                description={
                  <ul style={{ margin: '8px 0 0 0', paddingLeft: '20px' }}>
                    {validationResult.issues.map((issue, index) => (
                      <li key={index}>{issue}</li>
                    ))}
                  </ul>
                }
                style={{ fontSize: '12px' }}
              />
            )}

            {/* 建议的文件名 */}
            {showSuggestions && suggestedFilename !== filename && (
              <div>
                <Divider style={{ margin: '12px 0 8px 0' }} />
                <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
                  <Text strong>建议的文件名:</Text>
                  <Button
                    type="primary"
                    size="small"
                    onClick={acceptSuggestion}
                  >
                    采用建议
                  </Button>
                </div>
                <div style={{
                  padding: '8px 12px',
                  backgroundColor: '#f6ffed',
                  borderRadius: '6px',
                  border: '1px solid #b7eb8f'
                }}>
                  <Text code style={{ wordBreak: 'break-all', color: '#389e0d' }}>
                    {suggestedFilename}
                  </Text>
                </div>
              </div>
            )}

            {/* 改进建议 */}
            {validationResult.suggestions.length > 0 && (
              <div>
                <Divider style={{ margin: '12px 0 8px 0' }} />
                <Text strong>改进建议:</Text>
                <ul style={{ margin: '8px 0 0 0', paddingLeft: '20px', fontSize: '12px' }}>
                  {validationResult.suggestions.map((suggestion, index) => (
                    <li key={index}>{suggestion}</li>
                  ))}
                </ul>
              </div>
            )}
          </>
        )}

        {/* 使用提示 */}
        <div style={{
          padding: '8px 12px',
          backgroundColor: '#e6f7ff',
          borderRadius: '6px',
          fontSize: '12px',
          lineHeight: '1.4'
        }}>
          <Text style={{ color: '#0050b3' }}>
            <InfoCircleOutlined style={{ marginRight: 4 }} />
            <strong>文件名最佳实践:</strong><br />
            • 避免使用中文特殊字符【】（）<br />
            • 文件名长度建议在150字符以内<br />
            • 确保以.pdf结尾<br />
            • 避免使用&lt;&gt;:"/\\|?*等特殊字符
          </Text>
        </div>
      </Space>
    </div>
  );
};

export default FilenameValidator;

import React from 'react'
import { Card, Statistic, Tooltip } from 'antd'
import { ArrowUpOutlined, ArrowDownOutlined, MinusOutlined } from '@ant-design/icons'
import styles from './DataTrendCard.module.css'

interface DataTrendCardProps {
  title: string
  value: number
  suffix?: string
  precision?: number
  trend?: {
    value: number
    period: string
    isPositive: boolean
  }
  icon?: React.ReactNode
  color?: 'primary' | 'success' | 'warning' | 'error' | 'default'
  loading?: boolean
  size?: 'small' | 'default' | 'large'
}

const DataTrendCard: React.FC<DataTrendCardProps> = ({
  title,
  value,
  suffix = '',
  precision = 0,
  trend,
  icon,
  color = 'default',
  loading = false,
  size = 'default'
}) => {
  const getTrendIcon = () => {
    if (!trend) return null

    if (trend.isPositive) {
      return <ArrowUpOutlined />
    } else if (trend.value < 0) {
      return <ArrowDownOutlined />
    }
    return <MinusOutlined />
  }

  const getTrendText = () => {
    if (!trend) return ''
    const absValue = Math.abs(trend.value)
    const sign = trend.isPositive ? '+' : trend.value < 0 ? '-' : ''
    return `${sign}${absValue.toFixed(1)}%`
  }

  const getTrendClass = () => {
    if (!trend) return styles.trendNeutral
    if (trend.isPositive) return styles.trendUp
    return trend.value < 0 ? styles.trendDown : styles.trendNeutral
  }

  const getCardClassName = () => {
    const baseClass = styles.trendCard
    return `${baseClass} ${styles[color]} ${styles[size]}`
  }

  return (
    <Card
      className={getCardClassName()}
      loading={loading}
      bordered={false}
    >
      <div className={styles.cardHeader}>
        <div className={styles.cardTitle}>{title}</div>
        {icon && <div className={styles.cardIcon}>{icon}</div>}
      </div>

      <div className={styles.cardContent}>
        <Statistic
          value={value}
          precision={precision}
          suffix={suffix}
          valueStyle={{
            fontSize: size === 'large' ? 28 : size === 'small' ? 20 : 24,
            fontWeight: 600,
            color: color === 'default' ? '#1a1a1a' : undefined
          }}
        />

        {trend && (
          <div className={getTrendClass()}>
            <span className={styles.trendIcon}>{getTrendIcon()}</span>
            <span className={styles.trendText}>{getTrendText()}</span>
            <span className={styles.trendPeriod}>{trend.period}</span>
          </div>
        )}
      </div>
    </Card>
  )
}

export default DataTrendCard

import React from 'react'
import { Card, Row, Col, Typography, Space } from 'antd'
import {
  HomeOutlined,
  PieChartOutlined,
  RiseOutlined,
  AlertOutlined,
  CheckCircleOutlined
} from '@ant-design/icons'
import styles from './QuickInsights.module.css'

const { Title, Text } = Typography

interface QuickInsightsProps {
  data?: {
    totalAssets: number
    totalArea: number
    occupancyRate: number
    totalRentedArea: number
    totalUnrentedArea: number
    recentActivity?: {
      newAssets: number
      updatedAssets: number
      maintenanceRequired: number
    }
  }
  loading?: boolean
}

const QuickInsights: React.FC<QuickInsightsProps> = ({ data, loading }) => {
  const insights = React.useMemo(() => {
    if (!data) return []

    const items = []

    // 出租率洞察
    if (data.occupancyRate > 95) {
      items.push({
        type: 'success',
        icon: <RiseOutlined />,
        title: '出租率表现优异',
        description: `当前出租率达到 ${data.occupancyRate.toFixed(1)}%，超过了95%的优秀水平`,
        highlight: `${data.occupancyRate.toFixed(1)}%`
      })
    } else if (data.occupancyRate < 85) {
      items.push({
        type: 'warning',
        icon: <AlertOutlined />,
        title: '出租率有待提升',
        description: `当前出租率为 ${data.occupancyRate.toFixed(1)}%，建议关注空置资产的管理`,
        highlight: `${data.totalUnrentedArea.toFixed(0)}㎡ 空置面积`
      })
    } else {
      items.push({
        type: 'info',
        icon: <PieChartOutlined />,
        title: '出租率正常',
        description: `当前出租率为 ${data.occupancyRate.toFixed(1)}%，处于合理区间`,
        highlight: '运营状态良好'
      })
    }

    // 资产规模洞察
    if (data.totalAssets > 500) {
      items.push({
        type: 'info',
        icon: <HomeOutlined />,
        title: '资产规模可观',
        description: `管理着 ${data.totalAssets} 个资产，总面积达 ${data.totalArea.toFixed(0)}㎡`,
        highlight: `管理 ${data.totalAssets} 个资产`
      })
    }

    // 空置资产洞察
    if (data.totalUnrentedArea > 10000) {
      items.push({
        type: 'warning',
        icon: <AlertOutlined />,
        title: '空置面积较大',
        description: `空置面积达 ${data.totalUnrentedArea.toFixed(0)}㎡，建议制定营销策略`,
        highlight: `${data.totalUnrentedArea.toFixed(0)}㎡ 空置`
      })
    }

    // 默认洞察
    if (items.length === 0) {
      items.push({
        type: 'info',
        icon: <CheckCircleOutlined />,
        title: '系统运行正常',
        description: '资产管理系统运行良好，数据更新及时',
        highlight: '系统状态良好'
      })
    }

    return items
  }, [data])

  const getTypeClass = (type: string) => {
    switch (type) {
      case 'success':
        return styles.success
      case 'warning':
        return styles.warning
      case 'error':
        return styles.error
      default:
        return styles.info
    }
  }

  return (
    <Card
      className={styles.insightsContainer}
      title={
        <div className={styles.titleContainer}>
          <Title level={4} className={styles.title}>
            智能洞察
          </Title>
          <Text type="secondary">
            基于当前数据的智能分析
          </Text>
        </div>
      }
      bordered={false}
      loading={loading}
    >
      <Row gutter={[16, 16]}>
        {insights.map((insight, index) => (
          <Col xs={24} sm={12} lg={8} key={index}>
            <Card
              className={`${styles.insightCard} ${getTypeClass(insight.type)}`}
              bordered={false}
              size="small"
            >
              <div className={styles.insightHeader}>
                <div className={styles.insightIcon}>{insight.icon}</div>
                <div className={styles.insightTitle}>{insight.title}</div>
              </div>
              <div className={styles.insightContent}>
                <p className={styles.insightDescription}>{insight.description}</p>
                <div className={styles.insightHighlight}>{insight.highlight}</div>
              </div>
            </Card>
          </Col>
        ))}
      </Row>
    </Card>
  )
}

