import React, { Component, ErrorInfo, ReactNode } from 'react'
import { Result, Button, Typography, Card, Space, Alert } from 'antd'
import {
  ExclamationCircleOutlined,
  ReloadOutlined,
  HomeOutlined,
  BugOutlined,
} from '@ant-design/icons'

const { Paragraph, Text } = Typography

interface Props {
  children: ReactNode
  fallback?: ReactNode
  onError?: (error: Error, errorInfo: ErrorInfo) => void
}

interface State {
  hasError: boolean
  error?: Error
  errorInfo?: ErrorInfo
  errorId?: string
}

class GlobalErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false,
  }

  public static getDerivedStateFromError(error: Error): State {
    // 生成错误ID用于追踪
    const errorId = `ERR_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
    
    return {
      hasError: true,
      error,
      errorId,
    }
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('GlobalErrorBoundary caught an error:', error, errorInfo)
    
    this.setState({
      errorInfo,
    })

    // 调用外部错误处理函数
    if (this.props.onError) {
      this.props.onError(error, errorInfo)
    }

    // 发送错误报告到监控服务
    this.reportError(error, errorInfo)
  }

  private reportError = (error: Error, errorInfo: ErrorInfo) => {
    // 这里可以集成错误监控服务，如 Sentry
    const errorReport = {
      message: error.message,
      stack: error.stack,
      componentStack: errorInfo.componentStack,
      timestamp: new Date().toISOString(),
      userAgent: navigator.userAgent,
      url: window.location.href,
      errorId: this.state.errorId,
    }

    // 发送到错误监控服务
    // Log error report for debugging
    
    // 示例：发送到后端API
    // fetch('/api/errors', {
    //   method: 'POST',
    //   headers: { 'Content-Type': 'application/json' },
    //   body: JSON.stringify(errorReport),
    // }).catch(console.error)
  }

  private handleReload = () => {
    window.location.reload()
  }

  private handleGoHome = () => {
    window.location.href = '/'
  }

  private handleReset = () => {
    this.setState({
      hasError: false,
      error: undefined,
      errorInfo: undefined,
      errorId: undefined,
    })
  }

  private handleReportBug = () => {
    const subject = encodeURIComponent(`Bug Report - ${this.state.errorId}`)
    const body = encodeURIComponent(`
错误ID: ${this.state.errorId}
错误信息: ${this.state.error?.message}
发生时间: ${new Date().toLocaleString()}
页面地址: ${window.location.href}
浏览器: ${navigator.userAgent}

请描述您在遇到此错误前的操作步骤：
1. 
2. 
3. 

其他信息：

    `)
    
    window.open(`mailto:support@example.com?subject=${subject}&body=${body}`)
  }

  public render() {
    if (this.state.hasError) {
      // 如果提供了自定义fallback，使用它
      if (this.props.fallback) {
        return this.props.fallback
      }

      const isDevelopment = process.env.NODE_ENV === 'development'

      return (
        <div style={{ 
          padding: '50px 20px', 
          minHeight: '100vh', 
          background: '#f5f5f5',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center'
        }}>
          <Card style={{ maxWidth: 600, width: '100%' }}>
            <Result
              status="error"
              icon={<ExclamationCircleOutlined style={{ color: '#ff4d4f' }} />}
              title="页面出现错误"
              subTitle={
                <div>
                  <Paragraph>
                    抱歉，页面遇到了一些问题。我们已经记录了这个错误，技术团队会尽快修复。
                  </Paragraph>
                  {this.state.errorId && (
                    <Alert
                      message={
                        <Space>
                          <Text type="secondary">错误ID:</Text>
                          <Text code copyable>{this.state.errorId}</Text>
                        </Space>
                      }
                      type="info"
                      showIcon={false}
                      style={{ marginBottom: 16 }}
                    />
                  )}
                </div>
              }
              extra={[
                <Button 
                  type="primary" 
                  key="reload" 
                  icon={<ReloadOutlined />}
                  onClick={this.handleReload}
                >
                  刷新页面
                </Button>,
                <Button 
                  key="home" 
                  icon={<HomeOutlined />}
                  onClick={this.handleGoHome}
                >
                  返回首页
                </Button>,
                <Button 
                  key="reset" 
                  onClick={this.handleReset}
                >
                  重试
                </Button>,
                <Button 
                  key="report" 
                  icon={<BugOutlined />}
                  onClick={this.handleReportBug}
                >
                  报告问题
                </Button>,
              ]}
            />

            {/* 开发环境下显示详细错误信息 */}
            {isDevelopment && this.state.error && (
              <Card 
                title="开发调试信息" 
                size="small" 
                style={{ marginTop: 16 }}
                type="inner"
              >
                <div style={{ marginBottom: 16 }}>
                  <Text strong>错误信息:</Text>
                  <Paragraph 
                    code 
                    style={{ 
                      background: '#fff2f0', 
                      padding: 8, 
                      marginTop: 8,
                      whiteSpace: 'pre-wrap',
                      fontSize: '12px'
                    }}
                  >
                    {this.state.error.message}
                  </Paragraph>
                </div>

                {this.state.error.stack && (
                  <div style={{ marginBottom: 16 }}>
                    <Text strong>错误堆栈:</Text>
                    <Paragraph 
                      code 
                      style={{ 
                        background: '#f6f6f6', 
                        padding: 8, 
                        marginTop: 8,
                        whiteSpace: 'pre-wrap',
                        fontSize: '11px',
                        maxHeight: 200,
                        overflow: 'auto'
                      }}
                    >
                      {this.state.error.stack}
                    </Paragraph>
                  </div>
                )}

                {this.state.errorInfo?.componentStack && (
                  <div>
                    <Text strong>组件堆栈:</Text>
                    <Paragraph 
                      code 
                      style={{ 
                        background: '#f6f6f6', 
                        padding: 8, 
                        marginTop: 8,
                        whiteSpace: 'pre-wrap',
                        fontSize: '11px',
                        maxHeight: 200,
                        overflow: 'auto'
                      }}
                    >
                      {this.state.errorInfo.componentStack}
                    </Paragraph>
                  </div>
                )}
              </Card>
            )}
          </Card>
        </div>
      )
    }

    return this.props.children
  }
}

export default GlobalErrorBoundary

import React from 'react'
import { Modal, Typography, Space, Button } from 'antd'
import {
  ExclamationCircleOutlined,
  DeleteOutlined,
  EditOutlined,
  SaveOutlined,
  LogoutOutlined,
  StopOutlined,
  QuestionCircleOutlined,
  InfoCircleOutlined,
} from '@ant-design/icons'

const { Text, Paragraph } = Typography

export type ConfirmType = 'delete' | 'edit' | 'save' | 'logout' | 'cancel' | 'warning' | 'info'

interface ConfirmDialogProps {
  type?: ConfirmType
  title?: string
  content?: React.ReactNode
  visible?: boolean
  onConfirm?: () => void
  onCancel?: () => void
  confirmText?: string
  cancelText?: string
  confirmLoading?: boolean
  danger?: boolean
  width?: number
  centered?: boolean
  maskClosable?: boolean
  itemName?: string
  itemCount?: number
  details?: string[]
}

const ConfirmDialog: React.FC<ConfirmDialogProps> = ({
  type = 'warning',
  title,
  content,
  visible = false,
  onConfirm,
  onCancel,
  confirmText,
  cancelText = '取消',
  confirmLoading = false,
  danger,
  width = 416,
  centered = true,
  maskClosable = false,
  itemName,
  itemCount,
  details,
}) => {
  // 预设配置
  const presetConfigs = {
    delete: {
      icon: <DeleteOutlined style={{ color: '#ff4d4f', fontSize: 24 }} />,
      title: '确认删除',
      confirmText: '删除',
      danger: true,
      getContent: () => (
        <div>
          <Paragraph>
            {itemCount && itemCount > 1 
              ? `确定要删除这 ${itemCount} 个${itemName || '项目'}吗？`
              : `确定要删除${itemName ? `"${itemName}"` : '此项目'}吗？`
            }
          </Paragraph>
          {details && details.length > 0 && (
            <div style={{ marginTop: 16 }}>
              <Text type="secondary">将要删除的内容：</Text>
              <ul style={{ marginTop: 8, paddingLeft: 20 }}>
                {details.map((detail, index) => (
                  <li key={index}>
                    <Text type="secondary">{detail}</Text>
                  </li>
                ))}
              </ul>
            </div>
          )}
          <Paragraph type="danger" style={{ marginTop: 16, marginBottom: 0 }}>
            <Text strong>此操作不可撤销，请谨慎操作！</Text>
          </Paragraph>
        </div>
      ),
    },
    edit: {
      icon: <EditOutlined style={{ color: '#1890ff', fontSize: 24 }} />,
      title: '确认编辑',
      confirmText: '继续编辑',
      danger: false,
      getContent: () => (
        <div>
          <Paragraph>
            您有未保存的更改，确定要继续编辑吗？
          </Paragraph>
          <Paragraph type="warning">
            <Text>继续编辑将丢失当前的更改。</Text>
          </Paragraph>
        </div>
      ),
    },
    save: {
      icon: <SaveOutlined style={{ color: '#52c41a', fontSize: 24 }} />,
      title: '确认保存',
      confirmText: '保存',
      danger: false,
      getContent: () => (
        <div>
          <Paragraph>
            确定要保存当前的更改吗？
          </Paragraph>
          {details && details.length > 0 && (
            <div style={{ marginTop: 16 }}>
              <Text type="secondary">将要保存的更改：</Text>
              <ul style={{ marginTop: 8, paddingLeft: 20 }}>
                {details.map((detail, index) => (
                  <li key={index}>
                    <Text type="secondary">{detail}</Text>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      ),
    },
    logout: {
      icon: <LogoutOutlined style={{ color: '#faad14', fontSize: 24 }} />,
      title: '确认退出',
      confirmText: '退出',
      danger: false,
      getContent: () => (
        <div>
          <Paragraph>
            确定要退出登录吗？
          </Paragraph>
          <Paragraph type="secondary">
            退出后需要重新登录才能使用系统功能。
          </Paragraph>
        </div>
      ),
    },
    cancel: {
      icon: <StopOutlined style={{ color: '#faad14', fontSize: 24 }} />,
      title: '确认取消',
      confirmText: '确认取消',
      danger: false,
      getContent: () => (
        <div>
          <Paragraph>
            确定要取消当前操作吗？
          </Paragraph>
          <Paragraph type="warning">
            取消后将丢失所有未保存的更改。
          </Paragraph>
        </div>
      ),
    },
    warning: {
      icon: <ExclamationCircleOutlined style={{ color: '#faad14', fontSize: 24 }} />,
      title: '警告',
      confirmText: '确定',
      danger: false,
      getContent: () => (
        <Paragraph>
          请确认您要执行此操作。
        </Paragraph>
      ),
    },
    info: {
      icon: <InfoCircleOutlined style={{ color: '#1890ff', fontSize: 24 }} />,
      title: '提示',
      confirmText: '确定',
      danger: false,
      getContent: () => (
        <Paragraph>
          请确认相关信息。
        </Paragraph>
      ),
    },
  }

  const config = presetConfigs[type]

  return (
    <Modal
      title={
        <Space>
          {config.icon}
          <span>{title || config.title}</span>
        </Space>
      }
      open={visible}
      onOk={onConfirm}
      onCancel={onCancel}
      okText={confirmText || config.confirmText}
      cancelText={cancelText}
      confirmLoading={confirmLoading}
      width={width}
      centered={centered}
      maskClosable={maskClosable}
      okButtonProps={{
        danger: danger !== undefined ? danger : config.danger,
      }}
      destroyOnHidden
    >
      {content || config.getContent()}
    </Modal>
  )
}

