import { notification } from 'antd'
import { 
  CheckCircleOutlined, 
  ExclamationCircleOutlined, 
  InfoCircleOutlined, 
  CloseCircleOutlined,
  WifiOutlined,
  LockOutlined,
  CheckCircleOutlined as ServerOutlined
} from '@ant-design/icons'

interface NotificationOptions {
  type: 'success' | 'error' | 'warning' | 'info'
  title: string
  description?: string
  duration?: number
}

class SuccessNotification {
  static notify(options: NotificationOptions) {
    const { type, title, description, duration = 4.5 } = options
    
    const iconMap = {
      success: <CheckCircleOutlined style={{ color: '#52c41a' }} />,
      error: <CloseCircleOutlined style={{ color: '#ff4d4f' }} />,
      warning: <ExclamationCircleOutlined style={{ color: '#faad14' }} />,
      info: <InfoCircleOutlined style={{ color: '#1890ff' }} />,
    }

    notification[type]({
      message: title,
      description,
      duration,
      icon: iconMap[type],
      placement: 'topRight',
    })
  }

  static success = {
    save: () => SuccessNotification.notify({
      type: 'success',
      title: '保存成功',
      description: '数据已成功保存到系统中',
    }),
    
    create: () => SuccessNotification.notify({
      type: 'success',
      title: '创建成功',
      description: '新记录已成功创建',
    }),
    
    update: () => SuccessNotification.notify({
      type: 'success',
      title: '更新成功',
      description: '记录已成功更新',
    }),
    
    delete: () => SuccessNotification.notify({
      type: 'success',
      title: '删除成功',
      description: '记录已成功删除',
    }),
    
    import: (count: number) => SuccessNotification.notify({
      type: 'success',
      title: '导入成功',
      description: `成功导入 ${count} 条记录`,
    }),
    
    export: () => SuccessNotification.notify({
      type: 'success',
      title: '导出成功',
      description: '数据已成功导出到文件',
    }),
  }

  static error = {
    network: () => notification.error({
      message: '网络错误',
      description: '网络连接失败，请检查网络设置后重试',
      duration: 0,
      icon: <WifiOutlined style={{ color: '#ff4d4f' }} />,
    }),
    
    server: () => SuccessNotification.notify({
      type: 'error',
      title: '服务器错误',
      description: '服务器暂时无法响应，请稍后重试',
      duration: 0,
    }),
    
    validation: (message: string) => SuccessNotification.notify({
      type: 'error',
      title: '数据验证失败',
      description: message,
    }),
    
    permission: () => notification.error({
      message: '权限不足',
      description: '您没有执行此操作的权限，请联系管理员',
      icon: <LockOutlined style={{ color: '#ff4d4f' }} />,
    }),
    
    notFound: () => SuccessNotification.notify({
      type: 'error',
      title: '资源不存在',
      description: '请求的资源不存在或已被删除',
    }),
  }

  static warning = {
    unsaved: () => SuccessNotification.notify({
      type: 'warning',
      title: '有未保存的更改',
      description: '您有未保存的更改，离开页面将丢失这些更改',
      duration: 0,
    }),
    
    permission: () => notification.warning({
      message: '权限受限',
      description: '您的权限受限，某些功能可能无法使用',
      icon: <LockOutlined style={{ color: '#faad14' }} />,
    }),
    
    maintenance: () => SuccessNotification.notify({
      type: 'warning',
      title: '系统维护',
      description: '系统正在维护中，部分功能可能受到影响',
      duration: 0,
    }),
  }

  static info = {
    loading: (message: string = '正在处理...') => SuccessNotification.notify({
      type: 'info',
      title: '处理中',
      description: message,
      duration: 2,
    }),
    
    autoSave: () => SuccessNotification.notify({
      type: 'info',
      title: '自动保存',
      description: '数据已自动保存',
      duration: 2,
    }),
    
    offline: () => SuccessNotification.notify({
      type: 'info',
      title: '离线模式',
      description: '当前处于离线模式，数据将在网络恢复后同步',
      duration: 0,
    }),
  }
}

export default SuccessNotification

import React from 'react'
import { Breadcrumb } from 'antd'
import {
  HomeOutlined,
  DashboardOutlined,
  UnorderedListOutlined,
  PlusOutlined,
  SearchOutlined,
  FileExcelOutlined,
  UploadOutlined,
  DownloadOutlined,
  BarChartOutlined,
  LineChartOutlined,
  PieChartOutlined,
  SettingOutlined,
  EditOutlined,
  EyeOutlined,
} from '@ant-design/icons'
import { useLocation, Link } from 'react-router-dom'

const AppBreadcrumb: React.FC = () => {
  const location = useLocation()
  const pathname = location.pathname

  // 面包屑配置映射
  const breadcrumbNameMap: Record<string, { name: string; icon?: React.ReactNode }> = {
    '/': { name: '首页', icon: <HomeOutlined /> },
    '/dashboard': { name: '数据看板', icon: <DashboardOutlined /> },
    '/assets': { name: '资产列表', icon: <UnorderedListOutlined /> },
    '/assets/new': { name: '新增资产', icon: <PlusOutlined /> },
    '/assets/search': { name: '高级搜索', icon: <SearchOutlined /> },
    '/data/import': { name: '数据导入', icon: <UploadOutlined /> },
    '/data/export': { name: '数据导出', icon: <DownloadOutlined /> },
    '/data/import-export': { name: '导入导出', icon: <FileExcelOutlined /> },
    '/analytics/occupancy': { name: '出租率分析', icon: <LineChartOutlined /> },
    '/analytics/distribution': { name: '资产分布', icon: <PieChartOutlined /> },
    '/analytics/area': { name: '面积统计', icon: <BarChartOutlined /> },
    '/system/users': { name: '用户管理', icon: <SettingOutlined /> },
    '/system/roles': { name: '角色管理', icon: <SettingOutlined /> },
    '/system/logs': { name: '操作日志', icon: <SettingOutlined /> },
    '/system/dictionaries': { name: '枚举值字段', icon: <SettingOutlined /> },
    '/ownership': { name: '权属方管理', icon: <SettingOutlined /> },
  }

  // 生成面包屑项
  const generateBreadcrumbItems = () => {
    const pathSnippets = pathname.split('/').filter(i => i)
    
    // 首页面包屑
    const breadcrumbItems = [
      {
        title: (
          <Link to="/dashboard">
            <HomeOutlined style={{ marginRight: 4 }} />
            首页
          </Link>
        ),
      },
    ]

    // 处理特殊路径
    if (pathname === '/dashboard' || pathname === '/') {
      return [
        {
          title: (
            <span>
              <DashboardOutlined style={{ marginRight: 4 }} />
              数据看板
            </span>
          ),
        },
      ]
    }

    // 处理资产详情页面
    const assetDetailMatch = pathname.match(/^\/assets\/(\d+)$/)
    if (assetDetailMatch) {
      const assetId = assetDetailMatch[1]
      return [
        ...breadcrumbItems,
        {
          title: (
            <Link to="/assets">
              <UnorderedListOutlined style={{ marginRight: 4 }} />
              资产管理
            </Link>
          ),
        },
        {
          title: (
            <Link to="/assets">
              <UnorderedListOutlined style={{ marginRight: 4 }} />
              资产列表
            </Link>
          ),
        },
        {
          title: (
            <span>
              <EyeOutlined style={{ marginRight: 4 }} />
              资产详情
            </span>
          ),
        },
      ]
    }

    // 处理资产编辑页面
    const assetEditMatch = pathname.match(/^\/assets\/(\d+)\/edit$/)
    if (assetEditMatch) {
      const assetId = assetEditMatch[1]
      return [
        ...breadcrumbItems,
        {
          title: (
            <Link to="/assets">
              <UnorderedListOutlined style={{ marginRight: 4 }} />
              资产管理
            </Link>
          ),
        },
        {
          title: (
            <Link to="/assets">
              <UnorderedListOutlined style={{ marginRight: 4 }} />
              资产列表
            </Link>
          ),
        },
        {
          title: (
            <Link to={`/assets/${assetId}`}>
              <EyeOutlined style={{ marginRight: 4 }} />
              资产详情
            </Link>
          ),
        },
        {
          title: (
            <span>
              <EditOutlined style={{ marginRight: 4 }} />
              编辑资产
            </span>
          ),
        },
      ]
    }

    // 构建普通路径的面包屑
    let currentPath = ''
    
    pathSnippets.forEach((snippet, index) => {
      currentPath += `/${snippet}`
      const isLast = index === pathSnippets.length - 1
      const breadcrumbConfig = breadcrumbNameMap[currentPath]
      
      if (breadcrumbConfig) {
        if (isLast) {
          // 最后一项不添加链接
          breadcrumbItems.push({
            title: (
              <span>
                {breadcrumbConfig.icon && (
                  <span style={{ marginRight: 4 }}>{breadcrumbConfig.icon}</span>
                )}
                {breadcrumbConfig.name}
              </span>
            ),
          })
        } else {
          // 中间项添加链接
          breadcrumbItems.push({
            title: (
              <Link to={currentPath}>
                {breadcrumbConfig.icon && (
                  <span style={{ marginRight: 4 }}>{breadcrumbConfig.icon}</span>
                )}
                {breadcrumbConfig.name}
              </Link>
            ),
          })
        }
      }
    })

    // 添加分类面包屑
    if (pathname.startsWith('/assets') && !breadcrumbItems.some(item => 
      typeof item.title === 'object' && 
      React.isValidElement(item.title) && 
      item.title.props.children?.includes?.('资产管理')
    )) {
      breadcrumbItems.splice(1, 0, {
        title: (
          <span>
            <UnorderedListOutlined style={{ marginRight: 4 }} />
            资产管理
          </span>
        ),
      })
    }

    if (pathname.startsWith('/data') && !breadcrumbItems.some(item => 
      typeof item.title === 'object' && 
      React.isValidElement(item.title) && 
      item.title.props.children?.includes?.('数据管理')
    )) {
      breadcrumbItems.splice(1, 0, {
        title: (
          <span>
            <FileExcelOutlined style={{ marginRight: 4 }} />
            数据管理
          </span>
        ),
      })
    }

    if (pathname.startsWith('/analytics') && !breadcrumbItems.some(item => 
      typeof item.title === 'object' && 
      React.isValidElement(item.title) && 
      item.title.props.children?.includes?.('数据分析')
    )) {
      breadcrumbItems.splice(1, 0, {
        title: (
          <span>
            <BarChartOutlined style={{ marginRight: 4 }} />
            数据分析
          </span>
        ),
      })
    }

    if (pathname.startsWith('/system') && !breadcrumbItems.some(item =>
      typeof item.title === 'object' &&
      React.isValidElement(item.title) &&
      item.title.props.children?.includes?.('系统管理')
    )) {
      breadcrumbItems.splice(1, 0, {
        title: (
          <span>
            <SettingOutlined style={{ marginRight: 4 }} />
            系统管理
          </span>
        ),
      })
    }

    if (pathname.startsWith('/ownership') && !breadcrumbItems.some(item =>
      typeof item.title === 'object' &&
      React.isValidElement(item.title) &&
      item.title.props.children?.includes?.('资产管理')
    )) {
      breadcrumbItems.splice(1, 0, {
        title: (
          <span>
            <UnorderedListOutlined style={{ marginRight: 4 }} />
            资产管理
          </span>
        ),
      })
    }

    return breadcrumbItems
  }

  return (
    <Breadcrumb
      items={generateBreadcrumbItems()}
      style={{
        fontSize: '14px',
      }}
    />
  )
}

