  const getOpenKeys = () => {
    const pathname = location.pathname

    if (pathname.startsWith('/assets') && !pathname.startsWith('/assets/list')) return ['assets']
    if (pathname.startsWith('/rental')) return ['rental']
    if (pathname.startsWith('/system')) return ['system']

    return []
