            type="primary"
            icon={<EditOutlined />}
            onClick={onEdit}
          >
            编辑
          </Button>
        </Space>
      </Card>

      {/* 基本信息 */}
      <Card title="基本信息" style={{ marginTop: 16 }}>
        <Descriptions column={2} bordered>
          <Descriptions.Item label="权属方全称">
            {ownership.name}
          </Descriptions.Item>
          <Descriptions.Item label="权属方简称">
            {ownership.short_name || '-'}
          </Descriptions.Item>
          <Descriptions.Item label="状态">
            <Badge
              status={ownership.is_active ? 'success' : 'error'}
              text={ownership.is_active ? '启用' : '禁用'}
            />
          </Descriptions.Item>
          <Descriptions.Item label="关联资产数量">
            <Tag color="blue">
              {ownership.asset_count || 0} 个
            </Tag>
          </Descriptions.Item>
          <Descriptions.Item label="关联项目数量">
            <Tag color="green">
              {ownership.project_count || 0} 个
            </Tag>
          </Descriptions.Item>
        </Descriptions>
      </Card>

      {/* 关联项目信息 */}
      {ownership.related_projects && ownership.related_projects.length > 0 && (
        <Card title="关联项目" style={{ marginTop: 16 }}>
          <Table
            columns={projectColumns}
            dataSource={ownership.related_projects}
            rowKey="id"
            pagination={false}
            size="small"
          />
        </Card>
      )}

      {/* 系统信息 */}
      <Card title="系统信息" style={{ marginTop: 16 }}>
        <Descriptions column={2} bordered>
          <Descriptions.Item label="创建时间">
            {formatDate(ownership.created_at)}
          </Descriptions.Item>
          <Descriptions.Item label="更新时间">
            {formatDate(ownership.updated_at)}
          </Descriptions.Item>
        </Descriptions>
      </Card>
    </div>
  );
};

export default OwnershipDetail;

/**
 * 权属方表单组件
 */

import React, { useState, useEffect } from 'react';
import {
  Form,
  Input,
  Button,
  Space,
  Card,
  Row,
  Col,
  message,
  Divider,
  Switch,
  Select,
  InputNumber
} from 'antd';

const { Option } = Select;

import { ownershipService } from '@/services/ownershipService';
import { projectService } from '@/services/projectService';
import type { Ownership, OwnershipCreate, OwnershipUpdate } from '@/types/ownership';
import type { ProjectDropdownOption } from '@/types/project';

interface OwnershipFormProps {
  initialValues?: Ownership | null;
  onSuccess: () => void;
  onCancel: () => void;
}

const OwnershipForm: React.FC<OwnershipFormProps> = ({
  initialValues,
  onSuccess,
  onCancel
}) => {
  const [form] = Form.useForm();
  const [loading, setLoading] = useState(false);
  const [projectOptions, setProjectOptions] = useState<ProjectDropdownOption[]>([]);

  // 加载项目选项
  const loadProjectOptions = async () => {
    try {
      // Loading project options
      const response = await projectService.getProjectOptions(true);
      // Got project options response

      // 确保响应数据是数组
      const projects = Array.isArray(response) ? response : (response?.data || []);
      // Processed project options

      setProjectOptions(projects);
    } catch (error) {
      console.error('加载项目选项失败:', error);
      message.error('加载项目选项失败');
      setProjectOptions([]); // 设置为空数组避免 undefined 错误
    }
  };

  // 设置初始值
  useEffect(() => {
    if (initialValues) {
      form.setFieldsValue(initialValues);
    } else {
      form.resetFields();
    }
    loadProjectOptions();
  }, [initialValues, form]);

  
  // 表单验证规则接口
  interface FormValidationRule {
    field?: string
    fullField?: string
    type?: string
    validator?: (rule: FormValidationRule, value: unknown) => Promise<void>
  }

  // 验证名称唯一性
  const validateName = async (_: FormValidationRule, value: string) => {
    if (!value) return Promise.resolve();

    const isUnique = await ownershipService.validateOwnershipName(
      value,
      initialValues?.id
    );
    if (!isUnique) {
      return Promise.reject('该名称已存在');
    }

    return Promise.resolve();
  };

  
  // 提交表单
  const handleSubmit = async () => {
    try {
      const values = await form.validateFields();
      setLoading(true);

      if (initialValues) {
        // 更新权属方
        const updateData: OwnershipUpdate = {
          name: values.name,
          code: values.code,
          short_name: values.short_name,
          is_active: values.is_active
        };

        // Submit update data
        // console.log('提交的更新数据:', updateData);
        // console.log('关联项目数据:', values.related_projects);

        // 先更新基本信息
        await ownershipService.updateOwnership(initialValues.id, updateData);

        // 如果有关联项目数据，则更新关联项目
        if (values.related_projects && Array.isArray(values.related_projects)) {
          try {
            await ownershipService.updateOwnershipProjects(initialValues.id, values.related_projects);
            console.log('关联项目更新成功');
          } catch (projectError) {
            console.error('更新关联项目失败:', projectError);
            message.warning('基本信息更新成功，但关联项目更新失败');
          }
        }

        message.success('更新成功');
      } else {
        // 创建权属方 - 编码将由后端自动生成
        const createData: OwnershipCreate = {
          name: values.name,
          short_name: values.short_name
        };

        await ownershipService.createOwnership(createData);
        message.success('创建成功');
      }

      onSuccess();
    } catch (error: unknown) {
      message.error(error.message || '操作失败');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Form
      form={form}
      layout="vertical"
      onFinish={handleSubmit}
      initialValues={{
        is_active: true
      }}
    >
      <Card title="基本信息" size="small">
        <Row gutter={16}>
          <Col span={12}>
            <Form.Item
              label="权属方全称"
              name="name"
              rules={[
                { required: true, message: '请输入权属方全称' },
                { validator: validateName }
              ]}
            >
              <Input placeholder="请输入权属方全称" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              label="权属方简称"
              name="short_name"
            >
              <Input placeholder="请输入权属方简称（可选）" />
            </Form.Item>
          </Col>
        </Row>

        <Row gutter={16}>
          <Col span={24}>
            <Form.Item
              label="关联项目"
              name="related_projects"
              help="选择与该权属方关联的项目"
            >
              <Select
                mode="multiple"
                placeholder="请选择关联项目"
                style={{ width: '100%' }}
                showSearch
                filterOption={(input, option) => {
                  if (!option?.children) return false;
                  const optionText = String(option.children).toLowerCase();
                  return optionText.includes(input.toLowerCase());
                }}
              >
                {(projectOptions || []).map(project => (
                  <Option key={project.id} value={project.id}>
                    {project.name} ({project.code})
                  </Option>
                ))}
              </Select>
            </Form.Item>
          </Col>
        </Row>


        {initialValues && (
          <Form.Item
            label="状态"
            name="is_active"
            valuePropName="checked"
          >
            <Switch
              checkedChildren="启用"
              unCheckedChildren="禁用"
            />
          </Form.Item>
        )}
      </Card>

      <Divider />

      <Row>
        <Col span={24} style={{ textAlign: 'right' }}>
          <Space>
            <Button onClick={onCancel}>
              取消
            </Button>
            <Button
              type="primary"
              htmlType="submit"
              loading={loading}
            >
              {initialValues ? '更新' : '创建'}
            </Button>
          </Space>
        </Col>
      </Row>
    </Form>
  );
};

export default OwnershipForm;

/**
 * 权属方列表组件
 */

import React, { useState, useEffect } from 'react';
import {
  Table,
  Button,
  Space,
  Tag,
  Tooltip,
  Modal,
  message,
  Card,
  Row,
  Col,
  Statistic,
  Badge,
  Input,
  Select,
  Switch,
  Pagination
} from 'antd';
import {
  PlusOutlined,
  EditOutlined,
  DeleteOutlined,
  EyeOutlined,
  SearchOutlined,
  ReloadOutlined,
  ExclamationCircleOutlined
} from '@ant-design/icons';
import type { ColumnsType } from 'antd/es/table';

import { ownershipService } from '@/services/ownershipService';
import type { Ownership, OwnershipListResponse, OwnershipStatisticsResponse } from '@/types/ownership';
import OwnershipForm from './OwnershipForm';
import OwnershipDetail from './OwnershipDetail';

const { Search } = Input;
const { Option } = Select;
const { confirm } = Modal;

interface OwnershipListProps {
  onSelectOwnership?: (ownership: Ownership) => void;
  mode?: 'list' | 'select';
}

const OwnershipList: React.FC<OwnershipListProps> = ({
  onSelectOwnership,
  mode = 'list'
}) => {
  const [ownerships, setOwnerships] = useState<Ownership[]>([]);
  const [loading, setLoading] = useState(false);
  const [statistics, setStatistics] = useState<OwnershipStatisticsResponse | null>(null);
  const [total, setTotal] = useState(0);
  const [current, setCurrent] = useState(1);
  const [pageSize, setPageSize] = useState(10);

  // 搜索和筛选状态
  const [keyword, setKeyword] = useState('');
  const [isActive, setIsActive] = useState<boolean | undefined>(undefined);

  // 模态框状态
  const [formVisible, setFormVisible] = useState(false);
  const [detailVisible, setDetailVisible] = useState(false);
  const [editingOwnership, setEditingOwnership] = useState<Ownership | null>(null);
  const [viewingOwnership, setViewingOwnership] = useState<Ownership | null>(null);

  // 加载权属方列表
  const loadOwnerships = async () => {
    setLoading(true);
    try {
      const response: OwnershipListResponse = await ownershipService.getOwnerships({
        keyword,
        is_active: isActive,
        page: current,
        size: pageSize
      });
      setOwnerships(response.items);
      setTotal(response.total);
    } catch (error) {
      message.error('加载权属方列表失败');
    } finally {
      setLoading(false);
    }
  };

  // 加载统计信息
  const loadStatistics = async () => {
    try {
      const stats = await ownershipService.getOwnershipStatistics();
      setStatistics(stats);
    } catch (error) {
      console.error('加载统计信息失败:', error);
    }
  };


  useEffect(() => {
    loadOwnerships();
    loadStatistics();
  }, [current, pageSize]);

  useEffect(() => {
    setCurrent(1);
    loadOwnerships();
  }, [keyword, isActive]);

  // 刷新列表
  const handleRefresh = () => {
    loadOwnerships();
    loadStatistics();
  };

  // 搜索
  const handleSearch = () => {
    setCurrent(1);
    loadOwnerships();
  };

  // 重置筛选
  const handleReset = () => {
    setKeyword('');
    setIsActive(undefined);
    setCurrent(1);
  };

  // 创建权属方
  const handleCreate = () => {
    setEditingOwnership(null);
    setFormVisible(true);
  };

  // 编辑权属方
  const handleEdit = (record: Ownership) => {
    setEditingOwnership(record);
    setFormVisible(true);
  };

  // 查看详情
  const handleView = (record: Ownership) => {
    setViewingOwnership(record);
    setDetailVisible(true);
  };

  // 删除权属方
  const handleDelete = (record: Ownership) => {
    confirm({
      title: '确认删除',
      icon: <ExclamationCircleOutlined />,
      content: `确定要删除权属方"${record.name}"吗？此操作不可恢复。`,
      okText: '删除',
      okType: 'danger',
      cancelText: '取消',
      onOk: async () => {
        try {
          await ownershipService.deleteOwnership(record.id);
          message.success('删除成功');
          loadOwnerships();
          loadStatistics();
        } catch (error: unknown) {
          message.error(error.message || '删除失败');
        }
      }
    });
  };

  // 切换状态
  const handleToggleStatus = async (record: Ownership) => {
    try {
      await ownershipService.toggleOwnershipStatus(record.id);
      message.success(`${record.is_active ? '禁用' : '启用'}成功`);
      loadOwnerships();
      loadStatistics();
    } catch (error) {
      message.error('操作失败');
    }
  };

  // 表单提交成功
  const handleFormSuccess = () => {
    setFormVisible(false);
    loadOwnerships();
    loadStatistics();
  };

  // 选中权属方（选择模式）
  const handleSelect = (record: Ownership) => {
    if (mode === 'select' && onSelectOwnership) {
      onSelectOwnership(record);
    }
  };

  // 表格列定义
  const columns: ColumnsType<Ownership> = [
    {
      title: '权属方全称',
      dataIndex: 'name',
      key: 'name',
      render: (text: string, record: Ownership) => (
        <Button
          type="link"
          onClick={() => handleView(record)}
          style={{ padding: 0 }}
        >
          {text}
        </Button>
      )
    },
    {
      title: '权属方编码',
      dataIndex: 'code',
      key: 'code',
      width: 120,
      render: (text: string) => text || '-'
    },
    {
      title: '权属方简称',
      dataIndex: 'short_name',
      key: 'short_name',
      width: 150,
      render: (text: string) => text || '-'
    },
    {
      title: '关联资产',
      dataIndex: 'asset_count',
      key: 'asset_count',
      width: 100,
      render: (count: number) => count || 0
    },
    {
      title: '关联项目',
      dataIndex: 'project_count',
      key: 'project_count',
      width: 100,
      render: (count: number) => count || 0
    },
    {
      title: '状态',
      dataIndex: 'is_active',
      key: 'is_active',
      width: 80,
      render: (active: boolean) => (
        <Badge
          status={active ? 'success' : 'error'}
          text={active ? '启用' : '禁用'}
        />
      )
    },
    {
      title: '操作',
      key: 'action',
      width: 180,
      render: (_, record: Ownership) => (
        <Space size="small">
          {mode === 'select' && (
            <Button
              type="primary"
              size="small"
              onClick={() => handleSelect(record)}
            >
              选择
            </Button>
          )}
          {mode === 'list' && (
            <>
              <Tooltip title="查看详情">
                <Button
                  type="text"
                  icon={<EyeOutlined />}
                  onClick={() => handleView(record)}
                />
              </Tooltip>
              <Tooltip title="编辑">
                <Button
                  type="text"
                  icon={<EditOutlined />}
                  onClick={() => handleEdit(record)}
                />
              </Tooltip>
              <Tooltip title="删除">
                <Button
                  type="text"
                  danger
                  icon={<DeleteOutlined />}
                  onClick={() => handleDelete(record)}
                />
              </Tooltip>
            </>
          )}
          <Switch
            size="small"
            checked={record.is_active}
            onChange={() => handleToggleStatus(record)}
            checkedChildren="启用"
            unCheckedChildren="禁用"
          />
        </Space>
      )
    }
  ];

  return (
    <div className="ownership-list">
      {/* 统计卡片 */}
      {statistics && mode === 'list' && (
        <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="总数量"
                value={statistics.total_count}
                valueStyle={{ color: '#3f8600' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="启用数量"
                value={statistics.active_count}
                valueStyle={{ color: '#1890ff' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="禁用数量"
                value={statistics.inactive_count}
                valueStyle={{ color: '#cf1322' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="关联资产"
                value={ownerships.reduce((sum, ownership) => sum + (ownership.asset_count || 0), 0)}
                valueStyle={{ color: '#722ed1' }}
              />
            </Card>
          </Col>
        </Row>
      )}

      {/* 搜索和操作栏 */}
      <Card style={{ marginBottom: 16 }}>
        <Row gutter={[16, 16]} align="middle">
          <Col xs={24} sm={12} md={8} lg={6}>
            <Search
              placeholder="搜索权属方名称、简称等"
              allowClear
              enterButton={<SearchOutlined />}
              style={{ width: '100%' }}
              value={keyword}
              onChange={(e) => setKeyword(e.target.value)}
              onSearch={handleSearch}
            />
          </Col>
          <Col xs={24} sm={12} md={6} lg={4}>
            <Select
              placeholder="状态"
              allowClear
              style={{ width: '100%' }}
              value={isActive === undefined ? undefined : isActive}
              onChange={setIsActive}
            >
              <Option value={true}>启用</Option>
              <Option value={false}>禁用</Option>
            </Select>
          </Col>
          <Col xs={24} sm={12} md={6} lg={4}>
            <Space>
              <Button onClick={handleReset}>重置</Button>
            </Space>
          </Col>
          <Col xs={24} sm={12} md={6} lg={4}>
            <Space>
              <Button
                type="primary"
                icon={<PlusOutlined />}
                onClick={handleCreate}
              >
                新建权属方
              </Button>
              <Button
                icon={<ReloadOutlined />}
                onClick={handleRefresh}
                loading={loading}
              >
                刷新
              </Button>
            </Space>
          </Col>
        </Row>
      </Card>

      {/* 权属方表格 */}
      <Card>
        <Table
          columns={columns}
          dataSource={ownerships}
          rowKey="id"
          loading={loading}
          pagination={{
            current,
            pageSize,
            total,
            showSizeChanger: true,
            showQuickJumper: true,
            showTotal: (total, range) => `第 ${range[0]}-${range[1]} 条/共 ${total} 条`,
            onChange: (page, size) => {
              setCurrent(page);
              setPageSize(size || 10);
            }
          }}
          scroll={{ x: 1000 }}
        />
      </Card>

      {/* 权属方表单弹窗 */}
      <Modal
        title={editingOwnership ? '编辑权属方' : '新建权属方'}
        open={formVisible}
        onCancel={() => {
          setFormVisible(false);
          setEditingOwnership(null);
        }}
        footer={null}
        width={600}
        destroyOnHidden
      >
        <OwnershipForm
          initialValues={editingOwnership}
          onSuccess={handleFormSuccess}
          onCancel={() => {
            setFormVisible(false);
            setEditingOwnership(null);
          }}
        />
      </Modal>

      {/* 权属方详情弹窗 */}
      <Modal
        title="权属方详情"
        open={detailVisible}
        onCancel={() => {
          setDetailVisible(false);
          setViewingOwnership(null);
        }}
        footer={null}
        width={800}
        destroyOnHidden
      >
        {viewingOwnership && (
          <OwnershipDetail
            ownership={viewingOwnership}
            onEdit={() => {
              setDetailVisible(false);
              handleEdit(viewingOwnership);
            }}
          />
        )}
      </Modal>
    </div>
  );
};

export default OwnershipList;

import React, { useState, useCallback, useMemo } from 'react';
import {
  Select,
  Button,
  Modal,
  message,
  Space,
  Input,
  Tooltip,
  Tag
} from 'antd';
import {
  SearchOutlined,
  PlusOutlined,
  ReloadOutlined,
  UnorderedListOutlined
} from '@ant-design/icons';
import { useOwnershipOptions } from '@/hooks/useOwnership';
import type { Ownership } from '@/types/ownership';
import OwnershipList from './OwnershipList';

const { Option } = Select;
const { Search } = Input;

interface OwnershipSelectProps {
  /** 选中的权属方ID(s) */
  value?: string | string[];
  /** 变化回调 */
  onChange?: (value: string | string[], ownerships?: Ownership | Ownership[]) => void;
  /** 占位符 */
  placeholder?: string;
  /** 是否禁用 */
  disabled?: boolean;
  /** 是否允许清除 */
  allowClear?: boolean;
  /** 样式 */
  style?: React.CSSProperties;
  /** 尺寸 */
  size?: 'large' | 'middle' | 'small';
  /** 选择模式：single | multiple */
  mode?: 'single' | 'multiple';
  /** 是否显示创建按钮 */
  showCreateButton?: boolean;
  /** 是否只显示启用权属方 */
  onlyActive?: boolean;
  /** 是否显示高级选择按钮 */
  showAdvancedSelect?: boolean;
  /** 是否显示搜索框 */
  showSearch?: boolean;
  /** 最大选择数量（多选模式） */
  maxCount?: number;
}

const OwnershipSelect: React.FC<OwnershipSelectProps> = ({
  value,
  onChange,
  placeholder = '请选择权属方',
  disabled = false,
  allowClear = true,
  style = {},
  size = 'middle',
  mode = 'single',
  showCreateButton = true,
  onlyActive = true,
  showAdvancedSelect = true,
  showSearch = true,
  maxCount
}) => {
  const [searchText, setSearchText] = useState('');
  const [selectModalVisible, setSelectModalVisible] = useState(false);

  // 使用React Query获取权属方数据
  const { ownerships: allOwnerships, loading, refresh } = useOwnershipOptions(onlyActive);

  // 根据搜索文本过滤权属方
  const filteredOwnerships = useMemo(() => {
    if (!searchText) return allOwnerships;

    return allOwnerships.filter(ownership =>
      ownership.name.toLowerCase().includes(searchText.toLowerCase()) ||
      ownership.code.toLowerCase().includes(searchText.toLowerCase()) ||
      ownership.short_name?.toLowerCase().includes(searchText.toLowerCase())
    );
  }, [allOwnerships, searchText]);

  // 当前选中的权属方（单选模式）
  const selectedOwnership = useMemo(() => {
    if (mode === 'multiple' || !value) return null;
    const singleValue = Array.isArray(value) ? value[0] : value;
    return allOwnerships.find(o => o.id === singleValue) ||
           filteredOwnerships.find(o => o.name === singleValue) ||
           null;
  }, [value, filteredOwnerships, allOwnerships, mode]);

  // 当前选中的权属方（多选模式）
  const selectedOwnerships = useMemo(() => {
    if (mode === 'single' || !value) return [];
    const values = Array.isArray(value) ? value : value ? [value] : [];
    return allOwnerships.filter(o => values.includes(o.id)) ||
           filteredOwnerships.filter(o => values.includes(o.id));
  }, [value, filteredOwnerships, allOwnerships, mode]);

  // 处理搜索 - 防抖处理
  const handleSearch = useCallback((text: string) => {
    setSearchText(text);
  }, []);

  // 处理单选
  const handleSingleChange = (selectedValue: string | { value: string; label: React.ReactNode }) => {
    // 处理labelInValue模式
    let valueStr: string;
    if (typeof selectedValue === 'object' && selectedValue !== null) {
      valueStr = selectedValue.value;
    } else {
      valueStr = selectedValue;
    }

    const selected = filteredOwnerships.find(o => o.id === valueStr) ||
                    filteredOwnerships.find(o => o.name === valueStr);

    if (selected) {
      onChange?.(selected.id, selected);
    } else {
      onChange?.(valueStr);
    }
  };

  // 处理多选
  const handleMultipleChange = (selectedValues: string[]) => {
    const selectedOwners = allOwnerships.filter(o => selectedValues.includes(o.id));
    onChange?.(selectedValues, selectedOwners);
  };

  // 处理清除
  const handleClear = () => {
    onChange?.(mode === 'multiple' ? [] : '', mode === 'multiple' ? [] : undefined);
  };

  // 获取选项标签
  const getOptionLabel = (ownership: Ownership) => (
    <Space>
      <span>{ownership.name}</span>
      {ownership.short_name && (
        <span style={{ color: '#999', fontSize: '12px' }}>
          ({ownership.short_name})
        </span>
      )}
      <span style={{ color: '#666', fontSize: '12px' }}>
        [{ownership.code}]
      </span>
      {!ownership.is_active && (
        <Tag color="red" size="small">禁用</Tag>
      )}
    </Space>
  );

  // 多选模式下已选权属方的标签渲染
  const tagRender = (props: {
    label: React.ReactNode;
    value: string;
    closable: boolean;
    onClose: () => void;
  }) => {
    const { label, value, closable, onClose } = props;
    const ownership = allOwnerships.find(o => o.id === value);

    return (
      <Tag
        color={ownership?.is_active ? 'blue' : 'red'}
        closable={closable}
        onClose={onClose}
        style={{ marginRight: 3 }}
      >
        {ownership?.name || value}
      </Tag>
    );
  };

  // 打开选择弹窗
  const openSelectModal = () => {
    setSelectModalVisible(true);
  };

  // 从弹窗中选择权属方
  const handleModalSelect = (ownership: Ownership) => {
    if (mode === 'single') {
      onChange?.(ownership.id, ownership);
    } else {
      // 多选模式下，添加到已选列表
      const currentValues = Array.isArray(value) ? value : value ? [value] : [];
      if (!currentValues.includes(ownership.id)) {
        const newValues = maxCount ? [...currentValues.slice(-maxCount + 1), ownership.id] : [...currentValues, ownership.id];
        const selectedOwners = allOwnerships.filter(o => newValues.includes(o.id));
        onChange?.(newValues, selectedOwners);
      }
    }
    setSelectModalVisible(false);
  };

  // 刷新列表
  const handleRefresh = () => {
    refresh();
  };

  // 创建新权属方
  const handleCreateOwnership = () => {
    // 这里可以跳转到权属方管理页面或打开创建弹窗
    message.info('创建新权属方功能开发中');
  };

  return (
    <div style={style}>
      <Space.Compact style={{ width: '100%' }}>
        <Select
          value={value || (mode === 'multiple' ? [] : undefined)}
          onChange={mode === 'multiple' ? handleMultipleChange : handleSingleChange}
          onClear={handleClear}
          placeholder={placeholder}
          disabled={disabled}
          allowClear={allowClear}
          size={size}
          style={{ flex: 1 }}
          loading={loading}
          showSearch={showSearch}
          filterOption={false}
          onSearch={showSearch ? handleSearch : undefined}
          notFoundContent={loading ? '加载中...' : '暂无数据'}
          optionLabelProp="children"
          mode={mode === 'multiple' ? 'multiple' : undefined}
          maxCount={maxCount}
          tagRender={mode === 'multiple' ? tagRender : undefined}
        >
          {filteredOwnerships.map(ownership => (
            <Option key={ownership.id} value={ownership.id}>
              {getOptionLabel(ownership)}
            </Option>
          ))}
        </Select>

        <Tooltip title="从列表中选择">
          <Button
            icon={<SearchOutlined />}
            onClick={openSelectModal}
            disabled={disabled}
            size={size}
          />
        </Tooltip>

        {showAdvancedSelect && (
          <Tooltip title="从列表中选择">
            <Button
              icon={<UnorderedListOutlined />}
              onClick={openSelectModal}
              disabled={disabled}
              size={size}
            />
          </Tooltip>
        )}

        {showCreateButton && (
          <Tooltip title="创建新权属方">
            <Button
              icon={<PlusOutlined />}
              onClick={handleCreateOwnership}
              disabled={disabled}
              size={size}
            />
          </Tooltip>
        )}

        <Tooltip title="刷新">
          <Button
            icon={<ReloadOutlined />}
            onClick={handleRefresh}
            disabled={disabled}
            loading={loading}
            size={size}
          />
        </Tooltip>
      </Space.Compact>

      {/* 选择弹窗 */}
      <Modal
        title={`选择权属方${mode === 'multiple' ? '（可多选）' : ''}`}
        open={selectModalVisible}
        onCancel={() => setSelectModalVisible(false)}
        footer={null}
        width={1200}
        destroyOnHidden
      >
        <OwnershipList
          mode="select"
          onSelectOwnership={handleModalSelect}
        />
      </Modal>
    </div>
  );
};

export default OwnershipSelect;

/**
 * 性能监控组件
 * 监控应用性能指标并提供优化建议
 */

import React, { useEffect, useState, useCallback } from 'react'
import { Card, Statistic, Progress, Alert, Button, Modal, Table, Tag } from 'antd'
import { 
  DashboardOutlined, 
  ThunderboltOutlined, 
  ClockCircleOutlined,
  WarningOutlined,
  CheckCircleOutlined 
} from '@ant-design/icons'
import { getComponentLoadMetrics, SmartPreloader } from '@/utils/advancedLazyLoad'

interface PerformanceMetrics {
  // Web Vitals
  fcp?: number // First Contentful Paint
  lcp?: number // Largest Contentful Paint
  fid?: number // First Input Delay
  cls?: number // Cumulative Layout Shift
  
  // 自定义指标
  pageLoadTime?: number
  apiResponseTime?: number
  componentLoadTime?: number
  memoryUsage?: number
  
  // 网络信息
  connectionType?: string
  effectiveType?: string
  downlink?: number
  rtt?: number
}

interface ComponentMetrics {
  name: string
  loadTime: number
  status: 'success' | 'failed' | 'loading'
  retries: number
}

const PerformanceMonitor: React.FC = () => {
  const [metrics, setMetrics] = useState<PerformanceMetrics>({})
  const [componentMetrics, setComponentMetrics] = useState<ComponentMetrics[]>([])
  const [isVisible, setIsVisible] = useState(false)
  const [isMonitoring, setIsMonitoring] = useState(false)

  // 收集Web Vitals
  const collectWebVitals = useCallback(() => {
    // FCP - First Contentful Paint
    const fcpEntry = performance.getEntriesByName('first-contentful-paint')[0] as PerformanceEntry
    if (fcpEntry) {
      setMetrics(prev => ({ ...prev, fcp: fcpEntry.startTime }))
    }

    // 使用Performance Observer收集其他指标
    if ('PerformanceObserver' in window) {
      // LCP - Largest Contentful Paint
      const lcpObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries()
        const lastEntry = entries[entries.length - 1] as PerformanceEntry
        setMetrics(prev => ({ ...prev, lcp: lastEntry.startTime }))
      })
      lcpObserver.observe({ entryTypes: ['largest-contentful-paint'] })

      // FID - First Input Delay
      const fidObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries()
        entries.forEach((entry) => {
          const inputEntry = entry as PerformanceEventTiming
          setMetrics(prev => ({ ...prev, fid: inputEntry.processingStart - inputEntry.startTime }))
        })
      })
      fidObserver.observe({ entryTypes: ['first-input'] })

      // CLS - Cumulative Layout Shift
      let clsValue = 0
      const clsObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries()
        entries.forEach((entry) => {
          const layoutShiftEntry = entry as PerformanceEntry & { value: number; hadRecentInput: boolean }
          if (!layoutShiftEntry.hadRecentInput) {
            clsValue += layoutShiftEntry.value
          }
        })
        setMetrics(prev => ({ ...prev, cls: clsValue }))
      })
      clsObserver.observe({ entryTypes: ['layout-shift'] })
    }
  }, [])

  // 网络连接接口
interface NetworkConnection {
  type: string;
  effectiveType: string;
  downlink: number;
  rtt: number;
}

// 内存信息接口
interface MemoryInfo {
  usedJSHeapSize: number;
  jsHeapSizeLimit: number;
}

// 收集网络信息
  const collectNetworkInfo = useCallback(() => {
    if ('connection' in navigator) {
      const connection = (navigator as unknown as { connection?: NetworkConnection }).connection
      if (connection) {
        setMetrics(prev => ({
          ...prev,
          connectionType: connection.type,
          effectiveType: connection.effectiveType,
          downlink: connection.downlink,
          rtt: connection.rtt
        }))
      }
    }
  }, [])

  // 收集内存使用情况
  const collectMemoryInfo = useCallback(() => {
    if ('memory' in performance) {
      const memory = (performance as unknown as { memory: MemoryInfo }).memory
      setMetrics(prev => ({
        ...prev,
        memoryUsage: memory.usedJSHeapSize / memory.jsHeapSizeLimit * 100
      }))
    }
  }, [])

  // 收集组件加载指标
  const collectComponentMetrics = useCallback(() => {
    const report = getComponentLoadMetrics()
    // 这里需要根据实际的报告格式调整
    const mockComponentMetrics: ComponentMetrics[] = [
      { name: 'DashboardPage', loadTime: 1200, status: 'success', retries: 0 },
      { name: 'AssetListPage', loadTime: 800, status: 'success', retries: 1 },
      { name: 'AssetDetailPage', loadTime: 600, status: 'success', retries: 0 },
    ]
    setComponentMetrics(mockComponentMetrics)
  }, [])

  // 开始监控
  const startMonitoring = useCallback(() => {
    setIsMonitoring(true)
    collectWebVitals()
    collectNetworkInfo()
    collectMemoryInfo()
    collectComponentMetrics()

    // 定期更新指标
    const interval = setInterval(() => {
      collectMemoryInfo()
      collectComponentMetrics()
    }, 5000)

    return () => clearInterval(interval)
  }, [collectWebVitals, collectNetworkInfo, collectMemoryInfo, collectComponentMetrics])

  useEffect(() => {
    if (isMonitoring) {
      const cleanup = startMonitoring()
      return cleanup
    }
  }, [isMonitoring, startMonitoring])

  // 获取性能评分
  const getPerformanceScore = (metric: number, thresholds: [number, number]) => {
    if (metric <= thresholds[0]) return { score: 'good', color: 'green' }
    if (metric <= thresholds[1]) return { score: 'needs-improvement', color: 'orange' }
    return { score: 'poor', color: 'red' }
  }

  // 性能建议
  const getPerformanceAdvice = () => {
    const advice = []
    
    if (metrics.lcp && metrics.lcp > 2500) {
      advice.push('LCP过高，建议优化图片加载和关键资源')
    }
    
    if (metrics.fid && metrics.fid > 100) {
      advice.push('FID过高，建议减少JavaScript执行时间')
    }
    
    if (metrics.cls && metrics.cls > 0.1) {
      advice.push('CLS过高，建议为图片和广告预留空间')
    }
    
    if (metrics.memoryUsage && metrics.memoryUsage > 80) {
      advice.push('内存使用率过高，建议检查内存泄漏')
    }

    return advice
  }

  const componentColumns = [
    {
      title: '组件名称',
      dataIndex: 'name',
      key: 'name',
    },
    {
      title: '加载时间',
      dataIndex: 'loadTime',
      key: 'loadTime',
      render: (time: number) => `${time}ms`,
      sorter: (a: ComponentMetrics, b: ComponentMetrics) => a.loadTime - b.loadTime,
    },
    {
      title: '状态',
      dataIndex: 'status',
      key: 'status',
      render: (status: string) => {
        const colorMap = {
          success: 'green',
          failed: 'red',
          loading: 'blue'
        }
        return <Tag color={colorMap[status as keyof typeof colorMap]}>{status}</Tag>
      },
    },
    {
      title: '重试次数',
      dataIndex: 'retries',
      key: 'retries',
    },
  ]

  return (
    <>
      {/* 性能监控触发按钮 */}
      <Button
        type="primary"
        icon={<DashboardOutlined />}
        onClick={() => setIsVisible(true)}
        style={{ position: 'fixed', bottom: 20, right: 20, zIndex: 1000 }}
      >
        性能监控
      </Button>

      {/* 性能监控面板 */}
      <Modal
        title="性能监控面板"
        open={isVisible}
        onCancel={() => setIsVisible(false)}
        width={1000}
        footer={[
          <Button key="start" type="primary" onClick={() => setIsMonitoring(!isMonitoring)}>
            {isMonitoring ? '停止监控' : '开始监控'}
          </Button>,
          <Button key="close" onClick={() => setIsVisible(false)}>
            关闭
          </Button>
        ]}
      >
        {!isMonitoring ? (
          <Alert
            message="点击开始监控按钮开始收集性能数据"
            type="info"
            showIcon
          />
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            {/* Web Vitals 指标 */}
            <Card title="Web Vitals 指标" size="small">
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 16 }}>
                <Statistic
                  title="FCP (ms)"
                  value={metrics.fcp || 0}
                  precision={0}
                  valueStyle={{ 
                    color: metrics.fcp ? getPerformanceScore(metrics.fcp, [1800, 3000]).color : 'inherit' 
                  }}
                  prefix={<ThunderboltOutlined />}
                />
                <Statistic
                  title="LCP (ms)"
                  value={metrics.lcp || 0}
                  precision={0}
                  valueStyle={{ 
                    color: metrics.lcp ? getPerformanceScore(metrics.lcp, [2500, 4000]).color : 'inherit' 
                  }}
                  prefix={<ClockCircleOutlined />}
                />
                <Statistic
                  title="FID (ms)"
                  value={metrics.fid || 0}
                  precision={0}
                  valueStyle={{ 
                    color: metrics.fid ? getPerformanceScore(metrics.fid, [100, 300]).color : 'inherit' 
                  }}
                  prefix={<ThunderboltOutlined />}
                />
                <Statistic
                  title="CLS"
                  value={metrics.cls || 0}
                  precision={3}
                  valueStyle={{ 
                    color: metrics.cls ? getPerformanceScore(metrics.cls, [0.1, 0.25]).color : 'inherit' 
                  }}
                  prefix={<WarningOutlined />}
                />
              </div>
            </Card>

            {/* 系统资源使用 */}
            <Card title="系统资源" size="small">
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 16 }}>
                <div>
                  <div style={{ marginBottom: 8 }}>内存使用率</div>
                  <Progress
                    percent={metrics.memoryUsage || 0}
                    status={metrics.memoryUsage && metrics.memoryUsage > 80 ? 'exception' : 'normal'}
                    format={(percent) => `${percent?.toFixed(1)}%`}
                  />
                </div>
                <div>
                  <Statistic
                    title="网络类型"
                    value={metrics.effectiveType || '未知'}
                    prefix={<ThunderboltOutlined />}
                  />
                  {metrics.downlink && (
                    <div style={{ fontSize: 12, color: '#666', marginTop: 4 }}>
                      下行速度: {metrics.downlink} Mbps | RTT: {metrics.rtt}ms
                    </div>
                  )}
                </div>
              </div>
            </Card>

            {/* 组件加载性能 */}
            <Card title="组件加载性能" size="small">
              <Table
                dataSource={componentMetrics}
                columns={componentColumns}
                size="small"
                pagination={false}
                rowKey="name"
              />
            </Card>

            {/* 性能建议 */}
            {getPerformanceAdvice().length > 0 && (
              <Card title="性能优化建议" size="small">
                {getPerformanceAdvice().map((advice, index) => (
                  <Alert
                    key={index}
                    message={advice}
                    type="warning"
                    showIcon
                    style={{ marginBottom: 8 }}
                  />
                ))}
              </Card>
            )}
          </div>
        )}
      </Modal>
    </>
  )
}

export default PerformanceMonitor

/**
 * 项目列表组件 - 精简版本
 */

import React, { useState, useEffect } from 'react';
import {
  Table,
  Button,
  Space,
  Tag,
  Tooltip,
  Modal,
  message,
  Card,
  Row,
  Col,
  Statistic,
  Badge,
  Input,
  Select,
  Switch,
  Pagination
} from 'antd';
import {
  PlusOutlined,
  EditOutlined,
  DeleteOutlined,
  EyeOutlined,
  SearchOutlined,
  ReloadOutlined,
  ExclamationCircleOutlined
} from '@ant-design/icons';
import type { ColumnsType } from 'antd/es/table';

import { projectService } from '@/services/projectService';
import { ownershipService } from '@/services/ownershipService';
import type { Project, ProjectListResponse, ProjectStatisticsResponse } from '@/types/project';
import type { Ownership } from '@/types/ownership';
import ProjectForm from './ProjectForm';
import ProjectDetail from './ProjectDetail';
// import OwnershipSelect from '@/components/Ownership/OwnershipSelect';

// 项目查询参数接口
interface ProjectQueryParams {
  page: number;
  size: number;
  keyword?: string;
  is_active?: boolean;
  ownership_id?: string;
}

const { Search } = Input;
const { Option } = Select;
const { confirm } = Modal;

interface ProjectListProps {
  onSelectProject?: (project: Project) => void;
  mode?: 'list' | 'select';
}

const ProjectList: React.FC<ProjectListProps> = ({
  onSelectProject,
  mode = 'list'
}) => {
  const [projects, setProjects] = useState<Project[]>([]);
  const [statistics, setStatistics] = useState<ProjectStatisticsResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [editingProject, setEditingProject] = useState<Project | null>(null);
  const [isModalVisible, setIsModalVisible] = useState(false);
  const [isDetailVisible, setIsDetailVisible] = useState(false);
  const [searchKeyword, setSearchKeyword] = useState('');
  const [isActiveFilter, setIsActiveFilter] = useState<boolean | null>(null);
  const [ownershipFilter, setOwnershipFilter] = useState<string>('');
  const [ownerships, setOwnerships] = useState<Ownership[]>([]);
  const [ownershipsLoading, setOwnershipsLoading] = useState(false);

  // 分页状态
  const [pagination, setPagination] = useState({
    current: 1,
    pageSize: 10,
    total: 0
  });

  // 获取项目列表
  const fetchProjects = async () => {
    setLoading(true);
    try {
      const params: ProjectQueryParams = {
        page: pagination.current,
        size: pagination.pageSize
      };

      if (searchKeyword) {
        params.keyword = searchKeyword;
      }

      if (isActiveFilter !== null) {
        params.is_active = isActiveFilter;
      }

      if (ownershipFilter) {
        params.ownership_id = ownershipFilter;
      }

      const response = await projectService.getProjects(params);
      // API response received

      // 处理后端响应格式: {items: [...], total: 58, page: 1, size: 10, pages: 6}
      if (response && response.items) {
        // 标准响应格式：{items: [...], total: number, page: number, size: number}
        setProjects(response.items || []);
        setPagination(prev => ({
          ...prev,
          total: response.total || 0,
          current: response.page || prev.current,
          pageSize: response.size || prev.pageSize
        }));
      } else if (response && response.data && response.data.items) {
        // 嵌套响应格式：{data: {items: [...], total: number}}
        setProjects(response.data.items || []);
        setPagination(prev => ({
          ...prev,
          total: response.data.total || response.data.total_count || 0,
          current: response.data.page || prev.current,
          pageSize: response.data.size || prev.pageSize
        }));
      } else {
        console.error('Unexpected response format:', response);
        setProjects([]);
        setPagination(prev => ({
          ...prev,
          total: 0
        }));
      }

      // 在项目数据加载后，基于实际数据计算统计信息
      const loadedProjects = response?.items || response?.data?.items || [];
      const activeCount = loadedProjects.filter(p => p.is_active).length;
      const inactiveCount = loadedProjects.length - activeCount;

      setStatistics({
        total_count: loadedProjects.length,
        active_count: activeCount,
        inactive_count: inactiveCount,
        type_distribution: {}, // 如需要可基于项目数据计算
        status_distribution: {} // 如需要可基于项目数据计算
      });
    } catch (error) {
      console.error('获取项目列表失败:', error);
      console.error('Error details:', {
        message: error.message,
        status: error.response?.status,
        data: error.response?.data
      });
      message.error(`获取项目列表失败: ${error.message || '未知错误'}`);
    } finally {
      setLoading(false);
    }
  };

  // 获取统计信息 - 基于本地项目数据计算
  const fetchStatistics = async () => {
    try {
      // 由于后端没有提供统计API，我们基于当前项目数据计算统计信息
      // 这里使用空数组，实际统计会在项目数据加载后计算
      setStatistics({
        total_count: 0,
        active_count: 0,
        inactive_count: 0,
        type_distribution: {},
        status_distribution: {}
      });
    } catch (error) {
      console.error('获取统计信息失败:', error);
      setStatistics(null);
    }
  };

  // 获取权属方列表（使用下拉选项API，更高效）
  const fetchOwnerships = async () => {
    setOwnershipsLoading(true);
    try {
      const response = await ownershipService.getOwnershipOptions(true);
      setOwnerships(response);
    } catch (error) {
      console.error('获取权属方列表失败:', error);
    } finally {
      setOwnershipsLoading(false);
    }
  };

  useEffect(() => {
    const loadData = async () => {
      await Promise.all([
        fetchProjects(),
        fetchOwnerships()
      ]);
    };
    loadData();
  }, [pagination.current, pagination.pageSize, searchKeyword, isActiveFilter, ownershipFilter]);

  // 删除项目
  const handleDelete = (project: Project) => {
    confirm({
      title: '确认删除',
      icon: <ExclamationCircleOutlined />,
      content: `确定要删除项目 "${project.name}" 吗？`,
      okText: '确认',
      cancelText: '取消',
      onOk: async () => {
        try {
          await projectService.deleteProject(project.id);
          message.success('项目删除成功');
          fetchProjects();
        } catch (error) {
          console.error('删除项目失败:', error);
          message.error('删除项目失败');
        }
      }
    });
  };

  // 切换项目状态
  const handleToggleStatus = async (project: Project) => {
    try {
      await projectService.toggleProjectStatus(project.id);
      message.success('项目状态切换成功');
      fetchProjects();
    } catch (error) {
      console.error('切换项目状态失败:', error);
      message.error('切换项目状态失败');
    }
  };

  // 查看项目详情
  const handleView = (project: Project) => {
    setSelectedProject(project);
    setIsDetailVisible(true);
  };

  // 编辑项目
  const handleEdit = (project: Project) => {
    setEditingProject(project);
    setIsModalVisible(true);
  };

  // 创建项目
  const handleCreate = () => {
    setEditingProject(null);
    setIsModalVisible(true);
  };

  // 选择项目（在选择模式下）
  const handleSelect = (project: Project) => {
    if (mode === 'select' && onSelectProject) {
      onSelectProject(project);
    }
  };

  // 表格列定义
  const columns: ColumnsType<Project> = [
    {
      title: '项目名称',
      dataIndex: 'name',
      key: 'name',
      render: (text: string, record: Project) => (
        <Button
          type="link"
          onClick={() => handleView(record)}
          style={{ padding: 0, textAlign: 'left' }}
        >
          {text}
        </Button>
      )
    },
    {
      title: '项目编码',
      dataIndex: 'code',
      key: 'code',
      width: 120
    },
    {
      title: '权属方',
      dataIndex: 'ownership_entity',
      key: 'ownership_entity',
      width: 150,
      render: (text: string, record: Project) => {
        // 如果有直接权属方字段，显示它
        if (text) {
          return <Tag color="blue">{text}</Tag>;
        }

        // 如果有权属方关系，显示主要权属方
        if (record.ownership_relations && record.ownership_relations.length > 0) {
          const activeRelations = record.ownership_relations.filter(rel => rel.is_active);
          if (activeRelations.length > 0) {
            return (
              <div>
                {activeRelations.slice(0, 2).map((rel, index) => (
                  <Tag key={rel.id} color="blue" style={{ marginRight: 4 }}>
                    {rel.ownership_name || record.ownership_entity || '权属方已关联'}
                  </Tag>
                ))}
                {activeRelations.length > 2 && (
                  <Tag color="gray">+{activeRelations.length - 2}</Tag>
                )}
              </div>
            );
          }
        }

        return '-';
      }
    },
    {
      title: '描述',
      dataIndex: 'description',
      key: 'description',
      width: 200,
      render: (text: string) => text || '-'
    },
    {
      title: '关联资产',
      dataIndex: 'asset_count',
      key: 'asset_count',
      width: 100,
      render: (count: number) => count || 0
    },
    {
      title: '状态',
      dataIndex: 'is_active',
      key: 'is_active',
      width: 80,
      render: (isActive: boolean, record: Project) => (
        <Badge
          status={isActive ? 'success' : 'error'}
          text={isActive ? '启用' : '禁用'}
        />
      )
    },
    {
      title: '数据状态',
      dataIndex: 'data_status',
      key: 'data_status',
      width: 100,
      render: (text: string) => {
        let color = 'default';
        switch (text) {
          case '正常':
            color = 'green';
            break;
          case '禁用':
            color = 'red';
            break;
          case '删除':
            color = 'default';
            break;
        }
        return <Tag color={color}>{text}</Tag>;
      }
    },
    {
      title: '操作',
      key: 'action',
      width: 180,
      render: (_, record: Project) => (
        <Space size="small">
          {mode === 'select' && (
            <Button
              type="primary"
              size="small"
              onClick={() => handleSelect(record)}
            >
              选择
            </Button>
          )}
          {mode === 'list' && (
            <>
              <Tooltip title="查看详情">
                <Button
                  type="text"
                  icon={<EyeOutlined />}
                  onClick={() => handleView(record)}
                />
              </Tooltip>
              <Tooltip title="编辑">
                <Button
                  type="text"
                  icon={<EditOutlined />}
                  onClick={() => handleEdit(record)}
                />
              </Tooltip>
              <Tooltip title="删除">
                <Button
                  type="text"
                  danger
                  icon={<DeleteOutlined />}
                  onClick={() => handleDelete(record)}
                />
              </Tooltip>
            </>
          )}
          <Switch
            size="small"
            checked={record.is_active}
            onChange={() => handleToggleStatus(record)}
            checkedChildren="启用"
            unCheckedChildren="禁用"
          />
        </Space>
      )
    }
  ];

  return (
    <div className="project-list">
      {/* 统计卡片 */}
      <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="总项目数"
              value={statistics?.total_count || 0}
              prefix={<span style={{ color: '#1890ff' }}>📊</span>}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="启用项目"
              value={statistics?.active_count || 0}
              valueStyle={{ color: '#3f8600' }}
              prefix={<span style={{ color: '#52c41a' }}>✅</span>}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="禁用项目"
              value={statistics?.inactive_count || 0}
              valueStyle={{ color: '#cf1322' }}
              prefix={<span style={{ color: '#ff4d4f' }}>❌</span>}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="总关联资产"
              value={projects.reduce((sum, project) => sum + (project.asset_count || 0), 0)}
              prefix={<span style={{ color: '#722ed1' }}>🏢</span>}
            />
          </Card>
        </Col>
      </Row>

      {/* 搜索和操作栏 */}
      <Card style={{ marginBottom: 16 }}>
        <Row gutter={[16, 16]} align="middle">
          <Col xs={24} sm={12} md={8} lg={6}>
            <Search
              placeholder="搜索项目名称、编码"
              allowClear
              enterButton={<SearchOutlined />}
              value={searchKeyword}
              onChange={(e) => setSearchKeyword(e.target.value)}
              onSearch={fetchProjects}
            />
          </Col>
          <Col xs={24} sm={12} md={6} lg={4}>
            <Select
              placeholder="状态"
              allowClear
              style={{ width: '100%' }}
              value={isActiveFilter === null ? undefined : isActiveFilter}
              onChange={(value) => setIsActiveFilter(value === undefined ? null : value)}
            >
              <Option value={true}>启用</Option>
              <Option value={false}>禁用</Option>
            </Select>
          </Col>
          <Col xs={24} sm={12} md={6} lg={4}>
            <Select
              placeholder="权属方"
              allowClear
              style={{ width: '100%' }}
              value={ownershipFilter || undefined}
              onChange={(value) => setOwnershipFilter(value || '')}
              loading={ownershipsLoading}
              showSearch
              filterOption={(input, option) =>
                (option?.children as string)?.toLowerCase().includes(input.toLowerCase())
              }
            >
              {ownerships.map(ownership => (
                <Option key={ownership.id} value={ownership.id}>
                  {ownership.name}
                </Option>
              ))}
            </Select>
          </Col>
          <Col xs={24} sm={12} md={6} lg={4}>
            <Space>
              <Button onClick={() => {
                setSearchKeyword('');
                setIsActiveFilter(null);
                setOwnershipFilter('');
              }}>
                重置
              </Button>
            </Space>
          </Col>
          <Col xs={24} sm={12} md={6} lg={4}>
            <Space>
              <Button
                type="primary"
                icon={<PlusOutlined />}
                onClick={handleCreate}
              >
                新建项目
              </Button>
              <Button
                icon={<ReloadOutlined />}
                onClick={fetchProjects}
              >
                刷新
              </Button>
            </Space>
          </Col>
        </Row>
      </Card>

      {/* 项目表格 */}
      <Card>
        <Table
          columns={columns}
          dataSource={projects}
          rowKey="id"
          loading={loading}
          pagination={{
            current: pagination.current,
            pageSize: pagination.pageSize,
            total: pagination.total,
            showSizeChanger: true,
            showQuickJumper: true,
            showTotal: (total, range) => `第 ${range[0]}-${range[1]} 条/共 ${total} 条`,
            onChange: (page, pageSize) => {
              setPagination(prev => ({
                ...prev,
                current: page,
                pageSize: pageSize || prev.pageSize
              }));
            }
          }}
          scroll={{ x: 800 }}
        />
      </Card>

      {/* 项目表单弹窗 */}
      <Modal
        title={editingProject ? '编辑项目' : '新建项目'}
        open={isModalVisible}
        onCancel={() => {
          setIsModalVisible(false);
          setEditingProject(null);
        }}
        footer={null}
        width={600}
        destroyOnHidden
      >
        <ProjectForm
          project={editingProject}
          onSuccess={() => {
            setIsModalVisible(false);
            setEditingProject(null);
            fetchProjects();
          }}
          onCancel={() => {
            setIsModalVisible(false);
            setEditingProject(null);
          }}
        />
      </Modal>

      {/* 项目详情弹窗 */}
      <Modal
        title="项目详情"
        open={isDetailVisible}
        onCancel={() => {
          setIsDetailVisible(false);
          setSelectedProject(null);
        }}
        footer={null}
        width={800}
        destroyOnHidden
      >
        {selectedProject && (
          <ProjectDetail
            project={selectedProject}
            onEdit={() => {
              setIsDetailVisible(false);
              setEditingProject(selectedProject);
              setIsModalVisible(true);
            }}
          />
        )}
      </Modal>
    </div>
  );
};

export default ProjectList;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import {
  Select,
  Button,
  Modal,
  message,
  Space,
  Input,
  Tooltip,
  Tag
} from 'antd';
import {
  SearchOutlined,
  PlusOutlined,
  ReloadOutlined,
  UnorderedListOutlined
} from '@ant-design/icons';
import { useProjectOptions } from '@/hooks/useProject';
import type { Project } from '@/types/project';
import ProjectList from '@/components/Project/ProjectList';

const { Search } = Input;

interface ProjectSelectProps {
  value?: string;
  onChange?: (value: string, project?: Project) => void;
  placeholder?: string;
  disabled?: boolean;
  allowClear?: boolean;
  style?: React.CSSProperties;
  size?: 'large' | 'middle' | 'small';
  showCreateButton?: boolean;
  onlyActive?: boolean;
}

const ProjectSelect: React.FC<ProjectSelectProps> = ({
  value,
  onChange,
  placeholder = '请选择项目',
  disabled = false,
  allowClear = true,
  style = {},
  size = 'middle',
  showCreateButton = true,
  onlyActive = true
}) => {
    const [selectModalVisible, setSelectModalVisible] = useState(false);

  // 内部状态，用于管理显示的项目名称
  const [displayValue, setDisplayValue] = useState('');

  // 使用React Query获取项目数据
  const { projects: allProjects, loading, refresh } = useProjectOptions(onlyActive);

  // 所有可用项目（搜索功能由Select的filterOption处理）
  const filteredProjects = useMemo(() => {
    return allProjects;
  }, [allProjects]);

  // 当前选中的项目
  const selectedProject = useMemo(() => {
    if (!value) return null;
    return allProjects.find(p => p.id === value) ||
           allProjects.find(p => p.name === value) ||
           null;
  }, [value, allProjects]);

  // 监听value变化，更新显示值
  useEffect(() => {
    if (!value) {
      setDisplayValue('');
      return;
    }

    const project = allProjects.find(p => p.id === value);
    if (project) {
      const displayName = project.short_name ? `${project.name} (${project.short_name})` : project.name;
      setDisplayValue(displayName);
    } else {
      // 如果在allProjects中找不到项目，不要覆盖现有的显示值
      // 这可能发生在项目数据还在加载中的情况
      // 只有当displayValue为空时才设置为原始value
      if (!displayValue) {
        setDisplayValue(value);
      }
    }
  }, [value, allProjects, displayValue]);


  // 处理选择
  const handleChange = (selectedValue: string, option: {
    value: string;
    realValue?: string;
    label?: React.ReactNode;
    title?: React.ReactNode;
  }) => {
    // 从option中获取真实的项目ID
    const realValue = option?.realValue || option?.value;
    const selected = filteredProjects.find(p => p.id === realValue);

    if (selected) {
      setDisplayValue(selectedValue);
      onChange?.(selected.id, selected);
    } else {
      setDisplayValue(selectedValue);
      onChange?.(selectedValue);
    }
  };

  // 处理清除
  const handleClear = () => {
    onChange?.('');
    setDisplayValue('');
  };

  // 打开选择弹窗
  const openSelectModal = () => {
    setSelectModalVisible(true);
  };

  // 从弹窗中选择项目
  const handleModalSelect = (project: Project) => {
    // 更新显示值
    const displayName = project.short_name ? `${project.name} (${project.short_name})` : project.name;
    setDisplayValue(displayName);

    // 调用父组件的onChange
    onChange?.(project.id, project);
    setSelectModalVisible(false);
  };

  // 刷新列表
  const handleRefresh = () => {
    refresh();
  };

  // 创建新项目
  const handleCreateProject = () => {
    // 这里可以跳转到项目管理页面或打开创建弹窗
    message.info('创建新项目功能开发中');
  };

  return (
    <div style={style}>
      <Space.Compact style={{ width: '100%' }}>
        <Select
          value={displayValue || undefined}
          onChange={handleChange}
          onClear={handleClear}
          placeholder={placeholder}
          disabled={disabled}
          allowClear={allowClear}
          size={size}
          style={{ flex: 1 }}
          loading={loading}
          showSearch
          filterOption={(input, option) =>
            (option?.children as string)?.toLowerCase().includes(input.toLowerCase()) ||
            (option?.label as string)?.toLowerCase().includes(input.toLowerCase())
          }
          notFoundContent={loading ? '加载中...' : '暂无数据'}
          optionLabelProp="label"
          // 自定义显示文本，确保选择项目后显示项目名称而不是ID
          options={filteredProjects.map(project => ({
            label: project.short_name ? `${project.name} (${project.short_name})` : project.name,
            value: project.short_name ? `${project.name} (${project.short_name})` : project.name,
            // 存储真实的项目ID用于内部处理
            realValue: project.id,
            // 保留完整信息用于下拉显示
            title: (
              <Space>
                <span>{project.name}</span>
                {project.short_name && (
                  <span style={{ color: '#999', fontSize: '12px' }}>
                    ({project.short_name})
                  </span>
                )}
                <span style={{ color: '#666', fontSize: '12px' }}>
                  [{project.code}]
                </span>
              </Space>
            ),
          }))}
        />

        <Tooltip title="从列表中选择">
          <Button
            icon={<UnorderedListOutlined />}
            onClick={openSelectModal}
            disabled={disabled}
            size={size}
          />
        </Tooltip>

        {showCreateButton && (
          <Tooltip title="创建新项目">
            <Button
              icon={<PlusOutlined />}
              onClick={handleCreateProject}
              disabled={disabled}
              size={size}
            />
          </Tooltip>
        )}

        <Tooltip title="刷新">
          <Button
            icon={<ReloadOutlined />}
            onClick={handleRefresh}
            disabled={disabled}
            loading={loading}
            size={size}
          />
        </Tooltip>
      </Space.Compact>

      {/* 选择弹窗 */}
      <Modal
        title="选择项目"
        open={selectModalVisible}
        onCancel={() => setSelectModalVisible(false)}
        footer={null}
        width={1200}
        destroyOnHidden
      >
        <ProjectList
          mode="select"
          onSelectProject={handleModalSelect}
        />
      </Modal>
    </div>
  );
};

export default ProjectSelect;

/**
 * 统一项目选择组件
 * 支持单选和多选模式，基于React Query优化性能
 */

import React, { useState, useCallback, useMemo } from 'react';
import {
  Select,
  Button,
  Modal,
  message,
  Space,
  Input,
  Tooltip,
  Tag
} from 'antd';
import {
  SearchOutlined,
  PlusOutlined,
  ReloadOutlined,
  ListOutlined
} from '@ant-design/icons';
import { useProjectOptions } from '@/hooks/useProject';
import type { Project } from '@/types/project';
import ProjectList from '@/components/Project/ProjectList';

const { Option } = Select;
const { Search } = Input;

// Select组件标签渲染属性接口
interface CustomTagProps {
  label: React.ReactNode;
  value: string | number;
  closable: boolean;
  onClose: () => void;
}

interface UnifiedProjectSelectProps {
  /** 选中的项目ID(s) */
  value?: string | string[];
  /** 变化回调 */
  onChange?: (value: string | string[], projects?: Project | Project[]) => void;
  /** 占位符 */
  placeholder?: string;
  /** 是否禁用 */
  disabled?: boolean;
  /** 是否允许清除 */
  allowClear?: boolean;
  /** 样式 */
  style?: React.CSSProperties;
  /** 尺寸 */
  size?: 'large' | 'middle' | 'small';
  /** 选择模式：single | multiple */
  mode?: 'single' | 'multiple';
  /** 是否显示创建按钮 */
  showCreateButton?: boolean;
  /** 是否只显示启用项目 */
  onlyActive?: boolean;
  /** 是否显示高级选择按钮 */
  showAdvancedSelect?: boolean;
  /** 是否显示搜索框 */
  showSearch?: boolean;
  /** 最大选择数量（多选模式） */
  maxCount?: number;
}

const UnifiedProjectSelect: React.FC<UnifiedProjectSelectProps> = ({
  value,
  onChange,
  placeholder = '请选择项目',
  disabled = false,
  allowClear = true,
  style = {},
  size = 'middle',
  mode = 'single',
  showCreateButton = false,
  onlyActive = true,
  showAdvancedSelect = true,
  showSearch = true,
  maxCount
}) => {
  const [searchText, setSearchText] = useState('');
  const [selectModalVisible, setSelectModalVisible] = useState(false);

  // 使用React Query获取项目数据
  const { projects: allProjects, loading, refresh } = useProjectOptions(onlyActive);

  // 根据搜索文本过滤项目
  const filteredProjects = useMemo(() => {
    if (!searchText) return allProjects;

    return allProjects.filter(project =>
      project.name.toLowerCase().includes(searchText.toLowerCase()) ||
      project.code.toLowerCase().includes(searchText.toLowerCase())
    );
  }, [allProjects, searchText]);

  // 处理搜索 - 防抖处理
  const handleSearch = useCallback((text: string) => {
    setSearchText(text);
  }, []);

  // 处理单选
  const handleSingleChange = (selectedValue: string) => {
    const selected = allProjects.find(p => p.id === selectedValue);
    onChange?.(selectedValue, selected);
  };

  // 处理多选
  const handleMultipleChange = (selectedValues: string[]) => {
    const selectedProjects = allProjects.filter(p => selectedValues.includes(p.id));
    onChange?.(selectedValues, selectedProjects);
  };

  // 处理清除
  const handleClear = () => {
    onChange?.(mode === 'multiple' ? [] : '', mode === 'multiple' ? [] : undefined);
  };

  // 打开高级选择弹窗
  const openAdvancedSelect = () => {
    setSelectModalVisible(true);
  };

  // 从弹窗中选择项目
  const handleModalSelect = (project: Project) => {
    if (mode === 'single') {
      onChange?.(project.id, project);
    } else {
      // 多选模式下，添加到已选列表
      const currentValues = Array.isArray(value) ? value : value ? [value] : [];
      if (!currentValues.includes(project.id)) {
        const newValues = maxCount ? [...currentValues.slice(-maxCount + 1), project.id] : [...currentValues, project.id];
        const selectedProjects = allProjects.filter(p => newValues.includes(p.id));
        onChange?.(newValues, selectedProjects);
      }
    }
    setSelectModalVisible(false);
  };

  // 刷新列表
  const handleRefresh = () => {
    refresh();
  };

  // 创建新项目
  const handleCreateProject = () => {
    message.info('创建新项目功能开发中');
  };

  // 获取选项标签
  const getOptionLabel = (project: Project) => (
    <Space>
      <span>{project.name}</span>
      <span style={{ color: '#666', fontSize: '12px' }}>
        [{project.code}]
      </span>
      {!project.is_active && (
        <Tag color="red" size="small">禁用</Tag>
      )}
    </Space>
  );

  // 多选模式下已选项目的标签渲染
  const tagRender = (props: CustomTagProps) => {
    const { label, value, closable, onClose } = props;
    const project = allProjects.find(p => p.id === value);

    return (
      <Tag
        color={project?.is_active ? 'blue' : 'red'}
        closable={closable}
        onClose={onClose}
        style={{ marginRight: 3 }}
      >
        {project?.name || value}
      </Tag>
    );
  };

  return (
    <div style={style}>
      <Space.Compact style={{ width: '100%' }}>
        <Select
          value={value || (mode === 'multiple' ? [] : undefined)}
          onChange={mode === 'multiple' ? handleMultipleChange : handleSingleChange}
          onClear={handleClear}
          placeholder={placeholder}
          disabled={disabled}
          allowClear={allowClear}
          size={size}
          style={{ flex: 1 }}
          loading={loading}
          showSearch={showSearch}
          filterOption={false}
          onSearch={showSearch ? handleSearch : undefined}
          notFoundContent={loading ? '加载中...' : '暂无数据'}
          optionLabelProp="children"
          mode={mode === 'multiple' ? 'multiple' : undefined}
          maxCount={maxCount}
          tagRender={mode === 'multiple' ? tagRender : undefined}
        >
          {filteredProjects.map(project => (
            <Option key={project.id} value={project.id}>
              {getOptionLabel(project)}
            </Option>
          ))}
        </Select>

        {showAdvancedSelect && (
          <Tooltip title="高级选择">
            <Button
              icon={<ListOutlined />}
              onClick={openAdvancedSelect}
              disabled={disabled}
              size={size}
            />
          </Tooltip>
        )}

        {showCreateButton && (
          <Tooltip title="创建新项目">
            <Button
              icon={<PlusOutlined />}
              onClick={handleCreateProject}
              disabled={disabled}
              size={size}
            />
          </Tooltip>
        )}

        <Tooltip title="刷新">
          <Button
            icon={<ReloadOutlined />}
            onClick={handleRefresh}
            disabled={disabled}
            loading={loading}
            size={size}
          />
        </Tooltip>
      </Space.Compact>

      {/* 高级选择弹窗 */}
      <Modal
        title={`选择项目${mode === 'multiple' ? '（可多选）' : ''}`}
        open={selectModalVisible}
        onCancel={() => setSelectModalVisible(false)}
        footer={null}
        width={1200}
        destroyOnHidden
      >
        <ProjectList
          mode="select"
          onSelectProject={handleModalSelect}
        />
      </Modal>
    </div>
  );
};

export default UnifiedProjectSelect;

/**
 * 租金合同Excel导入导出组件
 */

import React, { useState, useRef } from 'react';
import {
  Button,
  Upload,
  Modal,
  Form,
  Switch,
  Checkbox,
  DatePicker,
  Space,
  Alert,
  Progress,
  Card,
  Row,
  Col,
  Statistic,
  Typography,
  Divider,
  List,
  Tag,
  message,
  Spin,
} from 'antd';
import {
  UploadOutlined,
  DownloadOutlined,
  ExportOutlined,
  FileExcelOutlined,
  CheckCircleOutlined,
  ExclamationCircleOutlined,
  InfoCircleOutlined,
} from '@ant-design/icons';
import type { UploadFile } from 'antd/es/upload/interface';
import dayjs from 'dayjs';
import { rentContractExcelService, ExcelImportResult } from '../../services/rentContractExcelService';

const { Title, Text, Paragraph } = Typography;
const { RangePicker } = DatePicker;

interface RentContractExcelImportProps {
  onImportSuccess?: () => void;
  className?: string;
}

const RentContractExcelImport: React.FC<RentContractExcelImportProps> = ({
  onImportSuccess,
  className,
}) => {
  const [form] = Form.useForm();
  const [importModalVisible, setImportModalVisible] = useState(false);
  const [exportModalVisible, setExportModalVisible] = useState(false);
  const [importing, setImporting] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [importResult, setImportResult] = useState<ExcelImportResult | null>(null);
  const [fileList, setFileList] = useState<UploadFile[]>([]);
  const [importOptions, setImportOptions] = useState({
    import_terms: true,
    import_ledger: false,
    overwrite_existing: false,
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  // 处理文件上传
  const handleFileUpload = async (file: File) => {
    try {
      setImporting(true);
      setImportResult(null);

      const result = await rentContractExcelService.handleFileUpload(file, {
        ...importOptions,
        onSuccess: (result) => {
          setImportResult(result);
          if (result.success) {
            message.success(rentContractExcelService.getImportSuccessSummary(result));
            if (onImportSuccess) {
              onImportSuccess();
            }
          } else {
            message.error(result.message);
          }
        },
        onError: (error) => {
          message.error(error.message);
        },
      });

      return result;
    } catch (error) {
      console.error('导入失败:', error);
      message.error('导入失败，请重试');
      return null;
    } finally {
      setImporting(false);
      setFileList([]);
    }
  };

  // 处理导出
  const handleExport = async () => {
    try {
      const values = await form.validateFields();
      setExporting(true);

      await rentContractExcelService.exportAndDownload({
        start_date: values.date_range?.[0]?.format('YYYY-MM-DD'),
        end_date: values.date_range?.[1]?.format('YYYY-MM-DD'),
        include_terms: values.include_terms,
        include_ledger: values.include_ledger,
      });

      message.success('导出成功');
      setExportModalVisible(false);
      form.resetFields();
    } catch (error) {
      console.error('导出失败:', error);
      message.error('导出失败，请重试');
    } finally {
      setExporting(false);
    }
  };

  // 下载模板
  const handleDownloadTemplate = async () => {
    try {
      await rentContractExcelService.downloadTemplateFile();
      message.success('模板下载成功');
    } catch (error) {
      message.error('模板下载失败，请重试');
    }
  };

  // 上传组件配置
  const uploadProps = {
    accept: '.xlsx,.xls',
    beforeUpload: (file: File) => {
      const validation = rentContractExcelService.validateExcelFile(file);
      if (!validation.isValid) {
        message.error(validation.error);
        return Upload.LIST_IGNORE;
      }

      // 开始上传
      handleFileUpload(file);
      return Upload.LIST_IGNORE; // 阻止自动上传
    },
    fileList,
    showUploadList: false,
    disabled: importing,
  };

  return (
    <div className={className}>
      <Row gutter={[16, 16]}>
        <Col span={12}>
          <Card
            title="导入数据"
            extra={<FileExcelOutlined style={{ color: '#52c41a' }} />}
            actions={[
              <Button
                key="template"
                type="link"
                icon={<DownloadOutlined />}
                onClick={handleDownloadTemplate}
              >
                下载模板
              </Button>,
              <Button
                key="import"
                type="primary"
                icon={<UploadOutlined />}
                onClick={() => setImportModalVisible(true)}
              >
                导入Excel
              </Button>,
            ]}
          >
            <Paragraph type="secondary">
              从Excel文件批量导入租金合同数据，支持合同信息、租金条款和台账记录的导入。
            </Paragraph>

            <Space direction="vertical" size="small" style={{ width: '100%' }}>
              <Alert
                message="导入说明"
                description={
                  <ul style={{ margin: 0, paddingLeft: 16 }}>
                    <li>请先下载模板，按照模板格式填写数据</li>
                    <li>支持.xlsx和.xls格式，文件大小不超过10MB</li>
                    <li>导入前请确保资产和权属方信息已存在</li>
                  </ul>
                }
                type="info"
                showIcon
              />
            </Space>
          </Card>
        </Col>

        <Col span={12}>
          <Card
            title="导出数据"
            extra={<ExportOutlined style={{ color: '#1890ff' }} />}
            actions={[
              <Button
                key="export"
                type="primary"
                icon={<ExportOutlined />}
                onClick={() => setExportModalVisible(true)}
              >
                导出Excel
              </Button>,
            ]}
          >
            <Paragraph type="secondary">
              将租金合同数据导出为Excel文件，支持按时间范围筛选和选择导出内容。
            </Paragraph>

            <Space direction="vertical" size="small" style={{ width: '100%' }}>
              <Alert
                message="导出说明"
                description={
                  <ul style={{ margin: 0, paddingLeft: 16 }}>
                    <li>可选择导出合同信息、租金条款和台账记录</li>
                    <li>支持按时间范围筛选数据</li>
                    <li>导出的Excel文件包含多个工作表</li>
                  </ul>
                }
                type="info"
                showIcon
              />
            </Space>
          </Card>
        </Col>
      </Row>

      {/* 导入模态框 */}
      <Modal
        title="导入Excel文件"
        open={importModalVisible}
        onCancel={() => {
          setImportModalVisible(false);
          setImportResult(null);
          setFileList([]);
        }}
        footer={null}
        width={600}
      >
        <Space direction="vertical" size="large" style={{ width: '100%' }}>
          {/* 导入选项 */}
          <Card title="导入选项" size="small">
            <Space direction="vertical" size="small" style={{ width: '100%' }}>
              <Checkbox
                checked={importOptions.import_terms}
                onChange={(e) =>
                  setImportOptions({
                    ...importOptions,
                    import_terms: e.target.checked,
                  })
                }
              >
                导入租金条款
              </Checkbox>
              <Checkbox
                checked={importOptions.import_ledger}
                onChange={(e) =>
                  setImportOptions({
                    ...importOptions,
                    import_ledger: e.target.checked,
                  })
                }
              >
                导入台账记录
              </Checkbox>
              <Checkbox
                checked={importOptions.overwrite_existing}
                onChange={(e) =>
                  setImportOptions({
                    ...importOptions,
                    overwrite_existing: e.target.checked,
                  })
                }
              >
                覆盖已存在的数据
              </Checkbox>
            </Space>
          </Card>

          {/* 文件上传 */}
          <Upload {...uploadProps}>
            <Button
              icon={<UploadOutlined />}
              loading={importing}
              disabled={importing}
              block
            >
              {importing ? '正在导入...' : '选择Excel文件'}
            </Button>
          </Upload>

          {/* 导入结果 */}
          {importResult && (
            <Card
              title={
                <Space>
                  {importResult.success ? (
                    <CheckCircleOutlined style={{ color: '#52c41a' }} />
                  ) : (
                    <ExclamationCircleOutlined style={{ color: '#ff4d4f' }} />
                  )}
                  <Text>导入结果</Text>
                </Space>
              }
              size="small"
            >
              <Space direction="vertical" size="small" style={{ width: '100%' }}>
                <Row gutter={16}>
                  <Col span={8}>
                    <Statistic
                      title="合同"
                      value={importResult.imported_contracts}
                      suffix="个"
                    />
                  </Col>
                  <Col span={8}>
                    <Statistic
                      title="条款"
                      value={importResult.imported_terms}
                      suffix="个"
                    />
                  </Col>
                  <Col span={8}>
                    <Statistic
                      title="台账"
                      value={importResult.imported_ledgers}
                      suffix="个"
                    />
                  </Col>
                </Row>

                {importResult.warnings.length > 0 && (
                  <>
                    <Divider orientation="left">警告</Divider>
                    <List
                      size="small"
                      dataSource={importResult.warnings.slice(0, 3)}
                      renderItem={(item) => (
                        <List.Item>
                          <Text type="warning">{item}</Text>
                        </List.Item>
                      )}
                    />
                    {importResult.warnings.length > 3 && (
                      <Text type="secondary">
                        还有 {importResult.warnings.length - 3} 个警告...
                      </Text>
                    )}
                  </>
                )}

                {importResult.errors.length > 0 && (
                  <>
                    <Divider orientation="left">错误</Divider>
                    <List
                      size="small"
                      dataSource={importResult.errors.slice(0, 3)}
                      renderItem={(item) => (
                        <List.Item>
                          <Text type="danger">{item}</Text>
                        </List.Item>
                      )}
                    />
                    {importResult.errors.length > 3 && (
                      <Text type="secondary">
                        还有 {importResult.errors.length - 3} 个错误...
                      </Text>
                    )}
                  </>
                )}
              </Space>
            </Card>
          )}
        </Space>
      </Modal>

      {/* 导出模态框 */}
      <Modal
        title="导出Excel文件"
        open={exportModalVisible}
        onOk={handleExport}
        onCancel={() => {
          setExportModalVisible(false);
          form.resetFields();
        }}
        confirmLoading={exporting}
        width={500}
      >
        <Form form={form} layout="vertical">
          <Form.Item
            name="include_terms"
            label="包含租金条款"
            valuePropName="checked"
            initialValue={true}
          >
            <Switch />
          </Form.Item>

          <Form.Item
            name="include_ledger"
            label="包含台账记录"
            valuePropName="checked"
            initialValue={true}
          >
            <Switch />
          </Form.Item>

          <Form.Item name="date_range" label="时间范围">
            <RangePicker style={{ width: '100%' }} />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
};

export default RentContractExcelImport;

/**
 * 租户合同创建/编辑表单组件
 */

import React, { useState, useEffect } from 'react';
import {
  Form,
  Input,
  Select,
  InputNumber,
  DatePicker,
  Button,
  Space,
  Card,
  Row,
  Col,
  Divider,
  Typography,
  message,
  Modal,
  Table,
  Tooltip,
  Tag,
  Popconfirm
} from 'antd';
import {
  SaveOutlined,
  PlusOutlined,
  DeleteOutlined,
  InfoCircleOutlined,
  CalendarOutlined,
  DollarOutlined
} from '@ant-design/icons';
import dayjs from 'dayjs';
import type { Dayjs } from 'dayjs';
import type { ColumnsType } from 'antd/es/table';

import { RentContractCreate, RentTermCreate } from '../../types/rentContract';
import { Asset } from '../../types/asset';
import { Ownership } from '../../types/ownership';
import { assetService } from '../../services/assetService';
import { ownershipService } from '../../services/ownershipService';

// 租金条款接口（用于编辑时）
interface RentTermData {
  start_date: string;
  end_date: string;
  monthly_rent: number;
  rent_description?: string;
  management_fee?: number;
  other_fees?: number;
}

// 租赁合同表单初始数据接口
interface RentContractInitialData {
  contract_number?: string;
  asset_id: string;
  ownership_id: string;
  tenant_name: string;
  tenant_contact?: string;
  tenant_phone?: string;
  tenant_address?: string;
  sign_date?: string;
  start_date: string;
  end_date: string;
  total_deposit?: number;
  monthly_rent_base?: number;
  contract_status?: string;
  payment_terms?: string;
  contract_notes?: string;
  rent_terms?: RentTermData[];
}

const { Option } = Select;
const { TextArea } = Input;
const { Title, Text } = Typography;

interface RentContractFormProps {
  initialData?: RentContractInitialData;
  onSubmit: (data: RentContractCreate) => Promise<void>;
  onCancel: () => void;
  loading?: boolean;
  mode?: 'create' | 'edit';
}

interface RentTermFormData {
  key: string;
  start_date: Dayjs;
  end_date: Dayjs;
  monthly_rent: number;
  rent_description?: string;
  management_fee?: number;
  other_fees?: number;
}

const RentContractForm: React.FC<RentContractFormProps> = ({
  initialData,
  onSubmit,
  onCancel,
  loading = false,
  mode = 'create'
}) => {
  const [form] = Form.useForm();
  const [assets, setAssets] = useState<Asset[]>([]);
  const [ownerships, setOwnerships] = useState<Ownership[]>([]);
  const [rentTerms, setRentTerms] = useState<RentTermFormData[]>([]);
  const [loadingAssets, setLoadingAssets] = useState(false);
  const [loadingOwnerships, setLoadingOwnerships] = useState(false);
  const [showRentTermModal, setShowRentTermModal] = useState(false);
  const [editingTerm, setEditingTerm] = useState<RentTermFormData | null>(null);
  const [termForm] = Form.useForm();

  // 加载资产和权属方数据
  useEffect(() => {
    loadAssets();
    loadOwnerships();
  }, []);

  // 初始化表单数据
  useEffect(() => {
    if (initialData && mode === 'edit') {
      const formData = {
        ...initialData,
        sign_date: initialData.sign_date ? dayjs(initialData.sign_date) : undefined,
        start_date: initialData.start_date ? dayjs(initialData.start_date) : undefined,
        end_date: initialData.end_date ? dayjs(initialData.end_date) : undefined,
      };
      form.setFieldsValue(formData);
      
      if (initialData.rent_terms) {
        const terms = initialData.rent_terms.map((term: RentTermData, index: number) => ({
          key: `term-${index}`,
          start_date: dayjs(term.start_date),
          end_date: dayjs(term.end_date),
          monthly_rent: term.monthly_rent,
          rent_description: term.rent_description,
          management_fee: term.management_fee || 0,
          other_fees: term.other_fees || 0,
        }));
        setRentTerms(terms);
      }
    }
  }, [initialData, mode, form]);

  const loadAssets = async () => {
    setLoadingAssets(true);
    try {
      const response = await assetService.getAssets({ limit: 100 });
      setAssets(response.items);
    } catch (error) {
      message.error('加载资产列表失败');
    } finally {
      setLoadingAssets(false);
    }
  };

  const loadOwnerships = async () => {
    setLoadingOwnerships(true);
    try {
      const response = await ownershipService.getOwnerships({ size: 100 });
      setOwnerships(response.items);
    } catch (error) {
      message.error('加载权属方列表失败');
    } finally {
      setLoadingOwnerships(false);
    }
  };

  // 提交表单
  const handleSubmit = async () => {
    try {
      const values = await form.validateFields();
      
      if (rentTerms.length === 0) {
        message.error('请至少添加一个租金条款');
        return;
      }

      // 转换租金条款数据
      const rent_terms: RentTermCreate[] = rentTerms.map(term => ({
        start_date: term.start_date.format('YYYY-MM-DD'),
        end_date: term.end_date.format('YYYY-MM-DD'),
        monthly_rent: term.monthly_rent,
        rent_description: term.rent_description,
        management_fee: term.management_fee || 0,
        other_fees: term.other_fees || 0,
        total_monthly_amount: term.monthly_rent + (term.management_fee || 0) + (term.other_fees || 0),
      }));

      const contractData: RentContractCreate = {
        contract_number: values.contract_number,
        asset_id: values.asset_id,
        ownership_id: values.ownership_id,
        tenant_name: values.tenant_name,
        tenant_contact: values.tenant_contact,
        tenant_phone: values.tenant_phone,
        tenant_address: values.tenant_address,
        sign_date: values.sign_date.format('YYYY-MM-DD'),
        start_date: values.start_date.format('YYYY-MM-DD'),
        end_date: values.end_date.format('YYYY-MM-DD'),
        total_deposit: values.total_deposit || 0,
        monthly_rent_base: values.monthly_rent_base,
        contract_status: values.contract_status || '有效',
        payment_terms: values.payment_terms,
        contract_notes: values.contract_notes,
        rent_terms,
      };

      await onSubmit(contractData);
    } catch (error) {
      console.error('表单验证失败:', error);
    }
  };

  // 添加租金条款
  const handleAddRentTerm = () => {
    setEditingTerm(null);
    termForm.resetFields();
    setShowRentTermModal(true);
  };

  // 编辑租金条款
  const handleEditRentTerm = (term: RentTermFormData) => {
    setEditingTerm(term);
    termForm.setFieldsValue(term);
    setShowRentTermModal(true);
  };

  // 删除租金条款
  const handleDeleteRentTerm = (key: string) => {
    setRentTerms(prev => prev.filter(term => term.key !== key));
  };

  // 保存租金条款
  const handleSaveRentTerm = async () => {
    try {
      const values = await termForm.validateFields();
      const termData: RentTermFormData = {
        key: editingTerm ? editingTerm.key : `term-${Date.now()}`,
        start_date: values.start_date,
        end_date: values.end_date,
        monthly_rent: values.monthly_rent,
        rent_description: values.rent_description,
        management_fee: values.management_fee || 0,
        other_fees: values.other_fees || 0,
      };

      if (editingTerm) {
        // 编辑现有条款
        setRentTerms(prev => prev.map(term => 
          term.key === editingTerm.key ? termData : term
        ));
      } else {
        // 添加新条款
        setRentTerms(prev => [...prev, termData]);
      }

      setShowRentTermModal(false);
      termForm.resetFields();
    } catch (error) {
      console.error('租金条款验证失败:', error);
    }
  };

  // 租金条款表格列定义
  const rentTermColumns: ColumnsType<RentTermFormData> = [
    {
      title: '开始日期',
      dataIndex: 'start_date',
      key: 'start_date',
      render: (date: Dayjs) => date.format('YYYY-MM-DD'),
      width: 120,
    },
    {
      title: '结束日期',
      dataIndex: 'end_date',
      key: 'end_date',
      render: (date: Dayjs) => date.format('YYYY-MM-DD'),
      width: 120,
    },
    {
      title: '月租金',
      dataIndex: 'monthly_rent',
      key: 'monthly_rent',
      render: (amount: number) => `¥${amount.toLocaleString()}`,
      width: 120,
    },
    {
      title: '管理费',
      dataIndex: 'management_fee',
      key: 'management_fee',
      render: (amount: number) => `¥${(amount || 0).toLocaleString()}`,
      width: 100,
    },
    {
      title: '其他费用',
      dataIndex: 'other_fees',
      key: 'other_fees',
      render: (amount: number) => `¥${(amount || 0).toLocaleString()}`,
      width: 100,
    },
    {
      title: '月应收总额',
      key: 'total_amount',
      render: (record: RentTermFormData) => {
        const total = record.monthly_rent + (record.management_fee || 0) + (record.other_fees || 0);
        return `¥${total.toLocaleString()}`;
      },
      width: 120,
    },
    {
      title: '说明',
      dataIndex: 'rent_description',
      key: 'rent_description',
      ellipsis: true,
    },
    {
      title: '操作',
      key: 'actions',
      width: 120,
      render: (record: RentTermFormData) => (
        <Space size="small">
          <Button
            type="text"
            size="small"
            icon={<DeleteOutlined />}
            onClick={() => handleEditRentTerm(record)}
          >
            编辑
          </Button>
          <Popconfirm
            title="确认删除"
            description="确实要删除这个租金条款吗？"
            onConfirm={() => handleDeleteRentTerm(record.key)}
            okText="确认"
            cancelText="取消"
          >
            <Button
              type="text"
              size="small"
              danger
              icon={<DeleteOutlined />}
            >
              删除
            </Button>
          </Popconfirm>
        </Space>
      ),
    },
  ];

  return (
    <>
      <Form
        form={form}
        layout="vertical"
        onFinish={handleSubmit}
        initialValues={{
          contract_status: '有效',
        }}
      >
        {/* 基本信息 */}
        <Card title="基本信息" size="small" style={{ marginBottom: 16 }}>
          <Row gutter={16}>
            <Col span={8}>
              <Form.Item
                label="合同编号"
                name="contract_number"
                tooltip="留空将自动生成"
              >
                <Input placeholder="留空将自动生成" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                label="签订日期"
                name="sign_date"
                rules={[{ required: true, message: '请选择签订日期' }]}
              >
                <DatePicker style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                label="合同状态"
                name="contract_status"
                rules={[{ required: true, message: '请选择合同状态' }]}
              >
                <Select>
                  <Option value="有效">有效</Option>
                  <Option value="到期">到期</Option>
                  <Option value="终止">终止</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
        </Card>

        {/* 关联信息 */}
        <Card title="关联信息" size="small" style={{ marginBottom: 16 }}>
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                label="关联资产"
                name="asset_id"
                rules={[{ required: true, message: '请选择关联资产' }]}
              >
                <Select
                  showSearch
                  placeholder="选择资产"
                  loading={loadingAssets}
                  optionFilterProp="children"
                  filterOption={(input, option) =>
                    (option?.children as string)?.toLowerCase().includes(input.toLowerCase())
                  }
                >
                  {assets.map(asset => (
                    <Option key={asset.id} value={asset.id}>
                      {asset.property_name} - {asset.address}
                    </Option>
                  ))}
                </Select>
              </Form.Item>
