// 智能骨架屏组件
interface SmartSkeletonProps {
  loading: boolean
  children: React.ReactNode
  type?: 'default' | 'list' | 'card' | 'table'
  rows?: number
  avatar?: boolean
  paragraph?: boolean
  title?: boolean
  active?: boolean
}

export const SmartSkeleton: React.FC<SmartSkeletonProps> = ({
