                </Col>
              ))}
            </Row>

            <div style={{ marginTop: '16px' }}>
              <Text type="secondary">
                点击性能类型可以查看详细优化建议
              </Text>
            </div>
          </Card>
        </Col>
      </Row>

      {showDetails && (
        <div style={{ marginTop: '16px' }}>
          <Card title="详细性能数据" size="small">
            <Space direction="vertical" style={{ width: '100%' }}>
              {metrics.slice(0, 10).map((metric, index) => (
                <div key={index} style={{
                  padding: '8px',
                  border: '1px solid #f0f0f0',
                  borderRadius: '4px',
                  marginBottom: '8px'
