                      <Text>{metric.responseTime.toFixed(2)}ms</Text>
                    </Col>
                    <Col span={4}>
                      <Text>
                        状态: {getResponseType(metric) === 'loading' ? '⏳' :
                             getResponseType(metric) === 'rendering' ? '🎨' :
                             getResponseType(metric) === 'compression' ? '📦' :
                             getResponseType(metric) === 'caching' ? '💾' :
                             '🌐'} {metric.cacheHit ? '✅' : '❌'}
                      </Text>
                    </Col>
                    <Col span={4}>
                      <Button size="small" onClick={() => {}}>
                        <EyeOutlined />
                      </Button>
                    </Col>
                  </Row>
                </div>
              ))}
            </Space>
          </Card>
        </div>
      )}
    </Card>
  )
}

