 */
export const useAsset = (id: string) => {
  const { setSelectedAsset } = useAssetStore()

  return useQuery({
    queryKey: ['asset', id],
    queryFn: async () => {
      const asset = await assetService.getAsset(id)
      setSelectedAsset(asset)
      return asset
