import { useState, useEffect, useCallback } from 'react'
import { message } from 'antd'
import { AuthService } from '../services/authService'
import type { User, Permission, LoginCredentials } from '../types/auth'

export const useAuth = () => {
  const [user, setUser] = useState<User | null>(AuthService.getLocalUser())
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  // 初始化认证状态
  useEffect(() => {
    const initAuth = async () => {
      try {
        if (AuthService.isAuthenticated()) {
          const currentUser = AuthService.getLocalUser()
          const permissions = AuthService.getLocalPermissions()

          setUser(currentUser)
          // 设置API请求头
          const token = localStorage.getItem('auth_token')
          if (token) {
            // 这里可以设置API默认的Authorization header
          }
        }
      } catch (error) {
        console.error('初始化认证状态失败:', error)
        // 清除可能损坏的本地存储
        AuthService.logout()
      }
    }

    initAuth()
  }, [])

  const login = useCallback(async (credentials: LoginCredentials) => {
    setLoading(true)
    setError(null)

    try {
      const response = await AuthService.login(credentials)

      if (response.success) {
        setUser(response.data.user)
        message.success('登录成功')
      } else {
        setError('用户名或密码错误')
      }
    } catch (err: { message?: string; response?: { status?: number; data?: Record<string, unknown> } }) {
      const errorMessage = err.message || '登录失败，请稍后重试'
      setError(errorMessage)
      message.error(errorMessage)
    } finally {
      setLoading(false)
    }
  }, [])

  const logout = useCallback(async () => {
    setLoading(true)

    try {
      await AuthService.logout()
      setUser(null)
      setError(null)
      message.success('已安全登出')
    } catch (err: { message?: string; response?: { status?: number; data?: Record<string, unknown> } }) {
      console.error('登出失败:', err)
      // 即使API失败，也要清除本地状态
      setUser(null)
      setError(null)
    } finally {
      setLoading(false)
    }
  }, [])

  const refreshUser = useCallback(async () => {
    try {
      if (AuthService.isAuthenticated()) {
        const currentUser = await AuthService.getCurrentUser()
        setUser(currentUser)
      }
    } catch (error) {
      console.error('刷新用户信息失败:', error)
      // 如果刷新失败，尝试刷新token
      try {
        await AuthService.refreshToken()
        const currentUser = await AuthService.getCurrentUser()
        setUser(currentUser)
      } catch (refreshError) {
        console.error('刷新token失败:', refreshError)
        // 彻底登出
        await logout()
      }
    }
  }, [logout])

  const hasPermission = useCallback((resource: string, action: string): boolean => {
    return AuthService.hasPermission(resource, action)
  }, [])

  const hasAnyPermission = useCallback((permissions: Array<{ resource: string; action: string }>): boolean => {
    return AuthService.hasAnyPermission(permissions)
  }, [])

  const clearError = useCallback(() => {
    setError(null)
  }, [])

  return {
    user,
    loading,
    error,
    isAuthenticated: !!user,
    permissions: AuthService.getLocalPermissions(),
    login,
    logout,
    refreshUser,
    hasPermission,
    hasAnyPermission,
    clearError
  }
}

/**
 * 统一字典Hook
 * 提供简单易用的字典数据获取和管理功能
 */

import React, { useState, useEffect, useCallback } from 'react'
import { useQuery } from '@tanstack/react-query'
import { unifiedDictionaryService } from '../services/dictionary'
import type { DictionaryOption } from '../services/dictionary'

interface UseDictionaryResult {
  options: DictionaryOption[]
  loading: boolean
  error: string | null
  refresh: () => Promise<void>
}

/**
 * 使用字典数据的Hook - 基于React Query优化
 */
export const useDictionary = (dictType: string, isActive: boolean = true): UseDictionaryResult => {
  const queryKey = ['dictionary', dictType, isActive]

  const { data, isLoading, error, refetch } = useQuery({
    queryKey,
    queryFn: async () => {
      if (!dictType) return { success: false, data: [], error: '字典类型不能为空' }

      const result: DictionaryServiceResult = await unifiedDictionaryService.getOptions(dictType, {
        useCache: true,
        useFallback: true,
        isActive
      })

      return result
    },
    staleTime: 10 * 60 * 1000, // 10分钟缓存
    cacheTime: 30 * 60 * 1000, // 30分钟保留缓存
    refetchOnWindowFocus: false,
    refetchOnMount: false,
    refetchOnReconnect: false,
    retry: 1,
    enabled: !!dictType
  })

  const options = data?.success ? data.data : []
  const errorMessage = data?.success ? null : (data?.error || error?.message)

  return {
    options,
    loading: isLoading,
    error: errorMessage,
    refresh: refetch
  }
}

/**
 * 批量使用多个字典的Hook - 基于React Query优化
 */
export const useDictionaries = (dictTypes: string[]): Record<string, UseDictionaryResult> => {
  const results: Record<string, UseDictionaryResult> = {}

  dictTypes.forEach(dictType => {
    const { options, loading, error, refresh } = useDictionary(dictType, true)
    results[dictType] = {
      options,
      loading,
      error,
      refresh
    }
  })

  return results
}

/**
 * 字典管理Hook（用于管理界面）
 */
export const useDictionaryManager = () => {
  const [types, setTypes] = useState<string[]>([])
  const [loading, setLoading] = useState(false)

  const loadTypes = useCallback(async () => {
    setLoading(true)
    try {
      const configs = unifiedDictionaryService.getAvailableTypes()
      const typeCodes = configs.map(config => config.code)
      setTypes(typeCodes)
    } catch (error) {
      console.error('获取字典类型失败:', error)
    } finally {
      setLoading(false)
    }
  }, [])

  const createDictionary = useCallback(async (dictType: string, options: Array<{
    label: string
    value: string
    code?: string
  }>) => {
    try {
      const success = await unifiedDictionaryService.quickCreate(dictType, { options })
      if (success) {
        await loadTypes() // 刷新类型列表
      }
      return success
    } catch (error) {
      console.error('创建字典失败:', error)
      return false
    }
  }, [loadTypes])

  const deleteDictionary = useCallback(async (dictType: string) => {
    try {
      const success = await unifiedDictionaryService.deleteType(dictType)
      if (success) {
        await loadTypes() // 刷新类型列表
      }
      return success
    } catch (error) {
      console.error('删除字典失败:', error)
      return false
    }
  }, [loadTypes])

  useEffect(() => {
    loadTypes()
  }, [loadTypes])

  return {
    types,
    loading,
    createDictionary,
    deleteDictionary,
    refresh: loadTypes
  }
}

import { useCallback } from 'react'
import { useNavigate } from 'react-router-dom'
import SuccessNotification from '@/components/Feedback/SuccessNotification'

interface ErrorInfo {
  code?: string | number
  message: string
  details?: Record<string, unknown>
  timestamp?: string
}

interface UseErrorHandlerOptions {
  showNotification?: boolean
  redirectOnError?: boolean
  logErrors?: boolean
}

export const useErrorHandler = (options: UseErrorHandlerOptions = {}) => {
  const {
    showNotification = true,
    redirectOnError = false,
    logErrors = true,
  } = options

  const navigate = useNavigate()

  // 处理API错误
  const handleApiError = useCallback((error: { response?: { status: number; data?: Record<string, unknown> }; message?: string }) => {
    let errorInfo: ErrorInfo = {
      message: '未知错误',
      timestamp: new Date().toISOString(),
    }

    // 解析不同类型的错误
    if (error?.response) {
      // HTTP错误响应
      const { status, data } = error.response
      errorInfo = {
        code: status,
        message: data?.message || data?.error || `HTTP ${status} 错误`,
        details: data,
        timestamp: new Date().toISOString(),
      }

      // 根据状态码处理
      switch (status) {
        case 400:
          errorInfo.message = data?.message || '请求参数错误'
          break
        case 401:
          errorInfo.message = '登录已过期，请重新登录'
          if (redirectOnError) {
            navigate('/login')
          }
          break
        case 403:
          errorInfo.message = '权限不足，无法访问'
          break
        case 404:
          errorInfo.message = '请求的资源不存在'
          break
        case 422:
          errorInfo.message = data?.message || '数据验证失败'
          break
        case 429:
          errorInfo.message = '请求过于频繁，请稍后重试'
          break
        case 500:
          errorInfo.message = '服务器内部错误'
          break
        case 502:
          errorInfo.message = '网关错误'
          break
        case 503:
          errorInfo.message = '服务暂时不可用'
          break
        case 504:
          errorInfo.message = '请求超时'
          break
        default:
          errorInfo.message = data?.message || `服务器错误 (${status})`
      }
    } else if (error?.request) {
      // 网络错误
      errorInfo = {
        code: 'NETWORK_ERROR',
        message: '网络连接失败，请检查网络设置',
        details: error.request,
        timestamp: new Date().toISOString(),
      }
    } else if (error?.message) {
      // JavaScript错误
      errorInfo = {
        code: 'CLIENT_ERROR',
        message: error.message,
        details: error,
        timestamp: new Date().toISOString(),
      }
    }

    // 记录错误日志
    if (logErrors) {
      console.error('Error handled:', errorInfo)
      
      // 发送错误报告到监控服务
      reportError(errorInfo)
    }

    // 显示错误通知
    if (showNotification) {
      if (errorInfo.code === 401) {
        SuccessNotification.warning.permission()
      } else if (errorInfo.code === 'NETWORK_ERROR') {
        SuccessNotification.error.network()
      } else if (typeof errorInfo.code === 'number' && errorInfo.code >= 500) {
        SuccessNotification.error.server()
      } else {
        SuccessNotification.notify({
          type: 'error',
          title: '操作失败',
          description: errorInfo.message,
        })
      }
    }

    return errorInfo
  }, [navigate, showNotification, redirectOnError, logErrors])

  // 处理表单验证错误
  const handleValidationError = useCallback((errors: Record<string, string[]>) => {
    const errorMessages = Object.entries(errors)
      .map(([field, messages]) => `${field}: ${messages.join(', ')}`)
      .join('\n')

    if (showNotification) {
      SuccessNotification.error.validation(errorMessages)
    }

    if (logErrors) {
      console.error('Validation errors:', errors)
    }

    return errors
  }, [showNotification, logErrors])

  // 处理业务逻辑错误
  const handleBusinessError = useCallback((message: string, code?: string) => {
    const errorInfo: ErrorInfo = {
      code: code || 'BUSINESS_ERROR',
      message,
      timestamp: new Date().toISOString(),
    }

    if (logErrors) {
      console.error('Business error:', errorInfo)
    }

    if (showNotification) {
      SuccessNotification.notify({
        type: 'warning',
        title: '操作提示',
        description: message,
      })
    }

    return errorInfo
  }, [showNotification, logErrors])

  // 处理文件上传错误
  const handleUploadError = useCallback((error: { response?: { status: number }; message?: string }) => {
    let message = '文件上传失败'

    if (error?.response?.status === 413) {
      message = '文件大小超出限制'
    } else if (error?.response?.status === 415) {
      message = '不支持的文件格式'
    } else if (error?.message?.includes('timeout')) {
      message = '上传超时，请重试'
    }

    const errorInfo: ErrorInfo = {
      code: 'UPLOAD_ERROR',
      message,
      details: error,
      timestamp: new Date().toISOString(),
    }

    if (logErrors) {
      console.error('Upload error:', errorInfo)
    }

    if (showNotification) {
      SuccessNotification.error.upload()
    }

    return errorInfo
  }, [showNotification, logErrors])

  // 重试机制
  const withRetry = useCallback(async <T>(
    operation: () => Promise<T>,
    maxRetries: number = 3,
    delay: number = 1000
  ): Promise<T> => {
    let lastError: unknown

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        return await operation()
      } catch (error) {
        lastError = error
        
        if (attempt === maxRetries) {
          break
        }

        // 指数退避延迟
        const waitTime = delay * Math.pow(2, attempt - 1)
        await new Promise(resolve => setTimeout(resolve, waitTime))
      }
    }

    throw lastError
  }, [])

  return {
    handleApiError,
    handleValidationError,
    handleBusinessError,
    handleUploadError,
    withRetry,
  }
}

// 错误报告函数
const reportError = (errorInfo: ErrorInfo) => {
  // 这里可以集成错误监控服务
  try {
    // 示例：发送到后端API
    // fetch('/api/errors', {
    //   method: 'POST',
    //   headers: { 'Content-Type': 'application/json' },
    //   body: JSON.stringify({
    //     ...errorInfo,
    //     userAgent: navigator.userAgent,
    //     url: window.location.href,
    //     userId: getCurrentUserId(), // 如果有用户信息
    //   }),
    // }).catch(console.error)

    // 示例：发送到第三方监控服务
    // if (window.Sentry) {
    //   window.Sentry.captureException(new Error(errorInfo.message), {
    //     extra: errorInfo,
    //   })
    // }
  } catch (error) {
    console.error('Failed to report error:', error)
  }
}

