/**
 * 路由性能监控器
 * 监控路由加载时间、交互性能和用户体验指标
 */

import { useEffect, useRef, useCallback } from 'react'
import { useLocation, useNavigationType } from 'react-router-dom'

interface RoutePerformanceMetrics {
  // Core Web Vitals
  FCP?: number  // First Contentful Paint
  LCP?: number  // Largest Contentful Paint
  FID?: number  // First Input Delay
  CLS?: number  // Cumulative Layout Shift

  // Route specific metrics
  routeLoadTime: number
  componentLoadTime: number
  renderTime: number
  interactiveTime: number

  // Memory metrics
  memoryUsage?: number
  jsHeapSize?: number

  // Network metrics
  resourceLoadTimes: Array<{ name: string; duration: number; size: number }>

  // User experience metrics
  errorCount: number
  retryCount: number

  // Metadata
  route: string
  navigationType: string
  timestamp: number
  userAgent: string
  sessionId: string
}

interface RoutePerformanceConfig {
  enableWebVitals: boolean
  enableMemoryTracking: boolean
  enableNetworkTracking: boolean
  sampleRate: number
  maxStoredMetrics: number
  reportInterval: number
  enableAutoReporting: boolean
}

class RoutePerformanceMonitor {
  private config: RoutePerformanceConfig
  private metrics: RoutePerformanceMetrics[]
  private observers: PerformanceObserver[]
  private sessionId: string
  private reportTimer: NodeJS.Timeout | null = null
  private isSupported: boolean

  constructor(config: Partial<RoutePerformanceConfig> = {}) {
    this.config = {
      enableWebVitals: true,
      enableMemoryTracking: true,
      enableNetworkTracking: true,
      sampleRate: 1.0,
      maxStoredMetrics: 100,
      reportInterval: 30000, // 30秒
      enableAutoReporting: true,
      ...config
    }

    this.metrics = []
    this.observers = []
    this.sessionId = this.generateSessionId()
    this.isSupported = this.checkSupport()

    if (this.isSupported) {
      this.initializeObservers()
      this.startAutoReporting()
    }
  }

  private generateSessionId(): string {
    return `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
  }

  private checkSupport(): boolean {
    return !!(window.performance && window.PerformanceObserver)
  }

  private initializeObservers() {
    if (!this.isSupported) return

    // Core Web Vitals
    if (this.config.enableWebVitals) {
      this.observeWebVitals()
    }

    // Resource timing
    if (this.config.enableNetworkTracking) {
      this.observeResourceTiming()
    }

    // Memory timing (Chrome only)
    if (this.config.enableMemoryTracking && (performance as unknown as { memory?: { usedJSHeapSize: number; totalJSHeapSize: number } }).memory) {
      this.observeMemory()
    }
  }

  private observeWebVitals() {
    try {
      // First Contentful Paint
      const fcpObserver = new PerformanceObserver((list) => {
        for (const entry of list.getEntries()) {
          if (entry.name === 'first-contentful-paint') {
            this.updateCurrentMetric('FCP', entry.startTime)
          }
        }
      })
      fcpObserver.observe({ entryTypes: ['paint'] })
      this.observers.push(fcpObserver)

      // Largest Contentful Paint
      const lcpObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries()
        const lastEntry = entries[entries.length - 1]
        if (lastEntry) {
          this.updateCurrentMetric('LCP', lastEntry.startTime)
        }
      })
      lcpObserver.observe({ entryTypes: ['largest-contentful-paint'] })
      this.observers.push(lcpObserver)

      // First Input Delay
      const fidObserver = new PerformanceObserver((list) => {
        for (const entry of list.getEntries()) {
          this.updateCurrentMetric('FID', (entry as PerformanceEventTiming & { processingStart?: number }).processingStart ? (entry as PerformanceEventTiming & { processingStart: number }).processingStart - entry.startTime : 0)
        }
      })
      fidObserver.observe({ entryTypes: ['first-input'] })
      this.observers.push(fidObserver)

      // Cumulative Layout Shift
      let clsValue = 0
      const clsObserver = new PerformanceObserver((list) => {
        for (const entry of list.getEntries()) {
          const layoutShiftEntry = entry as PerformanceEntry & { hadRecentInput?: boolean; value?: number }
          if (!layoutShiftEntry.hadRecentInput && layoutShiftEntry.value) {
            clsValue += layoutShiftEntry.value
          }
        }
        this.updateCurrentMetric('CLS', clsValue)
      })
      clsObserver.observe({ entryTypes: ['layout-shift'] })
      this.observers.push(clsObserver)
    } catch (error) {
      console.warn('Web Vitals observer initialization failed:', error)
    }
  }

  private observeResourceTiming() {
    try {
      const resourceObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries()
        const resourceTimes = entries.map(entry => ({
          name: entry.name,
          duration: entry.duration,
          size: (entry as PerformanceResourceTiming).transferSize || 0
        }))
        this.updateCurrentMetric('resourceLoadTimes', resourceTimes)
      })
      resourceObserver.observe({ entryTypes: ['resource'] })
      this.observers.push(resourceObserver)
    } catch (error) {
      console.warn('Resource timing observer initialization failed:', error)
    }
  }

  private observeMemory() {
    try {
      const memoryObserver = new PerformanceObserver(() => {
        const memory = (performance as unknown as { memory?: { usedJSHeapSize: number; totalJSHeapSize: number } }).memory
        if (memory) {
          this.updateCurrentMetric('memoryUsage', memory.usedJSHeapSize)
          this.updateCurrentMetric('jsHeapSize', memory.totalJSHeapSize)
        }
      })
      memoryObserver.observe({ entryTypes: ['measure'] })
      this.observers.push(memoryObserver)
    } catch (error) {
      console.warn('Memory observer initialization failed:', error)
    }
  }

  private updateCurrentMetric(key: keyof RoutePerformanceMetrics, value: unknown) {
    if (this.metrics.length === 0) return

    const currentMetric = this.metrics[this.metrics.length - 1]
    ;(currentMetric as Record<string, unknown>)[key] = value
  }

  startRouteMonitoring(route: string, navigationType: string) {
    if (!this.isSupported) return

    // 如果采样率不满，则跳过
    if (Math.random() > this.config.sampleRate) return

    const startTime = performance.now()

    const metric: RoutePerformanceMetrics = {
      routeLoadTime: 0,
      componentLoadTime: 0,
      renderTime: 0,
      interactiveTime: 0,
      resourceLoadTimes: [],
      errorCount: 0,
      retryCount: 0,
      route,
      navigationType,
      timestamp: Date.now(),
      userAgent: navigator.userAgent,
      sessionId: this.sessionId
    }

    this.metrics.push(metric)

    // 清理旧的指标
    if (this.metrics.length > this.config.maxStoredMetrics) {
      this.metrics = this.metrics.slice(-this.config.maxStoredMetrics)
    }

    // 设置性能标记
    performance.mark(`route-start-${route}`)

    return {
      endComponentLoad: () => {
        const componentTime = performance.now() - startTime
        this.updateCurrentMetric('componentLoadTime', componentTime)
        performance.mark(`component-loaded-${route}`)
      },

      endRender: () => {
        const renderTime = performance.now() - startTime
        this.updateCurrentMetric('renderTime', renderTime)
        performance.mark(`render-complete-${route}`)
      },

      endInteractive: () => {
        const interactiveTime = performance.now() - startTime
        this.updateCurrentMetric('interactiveTime', interactiveTime)
        this.updateCurrentMetric('routeLoadTime', interactiveTime)
        performance.mark(`route-interactive-${route}`)

        // 创建性能测量
        try {
          performance.measure(
            `route-total-${route}`,
            `route-start-${route}`,
            `route-interactive-${route}`
          )
        } catch (error) {
          // 忽略测量错误
        }
      }
    }
  }

  recordError(route: string, error: Error) {
    const metric = this.metrics.find(m => m.route === route)
    if (metric) {
      metric.errorCount++
    }
  }

  recordRetry(route: string) {
    const metric = this.metrics.find(m => m.route === route)
    if (metric) {
      metric.retryCount++
    }
  }

  getMetrics(route?: string): RoutePerformanceMetrics[] {
    if (route) {
      return this.metrics.filter(m => m.route === route)
    }
    return [...this.metrics]
  }

  getAggregatedMetrics(route?: string) {
    const metrics = this.getMetrics(route)
    if (metrics.length === 0) return null

    const aggregated = {
      avgLoadTime: 0,
      avgComponentLoadTime: 0,
      avgRenderTime: 0,
      avgInteractiveTime: 0,
      avgFCP: 0,
      avgLCP: 0,
      avgFID: 0,
      avgCLS: 0,
      totalErrors: 0,
      totalRetries: 0,
      sampleCount: metrics.length,
      routes: [...new Set(metrics.map(m => m.route))]
    }

    const sums = metrics.reduce((acc, metric) => {
      acc.routeLoadTime += metric.routeLoadTime
      acc.componentLoadTime += metric.componentLoadTime
      acc.renderTime += metric.renderTime
      acc.interactiveTime += metric.interactiveTime
      acc.FCP += metric.FCP || 0
      acc.LCP += metric.LCP || 0
      acc.FID += metric.FID || 0
      acc.CLS += metric.CLS || 0
      acc.errorCount += metric.errorCount
      acc.retryCount += metric.retryCount
      return acc
    }, {
      routeLoadTime: 0,
      componentLoadTime: 0,
      renderTime: 0,
      interactiveTime: 0,
      FCP: 0,
      LCP: 0,
      FID: 0,
      CLS: 0,
      errorCount: 0,
      retryCount: 0
    })

    const count = metrics.length
    aggregated.avgLoadTime = sums.routeLoadTime / count
    aggregated.avgComponentLoadTime = sums.componentLoadTime / count
    aggregated.avgRenderTime = sums.renderTime / count
    aggregated.avgInteractiveTime = sums.interactiveTime / count
    aggregated.avgFCP = sums.FCP / count
    aggregated.avgLCP = sums.LCP / count
    aggregated.avgFID = sums.FID / count
    aggregated.avgCLS = sums.CLS / count
    aggregated.totalErrors = sums.errorCount
    aggregated.totalRetries = sums.retryCount

    return aggregated
  }

  private startAutoReporting() {
    if (!this.config.enableAutoReporting) return

    this.reportTimer = setInterval(() => {
      this.reportMetrics()
    }, this.config.reportInterval)
  }

  private async reportMetrics() {
    if (this.metrics.length === 0) return

    try {
      const reportData = {
        sessionId: this.sessionId,
        metrics: this.metrics,
        aggregated: this.getAggregatedMetrics(),
        timestamp: Date.now()
      }

      // 发送到监控服务
      await fetch('/api/v1/monitoring/route-performance', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(reportData)
      })

      // Route metrics reported
    } catch (error) {
      console.warn('性能指标上报失败:', error)
    }
  }

  clearMetrics() {
    this.metrics = []
  }

  destroy() {
    // 清理观察者
    this.observers.forEach(observer => {
      observer.disconnect()
    })
    this.observers = []

    // 清理定时器
    if (this.reportTimer) {
      clearInterval(this.reportTimer)
      this.reportTimer = null
    }

    this.clearMetrics()
  }
}

// Hook for using the performance monitor
export const useRoutePerformanceMonitor = (config?: Partial<RoutePerformanceConfig>) => {
  const location = useLocation()
  const navigationType = useNavigationType()
  const monitorRef = useRef<RoutePerformanceMonitor>()
  const monitoringRef = useRef<{
    endComponentLoad: () => void;
    endRender: () => void;
    endInteractive: () => void;
  } | null>(null)

  // Initialize monitor
  if (!monitorRef.current) {
    monitorRef.current = new RoutePerformanceMonitor(config)
  }

  const monitor = monitorRef.current

  // Start monitoring when route changes
  useEffect(() => {
    if (!monitor) return

    const route = location.pathname
    const navType = navigationType === 'POP' ? 'back' :
                     navigationType === 'PUSH' ? 'navigate' : 'replace'

    const monitoring = monitor.startRouteMonitoring(route, navType)
    monitoringRef.current = monitoring

    // Record when route becomes interactive
    const timer = setTimeout(() => {
      if (monitoring) {
        monitoring.endInteractive()
      }
    }, 100)

    return () => {
      clearTimeout(timer)
    }
  }, [location.pathname, navigationType, monitor])

  // Cleanup
  useEffect(() => {
    return () => {
      if (monitor) {
        monitor.destroy()
      }
    }
  }, [monitor])

  const recordError = useCallback((error: Error) => {
    if (monitor) {
      monitor.recordError(location.pathname, error)
    }
  }, [monitor, location.pathname])

  const recordRetry = useCallback(() => {
    if (monitor) {
      monitor.recordRetry(location.pathname)
    }
  }, [monitor, location.pathname])

  const getMetrics = useCallback((route?: string) => {
    return monitor ? monitor.getMetrics(route) : []
  }, [monitor])

  const getAggregatedMetrics = useCallback((route?: string) => {
    return monitor ? monitor.getAggregatedMetrics(route) : null
  }, [monitor])

  return {
    recordError,
    recordRetry,
    getMetrics,
    getAggregatedMetrics,
    monitor
  }
}

// Development tools
export const usePerformanceDebug = () => {
  const { getMetrics, getAggregatedMetrics } = useRoutePerformanceMonitor()

  useEffect(() => {
    if (process.env.NODE_ENV === 'development') {
      // 暴露到全局对象用于调试
      (window as unknown as { __ROUTE_PERFORMANCE__?: {
        getMetrics: () => RoutePerformanceMetrics[];
        getAggregatedMetrics: () => ReturnType<RoutePerformanceMonitor['getAggregatedMetrics']>;
        exportData: () => {
          metrics: RoutePerformanceMetrics[];
          aggregated: ReturnType<RoutePerformanceMonitor['getAggregatedMetrics']>;
          timestamp: number
        }
      } }).__ROUTE_PERFORMANCE__ = {
        getMetrics,
        getAggregatedMetrics,
        exportData: () => ({
          metrics: getMetrics(),
          aggregated: getAggregatedMetrics(),
          timestamp: Date.now()
        })
      }
    }
  }, [getMetrics, getAggregatedMetrics])
}

export default RoutePerformanceMonitor

import React, { useState } from 'react'
import { Card, Row, Col, Spin, Alert, Empty, Typography, Space, Tag, Button, Statistic, message, Switch, Radio } from 'antd'
import styles from './AssetAnalyticsPage.module.css'
import { useQuery } from '@tanstack/react-query'
import {
  ReloadOutlined,
  DownloadOutlined,
  FullscreenOutlined,
  SettingOutlined
} from '@ant-design/icons'
import { analyticsService, type AnalyticsData } from '@/services/analyticsService'
import { exportAnalyticsData } from '@/services/analyticsExportService'
import { AnalyticsStatsGrid, FinancialStatsGrid } from '@/components/Analytics/AnalyticsStatsCard'
import {
  AnalyticsPieChart,
  AnalyticsBarChart,
  AnalyticsLineChart,
  chartDataUtils
} from '@/components/Analytics/AnalyticsChart'
import AnalyticsFilters from '@/components/Analytics/AnalyticsFilters'
import type { AssetSearchParams } from '@/types/asset'

const { Title, Text } = Typography

// 分析维度类型
type AnalysisDimension = 'count' | 'area'

const AssetAnalyticsPage: React.FC = () => {
  const [filters, setFilters] = useState<AssetSearchParams>({})
  const [showAdvancedFilters, setShowAdvancedFilters] = useState(false)
  const [dimension, setDimension] = useState<AnalysisDimension>('area')

  // 获取分析数据
  const { data: analyticsResponse, isLoading, error, refetch } = useQuery({
    queryKey: ['asset-analytics', filters],
    queryFn: async () => {
      const result = await analyticsService.getComprehensiveAnalytics(filters)
      return result
    },
    staleTime: 5 * 60 * 1000, // 5分钟缓存
    refetchOnWindowFocus: false
  })

  // React Query 可能直接返回解析后的数据，也可能是包装在响应对象中
  // 我们需要检查两种可能性
  let analytics
  if (analyticsResponse && analyticsResponse.data) {
    // 标准情况：analyticsResponse 是 AnalyticsResponse 类型
    analytics = analyticsResponse.data
  } else if (analyticsResponse && analyticsResponse.area_summary) {
    // React Query 直接返回了 AnalyticsData
    analytics = analyticsResponse
  } else {
    // 没有数据
    analytics = null
  }

  
  // 处理筛选条件变化
  const handleFilterChange = (newFilters: AssetSearchParams) => {
    setFilters(newFilters)
  }

  // 处理筛选条件重置
  const handleFilterReset = () => {
    setFilters({})
  }

  // 处理维度切换
  const handleDimensionChange = (newDimension: AnalysisDimension) => {
    setDimension(newDimension)
  }

  // 处理导出数据
  const handleExport = async () => {
    if (!analytics) return

    try {
      message.loading('正在导出数据...', 0)

      const exportData = {
        summary: {
          total_assets: analytics.area_summary.total_assets,
          total_area: analytics.area_summary.total_area,
          total_rentable_area: analytics.area_summary.total_rentable_area,
          occupancy_rate: analytics.area_summary.occupancy_rate,
          total_annual_income: analytics.financial_summary.total_annual_income,
          total_annual_expense: analytics.financial_summary.total_annual_expense,
          total_net_income: analytics.financial_summary.total_net_income,
          total_monthly_rent: analytics.financial_summary.total_monthly_rent
        },
        property_nature_distribution: analytics.property_nature_distribution,
        ownership_status_distribution: analytics.ownership_status_distribution,
        usage_status_distribution: analytics.usage_status_distribution,
        business_category_distribution: analytics.business_category_distribution,
        occupancy_trend: analytics.occupancy_trend,
        // 面积维度数据
        property_nature_area_distribution: analytics.property_nature_area_distribution,
        ownership_status_area_distribution: analytics.ownership_status_area_distribution,
        usage_status_area_distribution: analytics.usage_status_area_distribution,
        business_category_area_distribution: analytics.business_category_area_distribution
      }

      await exportAnalyticsData(exportData, 'excel')
      message.success('数据导出成功！')
    } catch (error) {
      console.error('导出失败:', error)
      message.error('导出失败，请重试')
    } finally {
      message.destroy()
    }
  }

  if (isLoading) {
    return (
      <div style={{ padding: '24px', textAlign: 'center' }}>
        <Spin size="large" />
        <div style={{ marginTop: '16px' }}>加载分析数据中...</div>
      </div>
    )
  }

  if (error) {
    // 调试 - 显示错误详情
    console.error('Analytics Error:', error)
    return (
      <div style={{ padding: '24px' }}>
        <Alert
          message="数据加载失败"
          description={`错误详情: ${error instanceof Error ? error.message : '未知错误'}`}
          type="error"
          showIcon
        />
      </div>
    )
  }

  const hasData = analytics && analytics.area_summary && Number(analytics.area_summary.total_assets) > 0

  
  return (
    <div className={styles.analyticsContainer}>
      {/* 页面标题和操作栏 */}
      <Card style={{ marginBottom: '24px' }}>
        <Row justify="space-between" align={['middle', 'stretch']} gutter={[16, 16]}>
          <Col xs={24} sm={12}>
            <Typography.Title level={3} style={{ margin: 0 }}>
              资产分析
            </Typography.Title>
          </Col>
          <Col xs={24} sm={12}>
            <Space wrap className={styles.headerActions}>
              <Button
                icon={<ReloadOutlined />}
                onClick={() => refetch()}
                loading={isLoading}
                size="small"
                className="no-print"
              >
                <span className={styles.btnText}>刷新</span>
              </Button>
              <Button
                icon={<DownloadOutlined />}
                onClick={handleExport}
                disabled={!hasData}
                size="small"
                className="no-print"
              >
                <span className={styles.btnText}>导出</span>
              </Button>
              <Button
                icon={<FullscreenOutlined />}
                onClick={() => {
                  // TODO: 实现全屏功能
                }}
                size="small"
                className="no-print"
              >
                <span className={styles.btnText}>全屏</span>
              </Button>
            </Space>
          </Col>
        </Row>
      </Card>

      {/* 筛选条件 */}
      <AnalyticsFilters
        filters={filters}
        onFiltersChange={handleFilterChange}
        onResetFilters={handleFilterReset}
        loading={isLoading}
      />

      {/* 维度切换 */}
      <Card style={{ marginBottom: '24px' }}>
        <Space align="center">
          <Text strong>分析维度：</Text>
          <Radio.Group
            value={dimension}
            onChange={(e) => handleDimensionChange(e.target.value)}
            buttonStyle="solid"
          >
            <Radio.Button value="count">数量维度</Radio.Button>
            <Radio.Button value="area">面积维度</Radio.Button>
          </Radio.Group>
          <Text type="secondary">
            {dimension === 'count' ? '基于资产个数进行分析' : '基于资产面积进行分析'}
          </Text>
        </Space>
      </Card>

      {!hasData ? (
        <Card>
          <Empty
            description="暂无数据"
            style={{ padding: '60px 0' }}
          >
            <p>数据库中还没有资产数据，请先录入资产信息</p>
          </Empty>
        </Card>
      ) : (
        <>
          {/* 概览统计卡片 */}
          <Card title="概览统计" style={{ marginBottom: '24px' }}>
            <AnalyticsStatsGrid
              data={{
                total_assets: analytics.area_summary.total_assets,
                total_area: analytics.area_summary.total_area,
                total_rentable_area: analytics.area_summary.total_rentable_area,
                occupancy_rate: analytics.area_summary.occupancy_rate,
                total_annual_income: analytics.financial_summary.total_annual_income,
                total_net_income: analytics.financial_summary.total_net_income,
                total_monthly_rent: analytics.financial_summary.total_monthly_rent
              }}
              loading={isLoading}
            />
          </Card>

          {/* 分布图表 */}
          <Row gutter={[16, 16]} style={{ marginBottom: '24px' }}>
            {/* 物业性质分布饼图 */}
            <Col xs={24} sm={12} xl={6}>
              <AnalyticsPieChart
                title={`物业性质分布 (${dimension === 'count' ? '数量' : '面积'})`}
                data={dimension === 'count'
                  ? chartDataUtils.toPieData(analytics.property_nature_distribution)
                  : chartDataUtils.toAreaData(analytics.property_nature_area_distribution)
                }
                loading={isLoading}
                height={280}
              />
            </Col>

            {/* 确权状态分布饼图 */}
            <Col xs={24} sm={12} xl={6}>
              <AnalyticsPieChart
                title={`确权状态分布 (${dimension === 'count' ? '数量' : '面积'})`}
                data={dimension === 'count'
                  ? chartDataUtils.toPieData(analytics.ownership_status_distribution.map(item => ({
                      name: item.status,
                      count: item.count,
                      percentage: item.percentage
                    })))
                  : chartDataUtils.toAreaData(analytics.ownership_status_area_distribution.map(item => ({
                      name: item.status,
                      total_area: item.total_area,
                      area_percentage: item.area_percentage,
                      average_area: item.average_area
                    })))
                }
                loading={isLoading}
                height={280}
              />
            </Col>

            {/* 使用状态分布柱状图 */}
            <Col xs={24} sm={12} xl={6}>
              <AnalyticsBarChart
                title={`使用状态分布 (${dimension === 'count' ? '数量' : '面积'})`}
                data={dimension === 'count'
                  ? analytics.usage_status_distribution.map(item => ({
                      name: item.status,
                      value: item.count
                    }))
                  : chartDataUtils.toAreaBarData(analytics.usage_status_area_distribution.map(item => ({
                      name: item.status,
                      total_area: item.total_area,
                      count: item.count,
                      average_area: item.average_area
                    })))
                }
                xAxisKey="name"
                barKey="value"
                loading={isLoading}
                height={280}
              />
            </Col>

            {/* 业态类别分布柱状图 */}
            <Col xs={24} sm={12} xl={6}>
              <AnalyticsBarChart
                title={`业态类别分布 (${dimension === 'count' ? '数量' : '面积'})`}
                data={dimension === 'count'
                  ? chartDataUtils.toBusinessCategoryData(analytics.business_category_distribution)
                  : chartDataUtils.toBusinessCategoryAreaData(analytics.business_category_area_distribution)
                }
                xAxisKey="name"
                barKey="value"
                loading={isLoading}
