  Tag,
  Timeline,
  Statistic,
  Modal,
  message,
  Descriptions,
  Divider
} from 'antd';
import {
  CheckCircleOutlined,
  LoadingOutlined,
  ExclamationCircleOutlined,
  CloseCircleOutlined,
  SyncOutlined,
  FileTextOutlined,
  RobotOutlined,
  DatabaseOutlined,
  EyeOutlined,
  DownloadOutlined,
  ReloadOutlined
} from '@ant-design/icons';

import {
  pdfImportService,
  type SessionProgress,
  type CompleteResult,
  type FileUploadResponse
} from '../../services/pdfImportService';

const { Title, Text, Paragraph } = Typography;
const { Step } = Steps;

interface ContractImportStatusProps {
  sessionId: string;
  fileInfo: FileUploadResponse['file_info'];
  onComplete: (result: CompleteResult) => void;
  onError: (error: string) => void;
  onCancel: () => void;
}

interface ProcessingStep {
  title: string;
  description: string;
  icon: React.ReactNode;
  status: 'wait' | 'process' | 'finish' | 'error';
  details?: string;
}

const ContractImportStatus: React.FC<ContractImportStatusProps> = ({
  sessionId,
  fileInfo,
  onComplete,
  onError,
  onCancel
}) => {
  const [currentProgress, setCurrentProgress] = useState<SessionProgress | null>(null);
  const [steps, setSteps] = useState<ProcessingStep[]>([]);
  const [result, setResult] = useState<CompleteResult | null>(null);
  const [showDetailsModal, setShowDetailsModal] = useState(false);
  const [autoRefresh, setAutoRefresh] = useState(true);

  // 初始化步骤
  useEffect(() => {
    // Component initialized

    const initialSteps: ProcessingStep[] = [
      {
        title: '文件上传',
        description: '上传PDF文件到服务器',
        icon: <FileTextOutlined />,
        status: 'finish',
        details: `文件: ${fileInfo?.filename} (${pdfImportService.formatFileSize(fileInfo?.size || 0)})`
      },
      {
        title: '文档转换',
        description: '将PDF转换为Markdown格式',
        icon: <RobotOutlined />,
        status: 'process',
        details: '使用MarkItDown引擎进行转换'
      },
      {
        title: '信息提取',
        description: '提取合同关键信息',
        icon: <DatabaseOutlined />,
        status: 'wait',
        details: '智能识别58个关键字段'
      },
      {
        title: '数据验证',
        description: '验证数据完整性和格式',
        icon: <CheckCircleOutlined />,
        status: 'wait',
        details: '检查必填字段和业务逻辑'
      },
      {
        title: '智能匹配',
        description: '匹配现有资产和权属方',
        icon: <EyeOutlined />,
        status: 'wait',
        details: '模糊匹配相似数据'
      }
    ];
    setSteps(initialSteps);
  }, [fileInfo, sessionId]);

  // 轮询进度
  const pollProgress = useCallback(async () => {
    try {
      const response = await pdfImportService.getProgress(sessionId);

      if (response.success && response.session_status) {
        setCurrentProgress(response.session_status);

        // 更新步骤状态
        updateStepsStatus(response.session_status);

        // 检查是否完成
        if (response.session_status.status === 'ready_for_review') {
          // 停止自动刷新
          setAutoRefresh(false);

          // 获取完整结果
          const resultResponse = await pdfImportService.getResult(sessionId);
          if (resultResponse.success && resultResponse.result) {
            setResult(resultResponse.result);
            onComplete(resultResponse.result);
          }
        } else if (response.session_status.status === 'failed') {
          // 停止自动刷新
          setAutoRefresh(false);
          onError(response.session_status.error_message || '处理失败');
        } else if (response.session_status.status === 'cancelled') {
          // 停止自动刷新
          setAutoRefresh(false);
          onError('处理已取消');
        }
      }
    } catch (error: unknown) {
      console.error('获取进度失败:', error);
      // 不立即调用onError，让轮询继续
      // 只有在连续多次失败时才停止
    }
  }, [sessionId, onComplete, onError]);

  // 自动轮询
  useEffect(() => {
    if (!autoRefresh) return;

    // 立即执行一次轮询
    pollProgress();

    // 然后每1.5秒轮询一次
    const interval = setInterval(() => {
      pollProgress();
    }, 1500);

    return () => clearInterval(interval);
  }, [autoRefresh, pollProgress]);

  // 更新步骤状态
  const updateStepsStatus = (progress: SessionProgress) => {
    setSteps(prevSteps => {
      const newSteps = [...prevSteps];
      const stepMapping: Record<string, number> = {
        'created': 0,
        'converting_pdf': 1,
        'extracting_info': 2,
        'validating_data': 3,
        'matching_data': 4,
        'ready_for_review': 5,
        'completed': 5,
        'failed': 5
      };

      const currentStep = stepMapping[progress.current_step] || 0;

      newSteps.forEach((step, index) => {
        if (index < currentStep) {
          step.status = 'finish';
        } else if (index === currentStep) {
          step.status = progress.status === 'failed' ? 'error' : 'process';
          step.details = progress.error_message || step.description;
        } else {
          step.status = 'wait';
        }
      });

      return newSteps;
    });
  };

  // 手动刷新
  const handleRefresh = () => {
    pollProgress();
  };

  // 下载原始文件
  const handleDownload = () => {
    message.info('下载功能待实现');
  };

  // 获取状态颜色
  const getStatusColor = (status: string) => {
    switch (status) {
      case 'ready_for_review': return '#52c41a';
      case 'failed':
      case 'cancelled': return '#ff4d4f';
      case 'completed': return '#1890ff';
      default: return '#faad14';
    }
  };

  // 获取状态文本
  const getStatusText = (status: string) => {
    switch (status) {
      case 'created': return '已创建';
      case 'converting': return '转换中';
      case 'extracting': return '提取中';
      case 'validating': return '验证中';
      case 'matching': return '匹配中';
      case 'ready_for_review': return '待确认';
      case 'failed': return '处理失败';
      case 'cancelled': return '已取消';
      case 'imported': return '已导入';
      default: return '处理中';
    }
  };

  // 获取状态图标
  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'ready_for_review': return <CheckCircleOutlined />;
      case 'failed':
      case 'cancelled': return <CloseCircleOutlined />;
      case 'completed': return <CheckCircleOutlined />;
      default: return <LoadingOutlined />;
    }
  };

  return (
    <div className="contract-import-status">
      {/* 头部信息 */}
      <Card style={{ marginBottom: 16 }}>
        <Row justify="space-between" align="middle">
          <Col>
            <Space size="large">
              <div>
                <Title level={4} style={{ margin: 0 }}>
                  PDF合同处理状态
                </Title>
                <Text type="secondary">
                  会话ID: {sessionId}
                </Text>
              </div>
            </Space>
          </Col>
          <Col>
            <Space>
              <Button
                icon={<ReloadOutlined />}
                onClick={handleRefresh}
                loading={!currentProgress}
              >
                刷新
              </Button>
              <Button
                icon={<DownloadOutlined />}
                onClick={handleDownload}
                disabled={!fileInfo}
              >
                下载
              </Button>
              <Button onClick={onCancel}>
                取消
              </Button>
            </Space>
          </Col>
        </Row>
      </Card>

      {/* 当前状态 */}
      {currentProgress && (
        <Card style={{ marginBottom: 16 }}>
          <Row gutter={16} align="middle">
            <Col flex="auto">
              <Space>
                <div style={{
                  width: 40,
                  height: 40,
                  borderRadius: '50%',
                  backgroundColor: getStatusColor(currentProgress.status),
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  color: 'white'
                }}>
                  {getStatusIcon(currentProgress.status)}
                </div>
                <div>
                  <Title level={5} style={{ margin: 0, color: getStatusColor(currentProgress.status) }}>
                    {getStatusText(currentProgress.status)}
                  </Title>
                  <Text type="secondary">
                    {currentProgress.current_step}
                  </Text>
                </div>
              </Space>
            </Col>
            <Col>
              <Statistic
                title="处理进度"
                value={currentProgress.progress}
                precision={0}
                suffix="%"
                valueStyle={{
                  color: getStatusColor(currentProgress.status)
                }}
              />
            </Col>
          </Row>

          {currentProgress.error_message && (
            <Alert
              message="处理错误"
              description={currentProgress.error_message}
              type="error"
              showIcon
              style={{ marginTop: 16 }}
            />
          )}
        </Card>
      )}

      {/* 处理步骤 */}
      <Card title="处理步骤" style={{ marginBottom: 16 }}>
        <Steps
          current={steps.findIndex(step => step.status === 'process')}
          status={steps.some(step => step.status === 'error') ? 'error' : 'process'}
        >
          {steps.map((step, index) => (
            <Step
              key={index}
              title={step.title}
              description={
                <div>
                  <div>{step.description}</div>
                  {step.details && (
                    <Text type="secondary" style={{ fontSize: 12 }}>
                      {step.details}
                    </Text>
                  )}
                </div>
              }
              icon={step.icon}
              status={step.status}
            />
          ))}
        </Steps>
      </Card>

      {/* 详细信息 */}
      <Card>
        <Row justify="space-between" align="middle" style={{ marginBottom: 16 }}>
          <Col>
            <Title level={5}>处理详情</Title>
          </Col>
          <Col>
            <Button
              type="text"
              onClick={() => setShowDetailsModal(true)}
            >
              查看详细信息
            </Button>
          </Col>
        </Row>

        <Row gutter={16}>
          <Col span={12}>
            <Descriptions column={1} size="small">
              <Descriptions.Item label="文件名">
                {fileInfo?.filename}
              </Descriptions.Item>
              <Descriptions.Item label="文件大小">
                {pdfImportService.formatFileSize(fileInfo?.size || 0)}
              </Descriptions.Item>
              <Descriptions.Item label="文件类型">
                {fileInfo?.content_type}
              </Descriptions.Item>
              <Descriptions.Item label="创建时间">
                {currentProgress?.created_at}
              </Descriptions.Item>
              <Descriptions.Item label="更新时间">
                {currentProgress?.updated_at}
              </Descriptions.Item>
            </Descriptions>
          </Col>
          <Col span={12}>
            {currentProgress && (
              <div>
                <Title level={5}>处理时间线</Title>
                <Timeline>
                  <Timeline.Item color="blue" dot>
                    <Text strong>会话创建</Text>
                    <br />
                    <Text type="secondary">{currentProgress.created_at}</Text>
                  </Timeline.Item>
                  <Timeline.Item color="green" dot>
                    <Text strong>开始处理</Text>
                    <br />
                    <Text type="secondary">{currentProgress.created_at}</Text>
                  </Timeline.Item>
                  {currentProgress.error_message && (
                    <Timeline.Item color="red" dot>
                      <Text strong>处理失败</Text>
                      <br />
                      <Text type="secondary">{currentProgress.updated_at}</Text>
                    </Timeline.Item>
                  )}
                  {currentProgress.status === 'ready_for_review' && (
                    <Timeline.Item color="green" dot>
                      <Text strong>处理完成</Text>
                      <br />
                      <Text type="secondary">{currentProgress.updated_at}</Text>
                    </Timeline.Item>
                  )}
                </Timeline>
              </div>
            )}
          </Col>
        </Row>
      </Card>

      {/* 结果统计 */}
      {result && (
        <Card title="处理结果统计" style={{ marginTop: 16 }}>
          <Row gutter={16}>
            <Col span={6}>
              <Statistic
                title="提取字段数"
                value={result.extraction_result.processed_fields}
                suffix={`/ ${result.extraction_result.total_fields}`}
                valueStyle={{ color: '#3f8600' }}
              />
            </Col>
            <Col span={6}>
              <Statistic
                title="验证评分"
                value={result.validation_result.validation_score}
                precision={2}
                suffix="%"
                valueStyle={{ color: '#3f8600' }}
              />
            </Col>
            <Col span={6}>
              <Statistic
                title="匹配置信度"
                value={result.matching_result.match_confidence}
                precision={2}
                suffix="%"
                valueStyle={{ color: '#3f8600' }}
              />
            </Col>
            <Col span={6}>
              <Statistic
                title="总体评分"
                value={result.summary.total_confidence}
                precision={2}
                suffix="%"
                valueStyle={{ color: '#3f8600' }}
              />
            </Col>
          </Row>

          {/* 处理摘要 */}
          <Divider />
          <Descriptions column={3} size="small">
            <Descriptions.Item label="提取方法">
              {result.extraction_result.extraction_method}
            </Descriptions.Item>
            <Descriptions.Item label="提取可信度">
              <Tag color={result.summary.extraction_confidence >= 0.8 ? 'green' : 'orange'}>
                {(result.summary.extraction_confidence * 100).toFixed(1)}%
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="验证字段数">
              {result.validation_result.processed_fields}
            </Descriptions.Item>
            <Descriptions.Item label="错误数量">
              <Tag color={result.validation_result.errors.length > 0 ? 'red' : 'green'}>
                {result.validation_result.errors.length}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="警告数量">
              <Tag color={result.validation_result.warnings.length > 0 ? 'orange' : 'green'}>
                {result.validation_result.warnings.length}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="匹配资产数">
              {result.matching_result.matched_assets.length}
            </Descriptions.Item>
            <Descriptions.Item label="匹配权属方数">
              {result.matching_result.matched_ownerships.length}
            </Descriptions.Item>
            <Descriptions.Item label="重复合同数">
              <Tag color={result.matching_result.duplicate_contracts.length > 0 ? 'red' : 'green'}>
                {result.matching_result.duplicate_contracts.length}
              </Tag>
            </Descriptions.Item>
          </Descriptions>
        </Card>
      )}

      {/* 详细信息模态框 */}
      <Modal
        title="处理详细信息"
        open={showDetailsModal}
        onCancel={() => setShowDetailsModal(false)}
        footer={[
          <Button key="close" onClick={() => setShowDetailsModal(false)}>
            关闭
          </Button>
        ]}
        width={800}
      >
        {currentProgress && (
          <Descriptions column={2} bordered size="small">
            <Descriptions.Item label="会话ID">
              <Text code>{sessionId}</Text>
            </Descriptions.Item>
            <Descriptions.Item label="当前状态">
              <Tag color={getStatusColor(currentProgress.status)}>
                {getStatusText(currentProgress.status)}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="当前步骤">
              {currentProgress.current_step}
            </Descriptions.Item>
            <Descriptions.Item label="进度">
              <Progress percent={currentProgress.progress} />
            </Descriptions.Item>
            <Descriptions.Item label="创建时间">
              {currentProgress.created_at}
            </Descriptions.Item>
            <Descriptions.Item label="更新时间">
              {currentProgress.updated_at}
            </Descriptions.Item>
            <Descriptions.Item label="错误信息" span={2}>
              {currentProgress.error_message || '无'}
            </Descriptions.Item>
          </Descriptions>
        )}
      </Modal>
    </div>
  );
};

export default ContractImportStatus;

/**
 * PDF合同文件上传组件
 */

import React, { useState, useCallback } from 'react';
import {
  Upload,
  Button,
  Card,
  Progress,
  Alert,
  Space,
  Typography,
  Divider,
  Tag,
  Row,
  Col,
  message
} from 'antd';
import {
  InboxOutlined,
  UploadOutlined,
  DeleteOutlined,
  EyeOutlined,
  SettingOutlined,
  CloseOutlined
} from '@ant-design/icons';
import type { UploadFile, UploadProps } from 'antd/es/upload/interface';

import { pdfImportService, type FileUploadResponse, type SessionProgress } from '../../services/pdfImportService';

const { Title, Text, Paragraph } = Typography;

interface ContractImportUploadProps {
  onUploadSuccess: (sessionId: string, fileInfo: UploadFile) => void;
  onUploadError: (error: string) => void;
  maxFileSize?: number; // MB
}

const ContractImportUpload: React.FC<ContractImportUploadProps> = ({
  onUploadSuccess,
  onUploadError,
  maxFileSize = 50
}) => {
  const [uploadStatus, setUploadStatus] = useState<'idle' | 'uploading' | 'success' | 'error'>('idle');
  const [uploadProgress, setUploadProgress] = useState(0);
  const [sessionId, setSessionId] = useState<string>('');
  const [uploadedFile, setUploadedFile] = useState<UploadFile | null>(null);
  const [systemInfo, setSystemInfo] = useState<any>(null);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [abortController, setAbortController] = useState<AbortController | null>(null);

  // 加载系统信息
  React.useEffect(() => {
    loadSystemInfo();
  }, []);

  const loadSystemInfo = async () => {
    try {
      const info = await pdfImportService.getSystemInfo();
      setSystemInfo(info);
    } catch (error) {
      console.error('加载系统信息失败:', error);
    }
  };

  // 文件上传前的验证
  const beforeUpload = useCallback((file: File) => {
    // 验证文件类型
    if (!pdfImportService.validateFileType(file)) {
      message.error('只支持PDF文件格式！');
      return false;
    }

    // 验证文件大小
    if (!pdfImportService.validateFileSize(file, maxFileSize)) {
      message.error(`文件大小不能超过 ${maxFileSize}MB！当前文件大小：${pdfImportService.formatFileSize(file.size)}`);
      return false;
    }

    // 不在这里设置状态，让customRequest处理
    return true;
  }, [maxFileSize]);

  // 取消上传
  const handleCancelUpload = useCallback(() => {
    if (abortController) {
      abortController.abort();
      setAbortController(null);
    }
    setUploadStatus('idle');
    setUploadProgress(0);
    message.info('已取消上传');
  }, [abortController]);

  // 自定义上传请求
  const customRequest = useCallback(async (options: {
    file: File;
    onProgress: (percent: number) => void;
    onSuccess: (response?: unknown) => void;
    onError: (error: Error) => void;
  }) => {
    const { file, onProgress, onSuccess, onError } = options;

    // 设置上传状态
    setUploadStatus('uploading');
    setUploadProgress(0);

    // 创建新的AbortController
    const controller = new AbortController();
    setAbortController(controller);

    try {

      const response: FileUploadResponse = await pdfImportService.uploadPDFFile(
        file,
        false, // 不再使用markitdown
        controller.signal
      );

      // 清理controller
      setAbortController(null);

      if (response.success) {
        // 完成进度
        setUploadProgress(100);
        onProgress({ percent: 100 });

        const uploadFile: UploadFile = {
          uid: response.session_id || Date.now().toString(),
          name: file.name,
          status: 'done',
          size: file.size,
          type: file.type,
          originFileObj: file
        };

        setUploadedFile(uploadFile);
        setSessionId(response.session_id || '');
        setUploadStatus('success');
        onSuccess(response);

        // 重要：立即调用父组件的成功回调，让父组件接管后续处理
        if (response.session_id) {
          onUploadSuccess(response.session_id, uploadFile);
          message.success('文件上传成功！正在处理中...');
        } else {
          throw new Error('未收到有效的会话ID');
        }
      } else {
        throw new Error(response.error || response.message || '上传失败');
      }
    } catch (error: unknown) {
      // 清理controller
      setAbortController(null);

      // 如果是手动取消，不显示错误消息
      if (error.name === 'AbortError' || error.message === 'canceled') {
        return;
      }

      setUploadStatus('error');
      setUploadProgress(0);
      onError(error);
      onUploadError(error.message || '上传失败');
      message.error(error.message || '文件上传失败');
    }
  }, [onUploadSuccess, onUploadError]);

  // 移除文件
  const handleRemove = useCallback(() => {
    setUploadedFile(null);
    setSessionId('');
    setUploadStatus('idle');
    setUploadProgress(0);
  }, []);

  // 重新上传
  const handleReupload = useCallback(() => {
    handleRemove();
  }, [handleRemove]);

  // 上传区域props
  const uploadProps: UploadProps = {
    name: 'file',
    multiple: false,
    accept: '.pdf',
    beforeUpload,
    customRequest,
    showUploadList: false,
    disabled: uploadStatus === 'uploading'
  };

  // 获取系统状态标签
  const getSystemStatusTags = () => {
    if (!systemInfo) return null;

    const { capabilities } = systemInfo;
    const tags = [];

    
    if (capabilities.pdfplumber_available) {
      tags.push(<Tag color="green" key="pdfplumber">PDFPlumber可用</Tag>);
    } else {
      tags.push(<Tag color="orange" key="pdfplumber">PDFPlumber不可用</Tag>);
    }

    if (capabilities.spacy_available) {
      tags.push(<Tag color="green" key="spacy">NLP增强可用</Tag>);
    } else {
      tags.push(<Tag color="default" key="spacy">NLP增强不可用</Tag>);
    }

    return tags;
  };

  return (
    <div className="contract-import-upload">
      <Card
        title={
          <Space>
            <UploadOutlined />
            <span>PDF合同文件上传</span>
          </Space>
        }
        extra={
          <Button
            type="text"
            icon={<SettingOutlined />}
            onClick={() => setShowAdvanced(!showAdvanced)}
          >
            {showAdvanced ? '隐藏高级' : '显示高级'}
          </Button>
        }
      >
        {/* 系统状态 */}
        {systemInfo && (
          <div style={{ marginBottom: 16 }}>
            <Row gutter={[16, 8]} align="middle">
              <Col>
                <Text type="secondary">系统状态：</Text>
              </Col>
              <Col>
                <Space wrap>{getSystemStatusTags()}</Space>
              </Col>
              <Col flex="auto" style={{ textAlign: 'right' }}>
                <Text type="secondary">
                  支持格式：{systemInfo.capabilities.supported_formats.join(', ')} |
                  最大文件：{systemInfo.capabilities.max_file_size_mb}MB |
                  预计时间：{systemInfo.capabilities.estimated_processing_time}
                </Text>
              </Col>
            </Row>
          </div>
        )}

        <Divider />

        {/* 上传区域 */}
        {uploadStatus === 'idle' && (
          <Upload.Dragger {...uploadProps}>
            <p className="ant-upload-drag-icon">
              <InboxOutlined style={{ fontSize: 48, color: '#1890ff' }} />
            </p>
            <p className="ant-upload-text" style={{ fontSize: 16, fontWeight: 500 }}>
              点击或拖拽PDF合同文件到此区域上传
            </p>
            <p className="ant-upload-hint" style={{ color: '#666' }}>
              支持单个PDF文件上传，文件大小不超过 {maxFileSize}MB
            </p>
            <p className="ant-upload-hint" style={{ color: '#999', fontSize: 12 }}>
              系统将自动提取合同信息，包括合同编号、承租方、地址、租金等关键字段
            </p>
          </Upload.Dragger>
        )}

        {/* 上传进度 */}
        {uploadStatus === 'uploading' && (
          <div style={{ textAlign: 'center', padding: '20px 0' }}>
            <Title level={4}>
              {uploadProgress < 100 ? '正在上传文件...' : '文件上传成功，正在处理中...'}
            </Title>
            <Progress
              percent={uploadProgress}
              status={uploadProgress < 100 ? "active" : "success"}
              strokeColor={{
                '0%': '#108ee9',
                '100%': '#87d068',
              }}
              style={{ marginBottom: 16 }}
            />
            <Text type="secondary">
              {uploadProgress < 100
                ? '正在上传文件到服务器，请稍候...'
                : '文件已上传，系统正在进行PDF转换和信息提取，请耐心等待...'}
            </Text>
            <div style={{ marginTop: 8 }}>
              <Text type="secondary" style={{ fontSize: 12 }}>
                提示：处理时间通常为30-60秒，复杂文件可能需要更长时间
              </Text>
            </div>

            {uploadProgress < 100 && (
              <div style={{ marginTop: 16 }}>
                <Button
                  danger
                  icon={<CloseOutlined />}
                  onClick={handleCancelUpload}
                >
                  取消上传
                </Button>
              </div>
            )}
          </div>
        )}

        {/* 上传成功 */}
        {uploadStatus === 'success' && uploadedFile && (
          <div style={{ textAlign: 'center', padding: '20px 0' }}>
            <div style={{
              width: 80,
              height: 80,
              margin: '0 auto 16px',
              borderRadius: '50%',
              backgroundColor: '#f6ffed',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}>
              <EyeOutlined style={{ fontSize: 32, color: '#52c41a' }} />
            </div>

            <Title level={4} style={{ color: '#52c41a', margin: '16px 0 8px' }}>
              文件上传成功！
            </Title>

            <div style={{
              backgroundColor: '#f5f5f5',
              padding: '12px 16px',
              borderRadius: '6px',
              marginBottom: 16
            }}>
              <Space direction="vertical" size="small" style={{ width: '100%' }}>
                <Row justify="space-between">
                  <Col><Text type="secondary">文件名：</Text></Col>
                  <Col><Text strong>{uploadedFile.name}</Text></Col>
                </Row>
                <Row justify="space-between">
                  <Col><Text type="secondary">文件大小：</Text></Col>
                  <Col><Text>{pdfImportService.formatFileSize(uploadedFile.size || 0)}</Text></Col>
                </Row>
                <Row justify="space-between">
                  <Col><Text type="secondary">会话ID：</Text></Col>
                  <Col><Text code style={{ fontSize: 12 }}>{sessionId}</Text></Col>
                </Row>
              </Space>
            </div>

            <Alert
              message="文件正在处理中"
              description="系统正在自动提取PDF中的合同信息，请稍候..."
              type="info"
              showIcon
              style={{ marginBottom: 16 }}
            />

            <Space>
              <Button
                type="primary"
                icon={<EyeOutlined />}
                onClick={() => {
                  // 这里可以跳转到进度查看页面
                  message.info('请等待处理完成后查看结果');
                }}
              >
                查看处理进度
              </Button>
              <Button
                icon={<UploadOutlined />}
                onClick={handleReupload}
              >
                重新上传
              </Button>
            </Space>
          </div>
        )}

        {/* 上传失败 */}
        {uploadStatus === 'error' && (
          <div style={{ textAlign: 'center', padding: '20px 0' }}>
            <div style={{
              width: 80,
              height: 80,
              margin: '0 auto 16px',
              borderRadius: '50%',
              backgroundColor: '#fff2f0',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}>
              <DeleteOutlined style={{ fontSize: 32, color: '#ff4d4f' }} />
            </div>

            <Title level={4} style={{ color: '#ff4d4f', margin: '16px 0 8px' }}>
              文件上传失败
            </Title>

            <Paragraph style={{ color: '#666', marginBottom: 16 }}>
              上传过程中发生错误，请检查文件格式和大小后重试。
            </Paragraph>

            <Space>
              <Button
                type="primary"
                icon={<UploadOutlined />}
                onClick={handleReupload}
              >
                重新上传
              </Button>
              <Button
                icon={<SettingOutlined />}
                onClick={() => setShowAdvanced(true)}
              >
                查看系统状态
              </Button>
            </Space>
          </div>
        )}

        {/* 高级选项 */}
        {showAdvanced && systemInfo && (
          <div style={{ marginTop: 24, padding: 16, backgroundColor: '#fafafa', borderRadius: 6 }}>
            <Title level={5}>系统详细信息</Title>
            <Row gutter={16}>
              <Col span={8}>
                <Text strong>提取器摘要：</Text>
                <pre style={{ fontSize: 12, backgroundColor: '#fff', padding: 8, borderRadius: 4 }}>
                  {JSON.stringify(systemInfo.extractor_summary, null, 2)}
                </pre>
              </Col>
              <Col span={8}>
                <Text strong>验证器摘要：</Text>
                <pre style={{ fontSize: 12, backgroundColor: '#fff', padding: 8, borderRadius: 4 }}>
                  {JSON.stringify(systemInfo.validator_summary, null, 2)}
                </pre>
              </Col>
              <Col span={8}>
                <Text strong>系统能力：</Text>
                <pre style={{ fontSize: 12, backgroundColor: '#fff', padding: 8, borderRadius: 4 }}>
                  {JSON.stringify(systemInfo.capabilities, null, 2)}
                </pre>
              </Col>
            </Row>
          </div>
        )}

        {/* 使用说明 */}
        {uploadStatus === 'idle' && (
          <div style={{ marginTop: 24, padding: 16, backgroundColor: '#e6f7ff', borderRadius: 6 }}>
            <Title level={5} style={{ color: '#0958d9', marginBottom: 12 }}>
              <EyeOutlined /> 使用说明
            </Title>
            <Space direction="vertical" size="small">
              <Text>• 支持标准PDF格式的合同文件</Text>
              <Text>• 系统将自动提取58个关键字段，包括合同编号、承租方、地址、租金等</Text>
              <Text>• 提取完成后可以进行人工确认和修改</Text>
              <Text>• 支持与现有资产和权属方数据进行智能匹配</Text>
              <Text>• 处理时间通常为30-60秒，取决于文件大小和复杂度</Text>
            </Space>
          </div>
        )}
      </Card>
    </div>
  );
};

export default ContractImportUpload;

/**
 * PDF导入主页面
 * 整合上传、状态查看、结果确认等所有功能
 */

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import './PDFImportPage.css';

// API 错误接口
interface ApiError extends Error {
  response?: {
    data?: {
      message?: string
      detail?: string
    }
  }
  message?: string
}
import {
  Card,
  Tabs,
  Button,
  Space,
  Typography,
  Alert,
  message,
  notification,
  Spin,
  Row,
  Col,
  Statistic,
  Tag,
  Tooltip,
  Switch,
  Modal
} from 'antd';
import {
  UploadOutlined,
  FileTextOutlined,
  HistoryOutlined,
  SettingOutlined,
  ReloadOutlined,
  CheckCircleOutlined,
  CloseCircleOutlined,
  QuestionCircleOutlined,
  EyeOutlined,
  ApiOutlined,
  StarOutlined,
  BulbOutlined
} from '@ant-design/icons';

import ContractImportUpload from './ContractImportUpload';
import ContractImportStatus from './ContractImportStatus';
import ContractImportReview from './ContractImportReview';
import PDFImportHelp from './PDFImportHelp';
import { pdfImportService } from '../../services/pdfImportService';
import type {
  FileUploadResponse,
  SessionProgress,
  CompleteResult,
  ConfirmedContractData,
  ConfirmImportResponse,
  ActiveSession
} from '../../services/pdfImportService';

const { Title, Text, Paragraph } = Typography;

interface UploadFile {
  uid: string;
  name: string;
  status: 'done' | 'error' | 'uploading';
  size?: number;
  type?: string;
  originFileObj?: File;
}

interface ProcessingSession {
  sessionId: string;
  fileInfo: UploadFile;
  status: 'uploading' | 'processing' | 'ready' | 'completed' | 'failed';
  progress: number;
  result?: CompleteResult;
  error?: string;
}

const PDFImportPage: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'upload' | 'history'>('upload');
  const [currentSession, setCurrentSession] = useState<ProcessingSession | null>(null);
  const [sessionHistory, setSessionHistory] = useState<ProcessingSession[]>([]);
  const [systemInfo, setSystemInfo] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [showSystemInfo, setShowSystemInfo] = useState(false);
  const [showHelp, setShowHelp] = useState(false);
  const [showKeyboardShortcuts, setShowKeyboardShortcuts] = useState(false);
  const [userPreferences, setUserPreferences] = useState({
    autoRefresh: true,
    showAdvancedOptions: false,
    preferMarkitdown: true,
    enableNotifications: true,
    compactView: false
  });

  // 使用 ref 避免闭包问题
  const currentSessionRef = useRef(currentSession);
  currentSessionRef.current = currentSession;

  // 加载系统信息和键盘快捷键
  useEffect(() => {
    loadSystemInfo();
    loadSessionHistory();
    loadUserPreferences();

    // 设置键盘快捷键
    const handleKeyDown = (event: KeyboardEvent) => {
      // Ctrl/Cmd + H: 显示帮助
      if ((event.ctrlKey || event.metaKey) && event.key === 'h') {
        event.preventDefault();
        setShowHelp(true);
      }
      // Ctrl/Cmd + K: 显示键盘快捷键
      if ((event.ctrlKey || event.metaKey) && event.key === 'k') {
        event.preventDefault();
        setShowKeyboardShortcuts(true);
      }
      // Ctrl/Cmd + R: 刷新数据
      if ((event.ctrlKey || event.metaKey) && event.key === 'r') {
        event.preventDefault();
        handleReload();
      }
      // Alt + 1: 切换到PDF导入标签
      if (event.altKey && event.key === '1') {
        event.preventDefault();
        setActiveTab('upload');
      }
      // Alt + 2: 切换到处理历史标签
      if (event.altKey && event.key === '2') {
        event.preventDefault();
        setActiveTab('history');
      }
      // Esc: 关闭所有模态框
      if (event.key === 'Escape') {
        setShowHelp(false);
        setShowKeyboardShortcuts(false);
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, []);

  // 加载用户偏好设置
  const loadUserPreferences = useCallback(() => {
    try {
      const saved = localStorage.getItem('pdf-import-preferences');
      if (saved) {
        setUserPreferences(JSON.parse(saved));
      }
    } catch (error) {
      console.warn('加载用户偏好设置失败:', error);
    }
  }, []);

  // 保存用户偏好设置
  const saveUserPreferences = useCallback((prefs: typeof userPreferences) => {
    try {
      localStorage.setItem('pdf-import-preferences', JSON.stringify(prefs));
      setUserPreferences(prefs);
    } catch (error) {
      console.warn('保存用户偏好设置失败:', error);
    }
  }, []);

  const loadSystemInfo = async () => {
    try {
      const info = await pdfImportService.getSystemInfo();
      setSystemInfo(info);
    } catch (error) {
      console.error('加载系统信息失败:', error);
    }
  };

  const loadSessionHistory = async () => {
    try {
      const response = await pdfImportService.getActiveSessions();
      if (response.success) {
        // 转换为历史记录格式
        const history = response.active_sessions
          .filter(session => ['ready_for_review', 'failed', 'cancelled', 'completed'].includes(session.status))
          .map(session => ({
            sessionId: session.session_id,
            fileInfo: {
              uid: session.session_id,
              name: session.file_name,
              status: 'done',
              size: 0,
              type: 'application/pdf'
            },
            status: session.status === 'ready_for_review' ? 'ready' : session.status as any,
            progress: session.progress
          }));
        setSessionHistory(history);
      }
    } catch (error) {
      console.error('加载会话历史失败:', error);
    }
  };

  // 文件上传成功处理
  const handleUploadSuccess = (sessionId: string, fileInfo: UploadFile) => {
    // Upload success

    const newSession: ProcessingSession = {
      sessionId,
      fileInfo,
      status: 'processing',
      progress: 0
    };

    setCurrentSession(newSession);
    setActiveTab('upload');

    // 强制重新渲染
    setTimeout(() => {
      setCurrentSession(prev => prev ? {...prev} : null);
    }, 100);
  };

  // 文件上传失败处理
  const handleUploadError = (error: string) => {
    message.error(error);
    setCurrentSession(null);
  };

  // 处理完成处理
  const handleProcessingComplete = (result: CompleteResult) => {
    // Processing complete

    if (currentSession) {
      setCurrentSession({
        ...currentSession,
        status: 'ready',
        progress: 100,
        result
      });
    }
  };

  // 处理错误处理
  const handleProcessingError = (error: string) => {
    if (currentSession) {
      setCurrentSession({
        ...currentSession,
        status: 'failed',
        error
      });
    }
    message.error(error);
  };

  // 确认导入处理
  const handleConfirmImport = async (data: ConfirmedContractData): Promise<ConfirmImportResponse> => {
    try {
      const response = await pdfImportService.confirmImport(
        currentSession!.sessionId,
        data
      );

      if (response.success) {
        // 更新会话状态
        setCurrentSession({
          ...currentSession!,
          status: 'completed'
        });

        // 添加到历史记录
        if (currentSession) {
          setSessionHistory(prev => [currentSession, ...prev]);
        }

        // 显示成功通知
        if (userPreferences.enableNotifications) {
          notification.success({
            message: '合同导入成功！',
            description: `已成功导入合同 ${currentSession.fileInfo.name}`,
            duration: 4.5,
            placement: 'topRight'
          });
        } else {
          message.success('合同导入成功！');
        }
      }

      return response;
    } catch (error: unknown) {
      const apiError = error as ApiError
      if (userPreferences.enableNotifications) {
        notification.error({
          message: '导入失败',
          description: error.message || '合同导入过程中发生错误',
          duration: 6,
          placement: 'topRight'
        });
      } else {
        message.error(error.message || '导入失败');
      }
      throw error;
    }
  };

  // 取消处理
  const handleCancel = async () => {
    if (currentSession) {
      try {
        const response = await pdfImportService.cancelSession(currentSession.sessionId);
        if (response.success) {
          message.info('已取消导入');
          setCurrentSession(null);
        }
      } catch (error: unknown) {
      const apiError = error as ApiError
        message.error(error.message || '取消失败');
      }
    }
  };

  // 返回上传页面
  const handleBackToUpload = () => {
    setCurrentSession(null);
    setActiveTab('upload');
  };

  // 重新加载
  const handleReload = async () => {
    setLoading(true);
    try {
      await Promise.all([
        loadSystemInfo(),
        loadSessionHistory()
      ]);
      message.success('数据已刷新');
    } catch (error) {
      message.error('刷新失败');
    } finally {
      setLoading(false);
    }
  };

  // 测试系统功能
  const handleTestSystem = async () => {
    try {
      setLoading(true);
      const response = await pdfImportService.testConversion();
      if (response.system_ready) {
        message.success('系统功能正常');
      } else {
        message.warning('系统可能存在问题');
      }
    } catch (error: unknown) {
      const apiError = error as ApiError
      message.error('测试失败');
    } finally {
      setLoading(false);
    }
  };

  // 获取系统状态统计 - 使用 useMemo 优化
  const systemStats = useMemo(() => {
    if (!systemInfo) return null;

    const { capabilities } = systemInfo;
    const availableCount = [
      capabilities.pdfplumber_available,
      capabilities.pymupdf_available,
      capabilities.spacy_available,
      capabilities.ocr_available
    ].filter(Boolean).length;

    return {
      total: 4,
      available: availableCount,
      percentage: Math.round((availableCount / 4) * 100)
    };
  }, [systemInfo]);

  // 渲染当前会话内容 - 使用 useMemo 优化复杂条件渲染
  const renderCurrentSession = useMemo(() => {
    if (!currentSession) {
      return (
        <ContractImportUpload
          key="upload-main"
          onUploadSuccess={handleUploadSuccess}
          onUploadError={handleUploadError}
        />
      );
    }

    const keyPrefix = `${currentSession.status}-${currentSession.sessionId}`;

    switch (currentSession.status) {
      case 'processing':
        return (
          <ContractImportStatus
            key={keyPrefix}
            sessionId={currentSession.sessionId}
            fileInfo={{
              filename: currentSession.fileInfo.name,
              size: currentSession.fileInfo.size || 0,
              content_type: currentSession.fileInfo.type || 'application/pdf'
            }}
            onComplete={handleProcessingComplete}
            onError={handleProcessingError}
            onCancel={handleCancel}
          />
        );
      case 'ready':
        return currentSession.result ? (
          <ContractImportReview
            key={keyPrefix}
            sessionId={currentSession.sessionId}
            result={currentSession.result}
            onConfirm={handleConfirmImport}
            onCancel={handleBackToUpload}
            onBack={handleBackToUpload}
          />
        ) : null;
      case 'completed':
        return (
          <div key={keyPrefix} style={{ textAlign: 'center', padding: '40px' }}>
            <CheckCircleOutlined style={{ fontSize: 64, color: '#52c41a', marginBottom: 16 }} />
            <Title level={4} style={{ color: '#52c41a' }}>
              导入成功！
            </Title>
            <Paragraph>
              合同已成功导入到系统中。
            </Paragraph>
            <Space>
              <Button type="primary" onClick={() => setCurrentSession(null)}>
                导入新合同
              </Button>
              <Button onClick={() => setActiveTab('history')}>
                查看历史记录
              </Button>
            </Space>
          </div>
        );
      case 'failed':
        return (
          <div key={keyPrefix} style={{ textAlign: 'center', padding: '40px' }}>
            <CloseCircleOutlined style={{ fontSize: 64, color: '#ff4d4f', marginBottom: 16 }} />
            <Title level={4} style={{ color: '#ff4d4f' }}>
              处理失败
            </Title>
            <Paragraph>
              {currentSession.error || '处理过程中发生错误'}
            </Paragraph>
            <Space>
              <Button onClick={() => setCurrentSession(null)}>
                重新上传
              </Button>
              <Button onClick={() => setActiveTab('history')}>
                查看历史记录
              </Button>
            </Space>
          </div>
        );
      default:
        return (
          <ContractImportUpload
            key="upload-initial"
            onUploadSuccess={handleUploadSuccess}
            onUploadError={handleUploadError}
          />
        );
    }
  }, [currentSession, handleUploadSuccess, handleUploadError, handleProcessingComplete,
      handleProcessingError, handleCancel, handleConfirmImport, handleBackToUpload, setActiveTab]);

  // 页面加载状态
  if (loading && !systemInfo && !currentSession) {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        height: '100vh',
        flexDirection: 'column',
        gap: 16
      }}>
        <Spin size="large" />
        <Text type="secondary">正在初始化PDF导入系统...</Text>
      </div>
    );
  }

  return (
    <div className="pdf-import-page" style={{
      animation: 'fadeIn 0.3s ease-in-out',
      minHeight: '100vh'
    }}>
      {/* 页面头部 */}
      <Card style={{ marginBottom: 16 }}>
        <Row justify="space-between" align="middle">
          <Col>
            <Space size="large">
              <div className="status-icon">
                <UploadOutlined style={{ fontSize: 24, color: '#1890ff' }} />
              </div>
              <div>
                <Title level={3} style={{ margin: 0 }}>
                  PDF合同智能导入
                </Title>
                <Text type="secondary">
                  上传PDF文件，自动提取合同信息并导入系统
                </Text>
              </div>
            </Space>
          </Col>
          <Col>
            <Space>
              <Button
                icon={<ApiOutlined />}
                onClick={() => setShowKeyboardShortcuts(true)}
                title="快捷键: Ctrl/Cmd + K"
              >
                快捷键
              </Button>
              <Button
                icon={<QuestionCircleOutlined />}
                onClick={() => setShowHelp(true)}
                title="快捷键: Ctrl/Cmd + H"
              >
                使用帮助
              </Button>
              <Button
                icon={<SettingOutlined />}
                onClick={() => setShowSystemInfo(!showSystemInfo)}
              >
                {showSystemInfo ? '隐藏状态' : '系统状态'}
              </Button>
              <Button
                icon={<ReloadOutlined />}
                onClick={handleReload}
                loading={loading}
                title="快捷键: Ctrl/Cmd + R"
              >
                刷新
              </Button>
            </Space>
          </Col>
        </Row>

        {/* 系统状态信息 */}
        {showSystemInfo && systemInfo && (
          <Alert
            message="系统状态"
            description={
              <div>
                <Row gutter={16}>
                  <Col span={6}>
                    <Tag color={systemInfo.capabilities.pdfplumber_available ? 'green' : 'orange'}>
                      PDFPlumber: {systemInfo.capabilities.pdfplumber_available ? '可用' : '不可用'}
                    </Tag>
                  </Col>
                  <Col span={6}>
                    <Tag color={systemInfo.capabilities.pymupdf_available ? 'green' : 'orange'}>
                      PyMuPDF: {systemInfo.capabilities.pymupdf_available ? '可用' : '不可用'}
                    </Tag>
                  </Col>
                  <Col span={6}>
                    <Tag color={systemInfo.capabilities.ocr_available ? 'green' : 'default'}>
                      OCR: {systemInfo.capabilities.ocr_available ? '可用' : '不可用'}
                    </Tag>
                  </Col>
                  <Col span={6}>
                    <Text type="secondary">
                      最大文件: {systemInfo.capabilities.max_file_size_mb}MB
                    </Text>
                  </Col>
                </Row>
                <div style={{ marginTop: 8 }}>
                  <Text type="secondary">
                    处理时间: {systemInfo.capabilities.estimated_processing_time} |
                    支持格式: {systemInfo.capabilities.supported_formats.join(', ')}
                  </Text>
                </div>
              </div>
            }
            type="info"
            showIcon
            action={
              <Button size="small" onClick={handleTestSystem}>
                测试功能
              </Button>
            }
            style={{ marginBottom: 16 }}
          />
        )}

        {/* 统计信息 */}
        <Row gutter={16}>
          <Col span={6}>
            <Card size="small">
              <Statistic
                title="活跃会话"
                value={sessionHistory.length + (currentSession ? 1 : 0)}
                prefix={<HistoryOutlined />}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card size="small">
