  Typography
} from 'antd';
import {
  PlusOutlined,
  SearchOutlined,
  EditOutlined,
  DeleteOutlined,
  EyeOutlined,
  FileTextOutlined,
  CalendarOutlined,
  DollarOutlined
} from '@ant-design/icons';
import type { ColumnsType } from 'antd/es/table';
import dayjs from 'dayjs';

import { RentContract, RentContractQueryParams, RentContractPageState } from '../../types/rentContract';
import { Asset } from '../../types/asset';
import { Ownership } from '../../types/ownership';
import { rentContractService } from '../../services/rentContractService';
import { assetService } from '../../services/assetService';
import { ownershipService } from '../../services/ownershipService';
import { useFormat } from '../../utils/format';
import RentContractExcelImport from '../../components/Rental/RentContractExcelImport';

const { Title } = Typography;
const { Search } = Input;
const { Option } = Select;
const { RangePicker } = DatePicker;

const ContractListPage: React.FC = () => {
  const [state, setState] = useState<RentContractPageState>({
    loading: false,
    contracts: [],
    pagination: {
      current: 1,
      pageSize: 10,
      total: 0,
    },
    filters: {},
    showModal: false,
    modalMode: 'create',
  });

  const [assets, setAssets] = useState<Asset[]>([]);
  const [ownerships, setOwnerships] = useState<Ownership[]>([]);
  const [statistics, setStatistics] = useState<any>(null);

  const format = useFormat();

  // 加载合同列表
  const loadContracts = async (params?: RentContractQueryParams) => {
    setState(prev => ({ ...prev, loading: true }));
    try {
      const response = await rentContractService.getContracts({
        page: state.pagination.current,
        limit: state.pagination.pageSize,
        ...state.filters,
        ...params,
      });

      // 安全检查：确保response和response.items存在
      if (!response) {
        console.error('合同API响应为空');
        message.error('加载合同列表失败：响应为空');
        setState(prev => ({ ...prev, loading: false }));
        return;
      }

      // 确保items是一个数组
      const contracts = Array.isArray(response.items) ? response.items : [];

      setState(prev => ({
        ...prev,
        loading: false,
        contracts: contracts,
        pagination: {
          ...prev.pagination,
          total: response.total || 0,
          pages: response.pages || 0,
        },
      }));
    } catch (error) {
      console.error('加载合同列表失败:', error);
      message.error(`加载合同列表失败: ${error instanceof Error ? error.message : '未知错误'}`);
      setState(prev => ({ ...prev, loading: false, contracts: [] }));
    }
  };

  // 加载统计数据
  const loadStatistics = async () => {
    try {
      const stats = await rentContractService.getRentStatistics();
      setStatistics(stats);
    } catch (error) {
      console.error('加载统计数据失败:', error);
    }
  };

  // 加载资产和权属方数据
  const loadReferenceData = async () => {
    try {
      const [assetsResponse, ownershipsData] = await Promise.all([
        assetService.getAssets({ limit: 100 }),
        ownershipService.getOwnershipOptions(true),
      ]);
      setAssets(assetsResponse.items);
      setOwnerships(ownershipsData);
    } catch (error) {
      message.error('加载参考数据失败');
    }
  };

  useEffect(() => {
    loadContracts();
    loadStatistics();
    loadReferenceData();
  }, []);

  // 处理分页变化
  const handleTableChange = (pagination: { current: number; pageSize: number; total?: number }) => {
    setState(prev => ({
      ...prev,
      pagination: {
        ...prev.pagination,
        current: pagination.current,
        pageSize: pagination.pageSize,
      },
    }));
    loadContracts({
      page: pagination.current,
      limit: pagination.pageSize,
    });
  };

  // 处理搜索
  const handleSearch = (values: Record<string, unknown>) => {
    setState(prev => ({
      ...prev,
      filters: values,
      pagination: { ...prev.pagination, current: 1 },
    }));
    loadContracts({ ...values, page: 1 });
  };

  // 重置搜索
  const handleReset = () => {
    setState(prev => ({
      ...prev,
      filters: {},
      pagination: { ...prev.pagination, current: 1 },
    }));
    loadContracts({ page: 1 });
  };

  // 删除合同
  const handleDelete = async (id: string) => {
    Modal.confirm({
      title: '确认删除',
      content: '确定要删除这个合同吗？删除后将无法恢复。',
      okText: '确认',
      cancelText: '取消',
      onOk: async () => {
        try {
          await rentContractService.deleteContract(id);
          message.success('删除成功');
          loadContracts();
          loadStatistics();
        } catch (error) {
          message.error('删除失败');
        }
      },
    });
  };

  // 生成台账
  const handleGenerateLedger = async (contractId: string) => {
    try {
      await rentContractService.generateMonthlyLedger({ contract_id: contractId });
      message.success('生成台账成功');
    } catch (error) {
      message.error('生成台账失败');
    }
  };

  // 查看合同详情
  const handleViewDetail = (contract: RentContract) => {
    // TODO: 实现查看详情逻辑
    // View contract details
  };

  // 编辑合同
  const handleEdit = (contract: RentContract) => {
    // TODO: 实现编辑逻辑
    // Edit contract
  };

  // 创建新合同
  const handleCreate = () => {
    // TODO: 实现创建逻辑
    // Create new contract
  };

  // 导入成功的回调
  const handleImportSuccess = () => {
    loadContracts(); // 重新加载数据
    loadStatistics(); // 重新加载统计数据
  };

  // 表格列定义
  const columns: ColumnsType<RentContract> = [
    {
      title: '合同编号',
      dataIndex: 'contract_number',
      key: 'contract_number',
      render: (text: string) => (
        <Tooltip title={text}>
          <Button type="link" size="small">
            {text}
          </Button>
        </Tooltip>
      ),
    },
    {
      title: '承租方',
      dataIndex: 'tenant_name',
      key: 'tenant_name',
      render: (text: string) => (
        <Space>
          <span>{text}</span>
        </Space>
      ),
    },
    {
      title: '物业名称',
      dataIndex: ['asset', 'property_name'],
      key: 'property_name',
      render: (text: string, record: RentContract) => (
        <Tooltip title={record.asset?.address}>
          {text || '未知'}
        </Tooltip>
      ),
    },
    {
      title: '权属方',
      dataIndex: ['ownership', 'name'],
      key: 'ownership_name',
      render: (text: string) => text || '未知',
    },
    {
      title: '租期',
      key: 'lease_period',
      render: (record: RentContract) => (
        <Space direction="vertical" size="small">
          <div>{dayjs(record.start_date).format('YYYY-MM-DD')}</div>
          <div>至</div>
          <div>{dayjs(record.end_date).format('YYYY-MM-DD')}</div>
        </Space>
      ),
    },
    {
      title: '月租金',
      dataIndex: 'monthly_rent_base',
      key: 'monthly_rent_base',
      render: (amount: number) => format.currency(amount),
      align: 'right' as const,
    },
    {
      title: '合同状态',
      dataIndex: 'contract_status',
      key: 'contract_status',
      render: (status: string) => {
        const statusConfig = {
          '有效': { color: 'green', text: '有效' },
          '到期': { color: 'orange', text: '到期' },
          '终止': { color: 'red', text: '终止' },
        };
        const config = statusConfig[status as keyof typeof statusConfig] || { color: 'default', text: status };
        return <Tag color={config.color}>{config.text}</Tag>;
      },
    },
    {
      title: '签订日期',
      dataIndex: 'sign_date',
      key: 'sign_date',
      render: (date: string) => dayjs(date).format('YYYY-MM-DD'),
    },
    {
      title: '操作',
      key: 'actions',
      width: 200,
      render: (record: RentContract) => (
        <Space size="small">
          <Tooltip title="查看详情">
            <Button
              type="text"
              icon={<EyeOutlined />}
              onClick={() => handleViewDetail(record)}
            />
          </Tooltip>
          <Tooltip title="编辑">
            <Button
              type="text"
              icon={<EditOutlined />}
              onClick={() => handleEdit(record)}
            />
          </Tooltip>
          <Tooltip title="生成台账">
            <Button
              type="text"
              icon={<FileTextOutlined />}
              onClick={() => handleGenerateLedger(record.id)}
            />
          </Tooltip>
          <Tooltip title="删除">
            <Button
              type="text"
              danger
              icon={<DeleteOutlined />}
              onClick={() => handleDelete(record.id)}
            />
          </Tooltip>
        </Space>
      ),
    },
  ];

  return (
    <div style={{ padding: '24px' }}>
      {/* 页面标题 */}
      <div style={{ marginBottom: '24px' }}>
        <Title level={2}>租金合同管理</Title>
        <p style={{ color: '#666' }}>管理物业租赁合同，支持租金条款设置和台账生成</p>
      </div>

      {/* 统计卡片 */}
      {statistics && (
        <Row gutter={16} style={{ marginBottom: '24px' }}>
          <Col span={6}>
            <Card>
              <Statistic
                title="总合同数"
                value={statistics.total_records}
                prefix={<FileTextOutlined />}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="应收总额"
                value={statistics.total_due}
                precision={2}
                prefix={<DollarOutlined />}
                suffix="元"
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="已收总额"
                value={statistics.total_paid}
                precision={2}
                prefix={<DollarOutlined />}
                suffix="元"
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="收缴率"
                value={statistics.payment_rate}
                precision={2}
                suffix="%"
                valueStyle={{ color: statistics.payment_rate > 80 ? '#3f8600' : '#cf1322' }}
              />
            </Card>
          </Col>
        </Row>
      )}

      {/* 搜索区域 */}
      <Card style={{ marginBottom: '24px' }}>
        <Row gutter={16}>
          <Col span={6}>
            <Search
              placeholder="搜索合同编号或承租方"
              onSearch={(value) => handleSearch({ keyword: value })}
              enterButton={<SearchOutlined />}
            />
          </Col>
          <Col span={4}>
            <Select
              placeholder="选择物业"
              style={{ width: '100%' }}
              allowClear
              onChange={(value) => handleSearch({ asset_id: value })}
            >
              {assets.map(asset => (
                <Option key={asset.id} value={asset.id}>
                  {asset.property_name}
                </Option>
              ))}
            </Select>
          </Col>
          <Col span={4}>
            <Select
              placeholder="选择权属方"
              style={{ width: '100%' }}
              allowClear
              onChange={(value) => handleSearch({ ownership_id: value })}
            >
              {ownerships.map(ownership => (
                <Option key={ownership.id} value={ownership.id}>
                  {ownership.name}
                </Option>
              ))}
            </Select>
          </Col>
          <Col span={4}>
            <Select
              placeholder="合同状态"
              style={{ width: '100%' }}
              allowClear
              onChange={(value) => handleSearch({ contract_status: value })}
            >
              <Option value="有效">有效</Option>
              <Option value="到期">到期</Option>
              <Option value="终止">终止</Option>
            </Select>
          </Col>
          <Col span={4}>
            <Button onClick={handleReset}>重置</Button>
          </Col>
          <Col span={2}>
            <Button
              type="primary"
              icon={<PlusOutlined />}
              onClick={handleCreate}
            >
              新建合同
            </Button>
          </Col>
        </Row>
      </Card>

      {/* Excel导入导出 */}
      <RentContractExcelImport onImportSuccess={handleImportSuccess} />

      {/* 合同列表 */}
      <Card>
        <Table
          columns={columns}
          dataSource={state.contracts}
          rowKey="id"
          loading={state.loading}
          pagination={{
            current: state.pagination.current,
            pageSize: state.pagination.pageSize,
            total: state.pagination.total,
            showSizeChanger: true,
            showQuickJumper: true,
            showTotal: (total, range) => `第 ${range[0]}-${range[1]} 条，共 ${total} 条`,
          }}
          onChange={handleTableChange}
          scroll={{ x: 1200 }}
        />
      </Card>
    </div>
  );
};

