  const [showAdvancedSettings, setShowAdvancedSettings] = useState(false);
  const [processingOptions, setProcessingOptions] = useState<EnhancedProcessingOptions>({
    prefer_ocr: true,
    enable_chinese_optimization: true,
    enable_table_detection: true,
    enable_seal_detection: true,
    confidence_threshold: 0.7,
    use_template_learning: true,
    enable_multi_engine_fusion: true,
    enable_semantic_validation: true
  });
  const [showResults, setShowResults] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);

  // 组件挂载时检查系统能力
  useEffect(() => {
    checkSystemCapabilities();
  }, []);

  // 检查系统增强功能能力
  const checkSystemCapabilities = useCallback(async () => {
    try {
      const capabilities = await pdfImportService.getEnhancedSystemInfo();
      if (capabilities.success) {
        setSystemCapabilities(capabilities.capabilities);

        // 如果增强功能不可用，调整选项
        if (!capabilities.capabilities.enhanced_extraction) {
          setProcessingOptions(prev => ({
            ...prev,
            enable_chinese_optimization: false,
            enable_table_detection: false,
            enable_seal_detection: false,
            use_template_learning: false,
            enable_multi_engine_fusion: false,
            enable_semantic_validation: false
          }));
        }
      }
    } catch (error) {
      console.error('检查系统能力失败:', error);
      message.error('无法检查系统能力');
    }
  }, []);

  // 文件上传前检查
  const beforeUpload = (file: File, fileList: File[]) => {
    const isValidType = file.type === 'application/pdf' || file.name.toLowerCase().endsWith('.pdf');
    if (!isValidType) {
      message.error('只支持PDF文件上传！');
      return false;
    }

    const isValidSize = file.size / 1024 / 1024 <= 50; // 50MB限制
    if (!isValidSize) {
      message.error('文件大小不能超过50MB！');
      return false;
    }

    return true;
  };

  // 自定义上传属性
  const uploadProps: UploadProps = {
    name: 'file',
    multiple: false,
    beforeUpload,
    accept: '.pdf,application/pdf',
    maxCount: 1,
    onRemove: () => {
      setFileList([]);
      setUploadProgress(0);
    },
    onDrop(e) {
      setFileList(e.dataTransfer.files);
    },
    onChange(info) {
      const { fileList: newFileList } = info;
      setFileList(newFileList);

      // 计算上传进度
      if (newFileList.length > 0 && info.file.status === 'uploading') {
        const progress = Math.round(info.file.percent || 0);
        setUploadProgress(progress);
      }
    },
    customRequest: async ({ file, onSuccess, onError }) => {
      try {
        setProcessing(true);
        setShowResults(false);

        // 使用增强版上传
        const result = await pdfImportService.uploadPDFFileEnhanced(
          file,
          processingOptions
        );

        if (result.success && result.session_id) {
          setSessionId(result.session_id);
          message.success('文件上传成功，开始智能处理...');

          // 开始轮询进度
          startProgressPolling(result.session_id);
        } else {
          message.error(result.error || '文件上传失败');
          setProcessing(false);
          onError(new Error(result.error || '上传失败'));
        }
      } catch (error) {
        console.error('上传失败:', error);
        message.error('上传过程中发生错误');
        setProcessing(false);
        onError(error instanceof Error ? error : new Error(String(error)));
      }
    }
  };

  // 轮询处理进度
  const startProgressPolling = useCallback((sessionId: string) => {
    pdfImportService.pollEnhancedProgress(
      sessionId,
      (status) => {
        setCurrentStatus(status);

        if (status.status === 'ready_for_review' || status.status === 'completed') {
          setProcessing(false);
          setShowResults(true);
        } else if (status.status === 'failed') {
          setProcessing(false);
          message.error('处理失败: ' + (status.error_message || '未知错误'));
        }
      }
    );
  }, []);

  // 重新开始处理
  const handleRetry = useCallback(() => {
    if (sessionId) {
      setProcessing(true);
      startProgressPolling(sessionId);
    }
  }, [sessionId]);

  // 取消处理
  const handleCancel = useCallback(async () => {
    if (sessionId && currentStatus) {
      try {
        const result = await pdfImportService.cancelEnhancedSession(sessionId);
        if (result.success) {
          message.success('处理已取消');
          setProcessing(false);
          setCurrentStatus(null);
          setSessionId(null);
        } else {
          message.error(result.error || '取消失败');
        }
      } catch (error) {
        console.error('取消失败:', error);
        message.error('取消过程中发生错误');
      }
    }
  }, [sessionId, currentStatus]);

  // 下载结果
  const handleDownloadResults = useCallback(() => {
    if (currentStatus?.enhanced_status?.final_fields) {
      const dataStr = JSON.stringify(currentStatus.enhanced_status.final_fields, null, 2);
      const blob = new Blob([dataStr], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `contract_extraction_${sessionId}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    }
  }, [currentStatus, sessionId]);

  // 渲染功能标签
  const renderFeatureTag = (enabled: boolean, text: string, color = 'green') => (
    <Tag color={enabled ? color : 'default'} style={{ margin: '2px' }}>
      {enabled ? '✓' : '✗'} {text}
    </Tag>
  );

  // 渲染处理选项
  const renderProcessingOptions = () => {
    if (!showAdvancedSettings) return null;

    return (
      <Card title="高级处理设置" size="small">
        <Form layout="vertical" size="small">
          <Form.Item label="中文优化">
            <Switch
              checked={processingOptions.enable_chinese_optimization}
              onChange={(checked) => setProcessingOptions(prev => ({
                ...prev,
                enable_chinese_optimization: checked
              }))}
              disabled={!systemCapabilities?.chinese_optimized}
            />
            <Text type="secondary" style={{ marginLeft: 8 }}>
              启用中文OCR优化，提高中文识别准确度
            </Text>
          </Form.Item>

          <Form.Item label="表格检测">
            <Switch
              checked={processingOptions.enable_table_detection}
              onChange={(checked) => setProcessingOptions(prev => ({
                ...prev,
                enable_table_detection: checked
              }))}
              disabled={!systemCapabilities?.table_detection}
            />
            <Text type="secondary" style={{ marginLeft: 8 }}>
              启用表格结构识别和分析
            </Text>
          </Form.Item>

          <Form.Item label="印章检测">
            <Switch
              checked={processingOptions.enable_seal_detection}
              onChange={(checked) => setProcessingOptions(prev => ({
                ...prev,
                enable_seal_detection: checked
              }))}
              disabled={!systemCapabilities?.seal_detection}
            />
            <Text type="secondary" style={{ marginLeft: 8 }}>
              启用印章和签名检测
            </Text>
          </Form.Item>

          <Form.Item label="模板学习">
            <Switch
              checked={processingOptions.use_template_learning}
              onChange={(checked) => setProcessingOptions(prev => ({
                ...prev,
                use_template_learning: checked
              }))}
              disabled={!systemCapabilities?.template_learning}
            />
            <Text type="secondary" style={{ marginLeft: 8 }}>
              启用合同模板学习和模式识别
            </Text>
          </Form.Item>

          <Form.Item label="多引擎融合">
            <Switch
              checked={processingOptions.enable_multi_engine_fusion}
              onChange={(checked) => setProcessingOptions(prev => ({
                ...prev,
                enable_multi_engine_fusion: checked
              }))}
              disabled={!systemCapabilities?.multi_engine_support}
            />
            <Text type="secondary" style={{ marginLeft: 8 }}>
              启用多引擎结果融合和质量评估
            </Text>
          </Form.Item>

          <Form.Item label="语义验证">
            <Switch
              checked={processingOptions.enable_semantic_validation}
              onChange={(checked) => setProcessingOptions(prev => ({
                ...prev,
                enable_semantic_validation: checked
              }))}
              disabled={!systemCapabilities?.semantic_validation}
            />
            <Text type="secondary" style={{ marginLeft: 8 }}>
              启用58字段语义理解和业务规则验证
            </Text>
          </Form.Item>

          <Form.Item label="置信度阈值">
            <InputNumber
              min={0.1}
              max={1.0}
              step={0.1}
              value={processingOptions.confidence_threshold}
              onChange={(value) => setProcessingOptions(prev => ({
                ...prev,
                confidence_threshold: value || 0.7
              }))}
              formatter={value => `${(value * 100).toFixed(0)}%`}
              parser={value => value as number}
              style={{ width: 100 }}
            />
            <Text type="secondary" style={{ marginLeft: 8 }}>
              字段提取的最低置信度要求
            </Text>
          </Form.Item>
        </Form>
      </Card>
    );
  };

  return (
    <div style={{ padding: '24px', maxWidth: 1200, margin: '0 auto' }}>
      <Title level={2} style={{ textAlign: 'center', marginBottom: 32 }}>
        <FireOutlined style={{ color: '#ff4d4f', marginRight: 8 }} />
        增强版PDF智能导入
        <Tag color="blue" style={{ marginLeft: 8 }}>中文合同专用</Tag>
      </Title>

      {/* 系统能力状态 */}
      {systemCapabilities && (
        <Alert
          message={
            <Space>
              <Text>增强功能状态: </Text>
              <Badge
                status={systemCapabilities.enhanced_extraction ? 'success' : 'warning'}
                text={
                  systemCapabilities.enhanced_extraction
                    ? '完全可用'
                    : '部分功能受限'
                }
              />
              <Text style={{ marginLeft: 8 }}>
                共7个优化模块可用
              </Text>
            </Space>
          }
          type={systemCapabilities.enhanced_extraction ? 'success' : 'warning'}
          showIcon
          style={{ marginBottom: 24 }}
        />
      )}

      {/* 功能展示 */}
      <Row gutter={16} style={{ marginBottom: 24 }}>
        <Col span={24}>
          <Card title="增强功能特性" size="small">
            <Row gutter={[16, 16]}>
              <Col span={6}>
                <Space direction="vertical" size="small">
                  {renderFeatureTag(systemCapabilities?.chinese_optimized, '中文OCR优化', 'blue')}
                  {renderFeatureTag(systemCapabilities?.table_detection, '表格分析', 'green')}
                  {renderFeatureTag(systemCapabilities?.seal_detection, '印章检测', 'purple')}
                </Space>
              </Col>
              <Col span={6}>
                <Space direction="vertical" size="small">
                  {renderFeatureTag(systemCapabilities?.multi_engine_support, '多引擎融合', 'orange')}
                  {renderFeatureTag(systemCapabilities?.semantic_validation, '语义验证', 'red')}
                  {renderFeatureTag(systemCapabilities?.template_learning, '模板学习', 'cyan')}
                </Space>
              </Col>
              <Col span={6}>
                <Space direction="vertical" size="small">
                  {renderFeatureTag(systemCapabilities?.real_time_validation, '实时验证', 'magenta')}
                  {renderFeatureTag(true, '智能匹配', 'default')}
                  {renderFeatureTag(true, '质量评估', 'default')}
                </Space>
              </Col>
              <Col span={6}>
                <Space direction="vertical" size="small">
                  {renderFeatureTag(systemCapabilities?.chinese_optimized, '深度学习', 'geekblue')}
                  {renderFeatureTag(true, '自适应算法', 'purple')}
                  {renderFeatureTag(true, '用户体验优化', 'gold')}
                </Space>
              </Col>
            </Row>
          </Card>
        </Col>
      </Row>

      {/* 上传和处理选项 */}
      <Row gutter={16}>
        <Col span={16}>
          <Card title="文件上传" style={{ minHeight: 300 }}>
            <Dragger {...uploadProps} style={{ padding: 24 }}>
              <p className="ant-upload-drag-icon">
                <InboxOutlined />
              </p>
              <p className="ant-upload-text">点击或拖拽PDF文件到此处上传</p>
              <p className="ant-upload-hint">
                支持中文合同扫描件，推荐使用高质量扫描
              </p>
            </Dragger>

            {fileList.length > 0 && (
              <div style={{ marginTop: 16 }}>
                <Text>文件: {fileList[0].name}</Text>
                <Progress
                  percent={uploadProgress}
                  status={uploadProgress === 100 ? 'success' : 'active'}
                  style={{ marginTop: 8 }}
                />
              </div>
            )}
          </Card>
        </Col>

        <Col span={8}>
          <Space direction="vertical" style={{ width: '100%' }}>
            <Card title="处理选项" size="small" style={{ flex: 1 }}>
              <Space direction="vertical" style={{ width: '100%' }}>
                <Button
                  type="default"
                  icon={<SettingOutlined />}
                  onClick={() => setShowAdvancedSettings(!showAdvancedSettings)}
                >
                  {showAdvancedSettings ? '隐藏设置' : '高级设置'}
                </Button>

                <div style={{ marginTop: 16 }}>
                  <Text strong>当前配置:</Text>
                  <div style={{ marginTop: 8 }}>
                    <div>中文优化: {processingOptions.enable_chinese_optimization ? '启用' : '禁用'}</div>
                    <div>多引擎: {processingOptions.enable_multi_engine_fusion ? '启用' : '禁用'}</div>
                    <div>语义验证: {processingOptions.enable_semantic_validation ? '启用' : '禁用'}</div>
                  </div>
                </div>
              </Space>
            </Card>

            <Space style={{ marginTop: 16 }}>
              <Button
                type="primary"
                icon={<RobotOutlined />}
                onClick={() => pdfImportService.testEnhancedFeatures()}
              >
                测试增强功能
              </Button>
            </Space>
          </Space>
        </Col>
      </Row>

      {/* 高级设置 */}
      {renderProcessingOptions()}

      {/* 处理状态 */}
      {processing && sessionId && (
        <Card title="处理状态" style={{ marginTop: 24 }}>
          <EnhancedProcessingStatus
            sessionId={sessionId}
            currentStatus={currentStatus}
            onError={(error) => message.error('处理状态错误: ' + error)}
            showDetails={true}
          />
        </Card>
      )}

      {/* 处理结果 */}
      {showResults && currentStatus && (
        <Card title="智能处理结果" style={{ marginTop: 24 }}>
          <Space direction="vertical" style={{ width: '100%' }}>
            <div style={{ marginBottom: 16 }}>
              <Title level={4}>
                <FileTextOutlined style={{ marginRight: 8 }} />
                处理摘要
              </Title>

              <Row gutter={16}>
                <Col span={6}>
                  <Statistic
                    title="识别字段数"
                    value={Object.keys(currentStatus.enhanced_status?.final_fields || {}).length}
                    suffix="/58"
                  />
                </Col>
                <Col span={6}>
                  <Statistic
                    title="总体置信度"
                    value={currentStatus.enhanced_status?.semantic_validation?.overall_confidence ?
                      (currentStatus.enhanced_status.semantic_validation.overall_confidence * 100).toFixed(1) : 0}
                    suffix="%"
                    precision={1}
                  />
                </Col>
                <Col span={6}>
                  <Statistic
                    title="处理时间"
                    value={currentStatus.enhanced_status?.processing_summary?.total_processing_time || '60-90秒'}
                  />
                </Col>
                <Col span={6}>
                  <Statistic
                    title="状态"
                    value={currentStatus.status === 'ready_for_review' ? '完成' : '处理中'}
                    valueStyle={{
                      color: currentStatus.status === 'ready_for_review' ? '#3f8600' : '#1890ff'
                    }}
                  />
                </Col>
              </Row>
            </div>

            <EnhancedContractReview
              sessionData={currentStatus}
              onConfirm={(confirmedData) => {
                // Confirm import data
                message.success('功能开发中，数据提交功能将在下个版本实现');
              }}
              onRetry={handleRetry}
              onCancel={handleCancel}
              onDownload={handleDownloadResults}
            />
          </Space>
        </Card>
      )}

      {/* 底部操作按钮 */}
      {processing && (
        <div style={{ textAlign: 'center', marginTop: 24 }}>
          <Space>
            <Button onClick={handleRetry} disabled={!sessionId}>
              <RobotOutlined />
              刷新状态
            </Button>
            <Button onClick={handleCancel} danger>
              取消处理
            </Button>
          </Space>
        </div>
      )}

      {/* 帮助提示 */}
      <Alert
        message={
          <Space>
            <QuestionCircleOutlined />
            <Text style={{ marginLeft: 8 }}>
              提示：增强版PDF导入专门针对中文租赁合同进行了优化，相比标准版本识别准确率提升25-35%
            </Text>
          </Space>
        }
        type="info"
        style={{ marginTop: 24 }}
        showIcon
      />
    </div>
  );
};

export default EnhancedPDFImportPage;

/**
 * 租金台账页面
 */

import React, { useState, useEffect } from 'react';
import {
  Table,
  Card,
  Button,
  Space,
  Tag,
  Input,
  Select,
  DatePicker,
  message,
  Modal,
  Tooltip,
  Badge,
  Row,
  Col,
  Statistic,
  Typography,
  Form,
  Alert
} from 'antd';
import {
  SearchOutlined,
  EditOutlined,
  CheckOutlined,
  ClockCircleOutlined,
  ExclamationCircleOutlined,
  DollarOutlined,
  FileExcelOutlined,
  SyncOutlined,
  CalendarOutlined
} from '@ant-design/icons';
import type { ColumnsType } from 'antd/es/table';
import dayjs from 'dayjs';

import { RentLedger, RentLedgerQueryParams, RentLedgerPageState, RentLedgerUpdate } from '../../types/rentContract';
import { Asset } from '../../types/asset';
import { Ownership } from '../../types/ownership';
import { rentContractService } from '../../services/rentContractService';
import { assetService } from '../../services/assetService';
import { ownershipService } from '../../services/ownershipService';
import { useFormat } from '../../utils/format';

const { Title } = Typography;
const { Search } = Input;
const { Option } = Select;
const { RangePicker } = DatePicker;
const { Text } = Typography;

const RentLedgerPage: React.FC = () => {
  const [form] = Form.useForm();

  const [state, setState] = useState<RentLedgerPageState>({
    loading: false,
    ledgers: [],
    pagination: {
      current: 1,
      pageSize: 10,
      total: 0,
    },
    filters: {},
    selectedLedgers: [],
    showBatchModal: false,
    showGenerateModal: false,
  });

  const [assets, setAssets] = useState<Asset[]>([]);
  const [ownerships, setOwnerships] = useState<Ownership[]>([]);
  const [statistics, setStatistics] = useState<any>(null);

  const format = useFormat();

  // 加载台账列表
  const loadLedgers = async (params?: RentLedgerQueryParams) => {
    setState(prev => ({ ...prev, loading: true }));
    try {
      const response = await rentContractService.getRentLedgers({
        page: state.pagination.current,
        limit: state.pagination.pageSize,
        ...state.filters,
        ...params,
      });

      // 安全检查：确保response和response.items存在
      if (!response) {
        console.error('API响应为空');
        message.error('加载台账列表失败：响应为空');
        setState(prev => ({ ...prev, loading: false }));
        return;
      }

      // 确保items是一个数组
      const ledgers = Array.isArray(response.items) ? response.items : [];

      setState(prev => ({
        ...prev,
        loading: false,
        ledgers: ledgers,
        pagination: {
          ...prev.pagination,
          total: response.total || 0,
          pages: response.pages || 0,
        },
      }));
    } catch (error) {
      console.error('加载台账列表失败:', error);
      message.error(`加载台账列表失败: ${error instanceof Error ? error.message : '未知错误'}`);
      setState(prev => ({ ...prev, loading: false, ledgers: [] }));
    }
  };

  // 加载统计数据
  const loadStatistics = async () => {
    try {
      const stats = await rentContractService.getRentStatistics();
      setStatistics(stats);
    } catch (error) {
      console.error('加载统计数据失败:', error);
    }
  };

  // 加载资产和权属方数据
  const loadReferenceData = async () => {
    try {
      const [assetsResponse, ownershipsResponse] = await Promise.all([
        assetService.getAssets({ limit: 100 }),
        ownershipService.getOwnerships({ size: 100 }),
      ]);

      // 安全检查：确保响应和items存在
      const assets = assetsResponse?.items || [];
      const ownerships = ownershipsResponse?.items || [];

      setAssets(assets);
      setOwnerships(ownerships);
    } catch (error) {
      console.error('加载参考数据失败:', error);
      message.error(`加载参考数据失败: ${error instanceof Error ? error.message : '未知错误'}`);
    }
  };

  useEffect(() => {
    loadLedgers();
    loadStatistics();
    loadReferenceData();
  }, []);

  // 处理分页变化
  const handleTableChange = (pagination: { current: number; pageSize: number; total?: number }) => {
    setState(prev => ({
      ...prev,
      pagination: {
        ...prev.pagination,
        current: pagination.current,
        pageSize: pagination.pageSize,
      },
    }));
    loadLedgers({
      page: pagination.current,
      limit: pagination.pageSize,
    });
  };

  // 处理搜索
  const handleSearch = (values: Record<string, unknown>) => {
    setState(prev => ({
      ...prev,
      filters: values,
      pagination: { ...prev.pagination, current: 1 },
    }));
    loadLedgers({ ...values, page: 1 });
  };

  // 重置搜索
  const handleReset = () => {
    setState(prev => ({
      ...prev,
      filters: {},
      pagination: { ...prev.pagination, current: 1 },
    }));
    loadLedgers({ page: 1 });
  };

  // 更新台账支付状态
  const handleUpdateLedger = async (id: string, data: RentLedgerUpdate) => {
    try {
      await rentContractService.updateRentLedger(id, data);
      message.success('更新成功');
      loadLedgers();
      loadStatistics();
    } catch (error) {
      message.error('更新失败');
    }
  };

  // 批量更新支付状态
  const handleBatchUpdate = async (values: { paymentStatus: string; paymentDate?: string }) => {
    if (state.selectedLedgers.length === 0) {
      message.warning('请先选择要更新的台账记录');
      return;
    }

    try {
      await rentContractService.batchUpdateRentLedger({
        ledger_ids: state.selectedLedgers.map(ledger => ledger.id),
        payment_status: values.payment_status,
        payment_date: values.payment_date,
        payment_method: values.payment_method,
        notes: values.notes,
      });
      message.success('批量更新成功');
      setState(prev => ({ ...prev, showBatchModal: false, selectedLedgers: [] }));
      loadLedgers();
      loadStatistics();
    } catch (error) {
      message.error('批量更新失败');
    }
  };

  // 导出Excel
  const handleExport = async () => {
    try {
      const blob = await rentContractService.exportLedgersToExcel(state.filters);
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `租金台账_${dayjs().format('YYYY-MM-DD')}.xlsx`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);
      message.success('导出成功');
    } catch (error) {
      message.error('导出失败');
    }
  };

  // 选择行变化
  const rowSelection = {
    selectedRowKeys: state.selectedLedgers.map(ledger => ledger.id),
    onChange: (selectedRowKeys: string[], selectedRows: RentLedger[]) => {
      setState(prev => ({ ...prev, selectedLedgers: selectedRows }));
    },
  };

  // 快速支付
  const handleQuickPayment = async (ledger: RentLedger) => {
    Modal.confirm({
      title: '确认支付',
      content: `确认将台账 ${ledger.year_month} 标记为已支付？`,
      okText: '确认',
      cancelText: '取消',
      onOk: async () => {
        await handleUpdateLedger(ledger.id, {
          payment_status: '已支付',
          paid_amount: ledger.due_amount,
          payment_date: dayjs().format('YYYY-MM-DD'),
        });
      },
    });
  };

  // 表格列定义
  const columns: ColumnsType<RentLedger> = [
    {
      title: '年月',
      dataIndex: 'year_month',
      key: 'year_month',
      render: (text: string) => <Text strong>{text}</Text>,
    },
    {
      title: '合同编号',
      dataIndex: ['contract', 'contract_number'],
      key: 'contract_number',
      render: (text: string) => text || '未知',
    },
    {
      title: '承租方',
      dataIndex: ['contract', 'tenant_name'],
      key: 'tenant_name',
      render: (text: string) => text || '未知',
    },
    {
      title: '物业名称',
      dataIndex: ['asset', 'property_name'],
      key: 'property_name',
      render: (text: string) => text || '未知',
    },
    {
      title: '权属方',
      dataIndex: ['ownership', 'name'],
      key: 'ownership_name',
      render: (text: string) => text || '未知',
    },
    {
      title: '应缴日期',
      dataIndex: 'due_date',
      key: 'due_date',
      render: (date: string) => dayjs(date).format('YYYY-MM-DD'),
    },
    {
      title: '应收金额',
      dataIndex: 'due_amount',
      key: 'due_amount',
      render: (amount: number) => format.currency(amount),
      align: 'right' as const,
    },
    {
      title: '实收金额',
      dataIndex: 'paid_amount',
      key: 'paid_amount',
      render: (amount: number, record: RentLedger) => {
        const color = amount < record.due_amount ? '#ff4d4f' : '#52c41a';
        return <Text style={{ color }}>{format.currency(amount)}</Text>;
      },
      align: 'right' as const,
    },
    {
      title: '欠款金额',
      dataIndex: 'overdue_amount',
      key: 'overdue_amount',
      render: (amount: number) => {
        if (amount > 0) {
          return <Text type="danger">{format.currency(amount)}</Text>;
        }
        return '-';
      },
      align: 'right' as const,
    },
    {
      title: '支付状态',
      dataIndex: 'payment_status',
      key: 'payment_status',
      render: (status: string) => {
        const statusConfig = {
          '未支付': { color: 'default', icon: <ClockCircleOutlined /> },
          '部分支付': { color: 'warning', icon: <ExclamationCircleOutlined /> },
          '已支付': { color: 'success', icon: <CheckOutlined /> },
          '逾期': { color: 'error', icon: <ExclamationCircleOutlined /> },
        };
        const config = statusConfig[status as keyof typeof statusConfig] || statusConfig['未支付'];
        return (
          <Tag color={config.color} icon={config.icon}>
            {status}
          </Tag>
        );
      },
    },
    {
      title: '支付日期',
      dataIndex: 'payment_date',
      key: 'payment_date',
      render: (date: string) => date ? dayjs(date).format('YYYY-MM-DD') : '-',
    },
    {
      title: '操作',
      key: 'actions',
      width: 150,
      render: (record: RentLedger) => (
        <Space size="small">
          {record.payment_status !== '已支付' && (
            <Tooltip title="快速支付">
              <Button
                type="primary"
                size="small"
                icon={<CheckOutlined />}
                onClick={() => handleQuickPayment(record)}
              />
            </Tooltip>
          )}
          <Tooltip title="编辑">
            <Button
              type="text"
              icon={<EditOutlined />}
              onClick={() => {
                form.setFieldsValue({
                  payment_status: record.payment_status,
                  paid_amount: record.paid_amount,
                  payment_date: record.payment_date ? dayjs(record.payment_date) : null,
                  payment_method: record.payment_method,
                  notes: record.notes,
                });
                setState(prev => ({ ...prev, selectedLedgers: [record] }));
              }}
            />
          </Tooltip>
        </Space>
      ),
    },
  ];

  return (
    <div style={{ padding: '24px' }}>
      {/* 页面标题 */}
      <div style={{ marginBottom: '24px' }}>
        <Title level={2}>租金台账管理</Title>
        <p style={{ color: '#666' }}>管理物业租金台账，支持支付状态更新和统计分析</p>
      </div>

      {/* 统计卡片 */}
      {statistics && (
        <Row gutter={16} style={{ marginBottom: '24px' }}>
          <Col span={6}>
            <Card>
              <Statistic
                title="应收总额"
                value={statistics.total_due}
                precision={2}
                prefix={<DollarOutlined />}
                suffix="元"
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="已收总额"
                value={statistics.total_paid}
                precision={2}
                prefix={<DollarOutlined />}
                suffix="元"
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="欠款总额"
                value={statistics.total_overdue}
                precision={2}
                prefix={<DollarOutlined />}
                suffix="元"
                valueStyle={{ color: '#cf1322' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="收缴率"
                value={statistics.payment_rate}
                precision={2}
                suffix="%"
                valueStyle={{ color: statistics.payment_rate > 80 ? '#3f8600' : '#cf1322' }}
              />
            </Card>
          </Col>
        </Row>
      )}

      {/* 搜索区域 */}
      <Card style={{ marginBottom: '24px' }}>
        <Row gutter={16}>
          <Col span={4}>
            <Search
              placeholder="搜索合同或承租方"
              onSearch={(value) => handleSearch({ keyword: value })}
              enterButton={<SearchOutlined />}
            />
          </Col>
          <Col span={4}>
            <Select
              placeholder="选择物业"
              style={{ width: '100%' }}
              allowClear
              onChange={(value) => handleSearch({ asset_id: value })}
            >
              {assets.map(asset => (
                <Option key={asset.id} value={asset.id}>
                  {asset.property_name}
                </Option>
              ))}
            </Select>
          </Col>
          <Col span={4}>
            <Select
              placeholder="选择权属方"
              style={{ width: '100%' }}
              allowClear
              onChange={(value) => handleSearch({ ownership_id: value })}
            >
              {ownerships.map(ownership => (
                <Option key={ownership.id} value={ownership.id}>
                  {ownership.name}
                </Option>
              ))}
            </Select>
          </Col>
          <Col span={4}>
            <Select
              placeholder="支付状态"
              style={{ width: '100%' }}
              allowClear
              onChange={(value) => handleSearch({ payment_status: value })}
            >
              <Option value="未支付">未支付</Option>
              <Option value="部分支付">部分支付</Option>
              <Option value="已支付">已支付</Option>
              <Option value="逾期">逾期</Option>
            </Select>
          </Col>
          <Col span={4}>
            <DatePicker.MonthPicker
              placeholder="选择月份"
              style={{ width: '100%' }}
              onChange={(date, dateString) => handleSearch({ year_month: dateString })}
            />
          </Col>
          <Col span={4}>
            <Space>
              <Button onClick={handleReset}>重置</Button>
              <Button
                type="primary"
                icon={<FileExcelOutlined />}
                onClick={handleExport}
              >
                导出
              </Button>
            </Space>
          </Col>
        </Row>
      </Card>

      {/* 操作区域 */}
      {state.selectedLedgers.length > 0 && (
        <Alert
          message={`已选择 ${state.selectedLedgers.length} 条记录`}
          type="info"
          showIcon
          style={{ marginBottom: 16 }}
          action={
            <Space>
              <Button
                type="primary"
                size="small"
                onClick={() => setState(prev => ({ ...prev, showBatchModal: true }))}
              >
                批量更新
              </Button>
              <Button
                size="small"
                onClick={() => setState(prev => ({ ...prev, selectedLedgers: [] }))}
              >
                取消选择
              </Button>
            </Space>
          }
        />
      )}

      {/* 台账列表 */}
      <Card>
        <Table
          columns={columns}
          dataSource={state.ledgers}
          rowKey="id"
          rowSelection={rowSelection}
          loading={state.loading}
          pagination={{
            current: state.pagination.current,
            pageSize: state.pagination.pageSize,
            total: state.pagination.total,
            showSizeChanger: true,
            showQuickJumper: true,
            showTotal: (total, range) => `第 ${range[0]}-${range[1]} 条，共 ${total} 条`,
          }}
          onChange={handleTableChange}
          scroll={{ x: 1400 }}
        />
      </Card>

      {/* 批量更新弹窗 */}
      <Modal
        title="批量更新支付状态"
        open={state.showBatchModal}
        onCancel={() => setState(prev => ({ ...prev, showBatchModal: false }))}
        footer={null}
        width={500}
      >
        <Form
          form={form}
          layout="vertical"
          onFinish={handleBatchUpdate}
        >
          <Form.Item
            name="payment_status"
            label="支付状态"
            rules={[{ required: true, message: '请选择支付状态' }]}
          >
            <Select>
              <Option value="未支付">未支付</Option>
              <Option value="部分支付">部分支付</Option>
              <Option value="已支付">已支付</Option>
              <Option value="逾期">逾期</Option>
            </Select>
          </Form.Item>

          <Form.Item
            name="payment_date"
            label="支付日期"
          >
            <DatePicker style={{ width: '100%' }} />
          </Form.Item>

          <Form.Item
            name="payment_method"
            label="支付方式"
          >
            <Select placeholder="请选择支付方式">
              <Option value="现金">现金</Option>
              <Option value="银行转账">银行转账</Option>
              <Option value="支票">支票</Option>
              <Option value="其他">其他</Option>
            </Select>
          </Form.Item>

          <Form.Item
            name="notes"
            label="备注"
          >
            <Input.TextArea rows={3} placeholder="请输入备注信息" />
          </Form.Item>

          <Form.Item>
            <Space style={{ width: '100%', justifyContent: 'flex-end' }}>
              <Button
                onClick={() => setState(prev => ({ ...prev, showBatchModal: false }))}
              >
                取消
              </Button>
              <Button type="primary" htmlType="submit">
                确认更新
              </Button>
            </Space>
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
};

export default RentLedgerPage;

import React, { useState, useEffect } from 'react';
import {
  Card,
  Row,
  Col,
  Statistic,
  Table,
  DatePicker,
  Select,
  Button,
  Tabs,
  Tag,
  Progress,
  Space,
  Typography,
  message,
  Tooltip
} from 'antd';
import {
  PieChart,
  Pie,
  Cell,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip as RechartsTooltip,
  Legend,
  ResponsiveContainer,
  LineChart,
  Line
} from 'recharts';
import {
  DollarOutlined,
  FileTextOutlined,
  AccountBookOutlined,
  RiseOutlined,
  DownloadOutlined,
  ReloadOutlined
} from '@ant-design/icons';
import moment from 'moment';
import 'moment/locale/zh-cn';
import type { ColumnsType } from 'antd/es/table';

import {
  rentContractService,
  OwnershipRentStatistics,
  AssetRentStatistics,
  MonthlyRentStatistics
} from '@/services/rentContractService';
import { formatCurrency } from '@/utils/format';

const { RangePicker } = DatePicker;
const { Option } = Select;
const { Title } = Typography;

moment.locale('zh-cn');

// 颜色配置
const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884D8', '#82CA9D'];

const RentStatisticsPage: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [dateRange, setDateRange] = useState<[moment.Moment, moment.Moment]>([
    moment().startOf('year'),
    moment().endOf('year')
  ]);
  const [overviewData, setOverviewData] = useState<any>(null);
  const [ownershipStats, setOwnershipStats] = useState<OwnershipRentStatistics[]>([]);
  const [assetStats, setAssetStats] = useState<AssetRentStatistics[]>([]);
  const [monthlyStats, setMonthlyStats] = useState<MonthlyRentStatistics[]>([]);
  const [selectedYear, setSelectedYear] = useState<number>(moment().year());

  // 获取统计数据
  const fetchStatistics = async () => {
    setLoading(true);
    try {
      const [startDate, endDate] = dateRange;

      // 并行获取所有统计数据
      const [overview, ownershipData, assetData, monthlyData] = await Promise.all([
        rentContractService.getStatisticsOverview({
          start_date: startDate.format('YYYY-MM-DD'),
          end_date: endDate.format('YYYY-MM-DD')
        }),
        rentContractService.getOwnershipStatistics({
          start_date: startDate.format('YYYY-MM-DD'),
          end_date: endDate.format('YYYY-MM-DD')
        }),
        rentContractService.getAssetStatistics({
          start_date: startDate.format('YYYY-MM-DD'),
          end_date: endDate.format('YYYY-MM-DD')
        }),
        rentContractService.getMonthlyStatistics({
          year: selectedYear
        })
      ]);

      setOverviewData(overview);
      setOwnershipStats(ownershipData);
      setAssetStats(assetData);
      setMonthlyStats(monthlyData);
    } catch (error) {
      message.error('获取统计数据失败');
      console.error('Statistics fetch error:', error);
      // 设置默认值以防止undefined错误
      setOverviewData(null);
      setOwnershipStats([]);
      setAssetStats([]);
      setMonthlyStats([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchStatistics();
  }, [dateRange, selectedYear]);

  // 导出统计数据
  const exportStatistics = async () => {
    try {
      const blob = await rentContractService.exportStatistics({
        start_date: dateRange[0].format('YYYY-MM-DD'),
        end_date: dateRange[1].format('YYYY-MM-DD')
      });

      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `租金统计报表_${dateRange[0].format('YYYYMMDD')}_${dateRange[1].format('YYYYMMDD')}.xlsx`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);

      message.success('导出成功');
    } catch (error) {
      message.error('导出失败');
    }
  };

  // 权属方统计表格列
  const ownershipColumns: ColumnsType<OwnershipRentStatistics> = [
    {
      title: '权属方名称',
      dataIndex: 'ownership_name',
      key: 'ownership_name',
      render: (text, record) => (
        <div>
          <div style={{ fontWeight: 'bold' }}>{text}</div>
          <div style={{ fontSize: '12px', color: '#666' }}>
            {record.ownership_short_name}
          </div>
        </div>
      )
    },
    {
      title: '合同数量',
      dataIndex: 'contract_count',
      key: 'contract_count',
      align: 'center',
      render: (count) => <Tag color="blue">{count} 个</Tag>
    },
    {
      title: '应收总额',
      dataIndex: 'total_due_amount',
      key: 'total_due_amount',
      align: 'right',
      render: (amount) => formatCurrency(amount)
    },
    {
      title: '已收总额',
      dataIndex: 'total_paid_amount',
      key: 'total_paid_amount',
      align: 'right',
      render: (amount) => (
        <span style={{ color: '#52c41a' }}>
          {formatCurrency(amount)}
        </span>
      )
    },
    {
      title: '欠款总额',
      dataIndex: 'total_overdue_amount',
      key: 'total_overdue_amount',
      align: 'right',
      render: (amount) => (
        <span style={{ color: amount > 0 ? '#f5222d' : '#52c41a' }}>
          {formatCurrency(amount)}
        </span>
      )
    },
    {
      title: '收缴率',
      dataIndex: 'payment_rate',
      key: 'payment_rate',
      align: 'center',
      render: (rate) => {
        const percentage = Number(rate);
        let color = '#f5222d';
        if (percentage >= 90) color = '#52c41a';
        else if (percentage >= 70) color = '#faad14';

        return (
          <Progress
            type="circle"
            percent={percentage}
            width={50}
            strokeColor={color}
            format={() => `${percentage.toFixed(1)}%`}
          />
        );
      }
    }
  ];

  // 资产统计表格列
  const assetColumns: ColumnsType<AssetRentStatistics> = [
    {
      title: '资产名称',
      dataIndex: 'asset_name',
      key: 'asset_name',
      render: (text, record) => (
        <div>
          <div style={{ fontWeight: 'bold' }}>{text}</div>
          <div style={{ fontSize: '12px', color: '#666' }}>
            {record.asset_address?.substring(0, 30)}...
          </div>
        </div>
      )
    },
    {
      title: '合同数量',
      dataIndex: 'contract_count',
      key: 'contract_count',
      align: 'center',
      render: (count) => <Tag color="blue">{count} 个</Tag>
    },
    {
      title: '应收总额',
      dataIndex: 'total_due_amount',
      key: 'total_due_amount',
      align: 'right',
      render: (amount) => formatCurrency(amount)
    },
    {
      title: '已收总额',
      dataIndex: 'total_paid_amount',
      key: 'total_paid_amount',
      align: 'right',
      render: (amount) => (
        <span style={{ color: '#52c41a' }}>
          {formatCurrency(amount)}
        </span>
      )
    },
    {
      title: '欠款总额',
      dataIndex: 'total_overdue_amount',
      key: 'total_overdue_amount',
      align: 'right',
      render: (amount) => (
        <span style={{ color: amount > 0 ? '#f5222d' : '#52c41a' }}>
          {formatCurrency(amount)}
        </span>
      )
    },
    {
      title: '收缴率',
      dataIndex: 'payment_rate',
      key: 'payment_rate',
      align: 'center',
      render: (rate) => {
        const percentage = Number(rate);
        let color = '#f5222d';
        if (percentage >= 90) color = '#52c41a';
        else if (percentage >= 70) color = '#faad14';

        return (
          <Progress
            type="circle"
            percent={percentage}
            width={50}
            strokeColor={color}
            format={() => `${percentage.toFixed(1)}%`}
          />
        );
      }
    }
  ];

  // 准备图表数据
  const ownershipChartData = (ownershipStats || []).map(item => ({
    name: item.ownership_name,
    value: Number(item.total_due_amount),
    paid: Number(item.total_paid_amount),
    overdue: Number(item.total_overdue_amount)
  }));

  const monthlyChartData = (monthlyStats || []).map(item => ({
    month: item.year_month,
    due: Number(item.total_due_amount),
    paid: Number(item.total_paid_amount),
    overdue: Number(item.total_overdue_amount),
    rate: Number(item.payment_rate)
  }));

  // 标签页配置
  const tabItems = [
    {
      key: 'ownership',
      label: '权属方统计',
      children: (
        <Row gutter={[16, 16]}>
          <Col xs={24} lg={12}>
            <Card title="权属方租金分布" loading={loading}>
              <ResponsiveContainer width="100%" height={300}>
                <PieChart>
                  <Pie
                    data={ownershipChartData}
                    cx="50%"
                    cy="50%"
                    labelLine={false}
                    label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                    outerRadius={80}
                    fill="#8884d8"
                    dataKey="value"
                  >
                    {ownershipChartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <RechartsTooltip formatter={(value) => formatCurrency(Number(value))} />
                </PieChart>
              </ResponsiveContainer>
            </Card>
          </Col>
          <Col xs={24} lg={12}>
            <Card title="权属方收缴情况" loading={loading}>
              <Table
                columns={ownershipColumns}
                dataSource={ownershipStats}
                rowKey="ownership_id"
                pagination={false}
                loading={loading}
                scroll={{ x: 800 }}
              />
            </Card>
          </Col>
        </Row>
      )
    },
    {
      key: 'asset',
      label: '资产统计',
      children: (
        <Row gutter={[16, 16]}>
          <Col xs={24}>
            <Card title="资产租金统计" loading={loading}>
              <Table
                columns={assetColumns}
                dataSource={assetStats}
                rowKey="asset_id"
                pagination={{
                  pageSize: 10,
                  showSizeChanger: true,
                  showQuickJumper: true
                }}
                loading={loading}
                scroll={{ x: 1000 }}
              />
            </Card>
          </Col>
        </Row>
      )
    },
    {
      key: 'monthly',
      label: '月度趋势',
      children: (
        <Row gutter={[16, 16]}>
          <Col xs={24} lg={16}>
            <Card title="月度租金趋势" loading={loading}>
              <ResponsiveContainer width="100%" height={400}>
                <BarChart data={monthlyChartData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="month" />
                  <YAxis />
                  <RechartsTooltip formatter={(value) => formatCurrency(Number(value))} />
                  <Legend />
                  <Bar dataKey="due" name="应收金额" fill="#1890ff" />
                  <Bar dataKey="paid" name="已收金额" fill="#52c41a" />
                  <Bar dataKey="overdue" name="欠款金额" fill="#f5222d" />
                </BarChart>
              </ResponsiveContainer>
            </Card>
          </Col>
          <Col xs={24} lg={8}>
            <Card title="收缴率趋势" loading={loading}>
              <ResponsiveContainer width="100%" height={400}>
                <LineChart data={monthlyChartData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="month" />
                  <YAxis domain={[0, 100]} />
                  <RechartsTooltip formatter={(value) => `${value}%`} />
                  <Legend />
                  <Line
                    type="monotone"
                    dataKey="rate"
                    name="收缴率"
                    stroke="#52c41a"
                    strokeWidth={2}
                    dot={{ fill: '#52c41a' }}
                  />
                </LineChart>
              </ResponsiveContainer>
            </Card>
          </Col>
        </Row>
      )
    }
  ];

  return (
    <div style={{ padding: '24px', background: '#f0f2f5', minHeight: '100vh' }}>
      <Card>
        <div style={{ marginBottom: '24px' }}>
          <Row justify="space-between" align="middle">
            <Col>
              <Title level={3} style={{ margin: 0 }}>
                <AccountBookOutlined /> 租金统计报表
              </Title>
            </Col>
            <Col>
              <Space>
                <RangePicker
                  value={dateRange}
                  onChange={(dates) => setDateRange(dates as [moment.Moment, moment.Moment])}
                  style={{ width: 300 }}
                />
                <Select
                  value={selectedYear}
                  onChange={setSelectedYear}
                  style={{ width: 120 }}
                >
                  {Array.from({ length: 5 }, (_, i) => moment().year() - i).map(year => (
                    <Option key={year} value={year}>{year}年</Option>
                  ))}
                </Select>
                <Button
                  type="primary"
                  icon={<ReloadOutlined />}
                  onClick={fetchStatistics}
                  loading={loading}
                >
                  刷新
                </Button>
                <Button
                  icon={<DownloadOutlined />}
                  onClick={exportStatistics}
                >
                  导出
                </Button>
              </Space>
            </Col>
          </Row>
        </div>

        {/* 概览统计卡片 */}
        {overviewData && (
          <Row gutter={[16, 16]} style={{ marginBottom: '24px' }}>
            <Col xs={24} sm={12} md={6}>
              <Card>
                <Statistic
                  title="应收总额"
                  value={Number(overviewData.total_due_amount || 0)}
                  precision={2}
                  prefix={<DollarOutlined />}
                  suffix="元"
                  valueStyle={{ color: '#1890ff' }}
                />
              </Card>
            </Col>
            <Col xs={24} sm={12} md={6}>
              <Card>
                <Statistic
                  title="已收总额"
                  value={Number(overviewData.total_paid_amount || 0)}
                  precision={2}
                  prefix={<DollarOutlined />}
                  suffix="元"
                  valueStyle={{ color: '#52c41a' }}
                />
              </Card>
            </Col>
            <Col xs={24} sm={12} md={6}>
              <Card>
                <Statistic
                  title="欠款总额"
                  value={Number(overviewData.total_overdue_amount || 0)}
                  precision={2}
                  prefix={<DollarOutlined />}
                  suffix="元"
                  valueStyle={{ color: Number(overviewData.total_overdue_amount || 0) > 0 ? '#f5222d' : '#52c41a' }}
                />
              </Card>
            </Col>
            <Col xs={24} sm={12} md={6}>
              <Card>
                <Statistic
                  title="收缴率"
                  value={Number(overviewData.payment_rate || 0)}
                  precision={1}
                  prefix={<RiseOutlined />}
                  suffix="%"
                  valueStyle={{ color: Number(overviewData.payment_rate || 0) >= 90 ? '#52c41a' : '#faad14' }}
                />
              </Card>
            </Col>
          </Row>
        )}

        <Tabs defaultActiveKey="ownership" type="card" items={tabItems} />
      </Card>
    </div>
  );
};

export default RentStatisticsPage;

import React, { useEffect, useMemo, useState } from 'react'
import { Button, Card, Form, Input, Modal, Select, Space, Switch, Table, Tag, message, Popconfirm, Row, Col, Badge } from 'antd'
import type { ColumnsType } from 'antd/es/table'
import dayjs from 'dayjs'
import { SearchOutlined } from '@ant-design/icons'
import { unifiedDictionaryService } from '../../services/dictionary'
import type { EnumFieldType, EnumFieldValue, SystemDictionary } from '../../services/dictionary'
import EnumValuePreview from '../../components/Dictionary/EnumValuePreview'
import { handleError, withErrorHandling, createErrorHandler } from '../../utils/errorHandler'

const { Option } = Select
const { Search } = Input

interface EnumFieldWithType {
  type: EnumFieldType
  values: EnumFieldValue[]
}

interface EditState {
  visible: boolean
}

const DictionaryPage: React.FC = () => {
  const [loading, setLoading] = useState(false)
  const [dictTypes, setDictTypes] = useState<string[]>([])
  const [enumTypes, setEnumTypes] = useState<EnumFieldType[]>([])
  const [activeType, setActiveType] = useState<string | undefined>(undefined)
  const [data, setData] = useState<SystemDictionary[]>([])
  const [edit, setEdit] = useState<EditState>({ visible: false })
  const [editingRecord, setEditingRecord] = useState<SystemDictionary | null>(null)
  const [form] = Form.useForm<SystemDictionary>()

  // 创建上下文相关的错误处理器
  const handleDictionaryError = createErrorHandler('字典管理', {
    showDetails: false,
    duration: 3
  })

  // 新增状态
  const [searchText, setSearchText] = useState('')
  const [selectedCategory, setSelectedCategory] = useState<string>('all')
  const [allEnumData, setAllEnumData] = useState<EnumFieldWithType[]>([])
  const [detailModalVisible, setDetailModalVisible] = useState<boolean>(false)

  // 获取字典类型列表
  const fetchTypes = async () => {
    const result = await withErrorHandling(async () => {
      const types = await unifiedDictionaryService.getTypes()
      setDictTypes(types || [])

      // 同时获取枚举类型详细信息
      const typesData = await unifiedDictionaryService.getEnumFieldTypes()
      setEnumTypes(typesData || [])
    }, {
      errorMessage: '获取字典类型失败',
      successMessage: undefined
    })

    if (!result.success) {
      // 错误已由 withErrorHandling 处理
    }
  }

  // 获取所有枚举数据
  const fetchAllEnumData = async () => {
    setLoading(true)
    try {
      const data = await unifiedDictionaryService.getEnumFieldData()
      // Got enum data
      setAllEnumData(data)
    } catch (e: unknown) {
      console.error('获取枚举数据失败:', e)
      message.error(e?.message || '获取枚举数据失败')
    } finally {
      setLoading(false)
    }
  }

  // 获取指定类型的字典数据
  const fetchList = async (type?: string) => {
    if (!type) {
      setData([])
      return
    }

    setLoading(true)
    try {
      // 使用新的方法通过类型代码获取枚举值
      const list = await unifiedDictionaryService.getEnumFieldValuesByTypeCode(type)
      setData(list)
    } catch (e: unknown) {
      console.error('获取枚举值失败:', e)
      message.error(e?.message || '获取枚举值失败')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchTypes()
    fetchAllEnumData()
  }, [])

  useEffect(() => {
    fetchList(activeType)
  }, [activeType])

  const handleCreate = async () => {
    if (!activeType) {
      message.warning('请先选择字典类型')
      return
    }

    // 获取对应的枚举类型
    const targetType = enumTypes.find(type => type.code === activeType)
    if (!targetType) {
      message.error('未找到对应的枚举类型')
      return
    }

    setEditingRecord(null)
    setEdit({ visible: true })
    form.resetFields()
    const initialValues = {
      dict_type: activeType,
      sort_order: data.length > 0 ? Math.max(...data.map(d => d.sort_order)) + 1 : 0,
      is_active: true
    }

    // 使用 setTimeout 确保模态框完全打开后再设置表单值
    setTimeout(() => {
      form.setFieldsValue(initialValues as any)
    }, 0)
  }

  const handleEdit = (record: SystemDictionary) => {
    const targetType = enumTypes.find(type => type.code === record.dict_type)
    setEditingRecord(record)
    setEdit({ visible: true })

    // 设置表单初始值
    const formData = {
      ...record,
      dict_type: record.dict_type,
      dict_label: record.dict_label,
      dict_value: record.dict_value,
      dict_code: record.dict_code,
      description: record.description || '',
      sort_order: record.sort_order || 0,
      is_active: record.is_active
    }

    // 使用 setTimeout 确保模态框完全打开后再设置表单值
    setTimeout(() => {
      form.setFieldsValue(formData as any)
    }, 0)
  }

  const handleDelete = async (record: SystemDictionary) => {
    try {
      const success = await unifiedDictionaryService.deleteEnumValue(record.id)
      if (success) {
        message.success('删除成功')
        fetchList(activeType)
        fetchAllEnumData()
        // 如果详情模态框打开，刷新详情数据
        if (detailModalVisible) {
          fetchList(activeType)
        }
      } else {
        message.error('删除失败')
      }
    } catch (e: unknown) {
      message.error(e?.message || '删除失败')
    }
  }

  const submit = async () => {
    try {
      const values = await form.validateFields()

      if (!activeType) {
        message.error('未找到对应的枚举类型')
        return
      }

      const targetType = enumTypes.find(type => type.code === activeType)
      if (!targetType) {
        message.error('未找到对应的枚举类型')
        return
      }

      if (editingRecord) {
        // 更新现有枚举值
        const success = await unifiedDictionaryService.updateEnumValue(editingRecord.id, {
          label: values.dict_label,
          value: values.dict_value,
          code: values.dict_code,
          description: values.description,
          sort_order: values.sort_order,
          is_active: values.is_active
        })

        if (success) {
          message.success('更新成功')
        } else {
          message.error('更新失败')
          return
        }
      } else {
        // 创建新的枚举值
        const success = await unifiedDictionaryService.createEnumValue(targetType.id, {
          label: values.dict_label,
          value: values.dict_value,
          code: values.dict_code,
          description: values.description,
          sort_order: values.sort_order
        })

        if (success) {
          message.success('创建成功')
        } else {
          message.error('创建失败')
          return
        }
      }

      setEdit({ visible: false })
      setEditingRecord(null)
      fetchList(activeType)
      fetchAllEnumData()
      // 如果详情模态框打开，刷新详情数据
      if (detailModalVisible) {
        fetchList(activeType)
      }
    } catch (e: unknown) {
      if (e?.errorFields) return
      message.error(e?.message || '保存失败')
    }
  }

  const handleToggleActive = async (record: SystemDictionary, checked: boolean) => {
    try {
      const success = await unifiedDictionaryService.toggleEnumValueActive(record.id, checked)
      if (success) {
        message.success('状态已更新')
        fetchList(activeType)
        fetchAllEnumData()
        // 如果详情模态框打开，刷新详情数据
        if (detailModalVisible) {
          fetchList(activeType)
        }
      } else {
        message.error('更新失败')
      }
    } catch (e: unknown) {
      message.error(e?.message || '更新失败')
    }
  }

  // 获取所有分类
  const categories = useMemo(() => {
    if (!enumTypes || enumTypes.length === 0) {
      return ['all']
    }
    const cats = enumTypes.map(type => type.category || '未分类')
    return ['all', ...Array.from(new Set(cats))]
  }, [enumTypes])

  // 过滤和搜索逻辑
  const filteredEnumData = useMemo(() => {
    return allEnumData.filter(item => {
      // 分类筛选
      if (selectedCategory !== 'all' && item.type.category !== selectedCategory) {
        return false
      }

      // 搜索筛选
      if (searchText) {
        const searchLower = searchText.toLowerCase()
        const typeMatch = item.type.name.toLowerCase().includes(searchLower) ||
                         item.type.code.toLowerCase().includes(searchLower)
        const valueMatch = item.values.some(value =>
          value.label.toLowerCase().includes(searchLower) ||
          value.value.toLowerCase().includes(searchLower) ||
          (value.code && value.code.toLowerCase().includes(searchLower))
        )
        return typeMatch || valueMatch
      }

      return true
    })
  }, [allEnumData, selectedCategory, searchText])

  // 获取类型统计信息
  const getTypeStats = (type: EnumFieldType) => {
    const values = allEnumData.find(item => item.type.id === type.id)?.values || []
    const activeCount = values.filter(v => v.is_active).length
    return {
      total: values.length,
      active: activeCount,
      inactive: values.length - activeCount
    }
  }

  // 查看详情处理
  const handleViewDetail = async (typeCode: string) => {
    setActiveType(typeCode)
    await fetchList(typeCode)
    setDetailModalVisible(true)
  }

  // 概览视图列定义
  const overviewColumns: ColumnsType<EnumFieldWithType> = useMemo(() => [
    {
      title: '类型名称',
      dataIndex: ['type', 'name'],
      width: 200,
      render: (name: string, record) => (
        <div>
          <div style={{ fontWeight: 500 }}>{name}</div>
          <div style={{ fontSize: '12px', color: '#666' }}>
            <Tag color="blue" size="small">{record.type.code}</Tag>
          </div>
        </div>
      ),
    },
    {
      title: '分类',
      dataIndex: ['type', 'category'],
      width: 120,
      render: (category: string) => category || '未分类',
    },
    {
      title: '描述',
      dataIndex: ['type', 'description'],
      width: 200,
      ellipsis: true,
      render: (desc: string) => desc || '-',
    },
    {
      title: '枚举值预览',
      width: 300,
      render: (_, record) => (
        <EnumValuePreview
          values={record.values}
          maxDisplay={3}
          size="small"
          showInactiveCount={true}
        />
      ),
    },
    {
      title: '操作',
      key: 'action',
      width: 100,
      render: (_, record) => (
        <Button
          type="link"
          size="small"
          onClick={() => handleViewDetail(record.type.code)}
        >
          查看详情
        </Button>
      ),
    },
  ], [allEnumData])

  const columns: ColumnsType<SystemDictionary> = useMemo(() => [
    {
      title: '类型',
      dataIndex: 'dict_type',
      width: 160,
      render: (t: string) => {
        const typeInfo = enumTypes.find(et => et.code === t)
        return (
          <div>
            <Tag color="blue">{t}</Tag>
            {typeInfo && (
              <div style={{ fontSize: '12px', color: '#666', marginTop: '2px' }}>
                {typeInfo.name}
              </div>
            )}
          </div>
        )
      },
    },
    {
      title: '编码',
      dataIndex: 'dict_code',
      width: 160,
      render: (code: string) => code || '-'
    },
    { title: '标签', dataIndex: 'dict_label', width: 200 },
    { title: '值', dataIndex: 'dict_value', width: 200 },
    {
      title: '排序',
      dataIndex: 'sort_order',
      width: 80,
      render: (v: number) => v ?? 0,
    },
    {
      title: '启用',
      dataIndex: 'is_active',
      width: 100,
      render: (v: boolean, record) => (
        <Switch
          checked={v}
          onChange={(checked) => handleToggleActive(record, checked)}
        />
      ),
    },
    {
      title: '更新时间',
      dataIndex: 'updated_at',
      width: 180,
      render: (v: string) => (v ? dayjs(v).format('YYYY-MM-DD HH:mm') : '-'),
    },
    {
      title: '操作',
      key: 'action',
      fixed: 'right',
      width: 180,
      render: (_, record) => (
        <Space>
          <Button size="small" type="link" onClick={() => handleEdit(record)}>
            编辑
          </Button>
          <Popconfirm
            title="确认删除该枚举项？"
            description={`${record.dict_type} / ${record.dict_label}`}
            onConfirm={() => handleDelete(record)}
            okText="删除"
            okType="danger"
            cancelText="取消"
          >
            <Button size="small" type="link" danger>
              删除
            </Button>
          </Popconfirm>
        </Space>
      ),
    },
  ], [activeType, enumTypes])

  return (
    <div style={{ padding: '24px' }}>
      <Card
        title={
          <Space>
            <span>枚举值字段管理</span>
            <Badge count={enumTypes.length} showZero />
          </Space>
        }
        extra={
          <Space>
            <Button onClick={() => {
              fetchTypes()
              fetchAllEnumData()
              fetchList(activeType)
            }}>
              刷新
            </Button>
          </Space>
        }
      >
        {/* 搜索和筛选区域 */}
        <Row gutter={16} style={{ marginBottom: 24 }}>
          <Col span={8}>
            <Search
              placeholder="搜索枚举类型或值"
              value={searchText}
              onChange={(e) => setSearchText(e.target.value)}
              prefix={<SearchOutlined />}
              allowClear
            />
          </Col>
          <Col span={6}>
            <Select
              placeholder="选择分类"
              value={selectedCategory}
              onChange={setSelectedCategory}
              style={{ width: '100%' }}
            >
              {categories.map(cat => (
                <Option key={cat} value={cat}>
                  {cat === 'all' ? '全部分类' : cat}
                </Option>
              ))}
            </Select>
          </Col>
          <Col span={6}>
            <Select
              placeholder="选择字典类型"
              value={activeType}
              onChange={(v) => setActiveType(v)}
              style={{ width: '100%' }}
              allowClear
            >
              {enumTypes.map(t => (
                <Option key={t.code} value={t.code}>
                  {t.name} ({t.code})
                </Option>
              ))}
            </Select>
          </Col>
          <Col span={4}>
            <div style={{ textAlign: 'right' }}>
              <span style={{ color: '#666', fontSize: '14px' }}>
                共 {filteredEnumData.length} 个类型
              </span>
            </div>
          </Col>
        </Row>

        {/* 列表视图 */}
        <Table
          rowKey={(record) => record.type.id}
          loading={loading}
          columns={overviewColumns}
          dataSource={filteredEnumData}
          pagination={{
            pageSize: 10,
            showTotal: (total, range) => `第 ${range[0]}-${range[1]} 条，共 ${total} 条`
          }}
          scroll={{ x: 1200 }}
          size="middle"
        />
      </Card>

      <Modal
        open={edit.visible}
        title={editingRecord ? '编辑枚举值' : '新增枚举值'}
        onOk={submit}
        onCancel={() => {
          form.resetFields()
          setEdit({ visible: false })
          setEditingRecord(null)
        }}
        okText="保存"
        cancelText="取消"
        width={600}
      >
        <Form form={form} layout="vertical">
          <Form.Item name="dict_type" label="字典类型">
            <Input disabled placeholder="自动填充" />
          </Form.Item>

          <Form.Item
            name="dict_label"
            label="显示标签"
            rules={[{ required: true, message: '请输入显示标签' }]}
          >
            <Input placeholder="如：已确权、经营性等" />
          </Form.Item>

          <Form.Item
            name="dict_value"
            label="枚举值"
            rules={[{ required: true, message: '请输入枚举值' }]}
          >
            <Input placeholder="如：CONFIRMED、COMMERCIAL等" />
          </Form.Item>

          <Form.Item name="dict_code" label="编码">
            <Input placeholder="可选，如：confirmed、commercial等" />
          </Form.Item>

          <Form.Item name="description" label="描述">
            <Input.TextArea rows={2} placeholder="可选描述信息" />
          </Form.Item>

          <Form.Item name="sort_order" label="排序">
            <Input type="number" placeholder="排序，数值越小越靠前" />
          </Form.Item>


          {enumTypes.find(t => t.code === activeType) && (
            <div style={{
              padding: '12px',
              backgroundColor: '#f5f5f5',
              borderRadius: '6px',
              fontSize: '12px',
              color: '#666'
            }}>
              <div><strong>枚举类型：</strong>{enumTypes.find(t => t.code === activeType)?.name}</div>
              <div><strong>类型编码：</strong>{activeType}</div>
              <div><strong>分类：</strong>{enumTypes.find(t => t.code === activeType)?.category || '未分类'}</div>
              {enumTypes.find(t => t.code === activeType)?.description && (
                <div><strong>描述：</strong>{enumTypes.find(t => t.code === activeType)?.description}</div>
              )}
            </div>
          )}
        </Form>
      </Modal>

      {/* 详情模态框 */}
      <Modal
        open={detailModalVisible}
        title={
          activeType ? `${enumTypes.find(t => t.code === activeType)?.name} (${activeType})` : '枚举值详情'
        }
        onCancel={() => setDetailModalVisible(false)}
        footer={[
          <Button key="close" onClick={() => setDetailModalVisible(false)}>
            关闭
          </Button>,
          <Button
            key="add"
            type="primary"
            onClick={() => {
              setDetailModalVisible(false)
              handleCreate()
            }}
          >
            新增枚举值
          </Button>
        ]}
        width={1200}
        destroyOnHidden
      >
        <Table
          rowKey="id"
          loading={loading}
          columns={columns}
          dataSource={data}
          pagination={{ pageSize: 10 }}
          scroll={{ x: 1200 }}
        />
      </Modal>
    </div>
  )
}

export default DictionaryPage

import React, { useState, useEffect } from 'react'
import { message, Form } from 'antd'
import { unifiedDictionaryService } from '../../services/dictionaryService'
import type { EnumFieldType, EnumFieldValue, SystemDictionary, EnumFieldStatistics } from '../../services/dictionaryService'
import EnumValuePreview from '../../components/Dictionary/EnumValuePreview'
import { withErrorHandling, createErrorHandler } from '../../utils/errorHandler'

// 错误类型定义
interface ApiError extends Error {
  response?: {
    data?: {
      message?: string
      detail?: string
    }
  }
  message?: string
}

// 表单数据类型
interface EnumTypeFormData {
  type_name: string
  type_description?: string
  is_active: boolean
}

interface EnumValueFormData {
  value_key: string
  value_label: string
  value_description?: string
  is_active: boolean
  sort_order?: number
}

const EnumFieldPage: React.FC = () => {
  const [enumTypes, setEnumTypes] = useState<EnumFieldType[]>([]);
  const [enumValues, setEnumValues] = useState<EnumFieldValue[]>([]);
  const [statistics, setStatistics] = useState<EnumFieldStatistics | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedTypeId, setSelectedTypeId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState('types');

  // 模态框状态
  const [typeModalVisible, setTypeModalVisible] = useState(false);
  const [valueModalVisible, setValueModalVisible] = useState(false);
  const [editingType, setEditingType] = useState<EnumFieldType | null>(null);
  const [editingValue, setEditingValue] = useState<EnumFieldValue | null>(null);

  // 表单实例
  const [typeForm] = Form.useForm();
  const [valueForm] = Form.useForm();

  // 加载数据
  const loadEnumTypes = async () => {
    setLoading(true);
    try {
      const data = await unifiedDictionaryService.getEnumFieldTypes()
      setEnumTypes(data);
    } catch (error: unknown) {
      const apiError = error as ApiError
      message.error(apiError?.response?.data?.detail || apiError?.message || '加载枚举类型失败');
    } finally {
      setLoading(false);
    }
  };

  const loadEnumValues = async (typeId: string) => {
    try {
      const data = await unifiedDictionaryService.getEnumFieldValues(typeId)
      setEnumValues(data);
    } catch (error: unknown) {
      const apiError = error as ApiError
      message.error(apiError?.response?.data?.detail || apiError?.message || '加载枚举值失败');
    }
  };

  const loadStatistics = async () => {
    try {
      const stats = await unifiedDictionaryService.getDictionaryStats()
      setStatistics({
        total_types: stats.totalTypes,
        active_types: stats.activeTypes,
        total_values: stats.totalValues,
        active_values: stats.activeTypes,
        usage_count: 0,
        categories: []
      });
    } catch (error: unknown) {
      const apiError = error as ApiError
      message.error(error?.message || '加载统计信息失败');
    }
  };

  useEffect(() => {
    loadEnumTypes();
    loadStatistics();
  }, []);

  useEffect(() => {
    if (selectedTypeId) {
      loadEnumValues(selectedTypeId);
    }
  }, [selectedTypeId]);

  // 监听模态框打开和编辑值的变化
  useEffect(() => {
    if (valueModalVisible) {
      if (editingValue) {
        // 编辑模式 - 设置表单字段值
        const formData = {
          label: String(editingValue.label || ''),
          value: String(editingValue.value || ''),
          code: String(editingValue.code || ''),
          description: String(editingValue.description || ''),
          sort_order: Number(editingValue.sort_order || 0),
          color: String(editingValue.color || ''),
          icon: String(editingValue.icon || ''),
          is_active: Boolean(editingValue.is_active),
          is_default: Boolean(editingValue.is_default),
          enum_type_id: String(editingValue.enum_type_id || selectedTypeId)
        };

        // 使用 setTimeout 确保 modal 完全打开后再设置表单值
        setTimeout(() => {
          valueForm.setFieldsValue(formData);
        }, 0);
      } else {
        // 新建模式 - 重置表单为默认值
        const formData = {
          label: '',
          value: '',
          code: '',
          description: '',
          sort_order: 0,
          color: '',
          icon: '',
          is_active: true,
          is_default: false,
          enum_type_id: String(selectedTypeId || '')
        };

        // 使用 setTimeout 确保 modal 完全打开后再设置表单值
        setTimeout(() => {
          valueForm.setFieldsValue(formData);
        }, 0);
      }
    }
  }, [valueModalVisible, editingValue, selectedTypeId, valueForm]);

  // 枚举类型表格列定义
  const typeColumns: ColumnsType<EnumFieldType> = [
    {
      title: '类型名称',
      dataIndex: 'name',
      key: 'name',
      render: (text, record) => (
        <Space>
          <span>{text}</span>
          {record.is_system && <Tag color="blue">系统</Tag>}
        </Space>
      ),
    },
    {
      title: '编码',
      dataIndex: 'code',
      key: 'code',
      render: (text) => <code>{text}</code>,
    },
    {
      title: '类别',
      dataIndex: 'category',
      key: 'category',
      render: (text) => text || '-',
    },
    {
      title: '配置',
      key: 'config',
      render: (_, record) => (
        <Space>
          {record.is_multiple && <Tag color="green">多选</Tag>}
          {record.is_hierarchical && <Tag color="orange">层级</Tag>}
        </Space>
      ),
    },
    {
      title: '状态',
      dataIndex: 'status',
      key: 'status',
      render: (status) => (
        <Badge
          status={status === 'active' ? 'success' : 'default'}
          text={status === 'active' ? '启用' : '禁用'}
        />
      ),
    },
    {
      title: '枚举值预览',
      key: 'enum_values_preview',
      render: (_, record) => (
        <EnumValuePreview
          values={record.enum_values || []}
          maxDisplay={5}
          size="small"
          showInactiveCount={false}
        />
      ),
    },
    {
      title: '操作',
      key: 'action',
      render: (_, record) => (
        <Space>
          <Tooltip title="查看枚举值">
            <Button
              type="link"
              icon={<EyeOutlined />}
              onClick={() => {
                setSelectedTypeId(record.id);
                setActiveTab('values');
              }}
            />
          </Tooltip>
          <Tooltip title="编辑">
            <Button
              type="link"
              icon={<EditOutlined />}
              onClick={() => handleEditType(record)}
            />
          </Tooltip>
          {!record.is_system && (
            <Popconfirm
              title="确定删除此枚举类型吗？"
              onConfirm={() => handleDeleteType(record.id)}
            >
              <Button type="link" danger icon={<DeleteOutlined />} />
            </Popconfirm>
          )}
        </Space>
      ),
    },
  ];

  // 枚举值表格列定义
  const valueColumns: ColumnsType<EnumFieldValue> = [
    {
      title: '标签',
      dataIndex: 'label',
      key: 'label',
    },
    {
      title: '值',
      dataIndex: 'value',
      key: 'value',
      render: (text) => <code>{text}</code>,
    },
    {
      title: '编码',
      dataIndex: 'code',
      key: 'code',
      render: (text) => text ? <code>{text}</code> : '-',
    },
    {
      title: '颜色',
      dataIndex: 'color',
      key: 'color',
      render: (color) => color ? (
        <Space>
          <div
            style={{
              width: 16,
              height: 16,
              backgroundColor: color,
              border: '1px solid #d9d9d9',
              borderRadius: 2,
            }}
          />
          <span>{color}</span>
        </Space>
      ) : '-',
    },
    {
      title: '排序',
      dataIndex: 'sort_order',
      key: 'sort_order',
    },
    {
      title: '状态',
      key: 'status',
      render: (_, record) => (
        <Space>
          <Badge
            status={record.is_active ? 'success' : 'default'}
            text={record.is_active ? '启用' : '禁用'}
          />
          {record.is_default && <Tag color="gold">默认</Tag>}
        </Space>
      ),
    },
    {
      title: '操作',
      key: 'action',
      render: (_, record) => (
        <Space>
          <Button
            type="link"
            icon={<EditOutlined />}
            onClick={() => handleEditValue(record)}
          />
          <Popconfirm
            title="确定删除此枚举值吗？"
            onConfirm={() => handleDeleteValue(record.id)}
          >
            <Button type="link" danger icon={<DeleteOutlined />} />
          </Popconfirm>
        </Space>
      ),
    },
  ];

  // 处理函数
  const handleCreateType = () => {
    setEditingType(null);
    typeForm.resetFields();
    setTypeModalVisible(true);
  };

  const handleEditType = (type: EnumFieldType) => {
    setEditingType(type);
    typeForm.setFieldsValue(type);
    setTypeModalVisible(true);
  };

  const handleDeleteType = async (id: string) => {
    try {
      const success = await unifiedDictionaryService.deleteEnumFieldType(id)
      if (success) {
        message.success('删除成功');
        loadEnumTypes();
        loadStatistics();
      } else {
        message.error('删除失败');
      }
    } catch (error: unknown) {
      const apiError = error as ApiError
      message.error(error?.message || '删除失败');
    }
  };

  const handleCreateValue = () => {
    if (!selectedTypeId) {
      message.warning('请先选择枚举类型');
      return;
    }

    setEditingValue(null);
    valueForm.resetFields();
    setValueModalVisible(true);
  };

  const handleEditValue = (value: EnumFieldValue) => {
    setEditingValue(value);
    setValueModalVisible(true);
  };

  const handleDeleteValue = async (id: string) => {
    try {
      const success = await unifiedDictionaryService.deleteEnumValue(id)
      if (success) {
        message.success('删除成功');
        if (selectedTypeId) {
          loadEnumValues(selectedTypeId);
        }
      } else {
        message.error('删除失败');
      }
    } catch (error: unknown) {
      const apiError = error as ApiError
      message.error(error?.message || '删除失败');
    }
  };

  const handleTypeSubmit = async (values: EnumTypeFormData) => {
    try {
      let success = false
      if (editingType) {
        success = await unifiedDictionaryService.updateEnumFieldType(editingType.id, values)
      } else {
        success = await unifiedDictionaryService.createEnumFieldType(values) !== null
      }

      if (success) {
        message.success(editingType ? '更新成功' : '创建成功');
        setTypeModalVisible(false);
        loadEnumTypes();
        loadStatistics();
      } else {
        message.error('操作失败');
      }
    } catch (error: unknown) {
      const apiError = error as ApiError
      message.error(error?.message || '操作失败');
    }
  };

  const handleValueSubmit = async (values: EnumValueFormData) => {
    try {
      let success = false
      if (editingValue) {
        success = await unifiedDictionaryService.updateEnumFieldValue(selectedTypeId || editingValue.enum_type_id, editingValue.id, values) !== null
      } else {
        success = await unifiedDictionaryService.addEnumFieldValue(selectedTypeId!, values) !== null
      }

      if (success) {
        message.success(editingValue ? '更新成功' : '创建成功');
        setValueModalVisible(false);
        setEditingValue(null);
        if (selectedTypeId) {
          loadEnumValues(selectedTypeId);
        }
      } else {
        message.error('操作失败');
      }
    } catch (error: unknown) {
      const apiError = error as ApiError
      message.error(error?.message || '操作失败');
    }
  };

  return (
    <div style={{ padding: 24 }}>
      <Row gutter={16} style={{ marginBottom: 24 }}>
        <Col span={6}>
          <Card>
            <Statistic
              title="枚举类型总数"
              value={statistics?.total_types || 0}
              valueStyle={{ color: '#1890ff' }}
            />
          </Card>
        </Col>
        <Col span={6}>
          <Card>
            <Statistic
              title="启用类型"
              value={statistics?.active_types || 0}
              valueStyle={{ color: '#52c41a' }}
            />
          </Card>
        </Col>
        <Col span={6}>
          <Card>
            <Statistic
              title="枚举值总数"
              value={statistics?.total_values || 0}
              valueStyle={{ color: '#722ed1' }}
            />
          </Card>
        </Col>
        <Col span={6}>
          <Card>
            <Statistic
              title="使用次数"
              value={statistics?.usage_count || 0}
              valueStyle={{ color: '#fa8c16' }}
            />
          </Card>
        </Col>
      </Row>

      <Card>
        <Tabs activeKey={activeTab} onChange={setActiveTab}>
          <TabPane tab="枚举类型" key="types">
            <div style={{ marginBottom: 16 }}>
              <Button
                type="primary"
                icon={<PlusOutlined />}
                onClick={handleCreateType}
              >
                新建枚举类型
              </Button>
            </div>
            <Table
              columns={typeColumns}
              dataSource={enumTypes}
              rowKey="id"
              loading={loading}
              pagination={{
                showSizeChanger: true,
                showQuickJumper: true,
                showTotal: (total) => `共 ${total} 条记录`,
              }}
            />
          </TabPane>

          <TabPane tab="枚举值管理" key="values">
            <div style={{ marginBottom: 16 }}>
              <Space>
                <Select
                  placeholder="选择枚举类型"
                  style={{ width: 200 }}
                  value={selectedTypeId}
                  onChange={setSelectedTypeId}
                  allowClear
                >
                  {enumTypes.map((type) => (
                    <Option key={type.id} value={type.id}>
                      {type.name}
                    </Option>
                  ))}
                </Select>
                <Button
                  type="primary"
                  icon={<PlusOutlined />}
                  onClick={handleCreateValue}
                  disabled={!selectedTypeId}
                >
                  新建枚举值
                </Button>
              </Space>
            </div>
            <Table
              columns={valueColumns}
              dataSource={enumValues}
              rowKey="id"
              loading={loading}
              pagination={{
                showSizeChanger: true,
                showQuickJumper: true,
                showTotal: (total) => `共 ${total} 条记录`,
              }}
            />
          </TabPane>
        </Tabs>
      </Card>

      {/* 枚举类型编辑模态框 */}
      <Modal
        title={editingType ? '编辑枚举类型' : '新建枚举类型'}
        open={typeModalVisible}
        onCancel={() => setTypeModalVisible(false)}
        onOk={() => typeForm.submit()}
        width={600}
      >
        <Form
          form={typeForm}
          layout="vertical"
          onFinish={handleTypeSubmit}
        >
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="name"
                label="类型名称"
                rules={[{ required: true, message: '请输入类型名称' }]}
              >
                <Input placeholder="请输入类型名称" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="code"
                label="类型编码"
                rules={[
                  { required: true, message: '请输入类型编码' },
                  { pattern: /^[a-zA-Z0-9_]+$/, message: '编码只能包含字母、数字和下划线' }
                ]}
              >
                <Input placeholder="请输入类型编码" />
              </Form.Item>
            </Col>
          </Row>

          <Row gutter={16}>
            <Col span={12}>
              <Form.Item name="category" label="类别">
                <Input placeholder="请输入类别" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item name="status" label="状态" initialValue="active">
                <Select>
                  <Option value="active">启用</Option>
                  <Option value="inactive">禁用</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>

          <Form.Item name="description" label="描述">
            <TextArea rows={3} placeholder="请输入描述" />
          </Form.Item>

          <Row gutter={16}>
            <Col span={8}>
              <Form.Item name="is_multiple" label="支持多选" valuePropName="checked">
                <Switch />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item name="is_hierarchical" label="层级结构" valuePropName="checked">
                <Switch />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item name="default_value" label="默认值">
                <Input placeholder="默认值" />
              </Form.Item>
            </Col>
          </Row>
        </Form>
      </Modal>

      {/* 枚举值编辑模态框 */}
      <Modal
        key={editingValue ? `edit-${editingValue.id}` : 'create'}
        title={editingValue ? '编辑枚举值' : '新建枚举值'}
        open={valueModalVisible}
        onCancel={() => {
          valueForm.resetFields();
          setValueModalVisible(false);
        }}
        onOk={() => {
          valueForm.submit();
        }}
        width={600}
      >
        <Form
          form={valueForm}
          layout="vertical"
          onFinish={handleValueSubmit}
        >
          <Form.Item name="enum_type_id" hidden>
            <Input />
          </Form.Item>
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="label"
                label="显示标签"
                rules={[{ required: true, message: '请输入显示标签' }]}
              >
                <Input placeholder="请输入显示标签" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="value"
                label="枚举值"
                rules={[{ required: true, message: '请输入枚举值' }]}
              >
                <Input placeholder="请输入枚举值" />
              </Form.Item>
            </Col>
          </Row>

          <Row gutter={16}>
            <Col span={12}>
              <Form.Item name="code" label="编码">
                <Input placeholder="请输入编码" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item name="sort_order" label="排序">
                <Input type="number" placeholder="排序" />
              </Form.Item>
            </Col>
          </Row>

          <Row gutter={16}>
            <Col span={12}>
              <Form.Item name="color" label="颜色">
                <Input placeholder="#FFFFFF" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item name="icon" label="图标">
                <Input placeholder="图标名称" />
              </Form.Item>
            </Col>
          </Row>

          <Form.Item name="description" label="描述">
            <TextArea rows={3} placeholder="请输入描述" />
          </Form.Item>

          <Row gutter={16}>
            <Col span={12}>
              <Form.Item name="is_active" label="启用" valuePropName="checked">
                <Switch />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item name="is_default" label="默认值" valuePropName="checked">
                <Switch />
              </Form.Item>
            </Col>
          </Row>
        </Form>
      </Modal>
    </div>
  );
};

export default EnumFieldPage;

