  response_time: number
  error_message: string | null
  details: Record<string, unknown> | null
  created_at: string
}

interface LogStatistics {
  total: number
  today: number
  this_week: number
  this_month: number
  by_action: Record<string, number>
  by_module: Record<string, number>
  error_count: number
  avg_response_time: number
}

