          module: 'assets',
          module_name: '资产管理',
          resource_type: 'asset',
          resource_id: 'asset456',
          resource_name: '示例资产',
          ip_address: '192.168.1.102',
          user_agent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
          request_method: 'GET',
          request_url: '/api/v1/assets/asset456',
          response_status: 200,
          response_time: 80,
          error_message: null,
          details: { view_type: 'detail' },
          created_at: dayjs().subtract(3, 'hours').toISOString()
        }
      ]
      setLogs(mockLogs)
    } catch (error) {
      message.error('加载操作日志失败')
    } finally {
      setLoading(false)
    }
  }

  const loadStatistics = async () => {
    try {
      // 模拟统计数据
      const mockStats: LogStatistics = {
        total: logs.length,
        today: logs.filter(log => dayjs(log.created_at).isSame(dayjs(), 'day')).length,
        this_week: logs.filter(log => dayjs(log.created_at).isSame(dayjs(), 'week')).length,
        this_month: logs.filter(log => dayjs(log.created_at).isSame(dayjs(), 'month')).length,
        by_action: {},
        by_module: {},
        error_count: logs.filter(log => log.response_status >= 400).length,
        avg_response_time: Math.round(logs.reduce((sum, log) => sum + log.response_time, 0) / logs.length) || 0
      }
      setStatistics(mockStats)
    } catch (error) {
      message.error('加载统计信息失败')
    }
  }

  const handleSearch = (value: string) => {
    setSearchText(value)
    // 这里可以添加搜索逻辑
  }

  const handleViewDetail = (log: OperationLog) => {
    setSelectedLog(log)
    setDetailDrawerVisible(true)
  }

  const getActionTag = (action: string) => {
    const actionConfig = actionOptions.find(a => a.value === action)
    return (
      <Tag color={actionConfig?.color || 'default'} icon={actionConfig?.icon}>
        {actionConfig?.label || action}
      </Tag>
    )
  }

  const getStatusTag = (status: number) => {
    if (status >= 200 && status < 300) {
      return <Tag color="green">成功</Tag>
    } else if (status >= 400 && status < 500) {
      return <Tag color="orange">客户端错误</Tag>
    } else if (status >= 500) {
      return <Tag color="red">服务器错误</Tag>
    }
    return <Tag>未知</Tag>
  }

  const columns: ColumnsType<OperationLog> = [
    {
      title: '操作时间',
      dataIndex: 'created_at',
      key: 'created_at',
      width: 180,
      render: (date) => dayjs(date).format('YYYY-MM-DD HH:mm:ss')
    },
    {
      title: '用户信息',
      key: 'user_info',
      width: 150,
      render: (_, record) => (
        <Space direction="vertical" size="small">
          <div style={{ fontWeight: 500 }}>{record.user_name}</div>
          <div style={{ fontSize: '12px', color: '#666' }}>
            @{record.username}
          </div>
        </Space>
      )
    },
    {
      title: '操作',
      dataIndex: 'action',
      key: 'action',
      width: 100,
      render: (action) => getActionTag(action)
    },
    {
      title: '模块',
      dataIndex: 'module_name',
      key: 'module',
      width: 120,
      render: (module) => <Tag color="blue">{module}</Tag>
    },
    {
      title: '资源',
      key: 'resource',
      width: 150,
      render: (_, record) => (
        <div>
          <div style={{ fontWeight: 500 }}>{record.resource_name || '-'}</div>
          <div style={{ fontSize: '12px', color: '#666' }}>
            {record.resource_type || '-'}
          </div>
        </div>
      )
    },
    {
      title: 'IP地址',
      dataIndex: 'ip_address',
      key: 'ip_address',
      width: 120,
      render: (ip) => (
        <Tooltip title={ip}>
          <span>{ip}</span>
        </Tooltip>
      )
    },
    {
      title: '响应状态',
      dataIndex: 'response_status',
      key: 'response_status',
      width: 100,
      render: (status) => getStatusTag(status)
    },
    {
      title: '响应时间',
      dataIndex: 'response_time',
      key: 'response_time',
      width: 100,
      render: (time) => (
        <span style={{ color: time > 1000 ? '#ff4d4f' : time > 500 ? '#fa8c16' : '#52c41a' }}>
          {time}ms
        </span>
      )
    },
    {
      title: '操作',
      key: 'action',
      fixed: 'right',
      width: 80,
      render: (_, record) => (
        <Tooltip title="查看详情">
          <Button
            type="link"
            size="small"
            icon={<EyeOutlined />}
            onClick={() => handleViewDetail(record)}
          />
        </Tooltip>
      )
    }
  ]

  return (
    <div style={{ padding: '24px' }}>
      {/* 统计卡片 */}
      {statistics && (
        <Row gutter={16} style={{ marginBottom: 24 }}>
          <Col span={6}>
            <Card>
              <Statistic
                title="今日操作"
                value={statistics.today}
                prefix={<FileTextOutlined />}
                valueStyle={{ color: '#3f8600' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="本周操作"
                value={statistics.this_week}
                prefix={<SettingOutlined />}
                valueStyle={{ color: '#1890ff' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="错误数量"
                value={statistics.error_count}
                prefix={<ExclamationCircleOutlined />}
                valueStyle={{ color: '#cf1322' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="平均响应时间"
                value={statistics.avg_response_time}
                suffix="ms"
                prefix={<SettingOutlined />}
                valueStyle={{
                  color: statistics.avg_response_time > 1000 ? '#cf1322' :
                         statistics.avg_response_time > 500 ? '#fa8c16' : '#3f8600'
                }}
              />
            </Card>
          </Col>
        </Row>
      )}

      <Card>
        <div style={{ marginBottom: 16 }}>
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={12} md={6}>
              <Search
                placeholder="搜索用户名、资源或操作"
                allowClear
                onSearch={handleSearch}
                prefix={<SearchOutlined />}
              />
            </Col>
            <Col xs={24} sm={12} md={4}>
              <Select
                placeholder="模块筛选"
                allowClear
                style={{ width: '100%' }}
                onChange={setModuleFilter}
              >
                {moduleOptions.map(module => (
                  <Option key={module.value} value={module.value}>
                    {module.label}
                  </Option>
                ))}
              </Select>
            </Col>
            <Col xs={24} sm={12} md={4}>
              <Select
                placeholder="操作筛选"
                allowClear
                style={{ width: '100%' }}
                onChange={setActionFilter}
              >
                {actionOptions.map(action => (
                  <Option key={action.value} value={action.value}>
                    {action.label}
                  </Option>
                ))}
              </Select>
            </Col>
            <Col xs={24} sm={12} md={4}>
              <Select
                placeholder="状态筛选"
                allowClear
                style={{ width: '100%' }}
                onChange={setStatusFilter}
              >
                {statusOptions.map(status => (
                  <Option key={status.value} value={status.value}>
                    {status.label}
                  </Option>
                ))}
              </Select>
            </Col>
            <Col xs={24} sm={12} md={6}>
              <RangePicker
                style={{ width: '100%' }}
                onChange={(dates) => setDateRange(dates)}
                placeholder={['开始日期', '结束日期']}
              />
            </Col>
            <Col xs={24} sm={12} md={4}>
              <Button
                icon={<ReloadOutlined />}
                onClick={loadLogs}
                loading={loading}
              >
                刷新
              </Button>
            </Col>
          </Row>
        </div>

        <Table
          columns={columns}
          dataSource={logs}
          rowKey="id"
          loading={loading}
          pagination={{
            total: logs.length,
            pageSize: 20,
            showSizeChanger: true,
            showQuickJumper: true,
            showTotal: (total, range) => `第 ${range[0]}-${range[1]} 条，共 ${total} 条记录`
          }}
          scroll={{ x: 1200 }}
        />
      </Card>

      {/* 详情抽屉 */}
      <Drawer
        title="操作日志详情"
        placement="right"
        onClose={() => setDetailDrawerVisible(false)}
        open={detailDrawerVisible}
        width={800}
      >
        {selectedLog && (
          <div>
            <Descriptions column={1} bordered>
              <Descriptions.Item label="操作时间">
                {dayjs(selectedLog.created_at).format('YYYY-MM-DD HH:mm:ss')}
              </Descriptions.Item>
              <Descriptions.Item label="用户信息">
                <Space>
                  <UserOutlined />
                  <span>{selectedLog.user_name} (@{selectedLog.username})</span>
                </Space>
              </Descriptions.Item>
              <Descriptions.Item label="操作类型">
                {getActionTag(selectedLog.action)}
              </Descriptions.Item>
              <Descriptions.Item label="所属模块">
                <Tag color="blue">{selectedLog.module_name}</Tag>
              </Descriptions.Item>
              <Descriptions.Item label="资源信息">
                {selectedLog.resource_name ? (
                  <div>
                    <div>{selectedLog.resource_name}</div>
                    <div style={{ fontSize: '12px', color: '#666' }}>
                      {selectedLog.resource_type} (ID: {selectedLog.resource_id})
                    </div>
                  </div>
                ) : (
                  '-'
                )}
              </Descriptions.Item>
              <Descriptions.Item label="请求信息">
                <div>
                  <div>
                    <Tag color="purple">{selectedLog.request_method}</Tag>
                    <code style={{ background: '#f5f5f5', padding: '2px 4px' }}>
                      {selectedLog.request_url}
                    </code>
                  </div>
                  <div style={{ marginTop: 8, fontSize: '12px', color: '#666' }}>
                    IP: {selectedLog.ip_address}
                  </div>
                </div>
              </Descriptions.Item>
              <Descriptions.Item label="响应信息">
                <div>
                  <div>状态: {getStatusTag(selectedLog.response_status)}</div>
                  <div>耗时: <span style={{
                    color: selectedLog.response_time > 1000 ? '#ff4d4f' :
                           selectedLog.response_time > 500 ? '#fa8c16' : '#52c41a'
                  }}>
                    {selectedLog.response_time}ms
                  </span></div>
                </div>
              </Descriptions.Item>
              {selectedLog.error_message && (
                <Descriptions.Item label="错误信息">
                  <div style={{ color: '#ff4d4f', background: '#fff2f0', padding: '8px', borderRadius: '4px' }}>
                    {selectedLog.error_message}
                  </div>
                </Descriptions.Item>
              )}
              <Descriptions.Item label="用户代理">
                <div style={{ fontSize: '12px', color: '#666', wordBreak: 'break-all' }}>
                  {selectedLog.user_agent}
                </div>
              </Descriptions.Item>
              {selectedLog.details && (
                <Descriptions.Item label="详细信息">
                  <pre style={{
                    background: '#f5f5f5',
                    padding: '12px',
                    borderRadius: '4px',
                    fontSize: '12px',
                    overflow: 'auto'
                  }}>
                    {JSON.stringify(selectedLog.details, null, 2)}
                  </pre>
                </Descriptions.Item>
              )}
            </Descriptions>
          </div>
        )}
      </Drawer>
    </div>
  )
}

export default OperationLogPage

import React, { useState, useEffect } from 'react';
import {
  Card,
  Table,
  Button,
  Space,
  Modal,
  Form,
  Input,
  Select,
  TreeSelect,
  InputNumber,
  message,
  Popconfirm,
  Tag,
  Tooltip,
  Row,
  Col,
  Statistic,
  Tree,
  Tabs,
  Divider,
  Badge
} from 'antd';
import {
  PlusOutlined,
  EditOutlined,
  DeleteOutlined,
  ReloadOutlined,
  PartitionOutlined,
  TeamOutlined,
  BankOutlined,
  ApartmentOutlined,
  SettingOutlined,
  HistoryOutlined
} from '@ant-design/icons';
import type { ColumnsType } from 'antd/es/table';
import type { DataNode } from 'antd/es/tree';
import { Organization, OrganizationStatistics, OrganizationHistory } from '../../types/organization';
import { organizationService } from '../../services/organizationService';
import OrganizationChart from '../../components/OrganizationChart';

// 组织表单数据类型
interface OrganizationFormData {
  name: string
  code: string
  type: string
  parent_id?: string
  description?: string
  status: string
  sort_order?: number
}

const { Option } = Select;
const { TabPane } = Tabs;
const { Search } = Input;

const OrganizationPage: React.FC = () => {
  const [organizations, setOrganizations] = useState<Organization[]>([]);
  const [organizationTree, setOrganizationTree] = useState<DataNode[]>([]);
  const [statistics, setStatistics] = useState<OrganizationStatistics | null>(null);
  const [loading, setLoading] = useState(false);
  const [modalVisible, setModalVisible] = useState(false);
  const [historyModalVisible, setHistoryModalVisible] = useState(false);
  const [editingOrganization, setEditingOrganization] = useState<Organization | null>(null);
  const [selectedOrganization, setSelectedOrganization] = useState<Organization | null>(null);
  const [organizationHistory, setOrganizationHistory] = useState<OrganizationHistory[]>([]);
  const [activeTab, setActiveTab] = useState('list');
  
  const [form] = Form.useForm();

  // 组织类型选项
  const organizationTypes = [
    { value: 'company', label: '公司', icon: <BankOutlined /> },
    { value: 'department', label: '部门', icon: <TeamOutlined /> },
    { value: 'group', label: '集团', icon: <ApartmentOutlined /> },
    { value: 'division', label: '事业部', icon: <PartitionOutlined /> },
    { value: 'team', label: '团队', icon: <TeamOutlined /> },
    { value: 'branch', label: '分公司', icon: <BankOutlined /> },
    { value: 'office', label: '办事处', icon: <SettingOutlined /> }
  ];

  // 状态选项
  const statusOptions = [
    { value: 'active', label: '活跃', color: 'green' },
    { value: 'inactive', label: '停用', color: 'red' },
    { value: 'suspended', label: '暂停', color: 'orange' }
  ];

  useEffect(() => {
    loadOrganizations();
    loadOrganizationTree();
    loadStatistics();
  }, []);

  const loadOrganizations = async () => {
    setLoading(true);
    try {
      const data = await organizationService.getOrganizations();
      setOrganizations(data);
    } catch (error) {
      message.error('加载组织列表失败');
    } finally {
      setLoading(false);
    }
  };

  const loadOrganizationTree = async () => {
    try {
      const data = await organizationService.getOrganizationTree();
      setOrganizationTree(convertTreeToDataNodes(data));
    } catch (error) {
      message.error('加载组织树失败');
    }
  };

  const loadStatistics = async () => {
    try {
      const data = await organizationService.getStatistics();
      setStatistics(data);
    } catch (error) {
      message.error('加载统计信息失败');
    }
  };

  const convertToTreeData = (organizations: Organization[]): DataNode[] => {
    return organizations.map(org => ({
      key: org.id,
      title: (
        <span>
          {getTypeIcon(org.type)} {org.name} ({org.code})
          <Tag color={getStatusColor(org.status)} style={{ marginLeft: 8 }}>
            {getStatusLabel(org.status)}
          </Tag>
        </span>
      ),
      children: org.children ? convertToTreeData(org.children) : []
    }));
  };

  const convertTreeToDataNodes = (treeNodes: Organization[]): DataNode[] => {
    return treeNodes.map(node => ({
      key: node.id,
      title: (
        <span>
          {getTypeIcon(node.type)} {node.name} ({node.code})
          <Tag color={getStatusColor(node.status)} style={{ marginLeft: 8 }}>
            {getStatusLabel(node.status)}
          </Tag>
        </span>
      ),
      children: node.children ? convertTreeToDataNodes(node.children) : []
    }));
  };

  const getTypeIcon = (type: string) => {
    const typeConfig = organizationTypes.find(t => t.value === type);
    return typeConfig?.icon || <TeamOutlined />;
  };

  const getStatusColor = (status: string) => {
    const statusConfig = statusOptions.find(s => s.value === status);
    return statusConfig?.color || 'default';
  };

  const getStatusLabel = (status: string) => {
    const statusConfig = statusOptions.find(s => s.value === status);
    return statusConfig?.label || status;
  };

  const handleSearch = async (keyword: string) => {
    if (!keyword.trim()) {
      loadOrganizations();
      return;
    }
    
    setLoading(true);
    try {
      const data = await organizationService.searchOrganizations(keyword);
      setOrganizations(data);
    } catch (error) {
      message.error('搜索失败');
    } finally {
      setLoading(false);
    }
  };

  const handleCreate = () => {
    setEditingOrganization(null);
    form.resetFields();
    setModalVisible(true);
  };

  const handleEdit = (organization: Organization) => {
    setEditingOrganization(organization);
    form.setFieldsValue({
      ...organization,
      parent_id: organization.parent_id || undefined
    });
    setModalVisible(true);
  };

  const handleDelete = async (id: string) => {
    try {
      await organizationService.deleteOrganization(id);
      message.success('删除成功');
      loadOrganizations();
      loadOrganizationTree();
      loadStatistics();
    } catch (error) {
      message.error('删除失败');
    }
  };

  const handleViewHistory = async (organization: Organization) => {
    setSelectedOrganization(organization);
    try {
      const history = await organizationService.getOrganizationHistory(organization.id);
      setOrganizationHistory(history);
      setHistoryModalVisible(true);
    } catch (error) {
      message.error('加载历史记录失败');
    }
  };

  const handleSubmit = async (values: OrganizationFormData) => {
    try {
      if (editingOrganization) {
        await organizationService.updateOrganization(editingOrganization.id, values);
        message.success('更新成功');
      } else {
        await organizationService.createOrganization(values);
        message.success('创建成功');
      }
      setModalVisible(false);
      loadOrganizations();
      loadOrganizationTree();
      loadStatistics();
    } catch (error) {
      message.error(editingOrganization ? '更新失败' : '创建失败');
    }
  };

  const columns: ColumnsType<Organization> = [
    {
      title: '组织名称',
      dataIndex: 'name',
      key: 'name',
      render: (text, record) => (
        <Space>
          {getTypeIcon(record.type)}
          <span>{text}</span>
          <Tag color="blue">{record.code}</Tag>
        </Space>
      )
    },
    {
      title: '类型',
      dataIndex: 'type',
      key: 'type',
      render: (type) => {
        const typeConfig = organizationTypes.find(t => t.value === type);
        return typeConfig?.label || type;
      }
    },
    {
      title: '层级',
      dataIndex: 'level',
      key: 'level',
      render: (level) => <Badge count={level} color="blue" />
    },
    {
      title: '负责人',
      dataIndex: 'leader_name',
      key: 'leader_name',
      render: (name, record) => (
        name ? (
          <Tooltip title={`电话: ${record.leader_phone || '未设置'} | 邮箱: ${record.leader_email || '未设置'}`}>
            <span>{name}</span>
          </Tooltip>
        ) : '-'
      )
    },
    {
      title: '状态',
      dataIndex: 'status',
      key: 'status',
      render: (status) => (
        <Tag color={getStatusColor(status)}>
          {getStatusLabel(status)}
        </Tag>
      )
    },
    {
      title: '创建时间',
      dataIndex: 'created_at',
      key: 'created_at',
      render: (date) => new Date(date).toLocaleString()
    },
    {
      title: '操作',
      key: 'action',
      render: (_, record) => (
        <Space size="middle">
          <Button
            type="link"
            icon={<EditOutlined />}
            onClick={() => handleEdit(record)}
          >
            编辑
          </Button>
          <Button
            type="link"
            icon={<HistoryOutlined />}
            onClick={() => handleViewHistory(record)}
          >
            历史
          </Button>
          <Popconfirm
            title="确定要删除这个组织吗？"
            onConfirm={() => handleDelete(record.id)}
            okText="确定"
            cancelText="取消"
          >
            <Button
              type="link"
              danger
              icon={<DeleteOutlined />}
            >
              删除
            </Button>
          </Popconfirm>
        </Space>
      )
    }
  ];

  const historyColumns: ColumnsType<OrganizationHistory> = [
    {
      title: '操作类型',
      dataIndex: 'action',
      key: 'action',
      render: (action) => {
        const actionMap: { [key: string]: { label: string; color: string } } = {
          create: { label: '创建', color: 'green' },
          update: { label: '更新', color: 'blue' },
          delete: { label: '删除', color: 'red' }
        };
        const config = actionMap[action] || { label: action, color: 'default' };
        return <Tag color={config.color}>{config.label}</Tag>;
      }
    },
    {
      title: '字段名称',
      dataIndex: 'field_name',
      key: 'field_name',
      render: (field) => field || '-'
    },
    {
      title: '原值',
      dataIndex: 'old_value',
      key: 'old_value',
      render: (value) => value || '-'
    },
    {
      title: '新值',
      dataIndex: 'new_value',
      key: 'new_value',
      render: (value) => value || '-'
    },
    {
      title: '操作人',
      dataIndex: 'created_by',
      key: 'created_by',
      render: (user) => user || '系统'
    },
    {
      title: '操作时间',
      dataIndex: 'created_at',
      key: 'created_at',
      render: (date) => new Date(date).toLocaleString()
    }
  ];

  return (
    <div style={{ padding: '24px' }}>
      {/* 统计卡片 */}
      {statistics && (
        <Row gutter={16} style={{ marginBottom: 24 }}>
          <Col span={6}>
            <Card>
              <Statistic
                title="总组织数"
                value={statistics.total}
                prefix={<ApartmentOutlined />}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="活跃组织"
                value={statistics.active}
                prefix={<TeamOutlined />}
                valueStyle={{ color: '#3f8600' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="停用组织"
                value={statistics.inactive}
                prefix={<SettingOutlined />}
                valueStyle={{ color: '#cf1322' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="组织类型"
                value={Object.keys(statistics.by_type).length}
                prefix={<PartitionOutlined />}
              />
            </Card>
          </Col>
        </Row>
      )}

      <Card>
        <Tabs activeKey={activeTab} onChange={setActiveTab}>
          <TabPane tab="列表视图" key="list">
            <div style={{ marginBottom: 16 }}>
              <Row justify="space-between">
                <Col>
                  <Space>
                    <Search
                      placeholder="搜索组织名称、编码或描述"
                      allowClear
                      style={{ width: 300 }}
                      onSearch={handleSearch}
                    />
                    <Button
                      icon={<ReloadOutlined />}
                      onClick={loadOrganizations}
                    >
                      刷新
                    </Button>
                  </Space>
                </Col>
                <Col>
                  <Button
                    type="primary"
                    icon={<PlusOutlined />}
                    onClick={handleCreate}
                  >
                    新建组织
                  </Button>
                </Col>
              </Row>
            </div>

            <Table
              columns={columns}
              dataSource={organizations}
              rowKey="id"
              loading={loading}
              pagination={{
                total: organizations.length,
                pageSize: 10,
                showSizeChanger: true,
                showQuickJumper: true,
                showTotal: (total) => `共 ${total} 条记录`
              }}
            />
          </TabPane>

          <TabPane tab="树形视图" key="tree">
            <div style={{ marginBottom: 16 }}>
              <Button
                icon={<ReloadOutlined />}
                onClick={loadOrganizationTree}
              >
                刷新树形结构
              </Button>
            </div>
            
            <Tree
              treeData={organizationTree}
              showLine={{ showLeafIcon: false }}
              defaultExpandAll
              style={{ background: '#fafafa', padding: 16, borderRadius: 6 }}
            />
          </TabPane>

          <TabPane tab="组织架构图" key="chart">
            <OrganizationChart
              onEdit={handleEdit}
              onRefresh={() => {
                loadOrganizations();
                loadOrganizationTree();
                loadStatistics();
              }}
              height={600}
            />
          </TabPane>
        </Tabs>
      </Card>

      {/* 创建/编辑模态框 */}
      <Modal
        title={editingOrganization ? '编辑组织' : '新建组织'}
        open={modalVisible}
        onCancel={() => setModalVisible(false)}
        footer={null}
        width={800}
      >
        <Form
          form={form}
          layout="vertical"
          onFinish={handleSubmit}
        >
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="name"
                label="组织名称"
                rules={[{ required: true, message: '请输入组织名称' }]}
              >
                <Input placeholder="请输入组织名称" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="code"
                label="组织编码"
                rules={[
                  { required: true, message: '请输入组织编码' },
                  { pattern: /^[A-Z0-9_-]+$/, message: '编码只能包含大写字母、数字、下划线和连字符' }
                ]}
              >
                <Input placeholder="请输入组织编码" />
              </Form.Item>
            </Col>
          </Row>

          <Row gutter={16}>
            <Col span={8}>
              <Form.Item
                name="type"
                label="组织类型"
                rules={[{ required: true, message: '请选择组织类型' }]}
              >
                <Select placeholder="请选择组织类型">
                  {organizationTypes.map(type => (
                    <Option key={type.value} value={type.value}>
                      {type.icon} {type.label}
                    </Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="status"
                label="状态"
                rules={[{ required: true, message: '请选择状态' }]}
              >
                <Select placeholder="请选择状态">
                  {statusOptions.map(status => (
                    <Option key={status.value} value={status.value}>
                      <Tag color={status.color}>{status.label}</Tag>
                    </Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="sort_order"
                label="排序"
              >
                <InputNumber min={0} placeholder="排序号" style={{ width: '100%' }} />
              </Form.Item>
            </Col>
          </Row>

          <Form.Item
            name="parent_id"
            label="上级组织"
          >
            <TreeSelect
              placeholder="请选择上级组织"
              allowClear
              treeData={organizationTree}
              treeDefaultExpandAll
            />
          </Form.Item>

          <Divider orientation="left">负责人信息</Divider>
          
          <Row gutter={16}>
            <Col span={8}>
              <Form.Item
                name="leader_name"
                label="负责人姓名"
              >
                <Input placeholder="请输入负责人姓名" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="leader_phone"
                label="负责人电话"
              >
                <Input placeholder="请输入负责人电话" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="leader_email"
                label="负责人邮箱"
                rules={[{ type: 'email', message: '请输入正确的邮箱格式' }]}
              >
                <Input placeholder="请输入负责人邮箱" />
              </Form.Item>
            </Col>
          </Row>

          <Divider orientation="left">联系信息</Divider>
          
          <Row gutter={16}>
            <Col span={8}>
              <Form.Item
                name="phone"
                label="组织电话"
              >
                <Input placeholder="请输入组织电话" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="email"
                label="组织邮箱"
                rules={[{ type: 'email', message: '请输入正确的邮箱格式' }]}
              >
                <Input placeholder="请输入组织邮箱" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="address"
                label="组织地址"
              >
                <Input placeholder="请输入组织地址" />
              </Form.Item>
            </Col>
          </Row>

          <Form.Item
            name="description"
            label="组织描述"
          >
            <Input.TextArea rows={3} placeholder="请输入组织描述" />
          </Form.Item>

          <Form.Item
            name="functions"
            label="主要职能"
          >
            <Input.TextArea rows={3} placeholder="请输入主要职能" />
          </Form.Item>

          <Form.Item style={{ textAlign: 'right', marginBottom: 0 }}>
            <Space>
              <Button onClick={() => setModalVisible(false)}>
                取消
              </Button>
              <Button type="primary" htmlType="submit">
                {editingOrganization ? '更新' : '创建'}
              </Button>
            </Space>
          </Form.Item>
        </Form>
      </Modal>

      {/* 历史记录模态框 */}
      <Modal
        title={`组织历史记录 - ${selectedOrganization?.name}`}
        open={historyModalVisible}
        onCancel={() => setHistoryModalVisible(false)}
        footer={null}
        width={1000}
      >
        <Table
          columns={historyColumns}
          dataSource={organizationHistory}
          rowKey="id"
          pagination={{
            pageSize: 10,
            showSizeChanger: true,
            showTotal: (total) => `共 ${total} 条记录`
          }}
        />
      </Modal>
    </div>
  );
};

export default OrganizationPage;

import React, { useState, useEffect, useCallback } from 'react'
import {
  Card,
  Table,
  Button,
  Space,
  Modal,
  Form,
  Input,
  Select,
  message,
  Popconfirm,
  Tag,
  Tooltip,
  Row,
  Col,
  Statistic,
  Switch,
  Badge,
  Tree,
  Transfer,
  Divider,
  Typography
} from 'antd'
import SystemBreadcrumb from '../../components/System/SystemBreadcrumb'
import { roleService, type Role, type CreateRoleData, type UpdateRoleData } from '../../services/systemService'
import {
  PlusOutlined,
  EditOutlined,
  DeleteOutlined,
  ReloadOutlined,
  TeamOutlined,
  SettingOutlined,
  KeyOutlined,
  SafetyOutlined,
  UserOutlined,
  ApartmentOutlined
} from '@ant-design/icons'
import type { ColumnsType } from 'antd/es/table'
import type { TransferItem } from 'antd/es/transfer'
import type { DataNode } from 'antd/es/tree'
import dayjs from 'dayjs'

const { Option } = Select
const { Search } = Input
const { TextArea } = Input
const { Text } = Typography

// Role类型已从systemService导入

interface Permission {
  id: string
  name: string
  code: string
  module: string
  description: string
  type: 'menu' | 'action' | 'data'
}

interface RoleStatistics {
  total: number
  active: number
  inactive: number
  system: number
  custom: number
  avg_permissions: number
}

const RoleManagementPage: React.FC = () => {
  const [roles, setRoles] = useState<Role[]>([])
  const [permissions, setPermissions] = useState<Permission[]>([])
  const [statistics, setStatistics] = useState<RoleStatistics | null>(null)
  const [loading, setLoading] = useState(false)
  const [modalVisible, setModalVisible] = useState(false)
  const [permissionModalVisible, setPermissionModalVisible] = useState(false)
  const [editingRole, setEditingRole] = useState<Role | null>(null)
  const [selectedRole, setSelectedRole] = useState<Role | null>(null)
  const [targetPermissions, setTargetPermissions] = useState<string[]>([])
  const [searchText, setSearchText] = useState('')
  const [statusFilter, setStatusFilter] = useState<string>('')
  const [permissionTreeData, setPermissionTreeData] = useState<DataNode[]>([])

  const [form] = Form.useForm()

  // 状态选项
  const statusOptions = [
    { value: 'active', label: '启用', color: 'green' },
    { value: 'inactive', label: '停用', color: 'red' }
  ]

  // 权限模块选项
  const permissionModules = [
    { value: 'dashboard', label: '数据看板', icon: <SettingOutlined /> },
    { value: 'assets', label: '资产管理', icon: <ApartmentOutlined /> },
    { value: 'rental', label: '租赁管理', icon: <UserOutlined /> },
    { value: 'ownership', label: '权属方管理', icon: <KeyOutlined /> },
    { value: 'project', label: '项目管理', icon: <TeamOutlined /> },
    { value: 'system', label: '系统管理', icon: <SettingOutlined /> }
  ]

  useEffect(() => {
    loadRoles()
    loadPermissions()
    loadStatistics()
  }, [])

  const loadRoles = async () => {
    setLoading(true)
    try {
      // 模拟API调用
      const mockRoles: Role[] = [
        {
          id: 'admin',
          name: '系统管理员',
          code: 'admin',
          description: '拥有系统所有权限的超级管理员',
          status: 'active',
          permissions: ['dashboard.view', 'assets.*', 'rental.*', 'ownership.*', 'project.*', 'system.*'],
          user_count: 1,
          created_at: '2024-01-01T00:00:00Z',
          updated_at: '2024-10-15T00:00:00Z',
          is_system: true
        },
        {
          id: 'manager',
          name: '项目经理',
          code: 'project_manager',
          description: '负责项目管理的高级用户',
          status: 'active',
          permissions: ['dashboard.view', 'assets.view', 'assets.create', 'rental.view', 'ownership.view', 'project.*'],
          user_count: 5,
          created_at: '2024-01-02T00:00:00Z',
          updated_at: '2024-10-14T00:00:00Z',
          is_system: false
        },
        {
          id: 'user',
          name: '普通用户',
          code: 'normal_user',
          description: '基础权限的普通用户',
          status: 'active',
          permissions: ['dashboard.view', 'assets.view', 'rental.view', 'ownership.view', 'project.view'],
          user_count: 20,
          created_at: '2024-01-03T00:00:00Z',
          updated_at: '2024-10-13T00:00:00Z',
          is_system: false
        }
      ]
      setRoles(mockRoles)
    } catch (error) {
      message.error('加载角色列表失败')
    } finally {
      setLoading(false)
    }
  }

  const loadPermissions = async () => {
    try {
      // 模拟权限数据
      const mockPermissions: Permission[] = [
        { id: 'dashboard.view', name: '查看看板', code: 'dashboard.view', module: 'dashboard', description: '查看数据看板', type: 'menu' },
        { id: 'assets.view', name: '查看资产', code: 'assets.view', module: 'assets', description: '查看资产列表', type: 'menu' },
        { id: 'assets.create', name: '创建资产', code: 'assets.create', module: 'assets', description: '创建新资产', type: 'action' },
        { id: 'assets.edit', name: '编辑资产', code: 'assets.edit', module: 'assets', description: '编辑资产信息', type: 'action' },
        { id: 'assets.delete', name: '删除资产', code: 'assets.delete', module: 'assets', description: '删除资产', type: 'action' },
        { id: 'rental.view', name: '查看租赁', code: 'rental.view', module: 'rental', description: '查看租赁合同', type: 'menu' },
        { id: 'rental.create', name: '创建合同', code: 'rental.create', module: 'rental', description: '创建租赁合同', type: 'action' },
        { id: 'ownership.view', name: '查看权属方', code: 'ownership.view', module: 'ownership', description: '查看权属方信息', type: 'menu' },
        { id: 'project.view', name: '查看项目', code: 'project.view', module: 'project', description: '查看项目信息', type: 'menu' },
        { id: 'project.create', name: '创建项目', code: 'project.create', module: 'project', description: '创建新项目', type: 'action' },
        { id: 'system.user.view', name: '查看用户', code: 'system.user.view', module: 'system', description: '查看用户管理', type: 'menu' },
        { id: 'system.user.create', name: '创建用户', code: 'system.user.create', module: 'system', description: '创建新用户', type: 'action' },
        { id: 'system.role.view', name: '查看角色', code: 'system.role.view', module: 'system', description: '查看角色管理', type: 'menu' },
        { id: 'system.role.create', name: '创建角色', code: 'system.role.create', module: 'system', description: '创建新角色', type: 'action' }
      ]
      setPermissions(mockPermissions)

      // 构建权限树
      const treeData = buildPermissionTree(mockPermissions)
      setPermissionTreeData(treeData)
    } catch (error) {
      message.error('加载权限列表失败')
    }
  }

  const buildPermissionTree = (permissions: Permission[]): DataNode[] => {
    const moduleMap: Record<string, DataNode> = {}

    // 按模块分组
    permissions.forEach(permission => {
      if (!moduleMap[permission.module]) {
        const module = permissionModules.find(m => m.value === permission.module)
        moduleMap[permission.module] = {
          key: permission.module,
          title: (
            <Space>
              {module?.icon || <SettingOutlined />}
              {module?.label || permission.module}
            </Space>
          ),
          children: []
        }
      }

      moduleMap[permission.module].children!.push({
        key: permission.id,
        title: (
          <Space>
            <span>{permission.name}</span>
            <Tag size="small" color={
              permission.type === 'menu' ? 'blue' :
              permission.type === 'action' ? 'green' : 'orange'
            }>
              {permission.type === 'menu' ? '菜单' :
               permission.type === 'action' ? '操作' : '数据'}
            </Tag>
          </Space>
        )
      })
    })

    return Object.values(moduleMap)
  }

  const loadStatistics = async () => {
    try {
      // 模拟统计数据
      const mockStats: RoleStatistics = {
        total: roles.length,
        active: roles.filter(r => r.status === 'active').length,
        inactive: roles.filter(r => r.status === 'inactive').length,
        system: roles.filter(r => r.is_system).length,
        custom: roles.filter(r => !r.is_system).length,
        avg_permissions: Math.round(roles.reduce((sum, r) => sum + r.permissions.length, 0) / roles.length) || 0
      }
      setStatistics(mockStats)
    } catch (error) {
      message.error('加载统计信息失败')
    }
  }

  const handleSearch = (value: string) => {
    setSearchText(value)
    // 这里可以添加搜索逻辑
  }

  const handleCreate = () => {
    setEditingRole(null)
    form.resetFields()
    setModalVisible(true)
  }

  const handleEdit = (role: Role) => {
    setEditingRole(role)
    form.setFieldsValue({
      name: role.name,
      code: role.code,
      description: role.description,
      status: role.status
    })
    setModalVisible(true)
  }

  const handleDelete = async (id: string) => {
    try {
      // 模拟删除API调用
      message.success('删除成功')
      loadRoles()
      loadStatistics()
    } catch (error) {
      message.error('删除失败')
    }
  }

  const handleToggleStatus = async (role: Role, newStatus: string) => {
    try {
      // 模拟状态切换API调用
      message.success('状态已更新')
      loadRoles()
      loadStatistics()
    } catch (error) {
      message.error('状态更新失败')
    }
  }

  const handleManagePermissions = (role: Role) => {
    setSelectedRole(role)
    setTargetPermissions(role.permissions)
    setPermissionModalVisible(true)
  }

  const handleSubmit = async (values: {
    name: string;
    description?: string;
    permissions?: string[];
    isActive?: boolean;
  }) => {
    try {
      if (editingRole) {
        // 模拟更新API调用
        message.success('更新成功')
      } else {
        // 模拟创建API调用
        message.success('创建成功')
      }
      setModalVisible(false)
      loadRoles()
      loadStatistics()
    } catch (error) {
      message.error(editingRole ? '更新失败' : '创建失败')
    }
  }

  const handleSavePermissions = async () => {
    try {
      // 模拟保存权限API调用
      message.success('权限配置已保存')
      setPermissionModalVisible(false)
      loadRoles()
    } catch (error) {
      message.error('保存权限失败')
    }
  }

  const getStatusTag = (status: string) => {
    const statusConfig = statusOptions.find(s => s.value === status)
    return (
      <Tag color={statusConfig?.color || 'default'}>
        {statusConfig?.label || status}
      </Tag>
    )
  }

  const columns: ColumnsType<Role> = [
    {
      title: '角色信息',
      key: 'role_info',
      render: (_, record) => (
        <Space>
          <TeamOutlined style={{ color: '#1890ff' }} />
          <div>
            <div style={{ fontWeight: 500 }}>{record.name}</div>
            <div style={{ fontSize: '12px', color: '#666' }}>
              {record.code}
              {record.is_system && (
                <Tag size="small" color="purple" style={{ marginLeft: 8 }}>
                  系统角色
                </Tag>
              )}
            </div>
          </div>
        </Space>
      )
    },
    {
      title: '描述',
      dataIndex: 'description',
      key: 'description',
      ellipsis: true
    },
    {
      title: '权限数量',
      dataIndex: 'permissions',
      key: 'permissions',
      render: (permissions) => (
        <Badge count={permissions.length} showZero color="#1890ff" />
      )
    },
    {
      title: '用户数量',
      dataIndex: 'user_count',
      key: 'user_count',
      render: (count) => (
        <Badge count={count} showZero color="#52c41a" />
      )
    },
    {
      title: '状态',
      dataIndex: 'status',
      key: 'status',
      render: (status) => getStatusTag(status)
    },
    {
      title: '创建时间',
      dataIndex: 'created_at',
      key: 'created_at',
      render: (date) => dayjs(date).format('YYYY-MM-DD')
    },
    {
      title: '操作',
      key: 'action',
      render: (_, record) => (
        <Space size="middle">
          <Tooltip title="编辑">
            <Button
              type="link"
              size="small"
              icon={<EditOutlined />}
              onClick={() => handleEdit(record)}
              disabled={record.is_system}
            />
          </Tooltip>
          <Tooltip title="权限配置">
            <Button
              type="link"
              size="small"
              icon={<KeyOutlined />}
              onClick={() => handleManagePermissions(record)}
            />
          </Tooltip>
          <Tooltip title={record.status === 'active' ? '停用' : '启用'}>
            <Switch
              size="small"
              checked={record.status === 'active'}
              onChange={(checked) => handleToggleStatus(record, checked ? 'active' : 'inactive')}
              disabled={record.is_system}
            />
          </Tooltip>
          <Popconfirm
            title="确定要删除这个角色吗？"
            onConfirm={() => handleDelete(record.id)}
            okText="确定"
            cancelText="取消"
            disabled={record.is_system}
          >
            <Tooltip title="删除">
              <Button
                type="link"
                size="small"
                danger
                icon={<DeleteOutlined />}
                disabled={record.is_system}
              />
            </Tooltip>
          </Popconfirm>
        </Space>
      )
    }
  ]

  // Transfer组件的数据转换
  const transferData: TransferItem[] = permissions.map(permission => ({
    key: permission.id,
    title: permission.name,
    description: `${permission.code} - ${permission.description}`
  }))

  return (
    <>
      <SystemBreadcrumb />
      <div style={{ padding: '24px' }}>
        {/* 统计卡片 */}
      {statistics && (
        <Row gutter={16} style={{ marginBottom: 24 }}>
          <Col span={6}>
            <Card>
              <Statistic
                title="总角色数"
                value={statistics.total}
                prefix={<TeamOutlined />}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="启用角色"
                value={statistics.active}
                prefix={<SafetyOutlined />}
                valueStyle={{ color: '#3f8600' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="系统角色"
                value={statistics.system}
                prefix={<SettingOutlined />}
                valueStyle={{ color: '#722ed1' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="平均权限数"
                value={statistics.avg_permissions}
                prefix={<KeyOutlined />}
                suffix="个"
              />
            </Card>
          </Col>
        </Row>
      )}

      <Card>
        <div style={{ marginBottom: 16 }}>
          <Row justify="space-between" gutter={16}>
            <Col flex="auto">
              <Space size="middle">
                <Search
                  placeholder="搜索角色名称或编码"
                  allowClear
                  style={{ width: 300 }}
                  onSearch={handleSearch}
                />
                <Select
                  placeholder="状态筛选"
                  allowClear
                  style={{ width: 120 }}
                  onChange={setStatusFilter}
                >
                  {statusOptions.map(status => (
                    <Option key={status.value} value={status.value}>
                      {status.label}
                    </Option>
                  ))}
                </Select>
                <Button
                  icon={<ReloadOutlined />}
                  onClick={loadRoles}
                >
                  刷新
                </Button>
              </Space>
            </Col>
            <Col>
              <Button
                type="primary"
                icon={<PlusOutlined />}
