        by_organization: {}
      }
      setStatistics(mockStats)
    } catch (error) {
      message.error('加载统计信息失败')
    }
  }

  const handleSearch = (value: string) => {
    setSearchText(value)
    // 这里可以添加搜索逻辑
  }

  const handleCreate = () => {
    setEditingUser(null)
    form.resetFields()
    setModalVisible(true)
  }

  const handleEdit = (user: User) => {
    setEditingUser(user)
    form.setFieldsValue({
      username: user.username,
      email: user.email,
      full_name: user.full_name,
      phone: user.phone,
      status: user.status,
      role: user.role,
      organization_id: user.organization_id
    })
    setModalVisible(true)
  }

  const handleDelete = async (id: string) => {
    try {
      // 模拟删除API调用
      message.success('删除成功')
      loadUsers()
      loadStatistics()
    } catch (error) {
      message.error('删除失败')
    }
  }

  const handleToggleStatus = async (user: User, newStatus: string) => {
    try {
      // 模拟状态切换API调用
      message.success('状态已更新')
      loadUsers()
      loadStatistics()
    } catch (error) {
      message.error('状态更新失败')
    }
  }

  const handleToggleLock = async (user: User) => {
    try {
      // 模拟锁定/解锁API调用
      message.success(user.is_locked ? '用户已解锁' : '用户已锁定')
      loadUsers()
      loadStatistics()
    } catch (error) {
      message.error('操作失败')
    }
  }

  const handleViewDetail = (user: User) => {
    setSelectedUser(user)
    setDetailDrawerVisible(true)
  }

  const handleSubmit = async (values: CreateUserData | UpdateUserData) => {
    try {
      if (editingUser) {
        // 模拟更新API调用
        message.success('更新成功')
      } else {
        // 模拟创建API调用
        message.success('创建成功')
      }
      setModalVisible(false)
      loadUsers()
      loadStatistics()
    } catch (error) {
      message.error(editingUser ? '更新失败' : '创建失败')
    }
  }

  const getStatusTag = (status: string) => {
    const statusConfig = statusOptions.find(s => s.value === status)
    return (
      <Tag color={statusConfig?.color || 'default'}>
        {statusConfig?.label || status}
      </Tag>
    )
  }

  const columns: ColumnsType<User> = [
    {
      title: '用户信息',
      key: 'user_info',
      render: (_, record) => (
        <Space>
          <Avatar icon={<UserOutlined />} />
          <div>
            <div style={{ fontWeight: 500 }}>{record.full_name}</div>
            <div style={{ fontSize: '12px', color: '#666' }}>
              @{record.username}
            </div>
          </div>
        </Space>
      )
    },
    {
      title: '联系方式',
      key: 'contact',
      render: (_, record) => (
        <div>
          <div>{record.email}</div>
          <div style={{ fontSize: '12px', color: '#666' }}>
            {record.phone || '未设置'}
          </div>
        </div>
      )
    },
    {
      title: '角色',
      dataIndex: 'role_name',
      key: 'role',
      render: (role) => <Tag color="blue">{role}</Tag>
    },
    {
      title: '组织',
      dataIndex: 'organization_name',
      key: 'organization'
    },
    {
      title: '状态',
      dataIndex: 'status',
      key: 'status',
      render: (status, record) => (
        <Space>
          {getStatusTag(status)}
          {record.is_locked && (
            <Tooltip title="账户已锁定">
              <LockOutlined style={{ color: '#ff4d4f' }} />
            </Tooltip>
          )}
        </Space>
      )
    },
    {
      title: '最后登录',
      dataIndex: 'last_login',
      key: 'last_login',
      render: (date) => date ? dayjs(date).format('YYYY-MM-DD HH:mm') : '从未登录'
    },
    {
      title: '操作',
      key: 'action',
      render: (_, record) => (
        <Space size="middle">
          <Tooltip title="查看详情">
            <Button
              type="link"
              size="small"
              icon={<EyeOutlined />}
              onClick={() => handleViewDetail(record)}
            />
          </Tooltip>
          <Tooltip title="编辑">
            <Button
              type="link"
              size="small"
              icon={<EditOutlined />}
              onClick={() => handleEdit(record)}
            />
          </Tooltip>
          <Tooltip title={record.is_locked ? '解锁' : '锁定'}>
            <Button
              type="link"
              size="small"
              icon={record.is_locked ? <UnlockOutlined /> : <LockOutlined />}
              onClick={() => handleToggleLock(record)}
              style={{ color: record.is_locked ? '#52c41a' : '#ff4d4f' }}
            />
          </Tooltip>
          <Tooltip title={record.status === 'active' ? '停用' : '启用'}>
            <Switch
              size="small"
              checked={record.status === 'active'}
              onChange={(checked) => handleToggleStatus(record, checked ? 'active' : 'inactive')}
            />
          </Tooltip>
          <Popconfirm
            title="确定要删除这个用户吗？"
            onConfirm={() => handleDelete(record.id)}
            okText="确定"
            cancelText="取消"
            icon={<ExclamationCircleOutlined style={{ color: 'red' }} />}
          >
            <Tooltip title="删除">
              <Button
                type="link"
                size="small"
                danger
                icon={<DeleteOutlined />}
              />
            </Tooltip>
          </Popconfirm>
        </Space>
      )
    }
  ]

  return (
    <>
      <SystemBreadcrumb />
      <div style={{ padding: '24px' }}>
        {/* 统计卡片 */}
      {statistics && (
        <Row gutter={16} style={{ marginBottom: 24 }}>
          <Col span={6}>
            <Card>
              <Statistic
                title="总用户数"
                value={statistics.total}
                prefix={<UserOutlined />}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="活跃用户"
                value={statistics.active}
                prefix={<TeamOutlined />}
                valueStyle={{ color: '#3f8600' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="停用用户"
                value={statistics.inactive}
                prefix={<SettingOutlined />}
                valueStyle={{ color: '#cf1322' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card>
              <Statistic
                title="锁定用户"
                value={statistics.locked}
                prefix={<LockOutlined />}
                valueStyle={{ color: '#fa8c16' }}
              />
            </Card>
          </Col>
        </Row>
      )}

      <Card>
        <div style={{ marginBottom: 16 }}>
          <Row justify="space-between" gutter={16}>
            <Col flex="auto">
              <Space size="middle">
                <Search
                  placeholder="搜索用户名、邮箱或姓名"
                  allowClear
                  style={{ width: 300 }}
                  onSearch={handleSearch}
                />
                <Select
                  placeholder="状态筛选"
                  allowClear
                  style={{ width: 120 }}
                  onChange={setStatusFilter}
                >
                  {statusOptions.map(status => (
                    <Option key={status.value} value={status.value}>
                      {status.label}
                    </Option>
                  ))}
                </Select>
                <Select
                  placeholder="角色筛选"
                  allowClear
                  style={{ width: 120 }}
                  onChange={setRoleFilter}
                >
                  {roles.map(role => (
                    <Option key={role.id} value={role.id}>
                      {role.name}
                    </Option>
                  ))}
                </Select>
                <Select
                  placeholder="组织筛选"
                  allowClear
                  style={{ width: 120 }}
                  onChange={setOrganizationFilter}
                >
                  {organizations.map(org => (
                    <Option key={org.id} value={org.id}>
                      {org.name}
                    </Option>
                  ))}
                </Select>
                <Button
                  icon={<ReloadOutlined />}
                  onClick={loadUsers}
                >
                  刷新
                </Button>
              </Space>
            </Col>
            <Col>
              <Button
                type="primary"
                icon={<PlusOutlined />}
                onClick={handleCreate}
              >
                新建用户
              </Button>
            </Col>
          </Row>
        </div>

        <Table
          columns={columns}
          dataSource={users}
          rowKey="id"
          loading={loading}
          pagination={{
            total: users.length,
            pageSize: 10,
            showSizeChanger: true,
            showQuickJumper: true,
            showTotal: (total) => `共 ${total} 条记录`
          }}
        />
      </Card>

      {/* 创建/编辑模态框 */}
      <Modal
        title={editingUser ? '编辑用户' : '新建用户'}
        open={modalVisible}
        onCancel={() => setModalVisible(false)}
        footer={null}
        width={600}
      >
        <Form
          form={form}
          layout="vertical"
          onFinish={handleSubmit}
        >
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="username"
                label="用户名"
                rules={[
                  { required: true, message: '请输入用户名' },
                  { pattern: /^[a-zA-Z0-9_]+$/, message: '用户名只能包含字母、数字和下划线' }
                ]}
              >
                <Input placeholder="请输入用户名" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="email"
                label="邮箱"
                rules={[
                  { required: true, message: '请输入邮箱' },
                  { type: 'email', message: '请输入正确的邮箱格式' }
                ]}
              >
                <Input placeholder="请输入邮箱" />
              </Form.Item>
            </Col>
          </Row>

          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="full_name"
                label="姓名"
                rules={[{ required: true, message: '请输入姓名' }]}
              >
                <Input placeholder="请输入姓名" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="phone"
                label="手机号"
                rules={[
                  { pattern: /^1[3-9]\d{9}$/, message: '请输入正确的手机号格式' }
                ]}
              >
                <Input placeholder="请输入手机号" />
              </Form.Item>
            </Col>
          </Row>

          <Row gutter={16}>
            <Col span={8}>
              <Form.Item
                name="status"
                label="状态"
                rules={[{ required: true, message: '请选择状态' }]}
              >
                <Select placeholder="请选择状态">
                  {statusOptions.map(status => (
                    <Option key={status.value} value={status.value}>
                      {status.label}
                    </Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="role"
                label="角色"
                rules={[{ required: true, message: '请选择角色' }]}
              >
                <Select placeholder="请选择角色">
                  {roles.map(role => (
                    <Option key={role.id} value={role.id}>
                      {role.name}
                    </Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="organization_id"
                label="所属组织"
                rules={[{ required: true, message: '请选择所属组织' }]}
              >
                <Select placeholder="请选择所属组织">
                  {organizations.map(org => (
                    <Option key={org.id} value={org.id}>
                      {org.name}
                    </Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
          </Row>

          <Form.Item style={{ textAlign: 'right', marginBottom: 0 }}>
            <Space>
              <Button onClick={() => setModalVisible(false)}>
                取消
              </Button>
              <Button type="primary" htmlType="submit">
                {editingUser ? '更新' : '创建'}
              </Button>
            </Space>
          </Form.Item>
        </Form>
      </Modal>

      {/* 用户详情抽屉 */}
      <Drawer
        title="用户详情"
        placement="right"
        onClose={() => setDetailDrawerVisible(false)}
        open={detailDrawerVisible}
        width={600}
      >
        {selectedUser && (
          <div>
            <div style={{ textAlign: 'center', marginBottom: 24 }}>
              <Avatar size={80} icon={<UserOutlined />} />
              <h3 style={{ marginTop: 16, marginBottom: 8 }}>
                {selectedUser.full_name}
              </h3>
              <p style={{ color: '#666', margin: 0 }}>
                @{selectedUser.username}
              </p>
            </div>

            <Descriptions column={1} bordered>
              <Descriptions.Item label="用户名">
                {selectedUser.username}
              </Descriptions.Item>
              <Descriptions.Item label="邮箱">
                {selectedUser.email}
              </Descriptions.Item>
              <Descriptions.Item label="手机号">
                {selectedUser.phone || '未设置'}
              </Descriptions.Item>
              <Descriptions.Item label="角色">
                <Tag color="blue">{selectedUser.role_name}</Tag>
              </Descriptions.Item>
              <Descriptions.Item label="所属组织">
                {selectedUser.organization_name}
              </Descriptions.Item>
              <Descriptions.Item label="状态">
                <Space>
                  {getStatusTag(selectedUser.status)}
                  {selectedUser.is_locked && (
                    <Tag color="red">已锁定</Tag>
                  )}
                </Space>
              </Descriptions.Item>
              <Descriptions.Item label="最后登录">
                {selectedUser.last_login
                  ? dayjs(selectedUser.last_login).format('YYYY-MM-DD HH:mm:ss')
                  : '从未登录'
                }
              </Descriptions.Item>
              <Descriptions.Item label="创建时间">
                {dayjs(selectedUser.created_at).format('YYYY-MM-DD HH:mm:ss')}
              </Descriptions.Item>
              <Descriptions.Item label="更新时间">
                {dayjs(selectedUser.updated_at).format('YYYY-MM-DD HH:mm:ss')}
              </Descriptions.Item>
            </Descriptions>

            <div style={{ marginTop: 24, textAlign: 'center' }}>
              <Space>
                <Button
                  type="primary"
                  icon={<EditOutlined />}
                  onClick={() => {
                    setDetailDrawerVisible(false)
                    handleEdit(selectedUser)
                  }}
                >
                  编辑用户
                </Button>
                <Button
                  icon={selectedUser.is_locked ? <UnlockOutlined /> : <LockOutlined />}
                  onClick={() => {
                    setDetailDrawerVisible(false)
                    handleToggleLock(selectedUser)
                  }}
                >
                  {selectedUser.is_locked ? '解锁账户' : '锁定账户'}
                </Button>
              </Space>
            </div>
          </div>
        )}
      </Drawer>
    </div>
    </>
  )
}

export default UserManagementPage

import React, { useState, useEffect } from 'react';
import {
  Card,
  Row,
  Col,
  Statistic,
  Progress,
  Table,
  Button,
  DatePicker,
  Space,
  Tag,
  Tooltip,
  Alert,
  Modal,
  Form,
  InputNumber,
  message,
  Tabs,
  Divider
} from 'antd';
import {
  ReloadOutlined,
  SettingOutlined,
  TrendingUpOutlined,
  TrendingDownOutlined,
  CheckCircleOutlined,
  CloseCircleOutlined,
  InfoCircleOutlined
} from '@ant-design/icons';
import { Line, Column } from '@ant-design/plots';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import dayjs from 'dayjs';
import type { ColumnsType } from 'antd/es/table';

// 类型定义
interface CoverageMetrics {
  module_name: string;
  coverage_percentage: number;
  lines_covered: number;
  lines_total: number;
  branches_covered: number;
  branches_total: number;
  functions_covered: number;
  functions_total: number;
  last_updated: string;
  file_path: string;
}

interface CoverageReport {
  project_name: string;
  total_coverage: number;
  backend_coverage?: number;
  frontend_coverage?: number;
  module_metrics: CoverageMetrics[];
  test_execution_time?: number;
  total_tests: number;
  passed_tests: number;
  failed_tests: number;
  skipped_tests: number;
  generated_at: string;
}

interface CoverageTrend {
  date: string;
  backend_coverage?: number;
  frontend_coverage?: number;
  total_coverage: number;
}

interface CoverageThreshold {
  backend_threshold: number;
  frontend_threshold: number;
  total_threshold: number;
}

// 图表数据类型定义
interface ChartDatum {
  覆盖率: number
  [key: string]: number | string
}

interface CoverageTrendDatum {
  date: string
  total_coverage: number
  backend_coverage?: number
  frontend_coverage?: number
}

interface QualityGateResult {
  passed: boolean;
  thresholds: {
    backend: number;
    frontend: number;
    total: number;
  };
  current_coverage: {
    backend?: number;
    frontend?: number;
    total: number;
  };
  failed_checks: string[];
}

// API服务函数
const fetchCoverageReport = async (): Promise<CoverageReport> => {
  const response = await fetch('/api/v1/test-coverage/report');
  if (!response.ok) {
    throw new Error('获取覆盖率报告失败');
  }
  return response.json();
};

const fetchCoverageTrend = async (days: number = 30): Promise<CoverageTrend[]> => {
  const response = await fetch(`/api/v1/test-coverage/trend?days=${days}`);
  if (!response.ok) {
    throw new Error('获取覆盖率趋势失败');
  }
  return response.json();
};

const fetchModuleCoverage = async (
  minCoverage: number = 0,
  maxCoverage: number = 100
): Promise<CoverageMetrics[]> => {
  const response = await fetch(
    `/api/v1/test-coverage/modules?min_coverage=${minCoverage}&max_coverage=${maxCoverage}`
  );
  if (!response.ok) {
    throw new Error('获取模块覆盖率失败');
  }
  return response.json();
};

const fetchCoverageThresholds = async (): Promise<CoverageThreshold> => {
  const response = await fetch('/api/v1/test-coverage/thresholds');
  if (!response.ok) {
    throw new Error('获取覆盖率阈值失败');
  }
  return response.json();
};

const updateCoverageThresholds = async (thresholds: CoverageThreshold): Promise<CoverageThreshold> => {
  const response = await fetch('/api/v1/test-coverage/thresholds', {
    method: 'PUT',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(thresholds),
  });
  if (!response.ok) {
    throw new Error('更新覆盖率阈值失败');
  }
  return response.json();
};

const fetchQualityGate = async (): Promise<QualityGateResult> => {
  const response = await fetch('/api/v1/test-coverage/quality-gate');
  if (!response.ok) {
    throw new Error('获取质量门禁状态失败');
  }
  return response.json();
};

// 主组件
const TestCoverageDashboard: React.FC = () => {
  const [trendDays, setTrendDays] = useState(30);
  const [thresholdModalVisible, setThresholdModalVisible] = useState(false);
  const [form] = Form.useForm();
  const queryClient = useQueryClient();

  // 获取覆盖率报告
  const { data: coverageReport, isLoading: reportLoading, refetch: refetchReport } = useQuery({
    queryKey: ['coverage-report'],
    queryFn: fetchCoverageReport,
    refetchInterval: 60000, // 每分钟刷新一次
  });

  // 获取覆盖率趋势
  const { data: coverageTrend, isLoading: trendLoading } = useQuery({
    queryKey: ['coverage-trend', trendDays],
    queryFn: () => fetchCoverageTrend(trendDays),
  });

  // 获取模块覆盖率
  const { data: moduleCoverage, isLoading: moduleLoading } = useQuery({
    queryKey: ['module-coverage'],
    queryFn: () => fetchModuleCoverage(),
  });

  // 获取阈值配置
  const { data: thresholds, isLoading: thresholdsLoading } = useQuery({
    queryKey: ['coverage-thresholds'],
    queryFn: fetchCoverageThresholds,
  });

  // 获取质量门禁状态
  const { data: qualityGate, isLoading: qualityGateLoading } = useQuery({
    queryKey: ['quality-gate'],
    queryFn: fetchQualityGate,
    refetchInterval: 30000, // 每30秒检查一次
  });

  // 更新阈值配置
  const updateThresholdsMutation = useMutation({
    mutationFn: updateCoverageThresholds,
    onSuccess: (data) => {
      message.success('阈值配置更新成功');
      setThresholdModalVisible(false);
      queryClient.setQueryData(['coverage-thresholds'], data);
    },
    onError: (error) => {
      message.error(`更新阈值失败: ${error.message}`);
    },
  });

  // 处理阈值表单提交
  const handleThresholdSubmit = (values: CoverageThreshold) => {
    updateThresholdsMutation.mutate(values);
  };

  // 模块覆盖率表格列配置
  const moduleColumns: ColumnsType<CoverageMetrics> = [
    {
      title: '模块名称',
      dataIndex: 'module_name',
      key: 'module_name',
      width: 200,
      render: (text, record) => (
        <Tooltip title={record.file_path}>
          <span>{text}</span>
        </Tooltip>
      ),
    },
    {
      title: '覆盖率',
      dataIndex: 'coverage_percentage',
      key: 'coverage_percentage',
      width: 120,
      sorter: (a, b) => a.coverage_percentage - b.coverage_percentage,
      render: (value) => {
        const color = value >= 80 ? '#52c41a' : value >= 60 ? '#faad14' : '#ff4d4f';
        return (
          <Progress
            percent={value}
            size="small"
            strokeColor={color}
            format={(percent) => `${percent?.toFixed(1)}%`}
          />
        );
      },
    },
    {
      title: '行覆盖率',
      key: 'lines',
      width: 120,
      render: (_, record) => (
        <span>
          {record.lines_covered}/{record.lines_total}
          <span style={{ marginLeft: 4, color: '#666' }}>
            ({((record.lines_covered / record.lines_total) * 100).toFixed(1)}%)
          </span>
        </span>
      ),
    },
    {
      title: '分支覆盖率',
      key: 'branches',
      width: 120,
      render: (_, record) => (
        <span>
          {record.branches_covered}/{record.branches_total}
          <span style={{ marginLeft: 4, color: '#666' }}>
            ({((record.branches_covered / record.branches_total) * 100).toFixed(1)}%)
          </span>
        </span>
      ),
    },
    {
      title: '函数覆盖率',
      key: 'functions',
      width: 120,
      render: (_, record) => (
        <span>
          {record.functions_covered}/{record.functions_total}
          <span style={{ marginLeft: 4, color: '#666' }}>
            ({((record.functions_covered / record.functions_total) * 100).toFixed(1)}%)
          </span>
        </span>
      ),
    },
    {
      title: '最后更新',
      dataIndex: 'last_updated',
      key: 'last_updated',
      width: 150,
      render: (value) => dayjs(value).format('YYYY-MM-DD HH:mm:ss'),
    },
  ];

  // 覆盖率趋势图表配置
  const trendConfig = {
    data: coverageTrend?.map(item => ({
      date: dayjs(item.date).format('MM-DD'),
      后端覆盖率: item.backend_coverage,
      前端覆盖率: item.frontend_coverage,
      总体覆盖率: item.total_coverage,
    })) || [],
    xField: 'date',
    yField: 'value',
    seriesField: 'type',
    smooth: true,
    color: ['#1890ff', '#52c41a', '#faad14'],
    point: {
      size: 3,
      shape: 'circle',
    },
    tooltip: {
      formatter: (datum: ChartDatum & { type?: string; value?: number }) => ({
        name: datum.type,
        value: `${datum.value?.toFixed(1)}%`,
      }),
    },
  };

  // 模块覆盖率柱状图配置
  const moduleCoverageConfig = {
    data: moduleCoverage?.slice(0, 10).map(item => ({
      module: item.module_name.length > 15 ? item.module_name.substring(0, 15) + '...' : item.module_name,
      覆盖率: item.coverage_percentage,
    })) || [],
    xField: 'module',
    yField: '覆盖率',
    color: (datum: ChartDatum) => {
      return datum.覆盖率 >= 80 ? '#52c41a' : datum.覆盖率 >= 60 ? '#faad14' : '#ff4d4f';
    },
    label: {
      position: 'middle',
      formatter: (datum: ChartDatum) => `${datum.覆盖率.toFixed(1)}%`,
    },
    meta: {
      覆盖率: {
        alias: '覆盖率(%)',
        min: 0,
        max: 100,
      },
    },
  };

  return (
    <div style={{ padding: '24px' }}>
      {/* 页面标题和操作按钮 */}
      <div style={{ marginBottom: 24, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h1>测试覆盖率监控</h1>
        <Space>
          <Button
            type="default"
            icon={<SettingOutlined />}
            onClick={() => setThresholdModalVisible(true)}
            loading={thresholdsLoading}
          >
            阈值设置
          </Button>
          <Button
            type="primary"
            icon={<ReloadOutlined />}
            onClick={() => refetchReport()}
            loading={reportLoading}
          >
            刷新数据
          </Button>
        </Space>
      </div>

      {/* 质量门禁状态 */}
      {!qualityGateLoading && qualityGate && (
        <Alert
          style={{ marginBottom: 24 }}
          type={qualityGate.passed ? 'success' : 'error'}
          message={
            qualityGate.passed
              ? '✅ 质量门禁通过 - 所有覆盖率指标都达到要求'
              : '❌ 质量门禁失败 - 存在不达标的覆盖率指标'
          }
          description={
            !qualityGate.passed && qualityGate.failed_checks.length > 0 && (
              <ul style={{ margin: '8px 0 0 0', paddingLeft: 20 }}>
                {qualityGate.failed_checks.map((check, index) => (
                  <li key={index}>{check}</li>
                ))}
              </ul>
            )
          }
          showIcon
        />
      )}

      {/* 总体覆盖率统计卡片 */}
      <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
        <Col span={6}>
          <Card>
            <Statistic
              title="总体覆盖率"
              value={coverageReport?.total_coverage || 0}
              precision={1}
              suffix="%"
              valueStyle={{
                color: (coverageReport?.total_coverage || 0) >= (thresholds?.total_threshold || 75) ? '#3f8600' : '#cf1322',
              }}
              prefix={(coverageReport?.total_coverage || 0) >= (thresholds?.total_threshold || 75) ? <TrendingUpOutlined /> : <TrendingDownOutlined />}
            />
            {thresholds && (
              <div style={{ fontSize: 12, color: '#666', marginTop: 8 }}>
                目标: {thresholds.total_threshold}%
              </div>
            )}
          </Card>
        </Col>
        <Col span={6}>
          <Card>
            <Statistic
              title="后端覆盖率"
              value={coverageReport?.backend_coverage || 0}
              precision={1}
              suffix="%"
              valueStyle={{
                color: (coverageReport?.backend_coverage || 0) >= (thresholds?.backend_threshold || 80) ? '#3f8600' : '#cf1322',
              }}
              prefix={(coverageReport?.backend_coverage || 0) >= (thresholds?.backend_threshold || 80) ? <CheckCircleOutlined /> : <CloseCircleOutlined />}
            />
            {thresholds && (
              <div style={{ fontSize: 12, color: '#666', marginTop: 8 }}>
                目标: {thresholds.backend_threshold}%
              </div>
            )}
          </Card>
        </Col>
        <Col span={6}>
          <Card>
            <Statistic
              title="前端覆盖率"
              value={coverageReport?.frontend_coverage || 0}
              precision={1}
              suffix="%"
              valueStyle={{
                color: (coverageReport?.frontend_coverage || 0) >= (thresholds?.frontend_threshold || 70) ? '#3f8600' : '#cf1322',
              }}
              prefix={(coverageReport?.frontend_coverage || 0) >= (thresholds?.frontend_threshold || 70) ? <CheckCircleOutlined /> : <CloseCircleOutlined />}
            />
            {thresholds && (
              <div style={{ fontSize: 12, color: '#666', marginTop: 8 }}>
                目标: {thresholds.frontend_threshold}%
