  // 租金合同相关API
  async getContracts(params?: RentContractQueryParams): Promise<RentContractListResponse> {
    try {
      const response = await apiClient.get(this.baseUrl, { params });

      // 确保响应数据存在且格式正确
      if (!response) {
        throw new Error('API响应数据为空');
