/**
 * 路由审查器
 * 定期审查路由结构的健康度和最佳实践合规性
 */

import { useCallback } from 'react'
import { ROUTE_CONFIG } from '../constants/routes'

interface RouteAuditIssue {
  severity: 'error' | 'warning' | 'info'
  type: string
  route: string
  message: string
  suggestion?: string
  autoFixable?: boolean
}

interface RouteAuditResult {
  timestamp: number
  totalRoutes: number
  issues: RouteAuditIssue[]
  score: number  // 0-100
  categories: {
    structure: RouteAuditIssue[]
    performance: RouteAuditIssue[]
    security: RouteAuditIssue[]
    maintainability: RouteAuditIssue[]
  }
  recommendations: string[]
  summary: {
    errors: number
    warnings: number
    info: number
  }
}

// 路由配置接口（兼容RouteConfig）
interface Route {
  path?: string
  title?: string
  icon?: string
  permissions?: Array<{ resource: string; action: string }>
  breadcrumb?: string[]
  children?: Route[]
  component?: unknown
  lazy?: boolean
  errorBoundary?: boolean
  [key: string]: unknown
}

interface RouteMetrics {
  route: string
  loadTime: number
  errorRate: number
  usage: number
  lastAccessed: number
}

class RouteAuditor {
  private auditRules: Map<string, (route: Route) => RouteAuditIssue[]> = new Map()
  private performanceThresholds = {
    maxLoadTime: 3000,      // 3秒
    maxErrorRate: 0.05,      // 5%
    minUsage: 10,            // 最少使用次数
    maxDepth: 4              // 最大嵌套深度
  }

  constructor() {
    this.initializeAuditRules()
  }

  private initializeAuditRules() {
    this.auditRules = new Map()

    // 结构审查规则
    this.auditRules.set('structure', (route) => {
      const issues: RouteAuditIssue[] = []

      // 检查路由深度
      const depth = this.calculateRouteDepth(route)
      if (depth > this.performanceThresholds.maxDepth) {
        issues.push({
          severity: 'warning',
          type: 'deep_nesting',
          route: route.path || '',
          message: `路由嵌套过深 (${depth}层)`,
          suggestion: '考虑扁平化路由结构或使用布局组件',
          autoFixable: false
        })
      }

      // 检查路由命名规范
      if (route.path && !this.isValidRoutePath(route.path)) {
        issues.push({
          severity: 'error',
          type: 'invalid_naming',
          route: route.path,
          message: '路由命名不符合规范',
          suggestion: '使用 kebab-case 命名规范，避免驼峰和下划线',
          autoFixable: true
        })
      }

      // 检查参数一致性
      if (route.path && this.hasInconsistentParams(route.path)) {
        issues.push({
          severity: 'warning',
          type: 'inconsistent_params',
          route: route.path,
          message: '路由参数不一致',
          suggestion: '确保相同类型资源的参数命名一致',
          autoFixable: false
        })
      }

      return issues
    })

    // 性能审查规则
    this.auditRules.set('performance', (route) => {
      const issues: RouteAuditIssue[] = []

      // 检查懒加载
      if (!route.lazy && route.component) {
        issues.push({
          severity: 'warning',
          type: 'missing_lazy_load',
          route: route.path || '',
          message: '路由未使用懒加载',
          suggestion: '对非首页路由使用懒加载以提高首屏性能',
          autoFixable: true
        })
      }

      // 检查权限守卫
      if (route.permissions && route.permissions.length > 0 && !route.errorBoundary) {
        issues.push({
          severity: 'info',
          type: 'missing_error_boundary',
          route: route.path || '',
          message: '权限路由缺少错误边界',
          suggestion: '为需要权限验证的路由添加错误边界保护',
          autoFixable: true
        })
      }

      return issues
    })

    // 安全审查规则
    this.auditRules.set('security', (route) => {
      const issues: RouteAuditIssue[] = []

      // 检查权限配置
      if (route.path && this.isSecureRoute(route.path) && (!route.permissions || route.permissions.length === 0)) {
        issues.push({
          severity: 'error',
          type: 'missing_permissions',
          route: route.path || '',
          message: '安全路由缺少权限配置',
          suggestion: '为敏感路由添加适当的权限验证',
          autoFixable: false
        })
      }

      // 检查权限粒度
      if (route.permissions && route.permissions.length > 3) {
        issues.push({
          severity: 'warning',
          type: 'over_granular_permissions',
          route: route.path || '',
          message: '权限配置过于细粒度',
          suggestion: '考虑合并相关权限或使用角色权限',
          autoFixable: false
        })
      }

      return issues
    })

    // 可维护性审查规则
    this.auditRules.set('maintainability', (route) => {
      const issues: RouteAuditIssue[] = []

      // 检查路由文档
      if (!route.title || route.title.trim() === '') {
        issues.push({
          severity: 'warning',
          type: 'missing_title',
          route: route.path || '',
          message: '路由缺少标题',
          suggestion: '为路由添加描述性标题以提高可维护性',
          autoFixable: false
        })
      }

      // 检查面包屑配置
      if (route.path && route.path.split('/').length > 2 && !route.breadcrumb) {
        issues.push({
          severity: 'info',
          type: 'missing_breadcrumb',
          route: route.path,
          message: '深层路由缺少面包屑配置',
          suggestion: '为深层路由添加面包屑导航',
          autoFixable: true
        })
      }

      return issues
    })
  }

  private calculateRouteDepth(route: Route): number {
    if (!route.children || route.children.length === 0) {
      return 1
    }

    return 1 + Math.max(...route.children.map((child: Route) => this.calculateRouteDepth(child)))
  }

  private isValidRoutePath(path: string): boolean {
    // 检查是否符合 kebab-case 规范
    const kebabCaseRegex = /^\/([a-z0-9]+(-[a-z0-9]+)*)*(\/:[a-z0-9]+)*\/?$/
    return kebabCaseRegex.test(path)
  }

  private hasInconsistentParams(path: string): boolean {
    // 检查参数命名一致性
    const params = path.match(/:([^\/]+)/g)
    if (!params) return false

    const paramNames = params.map(p => p.substring(1))

    // 检查是否使用了不一致的命名风格
    const hasCamelCase = paramNames.some(name => /[A-Z]/.test(name))
    const hasSnakeCase = paramNames.some(name => /_/.test(name))
    const hasKebabCase = paramNames.some(name => /-/.test(name))

    return (Number(hasCamelCase) + Number(hasSnakeCase) + Number(hasKebabCase)) > 1
  }

  private isSecureRoute(path: string): boolean {
    const securePatterns = [
      /^\/system\//,
      /^\/admin\//,
      /\/users\/.*\/edit/,
      /\/assets\/.*\/delete/
    ]

    return securePatterns.some(pattern => pattern.test(path))
  }

  public async auditRoutes(metrics?: RouteMetrics[]): Promise<RouteAuditResult> {
    const issues: RouteAuditIssue[] = []
    const categories = {
      structure: [] as RouteAuditIssue[],
      performance: [] as RouteAuditIssue[],
      security: [] as RouteAuditIssue[],
      maintainability: [] as RouteAuditIssue[]
    }

    // 递归审查路由
    const auditRoute = (route: Route, depth = 0) => {
      // 执行所有审查规则
      for (const [category, rule] of this.auditRules) {
        const ruleIssues = rule(route)
        categories[category as keyof typeof categories].push(...ruleIssues)
        issues.push(...ruleIssues)
      }

      // 审查子路由
      if (route.children) {
        route.children.forEach((child: Route) => auditRoute(child, depth + 1))
      }
    }

    // 审查所有路由配置
    ROUTE_CONFIG.forEach(route => auditRoute(route as Route))

    // 如果有性能指标，进行性能相关审查
    if (metrics) {
      const performanceIssues = this.auditRoutePerformance(metrics)
      categories.performance.push(...performanceIssues)
      issues.push(...performanceIssues)
    }

    // 计算审查得分
    const score = this.calculateAuditScore(issues)

    // 生成建议
    const recommendations = this.generateRecommendations(categories)

    // 统计摘要
    const summary = {
      errors: issues.filter(i => i.severity === 'error').length,
      warnings: issues.filter(i => i.severity === 'warning').length,
      info: issues.filter(i => i.severity === 'info').length
    }

    const result: RouteAuditResult = {
      timestamp: Date.now(),
      totalRoutes: this.countRoutes(ROUTE_CONFIG as Route[]),
      issues,
      score,
      categories,
      recommendations,
      summary
    }

    // 上报审查结果
    await this.reportAuditResult(result)

    return result
  }

  private countRoutes(routes: Route[]): number {
    let count = 0
    for (const route of routes) {
      count += 1
      if (route.children) {
        count += this.countRoutes(route.children)
      }
    }
    return count
  }

  private auditRoutePerformance(metrics: RouteMetrics[]): RouteAuditIssue[] {
    const issues: RouteAuditIssue[] = []

    for (const metric of metrics) {
      // 检查加载时间
      if (metric.loadTime > this.performanceThresholds.maxLoadTime) {
        issues.push({
          severity: 'warning',
          type: 'slow_route',
          route: metric.route,
          message: `路由加载时间过长 (${metric.loadTime}ms)`,
          suggestion: '优化组件代码分割或使用预加载',
          autoFixable: false
        })
      }

      // 检查错误率
      if (metric.errorRate > this.performanceThresholds.maxErrorRate) {
        issues.push({
          severity: 'error',
          type: 'high_error_rate',
          route: metric.route,
          message: `路由错误率过高 (${(metric.errorRate * 100).toFixed(1)}%)`,
          suggestion: '检查路由组件的错误处理逻辑',
          autoFixable: false
        })
      }

      // 检查使用率
      if (metric.usage < this.performanceThresholds.minUsage) {
        issues.push({
          severity: 'info',
          type: 'low_usage',
          route: metric.route,
          message: `路由使用率较低 (${metric.usage}次)`,
          suggestion: '考虑是否需要保留该路由或改进其可发现性',
          autoFixable: false
        })
      }
    }

    return issues
  }

  private calculateAuditScore(issues: RouteAuditIssue[]): number {
    const weights = {
      error: 10,
      warning: 5,
      info: 1
    }

    const totalDeduction = issues.reduce((sum, issue) => {
      return sum + weights[issue.severity]
    }, 0)

    const maxScore = 100
    const score = Math.max(0, maxScore - totalDeduction)

    return score
  }

  private generateRecommendations(categories: {
    structure: RouteAuditIssue[]
    performance: RouteAuditIssue[]
    security: RouteAuditIssue[]
    maintainability: RouteAuditIssue[]
  }): string[] {
    const recommendations: string[] = []

    // 基于问题类型生成建议
    const issueTypes = new Set(
      Object.values(categories)
        .flat()
        .map((issue) => (issue as RouteAuditIssue).type)
    )

    if (issueTypes.has('missing_lazy_load')) {
      recommendations.push('建议对所有非首页路由启用懒加载以提高首屏性能')
    }

    if (issueTypes.has('missing_permissions')) {
      recommendations.push('建议审查所有安全路由的权限配置，确保符合最小权限原则')
    }

    if (issueTypes.has('deep_nesting')) {
      recommendations.push('建议重构深层嵌套的路由结构，提高代码可维护性')
    }

    if (issueTypes.has('slow_route')) {
      recommendations.push('建议优化慢路由的性能，考虑代码分割和预加载策略')
    }

    // 通用建议
    if (recommendations.length === 0) {
      recommendations.push('路由结构良好，继续保持当前的代码质量')
    }

    return recommendations
  }

  private async reportAuditResult(result: RouteAuditResult) {
    try {
      // 发送审查结果到监控服务
      await fetch('/api/v1/monitoring/route-audit', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(result)
      })

      // Route audit completed

      if (result.summary.errors > 0) {
        console.warn(`发现 ${result.summary.errors} 个错误，需要立即处理`)
      }

      if (result.summary.warnings > 0) {
        console.info(`发现 ${result.summary.warnings} 个警告，建议优化`)
      }

    } catch (error) {
      console.warn('路由审计结果上报失败:', error)
    }
  }

  public async fixAutoFixableIssues(): Promise<string[]> {
    const fixedIssues: string[] = []

    // 这里可以实现自动修复逻辑
    // 例如：自动添加懒加载、自动修复路由命名等

    // Auto-fix completed
    // console.log('自动修复完成，修复了', fixedIssues.length, '个问题')
    return fixedIssues
  }
}

// Hook for using the route auditor
export const useRouteAuditor = () => {
  const auditor = new RouteAuditor()
  const audit = useCallback(async () => {
    // 执行审计
    return await auditor.auditRoutes()
  }, [auditor])

  const autoFix = useCallback(async () => {
    return await auditor.fixAutoFixableIssues()
  }, [auditor])

  return {
    audit,
    autoFix,
    auditor
  }
}

// 定期审计调度器
export class RouteAuditScheduler {
  private auditor: RouteAuditor
  private interval: NodeJS.Timeout | null = null
  private auditInterval: number // 毫秒

  constructor(auditInterval: number = 24 * 60 * 60 * 1000) { // 默认24小时
    this.auditor = new RouteAuditor()
    this.auditInterval = auditInterval
  }

  start() {
    if (this.interval) {
      this.stop()
    }

    // 立即执行一次审计
    this.performAudit()

    // 设置定期审计
    this.interval = setInterval(() => {
      this.performAudit()
    }, this.auditInterval)

    // Route periodic audit started
    // console.log(`路由定期审计已启动，间隔: ${this.auditInterval / 1000 / 60 / 60} 小时`)
  }

  stop() {
    if (this.interval) {
      clearInterval(this.interval)
      this.interval = null
      // Route periodic audit stopped
      // console.log('路由定期审计已停止')
    }
  }

  private async performAudit() {
    try {
      // Start executing periodic route audit
      // console.log('开始执行定期路由审计...')
      const result = await this.auditor.auditRoutes()

      // Route audit completed
      // console.log(`路由审计完成，得分: ${result.score}/100`)
      if (result.score < 80) {
        console.warn('路由健康度较低，建议关注并修复发现的问题')
      }

    } catch (error) {
      console.error('定期路由审计失败:', error)
    }
  }
}

export default RouteAuditor

/**
 * 路由变更检测器
 * 检测路由配置变更、权限变更和API变更
 */

import { useCallback, useEffect } from 'react'
import { ROUTE_CONFIG } from '../constants/routes'

// 路由配置接口（与RouteAuditor.ts保持一致）
interface Route {
  path?: string
  title?: string
  icon?: string
  permissions?: Array<{ resource: string; action: string }>
  breadcrumb?: string[]
  children?: Route[]
  component?: unknown
  lazy?: boolean
  errorBoundary?: boolean
  [key: string]: unknown
}

interface RouteChangeConfig {
  route: string
  permissions: Array<{ resource: string; action: string }>
  component: string
  params?: string[]
  query?: string[]
}

interface APIChangeConfig {
  endpoint: string
  method: string
  permissions: Array<{ resource: string; action: string }>
  version: string
  deprecated?: boolean
}

interface ChangeDetection {
  timestamp: number
  changes: {
    added: RouteChangeConfig[]
    removed: RouteChangeConfig[]
    modified: Array<{
      route: string
      old: RouteChangeConfig
      new: RouteChangeConfig
    }>
  }
  api_changes: {
    added: APIChangeConfig[]
    removed: APIChangeConfig[]
    modified: Array<{
      endpoint: string
      old: APIChangeConfig
      new: APIChangeConfig
    }>
  }
}

class RouteChangeDetector {
  private lastSnapshot: Map<string, RouteChangeConfig>
  private lastAPISnapshot: Map<string, APIChangeConfig>
  private changeHistory: ChangeDetection[]
  private maxHistorySize: number
  private checkInterval: NodeJS.Timeout | null = null

  constructor() {
    this.lastSnapshot = new Map()
    this.lastAPISnapshot = new Map()
    this.changeHistory = []
    this.maxHistorySize = 50

    this.initializeSnapshots()
    this.startPeriodicCheck()
  }

  private initializeSnapshots() {
    // 初始化路由快照
    this.takeRouteSnapshot()
    this.takeAPISnapshot()
  }

  private takeRouteSnapshot() {
    this.lastSnapshot.clear()

    // 从ROUTE_CONFIG提取路由信息
    const extractRoutes = (configs: Route[], prefix = '') => {
      configs.forEach(config => {
        if (config.path) {
          const routeKey = prefix + config.path
          this.lastSnapshot.set(routeKey, {
            route: routeKey,
            permissions: Array.isArray(config.permissions) ? config.permissions : [],
            component: (config.component as any)?.name || 'Unknown',
            params: this.extractParams(config.path),
            query: []
          })
        }

        if (config.children) {
          extractRoutes(config.children, prefix + (config.path || ''))
        }
      })
    }

    extractRoutes(ROUTE_CONFIG as Route[])
  }

  private takeAPISnapshot() {
    this.lastAPISnapshot.clear()

    // 从API配置提取端点信息
    const apiEndpoints = this.extractAPIEndpoints()
    apiEndpoints.forEach(endpoint => {
      this.lastAPISnapshot.set(`${endpoint.method}:${endpoint.endpoint}`, endpoint)
    })
  }

  private extractParams(path: string): string[] {
    const params: string[] = []
    const paramRegex = /:([^\/]+)/g
    let match

    while ((match = paramRegex.exec(path)) !== null) {
      params.push(match[1])
    }

    return params
  }

  private extractAPIEndpoints(): APIChangeConfig[] {
    // 这里应该从实际的API配置中提取
    // 简化版本，返回已知的API端点
    return [
      {
        endpoint: '/api/v1/assets',
        method: 'GET',
        permissions: [{ resource: 'asset', action: 'view' }],
        version: 'v1'
      },
      {
        endpoint: '/api/v1/assets',
        method: 'POST',
        permissions: [{ resource: 'asset', action: 'create' }],
        version: 'v1'
      },
      {
        endpoint: '/api/v1/assets/{asset_id}',
        method: 'PUT',
        permissions: [{ resource: 'asset', action: 'edit' }],
        version: 'v1'
      },
      {
        endpoint: '/api/v1/users',
        method: 'GET',
        permissions: [{ resource: 'user', action: 'view' }],
        version: 'v1'
      }
    ]
  }

  private startPeriodicCheck() {
    // 每30秒检查一次变更
    this.checkInterval = setInterval(() => {
      this.detectChanges()
    }, 30000)
  }

  public detectChanges(): ChangeDetection | null {
    const currentRoutes = new Map<string, RouteChangeConfig>()
    const currentAPIs = new Map<string, APIChangeConfig>()

    // 获取当前路由配置
    const extractCurrentRoutes = (configs: Route[], prefix = '') => {
      configs.forEach(config => {
        if (config.path) {
          const routeKey = prefix + config.path
          currentRoutes.set(routeKey, {
            route: routeKey,
            permissions: Array.isArray(config.permissions) ? config.permissions : [],
            component: (config.component as any)?.name || 'Unknown',
            params: this.extractParams(config.path),
            query: []
          })
        }

        if (config.children) {
          extractCurrentRoutes(config.children, prefix + (config.path || ''))
        }
      })
    }

    extractCurrentRoutes(ROUTE_CONFIG as Route[])

    // 获取当前API配置
    const currentAPIEndpoints = this.extractAPIEndpoints()
    currentAPIEndpoints.forEach(endpoint => {
      currentAPIs.set(`${endpoint.method}:${endpoint.endpoint}`, endpoint)
    })

    // 检测路由变更
    const routeChanges = {
      added: [] as RouteChangeConfig[],
      removed: [] as RouteChangeConfig[],
      modified: [] as Array<{
        route: string
        old: RouteChangeConfig
        new: RouteChangeConfig
      }>
    }

    // 检测新增的路由
    for (const [key, route] of currentRoutes) {
      if (!this.lastSnapshot.has(key)) {
        routeChanges.added.push(route)
      }
    }

    // 检测删除的路由
    for (const [key, route] of this.lastSnapshot) {
      if (!currentRoutes.has(key)) {
        routeChanges.removed.push(route)
      }
    }

    // 检测修改的路由
    for (const [key, currentRoute] of currentRoutes) {
      const lastRoute = this.lastSnapshot.get(key)
      if (lastRoute && this.routesDiffer(lastRoute, currentRoute)) {
        routeChanges.modified.push({
          route: key,
          old: lastRoute,
          new: currentRoute
        })
      }
    }

    // 检测API变更
    const apiChanges = {
      added: [] as APIChangeConfig[],
      removed: [] as APIChangeConfig[],
      modified: [] as Array<{
        endpoint: string
        old: APIChangeConfig
        new: APIChangeConfig
      }>
    }

    // 检测新增的API
    for (const [key, api] of currentAPIs) {
      if (!this.lastAPISnapshot.has(key)) {
        apiChanges.added.push(api)
      }
    }

    // 检测删除的API
    for (const [key, api] of this.lastAPISnapshot) {
      if (!currentAPIs.has(key)) {
        apiChanges.removed.push(api)
      }
    }

    // 检测修改的API
    for (const [key, currentAPI] of currentAPIs) {
      const lastAPI = this.lastAPISnapshot.get(key)
      if (lastAPI && this.apisDiffer(lastAPI, currentAPI)) {
        apiChanges.modified.push({
          endpoint: key,
          old: lastAPI,
          new: currentAPI
        })
      }
    }

    // 如果有变更，记录并更新快照
    const hasChanges = routeChanges.added.length > 0 ||
                     routeChanges.removed.length > 0 ||
                     routeChanges.modified.length > 0 ||
                     apiChanges.added.length > 0 ||
                     apiChanges.removed.length > 0 ||
                     apiChanges.modified.length > 0

    if (hasChanges) {
      const changeDetection: ChangeDetection = {
        timestamp: Date.now(),
        changes: routeChanges,
        api_changes: apiChanges
      }

      this.changeHistory.push(changeDetection)

      // 保持历史记录在限制范围内
      if (this.changeHistory.length > this.maxHistorySize) {
        this.changeHistory = this.changeHistory.slice(-this.maxHistorySize)
      }

      // 更新快照
      this.lastSnapshot = currentRoutes
      this.lastAPISnapshot = currentAPIs

      // 上报变更
      this.reportChanges(changeDetection)

      return changeDetection
    }

    return null
  }

  private routesDiffer(route1: RouteChangeConfig, route2: RouteChangeConfig): boolean {
    return JSON.stringify(route1.permissions) !== JSON.stringify(route2.permissions) ||
           route1.component !== route2.component
  }

  private apisDiffer(api1: APIChangeConfig, api2: APIChangeConfig): boolean {
    return JSON.stringify(api1.permissions) !== JSON.stringify(api2.permissions) ||
           api1.version !== api2.version ||
           api1.deprecated !== api2.deprecated
  }

  private async reportChanges(changes: ChangeDetection) {
    try {
      // 发送变更报告到监控服务
      await fetch('/api/v1/monitoring/route-changes', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(changes)
      })

      // Route changes reported
      // console.log('路由变更已上报', changes)

      // 如果有重大变更，显示通知
      if (this.hasBreakingChanges(changes)) {
        this.showBreakingChangeNotification(changes)
      }

    } catch (error) {
      console.warn('路由变更上报失败:', error)
    }
  }

  private hasBreakingChanges(changes: ChangeDetection): boolean {
    // 检查是否有破坏性变更
    const { removed, modified } = changes.changes
    const { removed: apiRemoved, modified: apiModified } = changes.api_changes

    // 删除路由或API是破坏性变更
    if (removed.length > 0 || apiRemoved.length > 0) {
      return true
    }

    // 权限变更是破坏性变更
    const permissionChanges = modified.filter(change =>
      JSON.stringify(change.old.permissions) !== JSON.stringify(change.new.permissions)
    )

    const apiPermissionChanges = apiModified.filter(change =>
      JSON.stringify(change.old.permissions) !== JSON.stringify(change.new.permissions)
    )

    return permissionChanges.length > 0 || apiPermissionChanges.length > 0
  }

  private showBreakingChangeNotification(changes: ChangeDetection) {
    // 显示破坏性变更通知
    const notification = new Notification('路由配置已更新', {
      body: '检测到破坏性变更，请查看控制台了解详情',
      icon: '/favicon.ico'
    })

    if (notification) {
      notification.onclick = () => {
        window.focus()
        console.group('🚨 路由变更详情')
        // Change time
        // console.log('变更时间:', new Date(changes.timestamp))
        // Route changes
        // console.log('路由变更:', changes.changes)
        // API changes
        // console.log('API变更:', changes.api_changes)
        console.groupEnd()
      }
    }
  }

  public getChangeHistory(): ChangeDetection[] {
    return [...this.changeHistory]
  }

  public getLastChange(): ChangeDetection | null {
    return this.changeHistory.length > 0 ? this.changeHistory[this.changeHistory.length - 1] : null
  }

  public getBreakingChanges(): ChangeDetection[] {
    return this.changeHistory.filter(changes => this.hasBreakingChanges(changes))
  }

  public manualCheck(): ChangeDetection | null {
    return this.detectChanges()
  }

  public destroy() {
    if (this.checkInterval) {
      clearInterval(this.checkInterval)
      this.checkInterval = null
    }
  }
}

// 全局变更检测器实例
const globalChangeDetector = new RouteChangeDetector()

// Hook for using the change detector
export const useRouteChangeDetector = () => {
  const detector = globalChangeDetector

  const checkChanges = useCallback(() => {
    return detector.manualCheck()
  }, [detector])

  const getHistory = useCallback(() => {
    return detector.getChangeHistory()
  }, [detector])

  const getLastChange = useCallback(() => {
    return detector.getLastChange()
  }, [detector])

  const getBreakingChanges = useCallback(() => {
    return detector.getBreakingChanges()
  }, [detector])

  return {
    checkChanges,
    getHistory,
    getLastChange,
    getBreakingChanges,
    detector
  }
}

// 开发模式下的调试工具
