/**
 * 数据转换工具
 * 处理前后端数据类型转换，特别是Decimal/number转换
 */

import { DecimalUtils } from '@/types/asset'

// 数据对象接口
interface DataObject {
  [key: string]: unknown;
}

// 需要Decimal转换的字段列表
const DECIMAL_FIELDS = [
  // 面积字段
  'land_area',
  'actual_property_area',
  'rentable_area',
  'rented_area',
  'unrented_area',
  'non_commercial_area',
  'occupancy_rate',

  // 金额字段
  'monthly_rent',
  'deposit',
  'annual_income',
  'annual_expense',
  'net_income'
]

/**
 * 将后端数据转换为前端数据
 * 处理Decimal字符串转换为number类型
 */
export const convertBackendToFrontend = <T = unknown>(data: unknown): T => {
  if (!data || typeof data !== 'object') {
    return data
  }

  const result: DataObject = Array.isArray(data) ? [] : {}

  for (const key in data) {
    if (Object.prototype.hasOwnProperty.call(data, key)) {
      const value = data[key]

      if (value === null || value === undefined) {
        result[key] = value
      } else if (DECIMAL_FIELDS.includes(key) && typeof value === 'string') {
        // 处理Decimal字段
        result[key] = DecimalUtils.parseDecimal(value)
      } else if (typeof value === 'object') {
        // 递归处理嵌套对象
        result[key] = convertBackendToFrontend(value)
      } else {
        result[key] = value
      }
    }
  }

  return result as T
}

/**
 * 将前端数据转换为后端数据
 * 处理number类型转换为Decimal字符串
 */
export const convertFrontendToBackend = <T = unknown>(data: unknown): T => {
  if (!data || typeof data !== 'object') {
    return data
  }

  const result: DataObject = Array.isArray(data) ? [] : {}

  for (const key in data) {
    if (Object.prototype.hasOwnProperty.call(data, key)) {
      const value = data[key]

      if (value === null || value === undefined) {
        result[key] = value
      } else if (DECIMAL_FIELDS.includes(key) && typeof value === 'number') {
        // 处理Decimal字段
        result[key] = DecimalUtils.formatDecimal(value)
      } else if (typeof value === 'object') {
        // 递归处理嵌套对象
        result[key] = convertFrontendToBackend(value)
      } else {
        result[key] = value
      }
    }
  }

  return result as T
}

/**
 * 安全的数值计算函数，用于前端的自动计算字段
 */
export const calculateDerivedFields = (asset: DataObject) => {
  const derived: DataObject = {}

  // 计算未出租面积 = 可出租面积 - 已出租面积
  if (asset.rentable_area && asset.rented_area) {
    derived.unrented_area = DecimalUtils.safeSubtract(asset.rentable_area, asset.rented_area)
  }

  // 计算出租率 = (已出租面积 / 可出租面积) × 100%
  if (asset.rentable_area && asset.rented_area && asset.rentable_area > 0) {
    derived.occupancy_rate = DecimalUtils.safeMultiply(
      DecimalUtils.safeDivide(asset.rented_area, asset.rentable_area),
      100
    )
  }

  // 计算净收益 = 年收益 - 年支出
  if (asset.annual_income && asset.annual_expense) {
    derived.net_income = DecimalUtils.safeSubtract(asset.annual_income, asset.annual_expense)
  }

  return derived
}

/**
 * 验证数值字段的合理性
 */
export const validateNumericFields = (asset: DataObject) => {
  const errors: string[] = []

  // 验证面积字段
  const areaFields = [
    { field: 'land_area', name: '土地面积' },
    { field: 'actual_property_area', name: '实际房产面积' },
    { field: 'rentable_area', name: '可出租面积' },
    { field: 'rented_area', name: '已出租面积' },
    { field: 'non_commercial_area', name: '非经营物业面积' }
  ]

  areaFields.forEach(({ field, name }) => {
    if (asset[field] !== undefined && asset[field] !== null) {
      const value = parseFloat(asset[field])
      if (isNaN(value) || value < 0) {
        errors.push(`${name}必须是非负数`)
      }
    }
  })

  // 验证金额字段
  const moneyFields = [
    { field: 'monthly_rent', name: '月租金' },
    { field: 'deposit', name: '押金' },
    { field: 'annual_income', name: '年收益' },
    { field: 'annual_expense', name: '年支出' }
  ]

  moneyFields.forEach(({ field, name }) => {
    const fieldValue = (asset as any)[field]
    if (fieldValue !== undefined && fieldValue !== null) {
      const value = parseFloat(String(fieldValue))
      if (isNaN(value) || value < 0) {
        errors.push(`${name}必须是非负数`)
      }
    }
  })

  // 验证出租率
  if (asset.occupancy_rate !== undefined && asset.occupancy_rate !== null) {
    const value = parseFloat(String(asset.occupancy_rate))
    if (isNaN(value) || value < 0 || value > 100) {
      errors.push('出租率必须在0-100之间')
    }
  }

  // 验证面积逻辑关系
  if (asset.rentable_area && asset.rented_area) {
    const rentableArea = parseFloat(String(asset.rentable_area))
    const rentedArea = parseFloat(String(asset.rented_area))
    if (rentedArea > rentableArea) {
      errors.push('已出租面积不能大于可出租面积')
    }
  }

  return errors
}

// 前端性能优化工具

import React, { useCallback, useMemo, useRef, useEffect, useState } from 'react'

// 防抖Hook
export const useDebounce = <T extends (...args: unknown[]) => unknown>(
  callback: T,
  delay: number
): T => {
  const timeoutRef = useRef<NodeJS.Timeout>()

  return useCallback(
    ((...args: Parameters<T>) => {
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current)
      }
      
      timeoutRef.current = setTimeout(() => {
        callback(...args)
      }, delay)
    }) as T,
    [callback, delay]
  )
}

// 节流Hook
export const useThrottle = <T extends (...args: unknown[]) => unknown>(
  callback: T,
  delay: number
): T => {
  const lastCallRef = useRef<number>(0)

  return useCallback(
    ((...args: Parameters<T>) => {
      const now = Date.now()
      if (now - lastCallRef.current >= delay) {
        lastCallRef.current = now
        callback(...args)
      }
    }) as T,
    [callback, delay]
  )
}

// 虚拟滚动Hook
export const useVirtualScroll = <T>(
  items: T[],
  itemHeight: number,
  containerHeight: number
) => {
  const [scrollTop, setScrollTop] = useState(0)

  const visibleItems = useMemo(() => {
    const startIndex = Math.floor(scrollTop / itemHeight)
    const endIndex = Math.min(
      startIndex + Math.ceil(containerHeight / itemHeight) + 1,
      items.length
    )

    return {
      startIndex,
      endIndex,
      items: items.slice(startIndex, endIndex),
      totalHeight: items.length * itemHeight,
      offsetY: startIndex * itemHeight,
    }
  }, [items, itemHeight, containerHeight, scrollTop])

  const handleScroll = useCallback((e: React.UIEvent<HTMLDivElement>) => {
    setScrollTop(e.currentTarget.scrollTop)
  }, [])

  return {
    ...visibleItems,
    handleScroll,
  }
}

// 图片懒加载Hook
export const useLazyImage = (src: string, options?: IntersectionObserverInit) => {
  const [imageSrc, setImageSrc] = useState<string>()
  const [isLoaded, setIsLoaded] = useState(false)
  const [isError, setIsError] = useState(false)
  const imgRef = useRef<HTMLImageElement>(null)

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setImageSrc(src)
          observer.disconnect()
        }
      },
      options
    )

    if (imgRef.current) {
      observer.observe(imgRef.current)
    }

    return () => observer.disconnect()
  }, [src, options])

  const handleLoad = useCallback(() => {
    setIsLoaded(true)
  }, [])

  const handleError = useCallback(() => {
    setIsError(true)
  }, [])

  return {
    imgRef,
    imageSrc,
    isLoaded,
    isError,
    handleLoad,
    handleError,
  }
}

// 内存泄漏检测
export const useMemoryLeakDetection = (componentName: string) => {
  const mountTimeRef = useRef<number>()
  const timersRef = useRef<Set<NodeJS.Timeout>>(new Set())
  const intervalsRef = useRef<Set<NodeJS.Timeout>>(new Set())
  const listenersRef = useRef<Map<string, EventListener>>(new Map())

  useEffect(() => {
    mountTimeRef.current = Date.now()
    
    return () => {
      const unmountTime = Date.now()
      const lifeTime = unmountTime - (mountTimeRef.current || 0)
      
      // 清理定时器
      timersRef.current.forEach(timer => clearTimeout(timer))
      intervalsRef.current.forEach(interval => clearInterval(interval))
      
      // 清理事件监听器
      listenersRef.current.forEach((listener, event) => {
        window.removeEventListener(event, listener)
      })
      
      // 在开发环境下记录组件生命周期
      if (process.env.NODE_ENV === 'development') {
        // Component unmounted
        
        if (timersRef.current.size > 0) {
          console.warn(`Component ${componentName} had ${timersRef.current.size} uncleaned timers`)
        }
        
        if (listenersRef.current.size > 0) {
          console.warn(`Component ${componentName} had ${listenersRef.current.size} uncleaned listeners`)
        }
      }
    }
  }, [componentName])

  const addTimer = useCallback((timer: NodeJS.Timeout) => {
    timersRef.current.add(timer)
    return timer
  }, [])

  const addInterval = useCallback((interval: NodeJS.Timeout) => {
    intervalsRef.current.add(interval)
    return interval
  }, [])

  const addListener = useCallback((event: string, listener: EventListener) => {
    listenersRef.current.set(event, listener)
    window.addEventListener(event, listener)
  }, [])

  return {
    addTimer,
    addInterval,
    addListener,
  }
}

// 组件渲染性能监控
export const useRenderPerformance = (componentName: string) => {
  const renderCountRef = useRef(0)
  const lastRenderTimeRef = useRef<number>()

  useEffect(() => {
    renderCountRef.current++
    const now = performance.now()
    
    if (lastRenderTimeRef.current) {
      const renderTime = now - lastRenderTimeRef.current
      
      if (process.env.NODE_ENV === 'development' && renderTime > 16) {
        console.warn(`Slow render detected in ${componentName}: ${renderTime.toFixed(2)}ms`)
      }
    }
    
    lastRenderTimeRef.current = now
  })

  useEffect(() => {
    return () => {
      if (process.env.NODE_ENV === 'development') {
        // Component rendered
      }
    }
  }, [componentName])

  return renderCountRef.current
}

// 缓存Hook
export const useCache = <T>(key: string, factory: () => T, deps: unknown[] = []) => {
  const cache = useRef<Map<string, T>>(new Map())

  return useMemo(() => {
    const cacheKey = `${key}_${JSON.stringify(deps)}`
    
    if (cache.current.has(cacheKey)) {
      return cache.current.get(cacheKey)!
    }
    
    const value = factory()
    cache.current.set(cacheKey, value)
    
    // 限制缓存大小
    if (cache.current.size > 100) {
      const firstKey = cache.current.keys().next().value
      if (firstKey) {
        cache.current.delete(firstKey)
      }
    }
    
    return value
  }, deps)
}

// 批量更新Hook
export const useBatchUpdate = <T>(initialValue: T) => {
  const [value, setValue] = useState(initialValue)
  const pendingUpdatesRef = useRef<Array<(prev: T) => T>>([])
  const timeoutRef = useRef<NodeJS.Timeout>()

  const batchUpdate = useCallback((updater: (prev: T) => T) => {
    pendingUpdatesRef.current.push(updater)
    
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current)
    }
    
    timeoutRef.current = setTimeout(() => {
      setValue(prev => {
        return pendingUpdatesRef.current.reduce((acc, update) => update(acc), prev)
      })
      pendingUpdatesRef.current = []
    }, 0)
  }, [])

  return [value, batchUpdate] as const
}

// Web Worker Hook
export const useWebWorker = (workerScript: string) => {
  const workerRef = useRef<Worker>()
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<Error>()

  useEffect(() => {
    try {
      workerRef.current = new Worker(workerScript)
      
      workerRef.current.onerror = (error) => {
        setError(new Error(error.message))
        setIsLoading(false)
      }
      
      return () => {
        workerRef.current?.terminate()
      }
    } catch (err) {
      setError(err as Error)
    }
  }, [workerScript])

  const postMessage = useCallback((data: unknown) => {
    if (workerRef.current) {
      setIsLoading(true)
      setError(undefined)
      workerRef.current.postMessage(data)
    }
  }, [])

  const onMessage = useCallback((callback: (data: unknown) => void) => {
    if (workerRef.current) {
      workerRef.current.onmessage = (event) => {
        setIsLoading(false)
        callback(event.data)
      }
    }
  }, [])

  return {
    postMessage,
    onMessage,
    isLoading,
    error,
  }
}

// 资源预加载
export const preloadResource = (url: string, type: 'script' | 'style' | 'image' = 'script') => {
  return new Promise((resolve, reject) => {
    let element: HTMLElement

    switch (type) {
      case 'script':
        element = document.createElement('script')
        ;(element as HTMLScriptElement).src = url
        break
      case 'style':
        element = document.createElement('link')
        ;(element as HTMLLinkElement).rel = 'stylesheet'
        ;(element as HTMLLinkElement).href = url
        break
      case 'image':
        element = document.createElement('img')
        ;(element as HTMLImageElement).src = url
        break
    }

    element.onload = () => resolve(element)
    element.onerror = reject

    if (type !== 'image') {
      document.head.appendChild(element)
    }
  })
}

// 批量预加载资源
export const preloadResources = async (resources: Array<{ url: string; type?: 'script' | 'style' | 'image' }>) => {
  const promises = resources.map(({ url, type = 'script' }) => preloadResource(url, type))
  return Promise.allSettled(promises)
}

// 性能监控装饰器
export const withPerformanceMonitoring = <P extends object>(
  Component: React.ComponentType<P>,
  componentName: string
) => {
  return React.memo((props: P) => {
    useRenderPerformance(componentName)
    useMemoryLeakDetection(componentName)

    return React.createElement(Component, props)
  })
}

